-- Poems batch 428
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuanqu-8826','小桃红','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','腊天不雨，喜在庄农，爱日暄晴昼也。',92,'元曲/yuanqu.json','["腊天不雨，喜在庄农，爱日暄晴昼也。", "转过疏篱步跷踵，极目看西东，四下里影无踪，只听得雷声也。", "莫不是老倒无能？怨天公令自行冬。", "远远望见卧牛岗边，一道火光，透入天门。", "莫非小的失火？待我观看。"]'),
('yuanqu-8827','下山虎','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','见一人高卧，见一人高卧，倒在蒿蓬，鼻息如雷振也。',72,'元曲/yuanqu.json','["见一人高卧，见一人高卧，倒在蒿蓬，鼻息如雷振也。", "气如吐虹。", "我把两眼摩挲，觑他貌容。", "呀！元来是霸业图王一大雄，更有蛇穿窍定须显荣，振动山河鱼化龙。"]'),
('yuanqu-8828','蛮牌令犯','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(外)急急去报三公。',231,'元曲/yuanqu.json','["(外)急急去报三公。", "(旦上)见怪非怪，其怪自害。", "(外)女孩儿因甚出闺门？(旦)怪哉怪哉真怪哉，见五色蛇儿坠紫青红，一步步赶来后，影也无踪。", "(外)孩儿，你为何到此？(旦)奴家在绣房中做女工针指，只见天窗下调下一条花蛇。", "奴家紧赶紧走，慢赶慢行，赶到这里，不见这蛇了。", "(外)我儿，你可要见这蛇么？(旦)奴家要见。", "在那里？(外)这不是蛇。", "(旦)见着后，见着后使奴心惊，莫不是妖精把他缠定？(外)女孩儿休得气冲冲，大贵人蛇穿七窍中。", "一朝运通，九霄气冲，异日轩昂把妻子来封。"]'),
('yuanqu-8829','傍妆台','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','爹爹做事不思维，他是我家牧牛的。',43,'元曲/yuanqu.json','["爹爹做事不思维，他是我家牧牛的。", "缘何把我与他做夫妻？爹听启，儿拜启，山鸡怎与凤凰栖？。"]'),
('yuanqu-8830','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(外)孩儿你好不思维，难道刘郎穷到底，不记得马鸣王庙里现出五爪金龙来取鸡。',64,'元曲/yuanqu.json','["(外)孩儿你好不思维，难道刘郎穷到底，不记得马鸣王庙里现出五爪金龙来取鸡。", "爹言语，儿记取，后来必定挂朝衣。", "你自进去，我自有主张。"]'),
('yuanqu-8831','驻马摘金桃','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','他本是豪门，住在沙陀小李村。',77,'元曲/yuanqu.json','["他本是豪门，住在沙陀小李村。", "我与他公公来往，与我家中有些薄亲。", "他暂时落薄暂时贫，领归来自然依本分。", "何故怒生嗔？交他进也无门，退也无门，全不有大人苦乐不均。"]'),
('yuanqu-8832','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(净、丑)上告严尊，他又不是我家相识我家亲。',84,'元曲/yuanqu.json','["(净、丑)上告严尊，他又不是我家相识我家亲。", "况兼官司文榜，不许窝藏面生乔人。", "当初来历不分明，被两邻觉察难藏隐，打教他须防人不仁。", "出入无凭，胡做为一个真歹人，累及我庄门。"]'),
('yuanqu-8833','忆多娇','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(外)你休怨忆，莫叹息，将他做小儿一般见识，巧语花言都勾讫。',47,'元曲/yuanqu.json','["(外)你休怨忆，莫叹息，将他做小儿一般见识，巧语花言都勾讫。", "凛凛雄威，凛凛雄威，管取前程显赫。"]'),
('yuanqu-8834','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生)蒙感激，承爱惜，你便是亲生父母将何报？自恨时乖遭困厄。',81,'元曲/yuanqu.json','["(生)蒙感激，承爱惜，你便是亲生父母将何报？自恨时乖遭困厄。", "暮打朝嗔，暮打朝嗔，如何过得？(外)贤倒，你且不要烦恼，少间央李三公来。", "与你说话，自有好处，不消回去。"]'),
('yuanqu-8835','生查子','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(末扮李三公上)村庄守已，茅屋悄然而已。',20,'元曲/yuanqu.json','["(末扮李三公上)村庄守已，茅屋悄然而已。"]'),
('yuanqu-8836','麻婆子','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(丑上)画烛画烛光摇映，宾相两边排。',46,'元曲/yuanqu.json','["(丑上)画烛画烛光摇映，宾相两边排。", "闻知姑娘嫁穷胎，好酒吃大碗，好肉吃大块，吃得桃花上脸来。"]'),
('yuanqu-8837','七娘子引','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生上)蒙君不弃我身寒，今日里喜结良缘。',39,'元曲/yuanqu.json','["(生上)蒙君不弃我身寒，今日里喜结良缘。", "(旦上)一朵奇花今有主，姻缘感谢苍天。"]'),
('yuanqu-8838','天下乐','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(外)我女孩儿，喜室家男女及时，看双双俏如比翼。',75,'元曲/yuanqu.json','["(外)我女孩儿，喜室家男女及时，看双双俏如比翼。", "五百年前结会，相看到此不暂离，行坐如鱼水，图伊改门闾，满家都荣贵。", "(合)岂容易，双双尽老，百岁效于飞。"]'),
('yuanqu-8839','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生)智远咨启，荷公婆收录提携，幸一身免遭污泥。',62,'元曲/yuanqu.json','["(生)智远咨启，荷公婆收录提携，幸一身免遭污泥。", "五百年前结会，山鸡怎与凤凰飞？深感不嫌弃。", "铭心在肺腑，难报恩和义。", "(合前)。"]'),
('yuanqu-8840','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(末)吉日良时，请新郎合把交杯，喜筵前满堂和气。',62,'元曲/yuanqu.json','["(末)吉日良时，请新郎合把交杯，喜筵前满堂和气。", "五百年前结会，朗才女貌多俊美，配合成一处。", "如今但愿取，夫荣与妻贵。", "(合前)。"]'),
('yuanqu-8841','越恁好','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','洞房罗帏里，洞房罗帏里，殷勤泛金杯。',61,'元曲/yuanqu.json','["洞房罗帏里，洞房罗帏里，殷勤泛金杯。", "才朗好似潘安貌，女赛西施，一双两好如鱼水。", "珠翠列两行，笙歌拥人生房裹，笙歌拥入兰房里。"]'),
('yuanqu-8842','尾声','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(众)刘朗误入桃源里，羡满门恩情乐意，愿百岁夫妻直到底。',28,'元曲/yuanqu.json','["(众)刘朗误入桃源里，羡满门恩情乐意，愿百岁夫妻直到底。"]'),
('yuanqu-8843','一剪梅','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生上)春色撩人似酒浓，花影重重，日影重重。',44,'元曲/yuanqu.json','["(生上)春色撩人似酒浓，花影重重，日影重重。", "(旦上)卖花声过小桥东，帘卷春风，人在春风。"]'),
('yuanqu-8844','水底鱼儿','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(净上)懊恨爹娘，无知忒性刚。',53,'元曲/yuanqu.json','["(净上)懊恨爹娘，无知忒性刚。", "招刘穷为婿，在家中惹祸殃。", "爹娘死了，那时我主张。", "赶刘穷出去，喜薄欢欢笑一场。"]'),
('yuanqu-8845','颂','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','急急修，急急修，和尚好吃烂猪头。',44,'元曲/yuanqu.json','["急急修，急急修，和尚好吃烂猪头。", "西天活佛没得与我做，再来阴凉树下舔鼻头。", "无量佛阿弥陀佛。"]'),
('yuanqu-8846','五更转犯','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(净)我献香香供养，(介)就把松柴权当香。',66,'元曲/yuanqu.json','["(净)我献香香供养，(介)就把松柴权当香。", "爹娘死了？我便为家长。", "赶出刘郎，心儿里快活帐。", "(合)愿慈悲显现，显现降临道场，消除这灾障。"]'),
('yuanqu-8847','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(旦)办志诚，灯供养，献光明照十方。',44,'元曲/yuanqu.json','["(旦)办志诚，灯供养，献光明照十方。", "神通显现，显现花台上。", "保佑爹娘，身康无恙。", "(合前)。"]'),
('yuanqu-8848','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(末)我献灯，灯光亮，作善须降祥。',42,'元曲/yuanqu.json','["(末)我献灯，灯光亮，作善须降祥。", "阴空保佑，保佑福无量。", "愿我哥嫂身位安康。", "(合前)。"]'),
('yuanqu-8849','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(丑)我献花，花供养，花开花落满园香。',72,'元曲/yuanqu.json','["(丑)我献花，花供养，花开花落满园香。", "也有青莲花红莲花白莲花五色样莲花，插在银瓶上。", "又不见馒头，馒头共粉汤。", "(合前)(丑)大官人。", "肚中青花田了。"]'),
('yuanqu-8850','临江仙','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生上)盖世英雄一旦休，不知和他有甚冤仇？犹如秋雨，一点一声愁。',109,'元曲/yuanqu.json','["(生上)盖世英雄一旦休，不知和他有甚冤仇？犹如秋雨，一点一声愁。", "(旦上)一别爹娘苦痛哉，被兄嫂日夜沈埋。", "夫妻两口浑无计。", "哥哥不念同胞共乳胎。", "(生)闭户推窗莫要来，推将出去又还来。", "(旦)朝嗔暮打何日了，不知兄嫂甚情怀？。"]'),
('yuanqu-8851','山坡羊','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生)三娘不知何处？你哥嫂直恁无理。',81,'元曲/yuanqu.json','["(生)三娘不知何处？你哥嫂直恁无理。", "无端逼写，逼写休书去。", "心惨凄，妻，你在房中怎得知？今番打散，打散鸳鸯对。", "一点一画难提笔起。", "思之，愁烦诉与谁？伤悲，交人珠泪垂。"]'),
('yuanqu-8852','玉交枝','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(净、丑)伊休执见，枉伤悲徒然泪涟。',66,'元曲/yuanqu.json','["(净、丑)伊休执见，枉伤悲徒然泪涟。", "急急写下休书，今日与你盘缠。", "迟延少待乞大拳，披麻惹火烧身怨，莫待等江心补漏船，莫待等江心补漏船。"]'),
('yuanqu-8853','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生)愁拈班管，展花笺盈盈泪涟。',66,'元曲/yuanqu.json','["(生)愁拈班管，展花笺盈盈泪涟。", "夫妻指望同百年，谁知付与花笺？画一画满怀愁万千，丢一丢顿觉心惊战。", "怎写得休书尽言？怎写得休书尽言？。"]'),
('yuanqu-8854','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','叔叔搭救，诉不尽衔冤负屈。',64,'元曲/yuanqu.json','["叔叔搭救，诉不尽衔冤负屈。", "没来由逼写休书，将他苦苦熬煎。", "天天，共乳同胞不见怜，铁石人五脏心不善。", "止不住盈盈泪涟，止不住盈盈泪涟。"]'),
('yuanqu-8855','石榴花','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','我哥哥眼内识贤人，情愿将伊妹子结成亲。',70,'元曲/yuanqu.json','["我哥哥眼内识贤人，情愿将伊妹子结成亲。", "他暂时落薄暂时贫，你们休得闲争论，被傍人闻知作话文。", "大凡事须要相和顺。", "刘郎发迹为官后，大家荣耀李庄门。"]'),
('yuanqu-8856','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(净)非因小侄怒生嗔，那得闲衣闲饭养闲人。',105,'元曲/yuanqu.json','["(净)非因小侄怒生嗔，那得闲衣闲饭养闲人。", "又不会锄田车水与耕耘，夫妻两口长欢庆。", "因此上逼他写下休书退了亲。", "(旦)哥哥，这个怎么使得？奴家有半年孕了。", "(丑)叫一个收生娶落了他身孕。", "刘穷若是身发迹，直待黄河水澄清。"]'),
('yuanqu-8857','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(丑)公公前日不识人，山鸡怎逐凤凰群？又没家舍又身贫，却不如马力共牛筋，那些个半斤逢八两门。',69,'元曲/yuanqu.json','["(丑)公公前日不识人，山鸡怎逐凤凰群？又没家舍又身贫，却不如马力共牛筋，那些个半斤逢八两门。", "傍人恁般行径。", "他还发迹为官日，做枝蜡烛照乾坤。"]'),
('yuanqu-8858','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生)我每年少正青春，更有武艺果超群。',72,'元曲/yuanqu.json','["(生)我每年少正青春，更有武艺果超群。", "我暂时落薄暂时贫，只得忍气吞声。", "你如何只管打骂人？不学跨下韩信。", "男儿有显达身荣日，果然一步跨青云。", "(下)。"]'),
('yuanqu-8859','生查子','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生上)满腹愁如织，此恨何日白？难道男儿不泪垂？事到如流水。',30,'元曲/yuanqu.json','["(生上)满腹愁如织，此恨何日白？难道男儿不泪垂？事到如流水。"]'),
('yuanqu-8860','剔银灯','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','闲时节三言两语，从今后一笔勾除。',52,'元曲/yuanqu.json','["闲时节三言两语，从今后一笔勾除。", "郎争舅子因合理，从此后一团和气。", "(合)一杯冲破了是非，今晚向瓜园中调理。"]'),
('yuanqu-8861','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生)刘智远得罪自知，因贫困多蒙周济。',40,'元曲/yuanqu.json','["(生)刘智远得罪自知，因贫困多蒙周济。", "有缘千里能相会，这恩德何日忘之？(合前)。"]'),
('yuanqu-8862','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(丑)刘姑夫听奴拜启，切莫要专心劳记。',95,'元曲/yuanqu.json','["(丑)刘姑夫听奴拜启，切莫要专心劳记。", "儿夫性刚忒没礼，把闲事一笔勾除。", "(合前。", "净)切莫要与三姑娘得知。", "(生)醉了，不吃了。", "(净浑介)。", "听我一言断送，须要勤耕苦种。", "若不听我良言，各自寻条蛇弄。"]'),
('yuanqu-8863','一枝花','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(旦上)哥哥忒恁毒，嫂嫂浑无计。',36,'元曲/yuanqu.json','["(旦上)哥哥忒恁毒，嫂嫂浑无计。", "夫妻分散怎施为？逼写休书，闪得我没存济。"]'),
('yuanqu-8864','一江风','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生)你是个妇人家，说这般输机话，神鬼偏不怕。',66,'元曲/yuanqu.json','["(生)你是个妇人家，说这般输机话，神鬼偏不怕。", "我为人顶着天地神明，生长在三光下。", "平生不信邪，平生不信邪，心正可去也。", "总然有鬼吾不怕。"]'),
('yuanqu-8865','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(旦)你后生家，说这般过头话，神鬼谁不怕？怕你五行乖。',101,'元曲/yuanqu.json','["(旦)你后生家，说这般过头话，神鬼谁不怕？怕你五行乖。", "官人，奴家有个古人，比与你听。", "不记得梅岭陈辛，季宝遇着金神，此事无虚诈。", "我哥哥使计策，我哥哥使计策，奴家苦恨他，怕你死在黄泉下。", "他那里有鬼，去不得。"]'),
('yuanqu-8866','临江仙','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生)他那里有邪魔，俺这里偏不怕。',17,'元曲/yuanqu.json','["(生)他那里有邪魔，俺这里偏不怕。"]'),
('yuanqu-8867','虞美人','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生上)可惜英雄都丧弃，无烦恼要寻烦恼。',34,'元曲/yuanqu.json','["(生上)可惜英雄都丧弃，无烦恼要寻烦恼。", "遥望卧牛冈上，今晚便知分晓。"]'),
('yuanqu-8868','祝英台','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','渐黄昏大欲暝，一抹淡云飘。',95,'元曲/yuanqu.json','["渐黄昏大欲暝，一抹淡云飘。", "孤鹜暮鸦，秋水长天月照。", "小涧溪桥，挟掉。", "见渔父收纶归去，又见前村深杳。", "睹此景天然一段难描。", "寻思李洪一这般样做作，交你一报还一报。", "只见乌鸦喜鹊同枝噪，吉凶事全然难保。"]'),
('yuanqu-8869','锁南枝','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','灵魂听咨启，今晚中他计。',41,'元曲/yuanqu.json','["灵魂听咨启，今晚中他计。", "舅舅着我看瓜，要害吾身已。", "望祖宗，阴保庇，有凶时，化为吉。"]'),
('yuanqu-8870','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','默默自思之，吉凶尚未知。',50,'元曲/yuanqu.json','["默默自思之，吉凶尚未知。", "四野全无纵迹，那更地冷天昏。", "猛可的狂风起。", "心下疑，自三思，害生灵，有何意？。"]'),
('yuanqu-8871','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','何妖怪甚么鬼？和咱比个英雄势。',45,'元曲/yuanqu.json','["何妖怪甚么鬼？和咱比个英雄势。", "我把两眼摩挲，看他来踪迹。", "黑魃魃，一个鬼，不下来，待何时？。"]'),
('yuanqu-8872','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','妖精听吾语，天交我来断送你。',69,'元曲/yuanqu.json','["妖精听吾语，天交我来断送你。", "生死今宵园内。", "到此不免将一块瓦打上去，看他如何？却元来宿乌惊栖，唬得我肝肠碎。", "望祖宗，阴保庇，有凶事。", "化为吉。"]'),
('yuanqu-8873','剔银灯','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','当答谢瓜园中土地，劳看守刀甲头盔兵书宝剑埋藏此，得前程方来取你。',87,'元曲/yuanqu.json','["当答谢瓜园中土地，劳看守刀甲头盔兵书宝剑埋藏此，得前程方来取你。", "神明听吾诉与，休泄漏天公事机。", "远远望见一个妇人，好似三姐。", "不免躲在一边则个。", "要知心腹事，但听口中言。", "(躲介)。"]'),
('yuanqu-8874','醉扶归','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(旦上)好苦切甘生受，只得到此且藏羞。',54,'元曲/yuanqu.json','["(旦上)好苦切甘生受，只得到此且藏羞。", "奴与哥哥有甚冤仇，只得慌忙便走，裙儿破忙把饭来兜。", "(合)泪湿透衣衫袖。"]'),
('yuanqu-8875','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','丈夫丈夫，信他甜言说诱，谁知今日悔成忧？百岁夫妻一旦休，先在卧牛冈上埋尸首，恩爱都付与水东流。',52,'元曲/yuanqu.json','["丈夫丈夫，信他甜言说诱，谁知今日悔成忧？百岁夫妻一旦休，先在卧牛冈上埋尸首，恩爱都付与水东流。", "(合前)。"]'),
('yuanqu-8876','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','指望和你白头相守，谁知今日不长久。',41,'元曲/yuanqu.json','["指望和你白头相守，谁知今日不长久。", "百岁夫妻一旦休，半年身孕伊知否？或男或女要当留。"]'),
('yuanqu-8877','醉扶归','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','自恨我好不唧留，这碗淡饭怎入。',15,'元曲/yuanqu.json','["自恨我好不唧留，这碗淡饭怎入。"]'),
('yuanqu-8878','桂枝香','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生)叔丈听告，容吾分道。',69,'元曲/yuanqu.json','["(生)叔丈听告，容吾分道。", "只因缺少盘缠，交我如何是好？多因命乖，多因命乖，吃他胡炒，是我分缘不到。", "自今朝，拜别恩人去。", "李洪一冤家恨怎消？。"]'),
('yuanqu-8879','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(旦)自从爹爹死了，止有嫡亲兄嫂。',75,'元曲/yuanqu.json','["(旦)自从爹爹死了，止有嫡亲兄嫂。", "他缘何反面生嗔？拆散大妻两口。", "望叔叔做主，望叔叔做主。", "想是姻缘不到，怎得大妻谐老？自今朝，拜别分离去，交奴苦怎熬？。"]'),
('yuanqu-8880','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(末)听吾言道，不须烦恼。',65,'元曲/yuanqu.json','["(末)听吾言道，不须烦恼。", "你若缺少盘缠，顷刻令人送到。", "他若昧心，他若昧心，上有苍天知道，必然还报。", "自今朝，步辇登程去，坚心莫惮劳。"]'),
('yuanqu-8881','狮子序','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(旦)伊说话太无情。',96,'元曲/yuanqu.json','["(旦)伊说话太无情。", "(生)你哥嫂无情。", "(旦)又道是一牢永定宁，死后如何交我改嫁人？是我腹中有孕，怎交儿女从别姓？你出言语忒煞伤情，这恩德如盐落井。", "(合)分别去各办志诚，便做铁石心肠也须交泪零。"]'),
('yuanqu-8882','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生)上告妻妻听，怕你执不定。',51,'元曲/yuanqu.json','["(生)上告妻妻听，怕你执不定。", "你哥嫂忒毒狠，只恐你口说无凭准。", "我独自守孤另，恐耽阁两下成病。", "(合前)。"]'),
('yuanqu-8883','入赚','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(丑上)去程已紧，李三公多怜悯，些少盘缠相赠恁。',80,'元曲/yuanqu.json','["(丑上)去程已紧，李三公多怜悯，些少盘缠相赠恁。", "(生)这恩德山样高来海样深，生死难忘叔丈恩。", "你与我回言拜禀，异日身荣来报恩。", "(丑)谨依台命，谨依台命。", "(丑下)。"]'),
('yuanqu-8884','金莲子','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生)办登程，办登程，渡水登山莫暂停。',40,'元曲/yuanqu.json','["(生)办登程，办登程，渡水登山莫暂停。", "天怜念，天怜念，名利早成，回归此日再欢庆。"]'),
('yuanqu-8885','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(旦)叮咛嘱付三四声，野草闲花莫要寻。',43,'元曲/yuanqu.json','["(旦)叮咛嘱付三四声，野草闲花莫要寻。", "将恩爱，将恩爱，番成作画饼，只恐别时容易瘦伶仃。"]'),
('yuanqu-8886','尾声','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生旦)生离死别皆前定，未知何日得见恁？铁石心肠也洞零。',28,'元曲/yuanqu.json','["(生旦)生离死别皆前定，未知何日得见恁？铁石心肠也洞零。"]'),
('yuanqu-8887','集贤宾','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','麻鞋紧系一似飞，只得步辇登程。',55,'元曲/yuanqu.json','["麻鞋紧系一似飞，只得步辇登程。", "野草闲花愁满地，过前村小桥流水。", "渔翁钓叟，动浪板歌声摇拽。", "堪玩处，遥望远浦帆归。"]'),
('yuanqu-8888','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','不恨你来却恨谁？此恨何日忘之？话别叮咛心惨凄，撇不下少年贤妻。',56,'元曲/yuanqu.json','["不恨你来却恨谁？此恨何日忘之？话别叮咛心惨凄，撇不下少年贤妻。", "行行泪滴，我为你越添憔悴。", "思念忆，真个是寸肠千里。"]'),
('yuanqu-8889','梁州序','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(外扮岳节使上)掌握三军胆气雄，有千里威风。',186,'元曲/yuanqu.json','["(外扮岳节使上)掌握三军胆气雄，有千里威风。", "朝廷敕命守山东，咱不免行吾军令。", "马跨征鞍将挂袍，柳梢枝上月儿高。", "将军未挂封侯印，腰下常悬带血刀。", "自家姓岳名勋，官拜节度使之职。", "如今四方离乱，民遭涂炭，士民荒凉。", "朝廷有旨，着俺招军买马，积草聚粮。", "正是\"君王有难思良将，人到中年忆子孙。", "\"左右的，与我扯起招军旗。", "叫街坊上民庶，三百六十行做买卖的，愿投军者，旗下报名。", "(净、丑应介)。"]'),
('yuanqu-8890','水底鱼','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','买马招军，何年得太子？愿立旗下，做个头目人。',22,'元曲/yuanqu.json','["买马招军，何年得太子？愿立旗下，做个头目人。"]'),
('yuanqu-8891','醉扶太平','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生上)闻说招军，智远慌忙来到。',160,'元曲/yuanqu.json','["(生上)闻说招军，智远慌忙来到。", "长官，(净)两张张半。", "(生)我是投军的。", "(净)禀老爷，辕门外一人投军。", "(外)方才咐吩你，军完马足，放下招军旗。", "违俺将令，斩讫报来。", "(净)爷爷，添来的寿，增来的福，有增无减。", "(外)令进来。", "(净)为你险些儿去了吃饭的家火。", "(生)有累了。", "(净)投军的进来。", "(生进见外。", "跪介。", "外)汉子那里人氏？。"]'),
('yuanqu-8892','引军旗','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生)小人住在沙陀村里，自小习兵机。',54,'元曲/yuanqu.json','["(生)小人住在沙陀村里，自小习兵机。", "十八般武艺皆能会，愿立旗下听差使。", "(合)忽朝名挂在云台上，方知武艺精细。"]'),
('yuanqu-8893','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(外)听他说兵机，此汉真奇异。',41,'元曲/yuanqu.json','["(外)听他说兵机，此汉真奇异。", "谙晓六韬三略法。", "那队少人？(净)都完了，长行队少人。"]'),
('yuanqu-8894','庆青春','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(旦上)冷清清，闷怀戚戚伤情，好梦难成。',74,'元曲/yuanqu.json','["(旦上)冷清清，闷怀戚戚伤情，好梦难成。", "明月穿窗，偏照奴独守孤另。", "一种黄连分两下，那边受苦这边愁。", "自从丈夫去后，被兄嫂凌逼。", "儿夫杳无音信回来，好苦。"]'),
('yuanqu-8895','集贤宾','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','当初指望谐老年，和你厮守百年。',71,'元曲/yuanqu.json','["当初指望谐老年，和你厮守百年。", "谁想我哥哥心改变，把骨肉顿成抛闪。", "凝望眼穿，空自把栏杆倚遍。", "儿夫去远，悄没个音书回转，常思念。", "何日里再得团圆？。"]'),
('yuanqu-8896','搅群羊','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(旦)嫂嫂话难听，激得我心儿闷。',61,'元曲/yuanqu.json','["(旦)嫂嫂话难听，激得我心儿闷。", "一马一鞍，再嫁傍人论。", "夫去投军，谁敢为媒证？那有休书，谁敢来询问？你如何交奴交奴再嫁人？。"]'),
('yuanqu-8897','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(丑)姑姑你试听，日夜里成孤另。',49,'元曲/yuanqu.json','["(丑)姑姑你试听，日夜里成孤另。", "寻个良媒，嫁个多聪俊。", "虚度青春，白发来侵鬓。", "你如何如何不改嫁人？。"]'),
('yuanqu-8898','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(旦)哥哥共乳同胞一母生，今日如何反面嗔？休听枕边言聒，且自宁心。',67,'元曲/yuanqu.json','["(旦)哥哥共乳同胞一母生，今日如何反面嗔？休听枕边言聒，且自宁心。", "亲旧情亲，姊妹莫相争。", "待奴身孕始倾，若得后来重复事，金瓯再覆李门庭。"]'),
('yuanqu-8899','三学士','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(净)堪笑非亲却是亲，把你做乞丐看承。',69,'元曲/yuanqu.json','["(净)堪笑非亲却是亲，把你做乞丐看承。", "刘郎去了无音信，何不改嫁别人？你若不依兄嫂说，打交身躯不直半分。", "(合)从今后挨磨到四更，挑水到黄昏。"]'),
('yuanqu-8900','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(丑)一世为人只要勤，那得闲衣闲饭养闲人。',41,'元曲/yuanqu.json','["(丑)一世为人只要勤，那得闲衣闲饭养闲人。", "(旦)爹娘产业都有分，何故苦乐不均平？。"]'),
('yuanqu-8901','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(旦)好笑哥哥人不仁，不念同胞兄妹情。',68,'元曲/yuanqu.json','["(旦)好笑哥哥人不仁，不念同胞兄妹情。", "刘郎去了无音信，何故改嫁别人？况兼奴有身怀孕，再嫁傍人作活文。", "(合)奴情愿挨磨到四更，挑水到黄昏。"]'),
('yuanqu-8902','尾声','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','哥哥嫂嫂没前程，苦逼奴家再嫁人。',32,'元曲/yuanqu.json','["哥哥嫂嫂没前程，苦逼奴家再嫁人。", "日间挑水三百担，夜间挨磨到天明。"]'),
('yuanqu-8903','山歌','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生上)四顾青山失翠微，乌鸦变作鹭鸶飞。',36,'元曲/yuanqu.json','["(生上)四顾青山失翠微，乌鸦变作鹭鸶飞。", "天宫勿念人寒冷，冻杀街头刘健儿。"]'),
('yuanqu-8904','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(净丑上)雪落纷纷似银铺，万里江山如画图。',131,'元曲/yuanqu.json','["(净丑上)雪落纷纷似银铺，万里江山如画图。", "鹭鸶失队难寻觅，黑和尚变化白师姑。", "刘健儿，怎么不买冻鱼酒来我每吃？(生)不曾支粮，支了粮请你每一醉。", "(净丑)也罢。", "刘健儿，今晚巡更，该你巡夜。", "一更是我，二更是他。", "三更四更五更都是你。", "老爷有铜牌花号为准，交你更次提铃喝号。"]'),
('yuanqu-8905','金钱花','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(众)我打一更鼓儿冬冬冬，一棒锣声当当当。',46,'元曲/yuanqu.json','["(众)我打一更鼓儿冬冬冬，一棒锣声当当当。", "将军马上醉醺醺，跃马扬鞭齐和声。", "(二三更照前唱)。"]'),
('yuanqu-8906','月云高','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生吊场)自别三娘面，劳役受万千遍。',80,'元曲/yuanqu.json','["(生吊场)自别三娘面，劳役受万千遍。", "到此投军，数目都招遍。", "落在长行队，提铃报更点。", "汤风冒雪图荣显。", "受此饥寒，没个可怜见。", "天天若肯周全，际会风云。", "方表刘皓字智远。"]'),
('yuanqu-8907','探春令','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','彤云缭绕，六花飞遍，楼台银砌。',80,'元曲/yuanqu.json','["彤云缭绕，六花飞遍，楼台银砌。", "拥红炉，添兽炭，犹嫌冷。", "看贫者谁肯相怜？尽道丰年瑞，丰年瑞若何？长安有贫者，宜瑞不宜多。", "奴家岳氏秀英，不免上层楼上，做些女工针指。"]'),
('yuanqu-8908','月云高','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','独上层楼去，听他甚行上。',96,'元曲/yuanqu.json','["独上层楼去，听他甚行上。", "仔细听来后，(生喝号介。", "小旦)却是巡更辈。", "喝号提铃，声音振屋宇，交奴听得心憔悴。", "落在长行队，难禁这劳役。", "腊雪满天飞，冻死街头，那有人来怜你？(生叫介)三更牌在那一家？。"]'),
('yuanqu-8909','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(小旦)喝号三更鼓，声音似龙虎。',71,'元曲/yuanqu.json','["(小旦)喝号三更鼓，声音似龙虎。", "款款推窗看，只见紫雾红光护。", "前生做人做人修不足，今世里罚令你受劳碌。", "好苦！倒跌倩谁扶？未审家乡，家乡在何所？。"]'),
('yuanqu-8910','孝顺歌','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生)巡更过转过营，凛烈寒风凄惨人。',75,'元曲/yuanqu.json','["(生)巡更过转过营，凛烈寒风凄惨人。", "跨街楼下暂安身，朦胧睡未醒。", "忽见天赐红袍，撇来遮我身。", "料莫是天显应，有前程可前进。", "若得应时还得见，果然胜似岳阳金。"]'),
('yuanqu-8911','菊花新','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(外上)庭前三友奈岁时，报道梅开数枝，珠帘绣幕低垂，瑞雪遍街银砌。',33,'元曲/yuanqu.json','["(外上)庭前三友奈岁时，报道梅开数枝，珠帘绣幕低垂，瑞雪遍街银砌。"]'),
('yuanqu-8912','玉交枝','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','这厮无礼。',61,'元曲/yuanqu.json','["这厮无礼。", "这锦袍官里赐的，新充小卒当差使，如何盗取衣袂？从实诉供休要违，迟延罪犯难饶恕。", "照军令将他斩取！照军令将他斩取！。"]'),
('yuanqu-8913','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生)停威息怒，听小人从头禀覆。',63,'元曲/yuanqu.json','["(生)停威息怒，听小人从头禀覆。", "新充小军当差使，焉敢盗取衣袂。", "昨夜三更巡警过，忽见紫袍空中听。", "料莫是天宫赐我。", "料莫是天宫赐我。"]'),
('yuanqu-8914','蛮牌令','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','昨夜二更时，见腊雪满空飞。',60,'元曲/yuanqu.json','["昨夜二更时，见腊雪满空飞。", "提铃喝号至，可伤悲顶门上红光闪烁，声音似虎啸龙嘶。", "非是奴强胡为，自不合把爹爹衣袍与他遮取寒威。"]'),
('yuanqu-8915','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(外)你是守闺女，辄敢乱胡为。',58,'元曲/yuanqu.json','["(外)你是守闺女，辄敢乱胡为。", "绣房中不去拈针指。", "他是个单身健儿，知他姓甚名谁？伊无礼太愚痴，辄敢把衣袍与他遮取寒威。"]'),
('yuanqu-8916','于飞乐','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(旦上)无计解开眉上锁，恶冤家要躲怎生躲？怨我爹娘，招灾惹祸。',31,'元曲/yuanqu.json','["(旦上)无计解开眉上锁，恶冤家要躲怎生躲？怨我爹娘，招灾惹祸。"]'),
('yuanqu-8917','五更转','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','恨命乖遭折挫，爹娘知苦么？哥哥嫂嫂你好横心做，赶出刘郎，罚奴挨磨。',70,'元曲/yuanqu.json','["恨命乖遭折挫，爹娘知苦么？哥哥嫂嫂你好横心做，赶出刘郎，罚奴挨磨。", "叫天不应，地不闻，如何过？(合)奴家那曾，那曾识挨磨、挑水辛勤，只为刘大。"]'),
('yuanqu-8918','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','向磨房愁眉锁，受劳碌也是没奈何？爹娘在日把奴如花朵，死了双亲，被哥嫂凌辱。',54,'元曲/yuanqu.json','["向磨房愁眉锁，受劳碌也是没奈何？爹娘在日把奴如花朵，死了双亲，被哥嫂凌辱。", "爹娘死，我孤单，如何过？(合前)。"]'),
('yuanqu-8919','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','挨几肩头晕转，腹肋遍疼腿又酸，神思困倦挨不转。',55,'元曲/yuanqu.json','["挨几肩头晕转，腹肋遍疼腿又酸，神思困倦挨不转。", "欲待缢死在房中，恐怕耽阁智远。", "寻思起，泪满腮，如何过？(合前)。"]'),
('yuanqu-8920','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','腹内疼欲分娩，有谁人来看管？阴空保佑，保佑奴分娩。',54,'元曲/yuanqu.json','["腹内疼欲分娩，有谁人来看管？阴空保佑，保佑奴分娩。", "但愿无虞，早得夫妻相见。", "思量起，我孤单，如何过？(合前)。"]'),
('yuanqu-8921','锁南枝','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','星月朗，傍四更，窗前犬吠鸡又鸣。',59,'元曲/yuanqu.json','["星月朗，傍四更，窗前犬吠鸡又鸣。", "哥嫂太无情，罚奴磨麦到天明。", "想刘郎去也，可不辜负年少人。", "磨房中冷清清，风儿吹得冷冰冰。"]'),
('yuanqu-8922','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','叫天不应地不闻，腹中遍身疼怎忍？料想分娩在今宵，没个人来问。',44,'元曲/yuanqu.json','["叫天不应地不闻，腹中遍身疼怎忍？料想分娩在今宵，没个人来问。", "望祖宗阴显应，保母子两身轻。"]'),
('yuanqu-8923','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生上)想是前生曾留恋，今日里误入桃源。',48,'元曲/yuanqu.json','["(生上)想是前生曾留恋，今日里误入桃源。", "(小旦上)珠帘卷，画堂列绮席华筵。", "(生、小旦见外拜介)。"]'),
('yuanqu-8924','黑麻序','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(外)吾奉朝宣，掌三军节使，品骘为官。',65,'元曲/yuanqu.json','["(外)吾奉朝宣，掌三军节使，品骘为官。", "家居福地，更兼文武双全，擎拳。", "今朝遇大贤，门阑喜气添。", "(合)两情欢，愿取人妻谐老，共结百年。"]'),
('yuanqu-8925','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(小旦)奴今拜贺椿萱，念奴家生居陋室微贱，想前世共结良缘非浅。',48,'元曲/yuanqu.json','["(小旦)奴今拜贺椿萱，念奴家生居陋室微贱，想前世共结良缘非浅。", "人妻美少年。", "双双拜谢天。", "(合前)。"]'),
('yuanqu-8926','尾声','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(众)今朝共合为姻眷，美满大妻共百年，双双齐效鹣鹣。',26,'元曲/yuanqu.json','["(众)今朝共合为姻眷，美满大妻共百年，双双齐效鹣鹣。"]'),
('yuanqu-8927','临江仙','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(旦上)父母一朝抛弃，夫妻两下分张。',96,'元曲/yuanqu.json','["(旦上)父母一朝抛弃，夫妻两下分张。", "哥哥嫂嫂铁心肠，交奴受万千磨障。", "今日我身分娩，始知恩爱难忘。", "自将心事细思量，眼下这般情况。", "我儿，生下你来，受了万千疼痛苦楚。", "想我母亲养我下来，也受这般苦楚。"]'),
('yuanqu-8928','步步娇','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(旦)养子方知娘生受，各自思前后。',47,'元曲/yuanqu.json','["(旦)养子方知娘生受，各自思前后。", "哥哥心狠毒嫂嫂不仁，暗使机谋苦逼我再招夫，闪得我一似丧家狗。"]'),
('yuanqu-8929','江儿水','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','闷似湘江水，涓涓不断流。',61,'元曲/yuanqu.json','["闷似湘江水，涓涓不断流。", "老天知道和天瘦，共乳同胞一个娘生受。", "又不是随娘改嫁瓜葛柳，罚奴磨麦生受。", "远在儿孙。", "近只在一身当受。"]'),
('yuanqu-8930','川拨棹','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','我欲待诉说个冤仇，我欲待诉说个冤仇，待说来谁人采揪？天若还念我孤单，天若还念我孤单，愿孩儿易长易寿。',73,'元曲/yuanqu.json','["我欲待诉说个冤仇，我欲待诉说个冤仇，待说来谁人采揪？天若还念我孤单，天若还念我孤单，愿孩儿易长易寿。", "子母每得到头，免使刘郎绝嗣后。", "(净扮窦老上)。"]'),
('yuanqu-8931','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','闻知三娘分娩无忧，闻知三娘分娩无忧，李三公交咱来问忧。',41,'元曲/yuanqu.json','["闻知三娘分娩无忧，闻知三娘分娩无忧，李三公交咱来问忧。", "(内丑叫介)闲人不计入磨房。"]'),
('yuanqu-8932','五供养','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','十中缺九，喜姑姑产下穷刘。',44,'元曲/yuanqu.json','["十中缺九，喜姑姑产下穷刘。", "儿夫曾嘱付。", "怎干休？把花言觅诱，倘说得儿入手，管交一命丧清流。"]'),
('yuanqu-8933','侥侥令','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','喜姑姑添小口，几度待不收，十月怀胎娘生受。',41,'元曲/yuanqu.json','["喜姑姑添小口，几度待不收，十月怀胎娘生受。", "儿子是眼前花水上鸥，儿子是眼前花水上鸥。"]'),
('yuanqu-8934','金钱花','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','姑姑分娩无忧？无忧？(旦)深谢嫂嫂耽忧，耽忧。',40,'元曲/yuanqu.json','["姑姑分娩无忧？无忧？(旦)深谢嫂嫂耽忧，耽忧。", "心儿闷怎干休？(丑)把一笔尽都勾。"]'),
('yuanqu-8935','尾声','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','如今幸喜身唧口留，把粥食频调产后，莫待老来病成不救。',26,'元曲/yuanqu.json','["如今幸喜身唧口留，把粥食频调产后，莫待老来病成不救。"]'),
('yuanqu-8936','哭相思','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(旦)耳边忽听叫三娘，犹如死去重生。',34,'元曲/yuanqu.json','["(旦)耳边忽听叫三娘，犹如死去重生。", "(净)我救得在此。", "(旦见净介)。"]'),
('yuanqu-8937','驻云飞','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','苦养孩儿，万苦千辛生下你。',63,'元曲/yuanqu.json','["苦养孩儿，万苦千辛生下你。", "头脸上都是水，七魄将离体。", "儿，空教你枉出世死了孩儿，谁来与娘争口气？好朵鲜花不遇时，好朵鲜花个遇时。"]'),
('yuanqu-8938','宜春令','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','窦公听诉闪依，兄嫂无知，将他撇在水。',67,'元曲/yuanqu.json','["窦公听诉闪依，兄嫂无知，将他撇在水。", "谢伊恩义，把我孩儿送到爹行处。", "见刘郎诉说详细，问的实甚年归计？(合)我儿，长成时，休忘了窦公恩义。"]'),
('yuanqu-8939','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(净)三娘听拜咨启，在边廷习学武艺，要归无计，料想着他身不由己。',55,'元曲/yuanqu.json','["(净)三娘听拜咨启，在边廷习学武艺，要归无计，料想着他身不由己。", "待老汉送将他孩儿，便知他行藏在何处？(合前)。"]'),
('yuanqu-8940','步步娇','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(丑上)传得杜康真绿酉羲真个多奇异，酸的似如醋，臭的是马尿。',106,'元曲/yuanqu.json','["(丑上)传得杜康真绿酉羲真个多奇异，酸的似如醋，臭的是马尿。", "老妇胆大心粗，卖酒不纳课租。", "不怕秦王霸王，赊酒留当则去。", "赛过文君当垆，强如师姑婆婆。", "老妇忙忙便把店开，挑水烧汤待客来。", "正是不将辛苦意，如何打动世间财？。"]'),
('yuanqu-8941','三月海棠','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(净上)年老人，登山涉水多劳顿，送孩儿知他认也不认？伤情！母在家中思儿苦，怎知儿在此没投奔？我移步趱行程，无言不觉泪沾襟。',176,'元曲/yuanqu.json','["(净上)年老人，登山涉水多劳顿，送孩儿知他认也不认？伤情！母在家中思儿苦，怎知儿在此没投奔？我移步趱行程，无言不觉泪沾襟。", "老汉蒙李三娘着我送孩儿到并州太原府去还刘大郎。", "一路辛苦，来到这里。", "夜来在客店中安歇了一宵，感得店主娘与孩儿吃一夜乳。", "如今想孩儿肚又饥，这里是酒店，想有妇人，再问他买些与他吃。", "多少是好？(净、丑见介。", "丑)公公那处来？莫不是买酒吃？。"]'),
('yuanqu-8942','红衲袄','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(净)告娘行听拜启，这孩儿便是冤苦儿，才离娘与娘分离。',82,'元曲/yuanqu.json','["(净)告娘行听拜启，这孩儿便是冤苦儿，才离娘与娘分离。", "他父亲在并州太原府为官。", "送此儿步着千山万水，望娘行可怜他是无母儿。", "(净跪介)觅些乳与他止肚饥，免致黄泉作小鬼。"]'),
('yuanqu-8943','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(丑)听伊言交我恶怒起，他还有舅舅亲人，下得将他厮控持。',100,'元曲/yuanqu.json','["(丑)听伊言交我恶怒起，他还有舅舅亲人，下得将他厮控持。", "料他三日孩儿有何罪？嫡亲子母成痛悲。", "儿母在家中恩爱你，愿天天遮护恁。", "便做钦打心肠也泪垂。", "公公，如今吃得饱了，你好生与他送去。", "(净)多谢！多谢！。"]'),
('yuanqu-8944','声声慢','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生上)梁唐多事，万姓荒荒，妻子尽皆流荡。',205,'元曲/yuanqu.json','["(生上)梁唐多事，万姓荒荒，妻子尽皆流荡。", "网祚方兴时，遇太平盛世。", "家家户户人无事，庆丰年民不号啼。", "拜跪。", "愿乾坤一统，圣寿天齐。", "古人有言：\"得宠思辱，居安虑危。", "\"刘智远自赘岳府，朝朝寒食，夜夜元霄，竟不知恩妻李三娘信息如何？一似和针吞却线，刺人肠肚系人心。", "(小旦上)若将容易得，便作等闲看。", "相公在此看甚么？(生)看兵书。", "(小旦)看到那里？(生)看到曹操与张飞对阵，曹兵把张飞追到霸陵桥，大喊一声，霸陵桥分为两段。"]'),
('yuanqu-8945','高阳台','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生)权统雄威，兵分八阵，名镇四方威势。',72,'元曲/yuanqu.json','["(生)权统雄威，兵分八阵，名镇四方威势。", "吕望六韬，更兼孙武兵书。", "张飞，喝水断桥声似雷，论军令不斩不齐。", "(合)奏到凯歌回，管取凌烟阁上，姓字名题。"]'),
('yuanqu-8946','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(小旦)听启，慈父严尊，见伊武艺，将奴配君为妻。',59,'元曲/yuanqu.json','["(小旦)听启，慈父严尊，见伊武艺，将奴配君为妻。", "征战之功，那时荫子封妻。", "须知赤心报国酬圣主，食大禄满门荣贵。", "(合前)。"]'),
('yuanqu-8947','山坡羊','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生)幸然孩儿来至，不觉交人垂泪。',124,'元曲/yuanqu.json','["(生)幸然孩儿来至，不觉交人垂泪。", "谢伊送我孩儿到此。", "面貌与娘俱无二。", "窦老儿，可有乳名了么？(净)三娘没有剪刀，把口咬断脐肠，叫他咬脐郎。", "(生)儿名咬脐，是你亲娘自取的。", "闻伊见说，见说肝肠碎，两泪交流一似珠。", "孩儿，你亲娘在那里？孩儿，爹在东时娘在西。"]'),
('yuanqu-8948','柰子花','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','感夫人恺悌仁慈。',56,'元曲/yuanqu.json','["感夫人恺悌仁慈。", "刘官人，三姐呵，磨房中产下孩儿，嫉妒嫂嫂撇在水里，是老夫救来还你。", "(合)看此儿，端的是相公嫡子。"]'),
('yuanqu-8949','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(小旦)看孩儿容貌希奇，与相公面庞无二。',40,'元曲/yuanqu.json','["(小旦)看孩儿容貌希奇，与相公面庞无二。", "收留在此犹如嫡子，长成时莫忘了窦公恩义。"]'),
('yuanqu-8950','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生)我在沙陀村里狼狈，荷公婆招我为婿，他大舅憎嫌心生恶意。',94,'元曲/yuanqu.json','["(生)我在沙陀村里狼狈，荷公婆招我为婿，他大舅憎嫌心生恶意。", "今日且喜孩儿送至此间，夫人好好与他看养。", "长成时教他武艺。", "(合前)三日孩儿你可收，三年乳哺不须忧。", "儿孙自有儿孙福，莫与儿孙作远忧。"]'),
('yuanqu-8951','北一枝花','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(净领众上)昔日做朝内官，今做个山中寇，俺只为朝中奸诈多。',55,'元曲/yuanqu.json','["(净领众上)昔日做朝内官，今做个山中寇，俺只为朝中奸诈多。", "有功的恨杀为仇，杀功的即便封侯，因此上撇了名锁和勾。"]'),
('yuanqu-8952','豹子令','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(净)头带金盔八宝攒，八宝攒。',62,'元曲/yuanqu.json','["(净)头带金盔八宝攒，八宝攒。", "茜红袍带血腥膻，血腥膻。", "雄威赳赳谁来犯？铁人见俺也心寒，也心寒。", "(合)张弓跃马下山关，下山关。"]'),
('yuanqu-8953','贺圣朝','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生上)自来独逞英雄，四夷皆惧威风。',33,'元曲/yuanqu.json','["(生上)自来独逞英雄，四夷皆惧威风。", "朝廷敕命守山东，管交一战成功。"]'),
('yuanqu-8954','四边静','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','苏林贼党侵边地，差吾去当备。',51,'元曲/yuanqu.json','["苏林贼党侵边地，差吾去当备。", "那更办赤心，捐躯答圣主。", "(合。", "众)愿听钧旨便驱驰，携取宝刀回，成功最为易。"]'),
('yuanqu-8955','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(众)将军号令如金石，星夜便前去。',52,'元曲/yuanqu.json','["(众)将军号令如金石，星夜便前去。", "时刻莫迟延，违令怎饶你？(合)愿听钧旨便驱驰，携取宝刀回，成功最为易。"]'),
('yuanqu-8956','凤凰阁','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(外上)端居高拱，圣主垂福无穷。',16,'元曲/yuanqu.json','["(外上)端居高拱，圣主垂福无穷。"]'),
('yuanqu-8957','排歌','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(外)战马如龙，断蛇宝刀，冲冲气贯青霄。',71,'元曲/yuanqu.json','["(外)战马如龙，断蛇宝刀，冲冲气贯青霄。", "鹏抟万里借扶摇，方显池中云雨蛟。", "(合)施三略，展六韬，功高赏厚受封褒。", "收王土，绝虏嚣，麒麟阁上姓名标。"]'),
('yuanqu-8958','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(小旦、生)颇牧同休，孙吴并高，堂堂间世人豪。',39,'元曲/yuanqu.json','["(小旦、生)颇牧同休，孙吴并高，堂堂间世人豪。", "折冲御侮在今朝，忠荩须教冠百僚。"]'),
('yuanqu-8959','番鼓儿','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','恁诸军恁诸军，疾速忙前进。',61,'元曲/yuanqu.json','["恁诸军恁诸军，疾速忙前进。", "并力夹攻，教他闻风怕影。", "(净领众上)手持刀剑，泼无徒敢来对阵。", "(合)活捉与生擒，得战时奏凯回程。"]'),
('yuanqu-8960','双劝酒','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生)叵耐畜生，辍敢无礼，速来拜降，免你身归泉世。',40,'元曲/yuanqu.json','["(生)叵耐畜生，辍敢无礼，速来拜降，免你身归泉世。", "常言道养兵千日，今朝用人之际。"]'),
('yuanqu-8961','胡捣练','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(旦上)兄嫂没前程，罚我挨磨到天明。',34,'元曲/yuanqu.json','["(旦上)兄嫂没前程，罚我挨磨到天明。", "把我孩儿撇在水，火公救不见回音。"]'),
('yuanqu-8962','桂枝香','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','孩儿一去，眼中流泪，全无力气精神。',57,'元曲/yuanqu.json','["孩儿一去，眼中流泪，全无力气精神。", "更兼纷纷细雨，酸疼两腿两腿难移，前去如何存济？闷心儿一两阵西风起，滴溜溜败叶飞。"]'),
('yuanqu-8963','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','儿夫别后，思量无计。',55,'元曲/yuanqu.json','["儿夫别后，思量无计。", "指望窦老回归，怎知全无一字？交奴展转展转越添憔悴，如何得睡？闷心儿欲寄音书去，山遥路更迷。"]'),
('yuanqu-8964','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','哥哥毒害，是我前生结债。',59,'元曲/yuanqu.json','["哥哥毒害，是我前生结债。", "他将我万种凌辱，这苦何日得泰？我愿丈夫，丈夫荣归故里，称奴心意告神祗。", "愿得儿夫至，还乡衣锦归。"]'),
('yuanqu-8965','番卜算','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生上)三箭定天山，一战成奇绩。',91,'元曲/yuanqu.json','["(生上)三箭定天山，一战成奇绩。", "捷音今已达彤庭，料想加官职。", "汉将承恩西破戎，捷书飞报未央宫。", "天子预开麟阁待，祗今谁数贰师功？下官平贼已来，即令史弘肇上本去了。", "想在目下，定有好音来也。"]'),
('yuanqu-8966','卜算先','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(小生上)喜色动龙颜，恩诏传丹凤。',202,'元曲/yuanqu.json','["(小生上)喜色动龙颜，恩诏传丹凤。", "圣旨已到，跪听宣读。", "皇帝诏曰：\"臣立其勋，君降其报，此今古之常经，国家之通谊也。", "兹尔刘皓，治兵仁勇，而屡收征伐之功；报国精忠，而卒成底定之业。", "特升尔为九州安抚使。", "先锋史弘肇遏□敌而战每先登，相主帅而功成一统，虽古名将，不是过也。", "特升尔为九州安抚使部下团练使，掌管一十六万雄兵，专听安抚使节制。", "呜呼。", "崇德报功，以彰盛典。", "而协力尽忠，以酬知遇。", "朕于尔辈，有深望焉，望阙谢恩。"]'),
('yuanqu-8967','卜算后','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(小旦上)夫荣妻贵福无穷，偕老百年同。',28,'元曲/yuanqu.json','["(小旦上)夫荣妻贵福无穷，偕老百年同。", "(生相见、见介)。"]'),
('yuanqu-8968','柳摇金','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生)春光明媚，游人似蚁，金勒马频嘶。',92,'元曲/yuanqu.json','["(生)春光明媚，游人似蚁，金勒马频嘶。", "万紫争妍丽，粉蝶儿成对飞。", "忽听得卖花声过，忽听得卖花声过。", "转过画桥西，欲卖几朵花来妆个花篮花轿儿。", "(合)朝欢暮乐，效学于飞，效学于飞和你永谐连理。"]'),
('yuanqu-8969','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','炎威可畏，凉亭避暑。',64,'元曲/yuanqu.json','["炎威可畏，凉亭避暑。", "浴罢晚凉时，纤手调冰水。", "佳人雪藕丝，听操瑶琴一曲，听操瑶琴一曲。", "句句有相思，一似冰盘浸浮瓜与沉李。", "(合前)。"]'),
('yuanqu-8970','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','金梧飘坠，纨扇懒挥。',74,'元曲/yuanqu.json','["金梧飘坠，纨扇懒挥。", "牛女会佳期，只见丹桂飘金蕊，风传香韵美。", "遥望着碧天如洗，遥望着碧天如洗，万里月扬辉。", "夫人，我和你一似皓月澄清团圆到底。", "(合前)。"]'),
('yuanqu-8971','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','严冬天气，彤云布密，满空飞。',80,'元曲/yuanqu.json','["严冬天气，彤云布密，满空飞。", "只见上下同一色。", "于山失翠微。", "画阁红炉深处，画阁红炉深处，欢宴饮琼卮。", "相公，我和你满拚沉醉，共乐共乐销金帐取。", "(合前。", "小生扮咬脐上)。"]'),
('yuanqu-8972','绕地游','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','朱扉画戟，画堂中万千丰丽。',29,'元曲/yuanqu.json','["朱扉画戟，画堂中万千丰丽。", "幸吾父品登高位，文武中尽称为最。"]'),
('yuanqu-8973','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','井深干旱，水又难提。',78,'元曲/yuanqu.json','["井深干旱，水又难提。", "一井水都被我吊干了。", "井有荣枯，眼泪何曾得住止？(介)奴是富家儿，颠倒做了驱使。", "莫怪伊家无礼，是我命该如是？倘有时刻差迟，乱捧打来不颐体。"]'),
('yuanqu-8974','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','寻思情苦泪双垂，夫在边廷，想我孩儿倚靠谁？吃淡饭黄齑，强要充饥。',65,'元曲/yuanqu.json','["寻思情苦泪双垂，夫在边廷，想我孩儿倚靠谁？吃淡饭黄齑，强要充饥。", "哥嫂每夜里巡更不睡，讨是寻非。", "哥嫂他那里昧己瞒心，料想苍天不负亏。"]'),
('yuanqu-8975','雁过沙','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(旦)衙内问我甚情怀？(小生)为何鞋也不穿？(旦)也曾穿着绣鞋。',142,'元曲/yuanqu.json','["(旦)衙内问我甚情怀？(小生)为何鞋也不穿？(旦)也曾穿着绣鞋。", "(小生)敢是挑水卖的？(旦)不曾挑水街头卖。", "(众)敢是作歹事？(旦)贞洁妇女。", "怎旨作歹事？(小生)被甚么人凌贱你？(旦)被无知兄嫂忒毒害。", "(小生)有父母么？(旦)双亲早丧十六载。", "(小生)曾有丈夫么？(旦)东床也曾入门来。"]'),
('yuanqu-8976','香罗带','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(旦)衙内听拜禀，(拜介。',102,'元曲/yuanqu.json','["(旦)衙内听拜禀，(拜介。", "小生作倒介)不要拜了。", "(旦)容奴说事因。", "一从间别鸾凤两处分，被哥哥嫂嫂苦逼分离也。", "朝朝挑水，夜夜辛勤。", "日日泪珠暗零。", "(合)异日说冤，恨取薄幸人，苦也天天，甚日得母子团圆说事因？。"]'),
('yuanqu-8977','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(小生)娘行免泪零，听吾混事因，俺爹爹管军兼管民。',65,'元曲/yuanqu.json','["(小生)娘行免泪零，听吾混事因，俺爹爹管军兼管民。", "我去与爹爹说了。", "军中挨问姓刘人也，教他取你，免伊家泪零。", "(众介)多只数日少半旬。"]'),
('yuanqu-8978','卜算子','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生上)盼望旌旗，每日耳闻消息，闻得孩儿回至。',23,'元曲/yuanqu.json','["(生上)盼望旌旗，每日耳闻消息，闻得孩儿回至。"]'),
('yuanqu-8979','普天乐','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','望芦葭，浅草中分围跨马。',70,'元曲/yuanqu.json','["望芦葭，浅草中分围跨马。", "见一个白兔前面过，赶到前村柳阴之下。", "见一个妇女身落薄，跣足蓬头吃折挫。", "被兄嫂日夜沉埋，他行行泪沥，口口声声只怨刘大。"]'),
('yuanqu-8980','歌儿','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','我在沙陀村受狼狈也是没极奈何。',112,'元曲/yuanqu.json','["我在沙陀村受狼狈也是没极奈何。", "为父的日间在马鸣王庙中栖身。", "感李太公领归我，他把嫡亲儿招我为夫妇。", "两老双双都亡过。", "被大舅争强，把我鸾凰都耽误。", "儿既来问我。", "华堂享富贵的是你继母，那村僻妇人是你亲母。", "剖剖心肠，磨房中生下你儿-个。"]'),
('yuanqu-8981','江儿水','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(小生)那日因游猎，见村中一妇人，满怀心事从头诉。',66,'元曲/yuanqu.json','["(小生)那日因游猎，见村中一妇人，满怀心事从头诉。", "裙布钗荆添凄楚，蓬头跣足身落薄，却元来亲娘生母。", "爹爹，你负义辜恩，全不念糟糠之妇。"]'),
('yuanqu-8982','八声甘州','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(旦挑水上)恹恹闷损，怎消遣心上横愁。',61,'元曲/yuanqu.json','["(旦挑水上)恹恹闷损，怎消遣心上横愁。", "儿夫别后，泪泣楚声无投。", "伤情最苦人易老，那更西风吹暮秋。", "休休，猛然间小鹿儿撞我心头。"]'),
('yuanqu-8983','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','今后洁可奈守，算古往今来似奴稀有。',85,'元曲/yuanqu.json','["今后洁可奈守，算古往今来似奴稀有。", "孩儿一去，到如今杳不回头。", "十六年来音信杳莫有，父子同欢不念母。", "休休，猛听得孤雁叫过南楼。", "神思困倦，就在井栏边少睡片时则个。", "(旦作睡介)。"]'),
('yuanqu-8984','粉蝶儿','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','睡思朦咙，觉来时却是牧童在此。',38,'元曲/yuanqu.json','["睡思朦咙，觉来时却是牧童在此。", "牧童，我的水桶在那里？(丑)你可见我黄牛么？。"]'),
('yuanqu-8985','临江仙','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生、旦)一十六年不见面，今朝又得再相逢。',21,'元曲/yuanqu.json','["(生、旦)一十六年不见面，今朝又得再相逢。"]'),
('yuanqu-8986','锁南枝','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(旦)从伊去后受禁持，不从改嫁生恶意。',50,'元曲/yuanqu.json','["(旦)从伊去后受禁持，不从改嫁生恶意。", "因此骨肉参商，罚奴磨麦并挑水。", "止望你，身显迹，又谁知，恁狼狈。"]'),
('yuanqu-8987','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生)一从散鸳侣，鸾凰两处飞。',51,'元曲/yuanqu.json','["(生)一从散鸳侣，鸾凰两处飞。", "受尽奔波劳役，只为苦取功名，此身不由己。", "身逗留，无所依，那知你，受狼狈。"]'),
('yuanqu-8988','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生)娘行听咨启，我把真情诉与伊，对面娘儿不识。',62,'元曲/yuanqu.json','["(生)娘行听咨启，我把真情诉与伊，对面娘儿不识。", "那日井边相逢打猎一衙内寻兔的，你道是谁？(旦)是那个？(生)名咬脐是你孩儿。"]'),
('yuanqu-8989','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(旦)思前日有个打猎的，他说九州按抚儿。',56,'元曲/yuanqu.json','["(旦)思前日有个打猎的，他说九州按抚儿。", "见他气宇轩昂，谁想是吾嫡子，心下疑难信。", "你莫不是没见识，卖与官家做奴婢。"]'),
('yuanqu-8990','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生)出语大相欺，九州按抚是我为品级。',56,'元曲/yuanqu.json','["(生)出语大相欺，九州按抚是我为品级。", "都堂爵位掌管一十五万官兵，权显达还乡里。", "我妆旧时私探你，休泄漏莫与外人知。"]'),
('yuanqu-8991','孝南枝','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(旦)听伊说转痛心，思之你是个薄幸人。',60,'元曲/yuanqu.json','["(旦)听伊说转痛心，思之你是个薄幸人。", "伊家恋新婚，交奴家守孤灯。", "我真心待等，你享荣华，奴遭薄幸。", "上有苍天，鉴察我年少人。"]'),
('yuanqu-8992','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(生)告娘行听咨启，望娘行免泪零。',48,'元曲/yuanqu.json','["(生)告娘行听咨启，望娘行免泪零。", "若不娶绣英，怎得我身荣？将彩凰冠来取你，取你到京中做一品夫人。"]'),
('yuanqu-8993','剔银灯','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(小生领众上)蒙尊命来迎我母亲，心如箭马不留停。',57,'元曲/yuanqu.json','["(小生领众上)蒙尊命来迎我母亲，心如箭马不留停。", "姻缘本是前生定。", "故令个白兔来引。", "艰辛，十六年命屯，今喜得枯枝再春。"]'),
('yuanqu-8994','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(旦上)望孩儿终日倚门，怕儿夫语言不定。',64,'元曲/yuanqu.json','["(旦上)望孩儿终日倚门，怕儿夫语言不定。", "哥哥嫂嫂忒薄幸，全不念手足情亲。", "艰辛，十六年命屯，料今日枯枝再春。", "(小生入相见，抱介)。"]'),
('yuanqu-8995','一封书','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','儿不孝远离，我娘行无所为。',80,'元曲/yuanqu.json','["儿不孝远离，我娘行无所为。", "儿名唤咬脐，一十六年如梦里。", "娘呵，若不在沙陀村来打猎，怎能够母子夫妻重会期？(合)母和儿痛伤悲，这段冤仇必报取。", "请母亲起程。", "(行介)。"]'),
('yuanqu-8996','前腔','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(旦)从别离你爹，兄嫂无情苦禁持。',56,'元曲/yuanqu.json','["(旦)从别离你爹，兄嫂无情苦禁持。", "说不尽那时，罚奴磨麦井挑水。", "我受了千辛并万苦，又谁知母子夫妻重会期？(合前)。"]'),
('yuanqu-8997','称人心','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','青山绿水年年好，不知人换几千秋。',16,'元曲/yuanqu.json','["青山绿水年年好，不知人换几千秋。"]'),
('yuanqu-8998','大环着','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','(众)因孩儿出路，因孩儿出路，打猎沙陀，偶见林中白兔跷蹊。',60,'元曲/yuanqu.json','["(众)因孩儿出路，因孩儿出路，打猎沙陀，偶见林中白兔跷蹊。", "若非他引见母，怎能够夫妻相会？前生里今日奇，从此团圆永效于飞。"]'),
('yuanqu-8999','红绣鞋','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','春有秀陌瑶池，瑶池，夏有流觞曲水，曲水，秋玩月，与冬时，观瑞雪，赏寒梅，拚今宵共沉醉。',43,'元曲/yuanqu.json','["春有秀陌瑶池，瑶池，夏有流觞曲水，曲水，秋玩月，与冬时，观瑞雪，赏寒梅，拚今宵共沉醉。"]'),
('yuanqu-9000','尾声','刘唐卿《白兔记》','元','元曲','yuanqu','','[]','贫者休要相轻弃，否极终有泰时，留与人间作话题。',23,'元曲/yuanqu.json','["贫者休要相轻弃，否极终有泰时，留与人间作话题。"]'),
('yuanqu-9001','中吕・上小楼钱塘感旧','吴仁卿','元','元曲','yuanqu','','[]','虚名仕途，微官苟禄。',398,'元曲/yuanqu.json','["虚名仕途，微官苟禄。", "愁里南闽，客里东吴，梦里西湖。", "到寓居，问士夫，都为鬼录，消磨尽旧时人物。", "题小卿双渐苏卿告覆，金山题句。", "行哭行啼，行想行思，行写行读。", "自应举，赴帝都，双郎何处，又随将贩茶人去。", "西湖宴饮人凭画阑，舟横锦岸。", "一线苏堤，两点高峰，四面湖山。", "玉筝弹，彩袖弯，红牙轻按，直吃的酒阑人散。", "春日闺怨伤春病体，残春天气。", "萦损柔肠，蹙损双蛾，瘦损香肌。", "唤小梅，你快疾，重门深闭，怕莺花笑人憔悴。", "西湖泛舟骄骢锦鞯，轻罗彩扇。", "帘卷东风，花绽香云，柳吐晴烟。", "泛画船，列骑筵，笙箫一片，人都在水晶宫殿。", "春残离思春光正浓，莺声相送。", "人云兰堂，尘锁妆台，画罨帘栊。", "锦帐中，翠被空，无人相共，央及煞绿窗春梦。", "佳人送别鸳鸯共栖，鸾凤相配。", "夜夜同衾，朝朝同乐，步步相随。", "猛可里，个厮离，相留无计，登时间粉憔脂悴。", "佳人话旧幽栏小轩，闲庭深院。", "同向书帏，共坐吟窗，对理冰弦。", "想在先，忆去年，今番相见，思量的人眼前活现。"]'),
('yuanqu-9002','中吕・醉高歌叹世','吴仁卿','元','元曲','yuanqu','','[]','风尘天外飞沙，日月窗间过马。',30,'元曲/yuanqu.json','["风尘天外飞沙，日月窗间过马。", "风俗扫地伤王化，谁正人伦大雅？。"]'),
('yuanqu-9003','商调・梧叶儿','吴仁卿','元','元曲','yuanqu','','[]','春三月，夜五更，孤枕梦难成。',237,'元曲/yuanqu.json','["春三月，夜五更，孤枕梦难成。", "香销尽，花弄影，此时情，辜负了窗前月明。", "花前约，月下期，欢笑忽分离。", "相思害，憔悴死，诉与谁？只有天知地知。", "乜斜害，药难医，陡峻恶相思。", "懊悔自，埋怨你，见面时，说几句知心话儿。", "桃花树，落绛英，和闷过清明。", "风才定，雨乍晴，绣针停，短叹长吁几声。", "暮春春云净，芳树晓，花外燕声娇。", "呼红袖，品玉箫，泛兰桡，十里春风画桥。", "韶华过，春色休，红瘦绿阴稠。", "花凝泪，柳带愁，泛兰舟，明日寻芳载酒。", "湖上舟中句，湖上景，芳酒泛金橙。", "云初退，月正明，雪初晴，几树梅花弄影。"]'),
('yuanqu-9004','大石调・青杏子惜春','吴仁卿','元','元曲','yuanqu','','[]','幽鸟正调舌，怯春归似有伤嗟。',37,'元曲/yuanqu.json','["幽鸟正调舌，怯春归似有伤嗟。", "虚檐凭得阑干暖，落花风里，游丝天外，远翠千叠。"]'),
('yuanqu-9005','望江南・音书断，人远路途赊。芳草啼残锦鹧鸪，粉墙飞困玉蝴蝶，日暮','吴仁卿','元','元曲','yuanqu','','[]','正愁绝。',4,'元曲/yuanqu.json','["正愁绝。"]'),
('yuanqu-9006','好观音・帘卷东风飘香雪，绮窗下翠屏横遮，庭院深沉袅篆斜。正黄昏，','吴仁卿','元','元曲','yuanqu','','[]','燕子来时节。',6,'元曲/yuanqu.json','["燕子来时节。"]'),
('yuanqu-9007','随煞・银烛高烧从今夜，好风光未可轻别。留得东君少住些，惟恐怕西园','吴仁卿','元','元曲','yuanqu','','[]','海棠谢。',43,'元曲/yuanqu.json','["海棠谢。", "闺情梁燕语呢喃，九十日春色过三。", "东风满院杨花谢，离情正苦，归情未准，鬼病将担。"]'),
('yuanqu-9008','好观音・信步闲庭院阑槛，荷钱小池面ソ蓝。点检芳丛总不堪，正蜻蜓雨','吴仁卿','元','元曲','yuanqu','','[]','过波纹蘸。',5,'元曲/yuanqu.json','["过波纹蘸。"]'),
('yuanqu-9009','幺・绿树成阴和烟暗，近香街羞对宜男。锦字书成粉泪缄，怕黄昏梦里将','吴仁卿','元','元曲','yuanqu','','[]','人赚。',3,'元曲/yuanqu.json','["人赚。"]'),
('yuanqu-9010','尾・窗下尘蒙青鸾鉴，问章台何处停骖？薄幸才郎不顾咱，有谁画青山两','吴仁卿','元','元曲','yuanqu','','[]','眉淡？。',4,'元曲/yuanqu.json','["眉淡？。"]'),
('yuanqu-9011','越调・斗鹌鹑','吴仁卿','元','元曲','yuanqu','','[]','天气融融，和风习习。',48,'元曲/yuanqu.json','["天气融融，和风习习。", "花发南枝，冰消岸北。", "庆贺新春，满斟玉液。", "朝禁阙，施拜礼。", "舞蹈扬尘，山呼万岁。"]'),
('yuanqu-9012','紫花儿序・托赖着一人有庆，五谷丰登，四海无敌。寒来暑往，兔走乌飞。','吴仁卿','元','元曲','yuanqu','','[]','节令相催，答贺新正圣节日。',31,'元曲/yuanqu.json','["节令相催，答贺新正圣节日。", "愿我皇又添一岁，丰稔年华，太平时世。"]'),
('yuanqu-9013','小桃红・官清法正古今稀，百姓安无差役。户口增添盗贼息，路不拾遗，','吴仁卿','元','元曲','yuanqu','','[]','托赖着万万岁当今帝。',26,'元曲/yuanqu.json','["托赖着万万岁当今帝。", "狼烟不起，干戈永退，齐贺凯歌回。"]'),
('yuanqu-9015','幺・太平无事罢征旗，祝延圣寿做筵席，百官文武两班齐。欢喜无尽期，','吴仁卿','元','元曲','yuanqu','','[]','都吃得醉如泥。',7,'元曲/yuanqu.json','["都吃得醉如泥。"]'),
('yuanqu-9016','秃厮儿・光禄寺琼浆玉液，尚食局御膳堂食，朝臣一发呼万岁。祝圣寿，','吴仁卿','元','元曲','yuanqu','','[]','庆官里，进金杯。',8,'元曲/yuanqu.json','["庆官里，进金杯。"]'),
('yuanqu-9017','圣药王・大殿里，设宴会，教坊司承应在丹墀。有舞的，有唱的，有凤箫','吴仁卿','元','元曲','yuanqu','','[]','象板共龙笛，奏一派乐声齐。',13,'元曲/yuanqu.json','["象板共龙笛，奏一派乐声齐。"]'),
('yuanqu-9018','尾・愿吾皇永坐在皇宫内，愿吾皇永掌着江山社稷。愿吾皇永穿着飞凤赭','吴仁卿','元','元曲','yuanqu','','[]','黄袍，愿吾皇永坐着万万载盘龙亢金椅。',18,'元曲/yuanqu.json','["黄袍，愿吾皇永坐着万万载盘龙亢金椅。"]'),
('yuanqu-9019','越调・斗鹌鹑自悟','吴仁卿','元','元曲','yuanqu','','[]','弃职休官，张良范蠡。',61,'元曲/yuanqu.json','["弃职休官，张良范蠡。", "释辞了紫绶金章，待看青山绿山。", "跳出狼虎丛中，不入麒麟画里。", "想爵禄高，性命危。", "一个个舍死忘生，争宣竞敕。"]'),
('yuanqu-9020','紫花儿序・你都待重ブ而卧，列鼎而食，不如我拂袖而归。急流中勇退，','吴仁卿','元','元曲','yuanqu','','[]','见贤思齐。',49,'元曲/yuanqu.json','["见贤思齐。", "当日个，宁武子左丘明孔仲尼。", "邦有道则仕，邦无道则废，齐魏里使煞个孙庞，殷商中饿杀了夷齐。"]'),
('yuanqu-9021','鬼三台・看了些英雄辈，争闲气，为功名将命亏。笑豫让，叹Θ迁，待图','吴仁卿','元','元曲','yuanqu','','[]','个甚的？论功劳胜似燕乐毅，论才学不如晋李仪。',35,'元曲/yuanqu.json','["个甚的？论功劳胜似燕乐毅，论才学不如晋李仪。", "常言道才广妨身，官高害己。"]'),
('yuanqu-9022','圣药王・我如今近七十，才晓得，方知道老而不死是为贼。指鹿做马，唤','吴仁卿','元','元曲','yuanqu','','[]','凤做鸡。',21,'元曲/yuanqu.json','["凤做鸡。", "葫芦今后大家提，想谁别辨个是和非。"]'),
('yuanqu-9023','调笑令・为甚每日醉如泥，除睡人间总不知。戒之在得因何意，老不必争','吴仁卿','元','元曲','yuanqu','','[]','名夺利。',21,'元曲/yuanqu.json','["名夺利。", "黄金垛到北斗齐，也跳不出是处轮回。"]'),
('yuanqu-9024','圣药王・赤紧的乌紧飞，兔紧催，暂时相赏莫相违。菊满篱，酒满杯。当','吴仁卿','元','元曲','yuanqu','','[]','吃得席前花影坐间移，白发故人稀。',16,'元曲/yuanqu.json','["吃得席前花影坐间移，白发故人稀。"]'),
('yuanqu-9025','尾・想当日子房公会觅全身计，一个识空便抽头的范蠡。归山去的待看翠','吴仁卿','元','元曲','yuanqu','','[]','巍巍千丈岭头云，归湖的待看绿湛湛长江万顷水。',22,'元曲/yuanqu.json','["巍巍千丈岭头云，归湖的待看绿湛湛长江万顷水。"]'),
('yuanqu-9026','越调・梅花引','吴仁卿','元','元曲','yuanqu','','[]','兰蕊檀心仙袂香，蝶粉蜂黄宫样妆。',35,'元曲/yuanqu.json','["兰蕊檀心仙袂香，蝶粉蜂黄宫样妆。", "紫云娘，彩衣郎，东君配偶，天然是一双。"]'),
('yuanqu-9027','紫花儿序・丹青模样，冰雪肌肤，锦绣心肠。惊魂未定，好事多妨。堪伤，','吴仁卿','元','元曲','yuanqu','','[]','不做美相知每早使伎俩。',26,'元曲/yuanqu.json','["不做美相知每早使伎俩。", "左右拦障，笑里藏刀，雪上加霜。"]'),
('yuanqu-9028','幺・日沉西浦，月转南楼，花暗东墙。尽教人妒，谁敢声扬？参详，但得','吴仁卿','元','元曲','yuanqu','','[]','伊家好觑当。',21,'元曲/yuanqu.json','["伊家好觑当。", "问甚凄凉，苦乐同受，生死难忘。"]'),
('yuanqu-9029','秃厮儿・分破金钗凤凰，拆开绣带鸳鸯，离怀扰扰愁闷广。不由俺，到黄','吴仁卿','元','元曲','yuanqu','','[]','昏，思量。',5,'元曲/yuanqu.json','["昏，思量。"]'),
('yuanqu-9031','中吕・粉蝶儿怨别','王挺秀','元','元曲','yuanqu','','[]','银烛高烧，画楼中月儿才照，绣帘前花影轻摇。',51,'元曲/yuanqu.json','["银烛高烧，画楼中月儿才照，绣帘前花影轻摇。", "翠屏闲，鸳衾剩，梦魂初觉。", "觉来时香汗初消，更那堪绣帏中冷落。"]'),
('yuanqu-9032','十二月・夜沉沉明河皎皎，昏惨惨暮景消消，低矮矮帏屏静悄，冷清清良','王挺秀','元','元曲','yuanqu','','[]','夜迢迢。',21,'元曲/yuanqu.json','["夜迢迢。", "闷恹恹把情人去了，急煎煎心痒难揉。"]'),
('yuanqu-9033','耍孩儿・银烛淡淡光先照，瘦影孤灯对着，教人怎不自量度，急煎煎业眼','王挺秀','元','元曲','yuanqu','','[]','难交。',43,'元曲/yuanqu.json','["难交。", "虚飘飘魂迷了枕上胡蝶梦，笑吟吟喜喜欢欢鸾凤交。", "相思病难医疗，云收雨歇，魄散魂消。"]'),
('yuanqu-9034','中吕・迎仙客风情','曾瑞','元','元曲','yuanqu','','[]','施计策，硬栽排，把明皇没扌刷地揣过来。',135,'元曲/yuanqu.json','["施计策，硬栽排，把明皇没扌刷地揣过来。", "假承塌，休<门系><门坐>，借债我做着傍牌。", "可敢别烧上风流怪。", "成密宠，正情浓，休听外人冷句儿哝。", "劣冤家，小业种，情我做着屏风。", "可休别凿透桃源洞。", "我共你，莫相离，肉铁索更粘如胶共漆。", "系着眉毛，结着{髟弟}髻，硬顶着头皮，熬一个心先退。"]'),
('yuanqu-9035','中吕・红绣鞋风情','曾瑞','元','元曲','yuanqu','','[]','值暮景烟花领袖，点秋霜风月班头，少年狂翻作老来羞。',548,'元曲/yuanqu.json','["值暮景烟花领袖，点秋霜风月班头，少年狂翻作老来羞。", "有人处把些礼数，无人处结遍绸缪，任谁问休道咱共你有。", "假认义做哥哥般亲厚，行人情似妹妹般追逐，着小局断儿包藏着鬼胡由。", "明讲着昆仲礼，暗结了燕莺俦，似恁般谁猜疑我共你有。", "祆庙火既烧着皮肉，蓝桥水已淹过咽喉，紧按捺风声满南州。", "便毕罢了终是点污，若成合了到敢风流，不恁么呵也道是有。", "会云雨风也教休透，闲是非屁也似休亻秋，去那无缝锁上十字儿纽一个封头。", "由那快抡锹的闪着手腕，散楚的叫破咽喉，俺两个痛关心的情越有。", "期白昼家前院后，约黄昏雨歇云收，知他是你卖风他负德我胡ㄐ。", "由你义秧儿栽个强证，草本儿指个牵头，见如今他共我有。", "题桥志文章锦绣，驾车心体态温柔，女貌郎才忒风流。", "语言间情暗许，眼色内意相投，两个委实无人道做有。", "口儿快特婪侃嗽，脚儿勤推恋俳优，每日家弄子里茶坊中紧相逐，为俺待的厚，也亻来气快要的恶也忒情熟，因此上外人观恰便似有。", "闲谈笑踏科儿寻斗，但离别觅缝儿承头，好一会弱一会厮奚酬。", "着厮拾啜为了题目，闲打骂做了开头，两个虚难当又真个有。", "乔断案村亻来杂嗽，望梅花子弟单兜，侧脚里姨夫做了冤仇，苏小小弃了舞榭，许盼盼闭上歌楼，似恁么难厮着怎做得有。", "实镘的剐皮割肉，虚恩情撇闪提<鼻勾>，乾遇讪乔敷演几时休。", "妆砌末招人谤，哮孛郎儿人羞，强折证刚道他有。"]'),
('yuanqu-9036','中吕・山坡羊自叹','曾瑞','元','元曲','yuanqu','','[]','南山空灿，白石空烂，星移物换愁无限。',266,'元曲/yuanqu.json','["南山空灿，白石空烂，星移物换愁无限。", "隔重关，困尘寰，几番肩锁空长叹。", "百事不成羞又赧。", "闲，一梦残。", "干，两鬓斑。", "叹世鸡鸣为利，鸦栖收计，几曾得觉囫囵睡。", "使心机，昧神祗，区区造下弥天罪。", "富贵一场春梦里。", "财，沤泛水。", "人，泉下鬼。", "荣华休傲，贫穷休笑，循环世态多颠倒。", "恰春朝，早秋宵，花开花谢都知道。", "今岁孟春花更早。", "花，依旧好。", "人，空谩老。", "虚名休就，眉头休皱，终身更不遭机彀。", "抱官囚，为谁愁，功名半纸难能够。", "争如漆园蝶梦叟。", "常，紧闭口。", "闲，且袖手。", "花逢春到，人逢时到，花开人旺多欢笑。", "看英豪，赏花娇，乐极悲至非人乐。", "花正发时风又恶。", "花，零落了。"]'),
('yuanqu-9037','中吕・快活三过朝天子警世','曾瑞','元','元曲','yuanqu','','[]','有见识越大夫，无转理楚三闾。',385,'元曲/yuanqu.json','["有见识越大夫，无转理楚三闾。", "正当权肯觅个脱身术，那的是高才处。", "老孤，面糊，休直待虚名误。", "全身远害倒大福，驾一叶扁舟去，烟水云林，皆无租赋，拣溪山好处居。", "相府，帅府，那与他别人住。", "肉撑翻鼎饕餮，土蚀损剑镆铘。", "诸公荣贵不曾绝，偏我如鸠拙。", "命耶，运耶，穷通内分优劣。", "蜂衙蚁阵且略别，伴四季闲风月。", "老瓦盆边，无明无夜，盆乾时酒再赊。", "醉也，睡也，一任教花开谢。", "受官厅暮雨残，待漏院晓霜寒。", "耽耽九虎隔重关，更险似连云栈。", "左难，右难，牢着脚周公旦。", "功成名遂不退闲，真个是痴呆汉。", "梦里浮华，浑无多限，觉来时两鬓斑。", "试看，这番，又是个新公案。", "老风情莺花寨不受敌，雨云乡纳降旗。", "簪花人老不相宜，枉惹的人牙戏。", "忏悔，罪累，要绝了鸾凤配，人心争奈不是木石，长感动思凡意。", "得遇知心，私情机密，有风声我怕谁。", "你任谁，问伊，硬抵着头皮讳。", "自误肉肥甘酒韵美，多一口便伤食。", "家传一瓮淡黄齑，吃过后须回味。"]'),
('yuanqu-9038','双调・折桂令闺怨','曾瑞','元','元曲','yuanqu','','[]','秋霄淡淡轻阴，暮景萧条，疏雨霪霖。',126,'元曲/yuanqu.json','["秋霄淡淡轻阴，暮景萧条，疏雨霪霖。", "林外鸟啼，天边雁叫，砌下蛩吟。", "更漏永声来绣枕，篆烟消寒透罗衾。", "恨杀邻砧，惊散离魂，捣碎人心。", "秦城望断箫声，时物供愁，夜景伤情。", "鹤唳松庭，风摇槛竹，雨滴檐楹。", "银烛暗雕盘篆冷，绣帏孤翠被寒增。", "数尽残更，天也难明，梦也难成。"]'),
('yuanqu-9039','仙吕・寄生草送别','曾瑞','元','元曲','yuanqu','','[]','阳关曲，歌金缕，别离杯，倒玉壶。',62,'元曲/yuanqu.json','["阳关曲，歌金缕，别离杯，倒玉壶。", "为功名不可留君住，远程途无计将奴去，想人间最是伤情处。", "玉容愁过武陵溪，雕鞍懒上临平路。", "套数。"]'),
('yuanqu-9040','黄钟・醉花阴远宵忆旧','曾瑞','元','元曲','yuanqu','','[]','冻雪才消腊梅谢，却早击碎泥牛应节，柳眼吐些些。',34,'元曲/yuanqu.json','["冻雪才消腊梅谢，却早击碎泥牛应节，柳眼吐些些。", "时序相催，斗把鳌山结。"]'),
('yuanqu-9041','出队子・想当初时节，那浓欢怎弃舍。新愁装满太平车，旧恨常堆几万叠，','曾瑞','元','元曲','yuanqu','','[]','若负德辜恩天地折。',9,'元曲/yuanqu.json','["若负德辜恩天地折。"]'),
('yuanqu-9042','神仗儿・这些时情诗倦写，和音书断绝。斜月笼明，残灯半灭。恨檐马玎','曾瑞','元','元曲','yuanqu','','[]','当，怨塞鸿凄切。',24,'元曲/yuanqu.json','["当，怨塞鸿凄切。", "猛然间想起多娇，那愁闷，怎拦截。"]'),
('yuanqu-9043','挂金索・业缘心肠，那烦恼何时彻。对景伤情，怎捱如年夜。灯火阑珊，','曾瑞','元','元曲','yuanqu','','[]','似万朵金莲谢。',22,'元曲/yuanqu.json','["似万朵金莲谢。", "车马<门便>阗，赛一火鸳鸯社。"]'),
('yuanqu-9044','喜迁莺・想才郎丰鉴，貌堂堂阔论高谈。那堪。并不愚滥，一见了春愁独','曾瑞','元','元曲','yuanqu','','[]','自搅，常好是忒大胆。',30,'元曲/yuanqu.json','["自搅，常好是忒大胆。", "怕不你心心儿里待贪，又则怕意意儿里相搀。"]'),
('yuanqu-9045','杏水仙子・将将将紫丝缰紧兜揽，是是是春纤长勒不住碧玉衔。飕飕飕摔','曾瑞','元','元曲','yuanqu','','[]','风过长亭，出出出方行过短站。',69,'元曲/yuanqu.json','["风过长亭，出出出方行过短站。", "见见见三家店忽的向南，淹淹淹映香尘晓日红含。", "我我我软兀剌绣鞍身半探，看看看曲弯弯两叶蛾眉淡，瘦怯怯六幅翠裙搀。"]'),
('yuanqu-9046','寨儿令・尴<九咸>，尴<九咸>，做的来所事忒严。想当初才貌两相堪，一','曾瑞','元','元曲','yuanqu','','[]','个是娇仕女，一个俊儿男，他自把那婚姻勘。',20,'元曲/yuanqu.json','["个是娇仕女，一个俊儿男，他自把那婚姻勘。"]'),
('yuanqu-9047','尾声・一担相思自摇撼，我和你两家担由自难担，将一个担不起担儿却怎','曾瑞','元','元曲','yuanqu','','[]','生分付俺。',5,'元曲/yuanqu.json','["生分付俺。"]'),
('yuanqu-9048','黄钟・愿成双赠老妓','曾瑞','元','元曲','yuanqu','','[]','娇鸾态，雏凤姿，正生红闹簇枯枝。',32,'元曲/yuanqu.json','["娇鸾态，雏凤姿，正生红闹簇枯枝。", "含香蓓蕾未开时，没乱杀莺儿燕子。"]'),
('yuanqu-9050','出队子・阑珊春事，恨题绝罗扇诗。玉容香散粉慵施，锦树花残蝶倦时，','曾瑞','元','元曲','yuanqu','','[]','正绿叶成阴子满枝。',9,'元曲/yuanqu.json','["正绿叶成阴子满枝。"]'),
('yuanqu-9052','正宫・端正好自序','曾瑞','元','元曲','yuanqu','','[]','一枕梦魂惊，千载风云过，将古来英俊评跋。',39,'元曲/yuanqu.json','["一枕梦魂惊，千载风云过，将古来英俊评跋。", "谁才能谁霸道谁王佐，只落得高冢麒麟卧。"]'),
('yuanqu-9053','幺・百年身隙外白驹过，事无成潘鬓双皤。既生来命与时相挫，去狼虎丛','曾瑞','元','元曲','yuanqu','','[]','服低捋。',4,'元曲/yuanqu.json','["服低捋。"]'),
('yuanqu-9054','滚绣球・时与命道不合，我和他气不和，皆前定并无差错。虽圣贤胸次包','曾瑞','元','元曲','yuanqu','','[]','罗，待据六合，要并一锅，其中有千万人我，各有天时地利人和。',54,'元曲/yuanqu.json','["罗，待据六合，要并一锅，其中有千万人我，各有天时地利人和。", "气难吞吴魏亡了诸葛，道不行齐梁丧了孟轲，天数难那。"]'),
('yuanqu-9055','倘秀才・举伊尹有汤王倚托，微管仲无桓公不可，相公子纠偏如何不九合。','曾瑞','元','元曲','yuanqu','','[]','失时也亡了家国，得意后霸了山河，也是君臣每会合。',24,'元曲/yuanqu.json','["失时也亡了家国，得意后霸了山河，也是君臣每会合。"]'),
('yuanqu-9056','脱布衫・时不遇版筑为活，时不遇荆南落魄，时不遇逾垣而躲，时不遇在','曾瑞','元','元曲','yuanqu','','[]','陈忍饿。',4,'元曲/yuanqu.json','["陈忍饿。"]'),
('yuanqu-9057','小梁州・男儿贫困果如何？击缶讴歌。甘贫守分淡消磨，颜回乐，知足后','曾瑞','元','元曲','yuanqu','','[]','一瓢多。',4,'元曲/yuanqu.json','["一瓢多。"]'),
('yuanqu-9058','幺・既功名不入凌烟阁，放疏狂落落陀陀。就着老瓦盆，浮香糯，直吃的','曾瑞','元','元曲','yuanqu','','[]','未醒后又如何。',7,'元曲/yuanqu.json','["未醒后又如何。"]'),
('yuanqu-9059','醉太平・看别人挥鞭登剑阁，举棹泛沧波，争如我得磨跎处且磨跎。无名','曾瑞','元','元曲','yuanqu','','[]','缰利锁，携壶策杖穿林落，临风对月闲吟课。',34,'元曲/yuanqu.json','["缰利锁，携壶策杖穿林落，临风对月闲吟课。", "有花有酒且高歌，居村落快活。"]'),
('yuanqu-9060','叨叨令・听樵歌牧唱依腔和，整丝纶独钓垂钩坐，铺苔茵展绿张云幕，披','曾瑞','元','元曲','yuanqu','','[]','渔蓑带雨和烟卧。',29,'元曲/yuanqu.json','["渔蓑带雨和烟卧。", "快活也么哥，快活也么哥，且潜居抱道随缘过。"]'),
('yuanqu-9061','一煞・也不学采薇自洁埋幽壑，不学举国独醒葬汨罗，也不学墨子回车，','曾瑞','元','元曲','yuanqu','','[]','巢由洗耳、河老腾云、许子衣褐，也不仰天长叹，也不待相宣言，也不扣角为歌，却回光照我，图甚苦张罗。',48,'元曲/yuanqu.json','["巢由洗耳、河老腾云、许子衣褐，也不仰天长叹，也不待相宣言，也不扣角为歌，却回光照我，图甚苦张罗。"]'),
('yuanqu-9062','二・忘冫食智士齐君果，不吐嫌兄仲子鹅。饱养鸡豚，广栽桃李，多植桑','曾瑞','元','元曲','yuanqu','','[]','剩种粳禾。',38,'元曲/yuanqu.json','["剩种粳禾。", "盖数椽茅屋，买四角黄牛，租百亩庄窠。", "时不遇也恁么，且耕种置个家活。"]'),
('yuanqu-9063','三・瓮头白酒新醅泼，碗内黄齑坌酱和。诗里乾坤，杯中日月，醉醒由己，','曾瑞','元','元曲','yuanqu','','[]','清浊从他。',32,'元曲/yuanqu.json','["清浊从他。", "我量宽似海，杯吸长鲸，酒泛洪波。", "醉乡宽阔，不饮待如何。"]'),
('yuanqu-9064','四・忘忧陋巷于咱可，乐道穷途奈我何。右抱琴书，左携妻子，无半纸功','曾瑞','元','元曲','yuanqu','','[]','名，躲万丈风波。',39,'元曲/yuanqu.json','["名，躲万丈风波。", "看别人日边牢落，天际驱驰，云外蹉跎。", "咱图个甚莫，未转首总南柯。"]'),
('yuanqu-9065','南吕・一枝花买笑','曾瑞','元','元曲','yuanqu','','[]','银筝暗麝尘，锦瑟空檀架。',59,'元曲/yuanqu.json','["银筝暗麝尘，锦瑟空檀架。", "青鸾临宝镜，丹凤隔烟霞。", "同是天涯，休辜负春无价。", "可憎他谁不夸，明出着月夜花朝，空寂寞鸳帏绣榻。"]'),
('yuanqu-9066','三煞・凭温柔举止特如法，论恩爱疏薄却有差。你则待这回云雨匿巫峡，','曾瑞','元','元曲','yuanqu','','[]','一任教眉淡了春山，也不要张京兆轻盈巧画。',45,'元曲/yuanqu.json','["一任教眉淡了春山，也不要张京兆轻盈巧画。", "陡恁地变了卦，阳台路新来下了面闸，要恋那谈笑生涯。"]'),
('yuanqu-9067','二・能清歌妙舞捱时霎，会受诨承科度岁华，就着这其间觑看你的甚参杂。','曾瑞','元','元曲','yuanqu','','[]','拣一个可意的冤家，酩子里由伊驱驾。',44,'元曲/yuanqu.json','["拣一个可意的冤家，酩子里由伊驱驾。", "更有行志不谎诈。", "肯的你舒心儿便许俺，我古自未敢道真假。"]'),
('yuanqu-9068','尾・怕你肯不肯回与我句真实话，可休是不是空教人指点咱。细寻思再想','曾瑞','元','元曲','yuanqu','','[]','咱，好前程不是耍。',44,'元曲/yuanqu.json','["咱，好前程不是耍。", "由你彻骨的娘透了的滑，你那疑惑心则有半米儿争差，可敢错系了绿杨门外马。"]'),
('yuanqu-9069','中吕・醉春风清高','曾瑞','元','元曲','yuanqu','','[]','七国谋臣诏，三闾贤相贬。',41,'元曲/yuanqu.json','["七国谋臣诏，三闾贤相贬。", "官极将相位双兼，险，险，险。", "众口难箝，您也久占，俺咱常严。"]'),
('yuanqu-9071','喜春来・客来碗镟巡山店，鹤去松阴转屋檐。野塘消遣酒频添，杯潋滟，','曾瑞','元','元曲','yuanqu','','[]','不顾老妻嫌。',6,'元曲/yuanqu.json','["不顾老妻嫌。"]'),
('yuanqu-9072','卖花声煞・悬河口紧闭山水间潜，经纶手忙抄尘世上闪。书万卷撑肠稳支','曾瑞','元','元曲','yuanqu','','[]','椽，有感幽怀露光焰，吐虹霓作歌挥剑。',18,'元曲/yuanqu.json','["椽，有感幽怀露光焰，吐虹霓作歌挥剑。"]'),
('yuanqu-9073','大石调・青杏子骋怀','曾瑞','元','元曲','yuanqu','','[]','花月酒家楼，可追欢亦可悲秋。',37,'元曲/yuanqu.json','["花月酒家楼，可追欢亦可悲秋。", "悲欢聚散为常事，明眸皓齿，歌莺舞燕，各逞温柔。"]'),
('yuanqu-9074','幺・人俊惜风流，欠前生酒病花愁。尚还不彻相思债，携云挈雨，批风切','曾瑞','元','元曲','yuanqu','','[]','月，到处绸缪。',7,'元曲/yuanqu.json','["月，到处绸缪。"]'),
('yuanqu-9075','催拍子・爱共寝花间锦鸠，恨孤眠水上白鸥。月宵花昼，大筵排回雪韦娘，','曾瑞','元','元曲','yuanqu','','[]','小酌会窃香韩寿。',81,'元曲/yuanqu.json','["小酌会窃香韩寿。", "举觞红袖，玉纤横管，银甲调筝，酒令诗筹。", "曲成诗就，韵协声律，情动魂消，腹稿冥搜。", "宿恩当受，水仙山鬼，月妹花妖，如还得遇，不许干休。", "会埋伏未尝泄漏。"]'),
('yuanqu-9076','幺・群芳会首，繁英故友。梦回时绿肥红瘦，荣华过可见疏薄，财物广始','曾瑞','元','元曲','yuanqu','','[]','知亲厚。',78,'元曲/yuanqu.json','["知亲厚。", "慕新思旧，簪遗佩解，镜破钗分，蜂妒蝶羞。", "恶缘难救，痼疾长发，业贯将盈，努力呈头。", "冷冫食重馅，口摇舌剑，吻搠唇枪，独攻决胜，混战无忧。", "不到得落人奸彀。"]'),
('yuanqu-9078','般涉调・哨遍秋扇','曾瑞','元','元曲','yuanqu','','[]','合欢制时人皆悦，斫湘川翠竹挑成篾。',105,'元曲/yuanqu.json','["合欢制时人皆悦，斫湘川翠竹挑成篾。", "量分寸短长截，充直性见火随斜。", "便屈节，盘圈攒柄，下漆投胶，按素练如秋月。", "龟背罗色同沉麝，柄分开白璧，圈来定乌蛇。", "线缠着万缕黑龙须，囊鼓双飞玉蝴蝶。", "样制孤高，停分无偏，圆成不缺。"]'),
('yuanqu-9079','幺・自谓奇绝，要和时辈争优劣。得架大人权，比蒲葵白羽特别。识破也，','曾瑞','元','元曲','yuanqu','','[]','其中隐漆，就里藏金，徒夸外面如冰雪。',63,'元曲/yuanqu.json','["其中隐漆，就里藏金，徒夸外面如冰雪。", "除一身外馀阴难籍，力难撑大厦，声不震惊蛰。", "中途见弃莫伤心，误世清谈谩争舌，几曾将溺庶携挈。"]'),
('yuanqu-9080','耍孩儿・果然是弄巧番成拙，挽造化非同苟且。要移寒暑不由天，奈四时','曾瑞','元','元曲','yuanqu','','[]','正气无邪。',37,'元曲/yuanqu.json','["正气无邪。", "当胸卷地兵尘避，举手谩天日色遮。", "风云隔，本人间器物，妆世上英杰。"]'),
('yuanqu-9081','幺・最难甘递互相抬贴，卖弄他风流酝藉。只能驱一握掌中风，几曾将烦','曾瑞','元','元曲','yuanqu','','[]','暑除绝。',36,'元曲/yuanqu.json','["暑除绝。", "偏宜皓齿歌金缕，不为生灵奏玉牒。", "临台榭，引歌声荡漾，牵情思和协。"]'),
('yuanqu-9082','二・苗稼枯木叶焦，涌泉涸井脉竭。晒曝得田亩龟纹裂，犹随酷吏临轩阁，','曾瑞','元','元曲','yuanqu','','[]','不播仁风到窟穴。',24,'元曲/yuanqu.json','["不播仁风到窟穴。", "民灾孽，障虚名有剩，慰残喘无些。"]'),
('yuanqu-9083','尾・汗沾襟似沸汤，地烘炉如炼铁。比及盼得到白露中秋节，把四海苍生','曾瑞','元','元曲','yuanqu','','[]','热杀也。',109,'元曲/yuanqu.json','["热杀也。", "麈腰千古风流旖旎，束纤腰偏称襄王意。", "翠盘中妃后逞妖娆，舞春风杨柳依依。", "喜则喜，深兜玉腹，浅露酥胸，拘束得宫腰细。", "一幅锦或挑或绣，金妆锦砌，翠绕珠围。", "卧铺绣褥酿春光，睡展香衾暗花溪。", "粉汗香袭，被底无双，怀中第一。"]'),
('yuanqu-9084','五・青连红晚霞照楚山，红连青春云射渭水，玉纤款款当胸系。带儿纟全','曾瑞','元','元曲','yuanqu','','[]','十二白蝶舞，牙子对一双碧翠飞，望得些风流意。',32,'元曲/yuanqu.json','["十二白蝶舞，牙子对一双碧翠飞，望得些风流意。", "拘钤寂寞，仰勒孤凄。"]'),
('yuanqu-9085','四・常常得靠柳腰，紧紧得贴素体。同行同坐同鸳被，本待遮藏秋水冰肌','曾瑞','元','元曲','yuanqu','','[]','瘦，包弄春风玉一围，先泄漏春消息。',36,'元曲/yuanqu.json','["瘦，包弄春风玉一围，先泄漏春消息。", "纵不是你忄总开罗叩，多应是我瘦损香肌。"]'),
('yuanqu-9086','二・也不索托香腮转转猜，伸纤腰细细比，不索觑搂带礻至衫儿礻肯裙儿','曾瑞','元','元曲','yuanqu','','[]','衤契。',42,'元曲/yuanqu.json','["衤契。", "则这红罗鞋宽掩过多三指，翠当头横搀了少年围。", "若见俺风流婿，便知消减，不索先题。"]'),
('yuanqu-9087','幺・青衣布满如蓝氵殿，烁烁寒光未转。可怜内洁几曾知，鸾台无用空悬。','曾瑞','元','元曲','yuanqu','','[]','桃腮怎对施朱粉，宫额难临贴翠钿，不称风流愿。',32,'元曲/yuanqu.json','["桃腮怎对施朱粉，宫额难临贴翠钿，不称风流愿。", "香奁宝砌，绣袋金圈。"]'),
('yuanqu-9088','五煞・照妖镇释坛，护心保命全。分开后对成姻眷，乐昌暗结风流配，鲁','曾瑞','元','元曲','yuanqu','','[]','肃深谋斩斫权。',23,'元曲/yuanqu.json','["肃深谋斩斫权。", "憔悴佳人倦，愁观衰貌，鼓照芳研。"]'),
('yuanqu-9089','四・圆光净更清，菱花明更坚。可怜世事云千变，玉盘本洁蒙尘垢，皓月','曾瑞','元','元曲','yuanqu','','[]','虽明障雾烟，云暗青霄掩，世情有分，物态无缘。',22,'元曲/yuanqu.json','["虽明障雾烟，云暗青霄掩，世情有分，物态无缘。"]'),
('yuanqu-9090','三・古铜时下收，菱花何处选。今来特许良工见，气吹黯雾飞天外，手抚','曾瑞','元','元曲','yuanqu','','[]','残云离月边。',22,'元曲/yuanqu.json','["残云离月边。", "光彩如银练，高低善辨，貌陋能传。"]'),
('yuanqu-9091','二・就中硬胜刚，外面软似绵。冰盆初破如刀剪，逢人射影停身分，睹物','曾瑞','元','元曲','yuanqu','','[]','遗形在眼前。',20,'元曲/yuanqu.json','["遗形在眼前。", "分明现，秋天朗朗，风露涓涓。"]'),
('yuanqu-9092','一・分毫无缕瑕，光莹净玉宣。残云刮地西风卷，寒光皎洁明盈室，素魄','曾瑞','元','元曲','yuanqu','','[]','团圆照满天。',23,'元曲/yuanqu.json','["团圆照满天。", "似银汉冰盘转，鉴窥星斗，照耀山川。"]'),
('yuanqu-9093','尾・据坚平明正清，非为俺自专。若回光返照仁人面，廉洁分明自然显。思乡','曾瑞','元','元曲','yuanqu','','[]','辇毂下人生有幸，乐太平歌舞同欢庆。',104,'元曲/yuanqu.json','["辇毂下人生有幸，乐太平歌舞同欢庆。", "金绮陌玉娉婷，间笙簧歌转流莺。", "斗驰骋，粉浓兰麝，肌莹琼酥，花解语娇相并。", "旦暮花魔酒病，诗酬酢好句，词赓和新声。", "樱唇月下品玉箫，春笋花前按银筝。", "正宴乐皇都，忽忆吴山，顿思越景。"]'),
('yuanqu-9094','幺・书剑南行，或征或止无定，飘泊若云萍。驾孤舟一叶帆轻，似脱颖，','曾瑞','元','元曲','yuanqu','','[]','辞九重凤阙，快万里鹏程。',64,'元曲/yuanqu.json','["辞九重凤阙，快万里鹏程。", "无名利徒奔竞，自愿瞰东南形胜。", "湖山留客醉，花柳系人情。", "梯航海峤暮云黄，轿马烟岚乱山青。", "屡曾经，莲渚芦汀。"]'),
('yuanqu-9095','耍孩儿・山屏锦幛繁花盛，雪霁风和雨晴，良工着色画难成。竹疏梅淡轻','曾瑞','元','元曲','yuanqu','','[]','盈，竹穿坏壁凉阴浅，梅枕寒流瘦影清。',32,'元曲/yuanqu.json','["盈，竹穿坏壁凉阴浅，梅枕寒流瘦影清。", "贪幽净，懒趋权势，不就功名。"]'),
('yuanqu-9096','幺・蹉跎到处闲蹭蹬，不觉秋霜鬓冷。客窗几度梦朝京，忆松楸败境荒荆。','曾瑞','元','元曲','yuanqu','','[]','见新人百倍增千倍，问故友十停无九停。',33,'元曲/yuanqu.json','["见新人百倍增千倍，问故友十停无九停。", "咱徼幸，尚天涯流落，海角飘零。"]'),
('yuanqu-9097','二・虽然动的脚根，何曾转的眼睛，杜鹃啼感动归家兴。羡孤云易举离南','曾瑞','元','元曲','yuanqu','','[]','浦，无双翼高飞过渭城。',26,'元曲/yuanqu.json','["浦，无双翼高飞过渭城。", "行装并，载满船风月，十里旗亭。"]'),
('yuanqu-9098','尾・剡溪水半合，山阴雪欲平。还乡子安道无踪影，不回棹先生望谁请。羊诉冤','曾瑞','元','元曲','yuanqu','','[]','十二宫分了巳未，禀乾坤二气成形质。',103,'元曲/yuanqu.json','["十二宫分了巳未，禀乾坤二气成形质。", "颜色异种多般，本性善群兽难及。", "向塞北，李陵台畔，苏武坡前，嚼卧夕阳外，趁满目无穷草地。", "散一川平野，走四塞荒陂。", "驭车善致晋侯欢，拂石能逃左慈危。", "舍命于家，就死成仁，杀身报国。"]'),
('yuanqu-9099','耍孩儿・从黑河边赶我到东吴内，我也则望前程万里。想道是物离乡贵有','曾瑞','元','元曲','yuanqu','','[]','些峥嵘，撞着个主人翁少东没西。',56,'元曲/yuanqu.json','["些峥嵘，撞着个主人翁少东没西。", "无料喂把肠胃都抛做粪，无水饮将脂膏尽化做尿。", "便似养虎豹牢监系，从朝至暮，坐守行随。"]'),
('yuanqu-9100','幺・见一日八十番觑我膘脂，除我柯杖外别有甚的。许下浙江等处恶神祗，','曾瑞','元','元曲','yuanqu','','[]','又请过在城新旧相知。',59,'元曲/yuanqu.json','["又请过在城新旧相知。", "待赁与老火者残岁里呈高戏，要雇与小子弟新年中扮社直。", "穷养的无巴避，待准折舞裙歌扇，要打摸暖帽春衣。"]'),
('yuanqu-9101','尾・我如今剌搭着两个蔫耳杂，滴溜着一条粗硬腿。我便似蝙蝠臀内精精','曾瑞','元','元曲','yuanqu','','[]','地，要祭赛的穷神下的呵吃。',119,'元曲/yuanqu.json','["地，要祭赛的穷神下的呵吃。", "村居人性善皆由天命，气清浊列等为贤圣。", "万物内最为灵，又幸为男子峥嵘。", "要自省，妍媸贵贱，寿夭穷通，这几事皆前定，使不着吾强我性。", "叹时乖运拙，随坎止流行。", "既知钟鼎果无缘，好向林泉且埋名。", "除去浮花，修养残躯，安排暮景。"]'),
('yuanqu-9102','幺・量力经营，数间茅屋临人境，车马少得安宁。有书堂药室茶亭，甚齐','曾瑞','元','元曲','yuanqu','','[]','鱼池内菱芡，溪岸上鸡鹅，壮观我乘高兴。',61,'元曲/yuanqu.json','["鱼池内菱芡，溪岸上鸡鹅，壮观我乘高兴。", "缫车响蝉声相应，妻蚕女茧，婢织奴耕。", "陇头残月荷锄歌，牛背夕阳短笛横，听农家野调山声。"]'),
('yuanqu-9103','幺・把闲花野草都锄净，尚又怕ㄗ稗交生。桑榆高接暮云平，笋黄菜绿瓜','曾瑞','元','元曲','yuanqu','','[]','葫芦花发香风细，杨柳阴浓暑气清。',30,'元曲/yuanqu.json','["葫芦花发香风细，杨柳阴浓暑气清。", "开心镜，静观消长，闲考亏盈。"]'),
('yuanqu-9104','五煞・菜老便枯，菜嫩便荣，荣枯消长教人为证。菜因浇灌多荣旺，人为','曾瑞','元','元曲','yuanqu','','[]','功名苦战争。',20,'元曲/yuanqu.json','["功名苦战争。", "徒然竞，百年身世，数度阴晴。"]'),
('yuanqu-9105','四・兴来画片山，闲来看卷经，推敲访友针诗病。消磨世态杯中酒，聚散','曾瑞','元','元曲','yuanqu','','[]','人情水上萍。',20,'元曲/yuanqu.json','["人情水上萍。", "心方定，但缘有酒，与世忘形。"]'),
('yuanqu-9106','三・无愁心自安，高眠梦不惊，不乏衣食为侥幸。身闲才见公途险，累少','曾瑞','元','元曲','yuanqu','','[]','方知担子轻。',20,'元曲/yuanqu.json','["方知担子轻。", "成家庆，顽童前引，稚子随行。"]'),
('yuanqu-9107','二・樵夫叉了柴，渔翁扳了罾，故来下访相钦敬。盘中熟笋和生菜，瓮里','曾瑞','元','元曲','yuanqu','','[]','新醅泼自清。',20,'元曲/yuanqu.json','["新醅泼自清。", "行歪令，饮竭正盏，斟满罚觥。"]'),
('yuanqu-9109','商调・集贤宾宫词','曾瑞','元','元曲','yuanqu','','[]','闷登楼倚阑干看暮景，天阔水云平。',77,'元曲/yuanqu.json','["闷登楼倚阑干看暮景，天阔水云平。", "浸池面楼台倒影，书去笺雁字斜横。", "衰柳拂月户云窗，残荷临水阁凉亭。", "景凄凉助人愁越逞，下妆楼步月空庭。", "鸟惊环佩响，鹤吹铎铃鸣。"]'),
('yuanqu-9110','逍遥乐・对景如青鸾舞镜，天隔羊车，人囚凤城。好姻缘辜负了今生，痛','曾瑞','元','元曲','yuanqu','','[]','伤悲雨泪如倾。',39,'元曲/yuanqu.json','["伤悲雨泪如倾。", "心如醉满怀何日醒，西风传玉漏丁宁。", "恰过半夜，胜似三秋，才交四更。"]'),
('yuanqu-9111','金菊香・秋虫夜语不堪听，啼树宫鸦不住声。入孤帏强眠寻梦境，被相思','曾瑞','元','元曲','yuanqu','','[]','鬼绰了魂灵，纵有梦也难成。',13,'元曲/yuanqu.json','["鬼绰了魂灵，纵有梦也难成。"]'),
('yuanqu-9112','醋葫芦・睡不着，坐不宁，又不疼不痛病萦萦。待不思量霎儿心未肯，没','曾瑞','元','元曲','yuanqu','','[]','乱到更阑人静。',7,'元曲/yuanqu.json','["乱到更阑人静。"]'),
('yuanqu-9113','高平煞・照愁人残蜡碧荧荧，沉水烟消金兽鼎。败叶走庭除，修竹扫苍楹。','曾瑞','元','元曲','yuanqu','','[]','唱道是人和闷可难争，则我瘦身躯怎敢共愁肠竞。',54,'元曲/yuanqu.json','["唱道是人和闷可难争，则我瘦身躯怎敢共愁肠竞。", "伤心情脉脉，病体困腾腾。", "画屋风轻，翠被寒增，也温不过早来袜儿冷。"]'),
('yuanqu-9114','尾・睡魔盼不来，丫鬟叫不应，香消烛灭冷清清。唯嫦娥与人无世情，可','曾瑞','元','元曲','yuanqu','','[]','怜咱孤另，透疏帘斜照月偏明。',14,'元曲/yuanqu.json','["怜咱孤另，透疏帘斜照月偏明。"]'),
('yuanqu-9116','双调・行香子叹世','曾瑞','元','元曲','yuanqu','','[]','名利相签，祸福相兼，使得人白发苍髯。',41,'元曲/yuanqu.json','["名利相签，祸福相兼，使得人白发苍髯。", "残花雨过，落絮泥沾，似梦中身、石中火、水中盐。"]'),
('yuanqu-9117','幺・跳下竿尖，摆脱钩钳，乐天真休问人嫌。顾前盼后，识耻知廉。是汉','曾瑞','元','元曲','yuanqu','','[]','张良，越范蠡，晋陶潜。',11,'元曲/yuanqu.json','["张良，越范蠡，晋陶潜。"]'),
('yuanqu-9118','乔木查・尽秋霜鬓染，老去红尘厌。名利为心无半点，庄周蝶梦甜，疏散','曾瑞','元','元曲','yuanqu','','[]','威严。',3,'元曲/yuanqu.json','["威严。"]'),
('yuanqu-9119','搅筝琶・君休欠，何故苦厌厌。月满还亏，杯盈自滟，荣贵路景稠粘。沾','曾瑞','元','元曲','yuanqu','','[]','惹情タ，把穿。',19,'元曲/yuanqu.json','["惹情タ，把穿。", "绝业贯休再添，徒尔趋炎。"]'),
('yuanqu-9120','拨不断・弃雕檐，隐闾阎。灰心打灭烧身焰，袖手擘开锁顶钳，柔舌砍钝','曾瑞','元','元曲','yuanqu','','[]','吹毛剑。',9,'元曲/yuanqu.json','["吹毛剑。", "旧由绝念。"]'),
('yuanqu-9121','离亭宴带歇指煞・无钱妆富刚为僭，有财合散休从俭。狂夫不厌，为口腹','曾瑞','元','元曲','yuanqu','','[]','遥天外置网罗，贪贿赂满肚里生荆棘，争人我平地上撅坑堑。',103,'元曲/yuanqu.json','["遥天外置网罗，贪贿赂满肚里生荆棘，争人我平地上撅坑堑。", "六印多你尚贪，一瓢足咱无欠。", "君子退谦，把两字利名勾，向百岁光阴里，将一味清闲占。", "供庖厨野齑香，忘宠辱村醪酽。", "无客至柴荆昼掩，卧松菊北窗凉，躲风波世途险。"]'),
('yuanqu-9122','双调・蝶恋花闺怨','曾瑞','元','元曲','yuanqu','','[]','夜月楼头横玉管，雾帐云屏，常恨春霄短。',35,'元曲/yuanqu.json','["夜月楼头横玉管，雾帐云屏，常恨春霄短。", "别后身属新恨管，泥金翠袖啼痕满。"]'),
('yuanqu-9124','离亭带歇指煞・顿不开眉上连环贯，续不上腹内柔肠断。凄惶业债，风流','曾瑞','元','元曲','yuanqu','','[]','婿魂梦中少团圆。',101,'元曲/yuanqu.json','["婿魂梦中少团圆。", "淹渐病昼夜家厮缠缴，相思鬼行坐里常陪伴。", "暮寒生灯渐昏，微雨歇云初判。", "添愁衅端，风引漏声来，月移花影去，物感愁心乱。", "强解开闷套头，硬剁断愁羁绊，先擗掠凄凉两般。", "怀抱的枕儿温，香熏的被儿暖。"]'),
('yuanqu-9125','破幽梦孤雁汉宫秋・仙吕/赏花时','马致远','元','元曲','yuanqu','','[]','四海平安绝士马，五谷丰登没战伐。',50,'元曲/yuanqu.json','["四海平安绝士马，五谷丰登没战伐。", "寡人待刷室女选宫娃，你避不的驰驱困乏。", "看那一个合属俺帝王家。", "(下)。"]'),
('yuanqu-9126','破幽梦孤雁汉宫秋・仙吕/点绛唇','马致远','元','元曲','yuanqu','','[]','车碾残花，玉人月下，吹箫罢。',26,'元曲/yuanqu.json','["车碾残花，玉人月下，吹箫罢。", "未遇宫娃，是几度添白发。"]'),
('yuanqu-9127','破幽梦孤雁汉宫秋・混江龙','马致远','元','元曲','yuanqu','','[]','料必他竹帘不挂，望昭阳一步一天涯。',237,'元曲/yuanqu.json','["料必他竹帘不挂，望昭阳一步一天涯。", "疑了些无风竹影，恨了些有月窗纱。", "他每见弦管声中寻玉辇，恰便似斗牛星畔盼浮槎。", "(旦做弹科)(驾云)是那里弹的琵琶响？(内官云)是。", "(正末唱)是谁人偷弹一曲，写出嗟呀？(内官云)快报去接驾。", "(驾云)不要。", "(唱)莫便要忙传圣旨，报与他家。", "我则怕乍蒙恩，把不定心儿怕，惊起宫槐宿鸟、庭树栖鸦。", "(云)小黄门，你看是那一宫的宫女弹琵琶，传旨去教他来接驾，不要惊吓着他。", "(内官报科，云)兀那弹琵琶的是那位娘娘？圣驾到来，急忙迎接者。", "(旦趋接科)(驾唱)。"]'),
('yuanqu-9128','破幽梦孤雁汉宫秋・天下乐','马致远','元','元曲','yuanqu','','[]','和他也弄着精神射绛纱。',107,'元曲/yuanqu.json','["和他也弄着精神射绛纱。", "卿家，你觑咱，则他那瘦岩岩影儿可喜杀。", "(旦云)妾身早知陛下驾临，只合迎接。", "接驾不早，妾该万死。", "(驾唱)迎头儿称妾身，满口儿呼陛下，必不是寻常百姓家。", "(云)看了他容貌端正，是好女子也呵！(唱)。"]'),
('yuanqu-9129','破幽梦孤雁汉宫秋・醉中天','马致远','元','元曲','yuanqu','','[]','将两叶赛宫样眉儿画，把一个宜梳裹脸儿搽；额角香钿贴翠花，一笑有倾城价。',66,'元曲/yuanqu.json','["将两叶赛宫样眉儿画，把一个宜梳裹脸儿搽；额角香钿贴翠花，一笑有倾城价。", "若是越勾践姑苏台上见他，那西施半筹也不纳，更敢早十年败国亡家。"]'),
('yuanqu-9130','破幽梦孤雁汉宫秋・金盏儿','马致远','元','元曲','yuanqu','','[]','我看你眉扫黛，鬓堆鸦，腰弄柳，脸舒霞。',75,'元曲/yuanqu.json','["我看你眉扫黛，鬓堆鸦，腰弄柳，脸舒霞。", "那昭阳到处难安插，谁问你一梨两坝做生涯？也是你君恩留枕簟，天教雨露润桑麻。", "既不沙俺江山千万里，直寻到茅舍两三家。"]'),
('yuanqu-9131','破幽梦孤雁汉宫秋・醉扶归','马致远','元','元曲','yuanqu','','[]','我则问那待诏别无话，却怎么这颜色不加搽？点得这一寸秋波玉有暇。',68,'元曲/yuanqu.json','["我则问那待诏别无话，却怎么这颜色不加搽？点得这一寸秋波玉有暇。", "端的是卿眇目，他双瞎？便宣的八百姻娇比并他，也未必强如俺娘娘带破赚丹青画。"]'),
('yuanqu-9132','破幽梦孤雁汉宫秋・金盏儿','马致远','元','元曲','yuanqu','','[]','你便晨挑菜，夜看瓜，春种谷，夏浇麻。',129,'元曲/yuanqu.json','["你便晨挑菜，夜看瓜，春种谷，夏浇麻。", "情取棘针门粉壁上除了差法，你向正阳门改嫁的倒荣华。", "俺官职颇高如村社长，这宅院刚大似县官衙。", "谢天地可怜穷女婿，再谁敢欺负俺丈人家！(云)近前来，听寡人旨，封你做明妃者。", "(旦云)量妾身怎生消受的陛下恩宠！(做谢恩科)(驾唱)。"]'),
('yuanqu-9133','破幽梦孤雁汉宫秋・赚煞','马致远','元','元曲','yuanqu','','[]','且尽此宵情，休问明朝话。',149,'元曲/yuanqu.json','["且尽此宵情，休问明朝话。", "(旦云)陛下明朝早早驾临，妾这里侯驾。", "(驾唱)到明日，多管是醉卧在昭阳御榻。", "(旦云)妾身贱微，虽蒙恩宠，怎敢耍望与陛下同榻？(驾唱)休烦恼，吾当且是耍，斗卿来便当真假。", "恰才家辇路儿熟滑，怎下的真个长门再不踏！明夜里西宫阁下，你是必悄声儿接驾，我则怕六宫人攀例拨琵琶。", "(下)。"]'),
('yuanqu-9134','破幽梦孤雁汉宫秋・南吕/一枝花','马致远','元','元曲','yuanqu','','[]','四时雨露匀，万里江山秀。',64,'元曲/yuanqu.json','["四时雨露匀，万里江山秀。", "忠臣皆有用，高枕已无忧。", "守着那皓齿星眸，争忍的虚白昼。", "近新来染得些症候，一半儿为国忧民，一半儿愁花病酒。"]'),
('yuanqu-9135','破幽梦孤雁汉宫秋・梁州第七','马致远','元','元曲','yuanqu','','[]','我虽是见宰相似文王施礼，一头地离明妃，早宋玉悲秋。',162,'元曲/yuanqu.json','["我虽是见宰相似文王施礼，一头地离明妃，早宋玉悲秋。", "怎奈他带天香着莫定龙衣袖。", "他诸余可爱，所事儿相投；消磨人幽闷，陪伴我闲游；偏宜向梨花月底登楼，芙蓉烛下藏阄。", "体态是二十年挑剔就的温柔，姻缘是五百载该拨下的配偶，脸儿有一千般说不尽的风流，寡人乞求他左右，他比那落伽山观自在无杨柳，见一面得长寿。", "情系人心早晚休，则除是雨歇云收。"]'),
('yuanqu-9136','破幽梦孤雁汉宫秋・隔尾','马致远','元','元曲','yuanqu','','[]','恁的般长门前抱怨的宫娥旧，怎知我西宫下偏心儿梦境熟。',81,'元曲/yuanqu.json','["恁的般长门前抱怨的宫娥旧，怎知我西宫下偏心儿梦境熟。", "爱他晚妆罢，描不成画不就，尚对菱花自羞。", "(做到旦背后看科)(唱)我来到这妆台背后，原来广寒殿嫦娥在这月明里有。"]'),
('yuanqu-9137','破幽梦孤雁汉宫秋・哭皇天','马致远','元','元曲','yuanqu','','[]','你有甚事疾忙奏，俺无那鼎镬边滚热油。',115,'元曲/yuanqu.json','["你有甚事疾忙奏，俺无那鼎镬边滚热油。", "我道您文臣安社稷，武将定戈矛；您只会文武班头，山呼万岁，舞蹈扬尘，道那声诚惶顿首。", "如今阳关路上，昭君出塞；当日未央宫里，女主垂旒。", "文武每，我不信你敢差排吕太后。", "枉以后、龙争虎斗，都是俺鸾交凤友。"]'),
('yuanqu-9138','破幽梦孤雁汉宫秋・乌夜啼','马致远','元','元曲','yuanqu','','[]','今日嫁单于，宰相休生受，早则俺汉明妃有国难投，它那里黄云不出青山岫。',90,'元曲/yuanqu.json','["今日嫁单于，宰相休生受，早则俺汉明妃有国难投，它那里黄云不出青山岫。", "投至两处凝眸，盼得一雁横秋。", "单注着寡人今岁揽闲愁，王嫱这运添憔瘦。", "翠羽冠，香罗绶，都做了锦蒙头暖帽，珠络缝貂裘。"]'),
('yuanqu-9139','破幽梦孤雁汉宫秋・三煞','马致远','元','元曲','yuanqu','','[]','我则恨那忘恩咬主贼禽兽，怎生不画在凌烟阁上头？紫台行都是俺手里的众公侯，有那椿儿不共卿谋，那件儿不依卿奏，争忍教第一夜梦迤逗？从今后不见长安望北斗，生扭作织女牵',126,'元曲/yuanqu.json','["我则恨那忘恩咬主贼禽兽，怎生不画在凌烟阁上头？紫台行都是俺手里的众公侯，有那椿儿不共卿谋，那件儿不依卿奏，争忍教第一夜梦迤逗？从今后不见长安望北斗，生扭作织女牵牛！(尚书云)不是臣等强逼娘娘和番，奈番使定名索取。", "况自古以来，多有因女色败国者。", "(驾唱)。"]'),
('yuanqu-9140','破幽梦孤雁汉宫秋・二煞','马致远','元','元曲','yuanqu','','[]','虽然似昭君般成败都皆有，谁似这做天子的官差不自由！情知他怎收那膘满的骅骝。',76,'元曲/yuanqu.json','["虽然似昭君般成败都皆有，谁似这做天子的官差不自由！情知他怎收那膘满的骅骝。", "往常时翠轿香兜，兀自倦朱帘揭绣，上下处要成就。", "谁承望月自空明水自流，恨思悠悠。"]'),
('yuanqu-9141','破幽梦孤雁汉宫秋・黄钟尾','马致远','元','元曲','yuanqu','','[]','怕娘娘觉饥时吃一块淡淡盐烧肉，害渴时喝一杓儿酪和粥。',85,'元曲/yuanqu.json','["怕娘娘觉饥时吃一块淡淡盐烧肉，害渴时喝一杓儿酪和粥。", "我索折一枝断肠柳，饯一杯送路酒。", "眼见得赶程途趁宿头，痛伤心重回首。", "则怕他望不见凤阁龙楼，今夜且则向灞陵桥畔宿。", "(下)。"]'),
('yuanqu-9142','破幽梦孤雁汉宫秋・双调/新水令','马致远','元','元曲','yuanqu','','[]','锦貂裘生改尽汉宫妆，我则索看昭君图画模样。',49,'元曲/yuanqu.json','["锦貂裘生改尽汉宫妆，我则索看昭君图画模样。", "旧恩金勒短，新恨玉鞭长。", "本是对金殿鸳鸯，分飞翼怎承望！。"]'),
('yuanqu-9143','破幽梦孤雁汉宫秋・驻马听','马致远','元','元曲','yuanqu','','[]','宰相每商量，大国使还朝多赐赏。',73,'元曲/yuanqu.json','["宰相每商量，大国使还朝多赐赏。", "早是俺夫妻悒怏，小家儿出外也摇装。", "尚兀自渭城衰柳助凄凉，共那灞桥流水添惆怅。", "您偏不断肠。", "想娘娘那一天愁都撮在琵琶上。"]'),
('yuanqu-9144','破幽梦孤雁汉宫秋・步步娇','马致远','元','元曲','yuanqu','','[]','您将那一曲阳关休轻放，俺咫尺如天样。',55,'元曲/yuanqu.json','["您将那一曲阳关休轻放，俺咫尺如天样。", "慢慢捧玉觞，朕本意待尊前捱些时光。", "且休问劣了宫商，您则与我半句儿俄延着唱。"]'),
('yuanqu-9145','破幽梦孤雁汉宫秋・落梅风','马致远','元','元曲','yuanqu','','[]','可怜俺别离重，你好是归去的忙。',44,'元曲/yuanqu.json','["可怜俺别离重，你好是归去的忙。", "寡人心先到他李陵台上。", "回头儿却才魂梦里想，便休题贵人多忘。"]'),
('yuanqu-9146','破幽梦孤雁汉宫秋・殿前欢','马致远','元','元曲','yuanqu','','[]','说甚么留下舞衣裳，被西风吹散旧时香。',73,'元曲/yuanqu.json','["说甚么留下舞衣裳，被西风吹散旧时香。", "我委实怕宫车再过青苔巷，猛到椒房，那一会想菱花镜里妆，风流相，兜的又横心上。", "看今日昭君出塞，几时似苏武还乡？。"]'),
('yuanqu-9147','破幽梦孤雁汉宫秋・雁儿落','马致远','元','元曲','yuanqu','','[]','我做了别虞姬楚霸王，全不见守玉关征西将。',55,'元曲/yuanqu.json','["我做了别虞姬楚霸王，全不见守玉关征西将。", "那里取保亲的李左车，送女客的萧丞相？(尚书云)陛下不必挂念。", "(驾唱)。"]'),
('yuanqu-9148','破幽梦孤雁汉宫秋・得胜令','马致远','元','元曲','yuanqu','','[]','那里也架海紫金梁？枉养着那边庭上铁衣郎。',73,'元曲/yuanqu.json','["那里也架海紫金梁？枉养着那边庭上铁衣郎。", "您也要左右人扶持，俺可甚糟糠妻不下堂！您但提起刀枪，却早小鹿儿心头撞。", "今日央及煞娘娘，怎做的男儿当自强！。"]'),
('yuanqu-9149','破幽梦孤雁汉宫秋・川拨棹','马致远','元','元曲','yuanqu','','[]','怕不待放丝缰，咱可甚鞭敲金镫响。',80,'元曲/yuanqu.json','["怕不待放丝缰，咱可甚鞭敲金镫响。", "你管燮理阴阳，掌握朝纲。", "治国安邦，展土开疆。", "假若俺高皇，差你个梅香，背井离乡，卧雪眠霜。", "若是他不恋您春风画堂，我便官封你一字王。"]'),
('yuanqu-9150','破幽梦孤雁汉宫秋・七兄弟','马致远','元','元曲','yuanqu','','[]','说甚么大王、不当、恋王嫱，兀良，怎禁他临去也回头望！那堪这散风雪旌节影悠扬，动关山鼓角声悲壮。',47,'元曲/yuanqu.json','["说甚么大王、不当、恋王嫱，兀良，怎禁他临去也回头望！那堪这散风雪旌节影悠扬，动关山鼓角声悲壮。"]'),
('yuanqu-9151','破幽梦孤雁汉宫秋・收江南','马致远','元','元曲','yuanqu','','[]','呀！不思量除是铁心肠。',47,'元曲/yuanqu.json','["呀！不思量除是铁心肠。", "铁心肠也愁泪滴千行。", "美人图今夜挂昭阳，我那里从养，便是我高烧银烛照红妆。"]'),
('yuanqu-9152','破幽梦孤雁汉宫秋・鸳鸯煞','马致远','元','元曲','yuanqu','','[]','我则索大臣行说一个推辞谎，又则怕笔尖儿那火编修讲。',96,'元曲/yuanqu.json','["我则索大臣行说一个推辞谎，又则怕笔尖儿那火编修讲。", "不见他花朵儿精神，怎趁那草地里风光？唱道伫立多时，徘徊半响；猛听的塞雁南翔，呀呀的声嘹亮。", "却原来满目牛羊，是兀那载离恨的毡车半坡里响。", "(下)。"]'),
('yuanqu-9153','破幽梦孤雁汉宫秋・中吕/粉蝶儿','马致远','元','元曲','yuanqu','','[]','宝殿凉生，夜迢迢六宫人静。',52,'元曲/yuanqu.json','["宝殿凉生，夜迢迢六宫人静。", "对银台一点寒灯，枕席间、临寝处，越显的吾身薄幸。", "万里龙廷，知他宿谁家一灵真性。"]'),
('yuanqu-9154','破幽梦孤雁汉宫秋・醉春风','马致远','元','元曲','yuanqu','','[]','烧尽御炉香，再添黄串饼。',52,'元曲/yuanqu.json','["烧尽御炉香，再添黄串饼。", "想娘娘似竹林寺不见半分形，则留下这个影、影。", "未死之时，再生之日，我可也一般恭敬。"]'),
('yuanqu-9155','破幽梦孤雁汉宫秋・叫声','马致远','元','元曲','yuanqu','','[]','高唐梦苦难成，那里也爱卿、爱卿，却怎生无些灵圣？偏不许楚襄王枕上雨云情。',159,'元曲/yuanqu.json','["高唐梦苦难成，那里也爱卿、爱卿，却怎生无些灵圣？偏不许楚襄王枕上雨云情。", "(做睡科，)(旦上，云)妾身王嫱，一番到北地，私自逃回。", "兀的不是我主人！陛下，妾身来了也。", "(番兵上，云)恰才我打了个盹，王昭君就偷走回去了。", "我急急赶来，进的汉宫，兀的不是昭君！(做拿旦下)(驾醒科，云)恰才见昭君回来，这些儿如何就不见了？(唱)。"]'),
('yuanqu-9156','破幽梦孤雁汉宫秋・剔银灯','马致远','元','元曲','yuanqu','','[]','恰才这搭儿单于王使命，呼唤俺那昭君名姓。',60,'元曲/yuanqu.json','["恰才这搭儿单于王使命，呼唤俺那昭君名姓。", "偏寡人唤娘娘不肯灯前应，却原来是画上的丹青。", "猛听得仙音院凤管鸣，更说甚萧韶九成。"]'),
('yuanqu-9157','破幽梦孤雁汉宫秋・蔓青菜','马致远','元','元曲','yuanqu','','[]','白日里无承应，教寡人不曾一觉到天明，做的个团圆梦境。',55,'元曲/yuanqu.json','["白日里无承应，教寡人不曾一觉到天明，做的个团圆梦境。", "(雁见科)(唱)却原来雁叫长门两三声，怎知道更有个人孤另。"]'),
('yuanqu-9158','破幽梦孤雁汉宫秋・白鹤子','马致远','元','元曲','yuanqu','','[]','多管是春秋高，筋力短，莫不是食水少，骨毛轻？待去后，愁江南网罗宽；待向前，怕塞北雕弓硬。',44,'元曲/yuanqu.json','["多管是春秋高，筋力短，莫不是食水少，骨毛轻？待去后，愁江南网罗宽；待向前，怕塞北雕弓硬。"]'),
('yuanqu-9159','破幽梦孤雁汉宫秋・幺篇','马致远','元','元曲','yuanqu','','[]','伤感似替昭君思汉主，哀怨似作薤露哭田横，凄怆似和半夜梦歌声，悲切似唱三叠阳关令。',65,'元曲/yuanqu.json','["伤感似替昭君思汉主，哀怨似作薤露哭田横，凄怆似和半夜梦歌声，悲切似唱三叠阳关令。", "(雁叫科)(云)则被那泼毛团叫的凄楚人也。", "(唱)。"]'),
('yuanqu-9160','破幽梦孤雁汉宫秋・上小楼','马致远','元','元曲','yuanqu','','[]','早是我神思不安，又添个冤家缠定。',59,'元曲/yuanqu.json','["早是我神思不安，又添个冤家缠定。", "他叫得慢一会儿紧一声儿，和尽寒更。", "不争你打盘旋，这搭里同声相应，可不差讹了四时节令？。"]'),
('yuanqu-9161','破幽梦孤雁汉宫秋・幺篇','马致远','元','元曲','yuanqu','','[]','你却待寻子卿、觅李陵，对着银台，叫醒咱家，对影生情。',53,'元曲/yuanqu.json','["你却待寻子卿、觅李陵，对着银台，叫醒咱家，对影生情。", "则俺那远乡的汉明妃虽然得命，不见你个泼毛团也耳根清净。"]'),
('yuanqu-9162','破幽梦孤雁汉宫秋・满庭芳','马致远','元','元曲','yuanqu','','[]','又不是心中爱听，大古似林风瑟瑟，岩溜冷冷。',115,'元曲/yuanqu.json','["又不是心中爱听，大古似林风瑟瑟，岩溜冷冷。", "我只见山长水远天如镜，又生怕误了你途程。", "见被你冷落了潇湘暮景，更打动我边塞离情，还说甚雁过留声。", "那堪更瑶阶夜永，嫌杀月儿明。", "(黄门云)陛下省烦恼，龙体为重。", "(驾云)不由我不烦恼也。", "(唱)。"]'),
('yuanqu-9163','破幽梦孤雁汉宫秋・十二月','马致远','元','元曲','yuanqu','','[]','休道是咱家动情，你宰相每也生憎。',49,'元曲/yuanqu.json','["休道是咱家动情，你宰相每也生憎。", "不比那雕梁燕语，不比那锦树莺鸣。", "汉昭君离乡背井，知他在何处愁听！。"]'),
('yuanqu-9164','破幽梦孤雁汉宫秋・尧民歌','马致远','元','元曲','yuanqu','','[]','呀呀的飞过蓼花汀，孤雁儿不离了凤凰城。',54,'元曲/yuanqu.json','["呀呀的飞过蓼花汀，孤雁儿不离了凤凰城。", "画檐间铁马响丁丁，宝殿中御榻冷清清。", "寒也波更，萧萧落叶声，烛暗长门静。"]'),
('yuanqu-9165','破幽梦孤雁汉宫秋・随煞','马致远','元','元曲','yuanqu','','[]','一声儿绕汉宫，一声儿寄渭城；暗添人白发成衰病，直恁的吾家可也劝不省。',34,'元曲/yuanqu.json','["一声儿绕汉宫，一声儿寄渭城；暗添人白发成衰病，直恁的吾家可也劝不省。"]'),
('yuanqu-9166','吕洞宾三度城南柳・仙吕/赏花时','谷子敬','元','元曲','yuanqu','','[]','今日个嫩蕊犹含粉脸羞，密叶空攒翠黛愁。',43,'元曲/yuanqu.json','["今日个嫩蕊犹含粉脸羞，密叶空攒翠黛愁。", "夸艳冶逞风流，结上些莺朋燕友，可索及早里便抽头。"]'),
('yuanqu-9167','吕洞宾三度城南柳・幺篇','谷子敬','元','元曲','yuanqu','','[]','休则管恼乱春风卒未休，恐怕你憔悴秋霜非是久。',51,'元曲/yuanqu.json','["休则管恼乱春风卒未休，恐怕你憔悴秋霜非是久。", "只等的红雨散绿云收，我那其间寻花问柳，重到岳阳楼。", "(下)。"]'),
('yuanqu-9168','吕洞宾三度城南柳・仙吕/点绛唇','谷子敬','元','元曲','yuanqu','','[]','别却蓬壶，坦然独步，尘寰去。',28,'元曲/yuanqu.json','["别却蓬壶，坦然独步，尘寰去。", "回首仙居，兀良在缥缈云深处。"]'),
('yuanqu-9169','吕洞宾三度城南柳・混江龙','谷子敬','元','元曲','yuanqu','','[]','仙凡有路，全凭着足底一双凫，翱翔天地，放浪江湖。',139,'元曲/yuanqu.json','["仙凡有路，全凭着足底一双凫，翱翔天地，放浪江湖。", "东方丹丘西太华，朝游北海暮苍梧。", "暂离真境，来混尘俗。", "觑百年浮世，似一梦华胥，信壶里乾坤广阔，叹人间甲子须臾。", "眨眼间白石已烂，转头时沧海重枯。", "箭也似走乏玉兔，梭也似飞困金乌。", "看了这短光阴，则不如且入无何去，落的个诗怀浩荡，醉眼模糊。"]'),
('yuanqu-9170','吕洞宾三度城南柳・油葫芦','谷子敬','元','元曲','yuanqu','','[]','高耸耸雕栏十二曲，接太虚，层梯百尺步云衢。',76,'元曲/yuanqu.json','["高耸耸雕栏十二曲，接太虚，层梯百尺步云衢。", "一会家望齐州则索低头数，只恐怕近天宫不敢高声浯。", "这楼襟三江，带五湖。", "更对着君山千仞青如许，咱这里不饮待何如？。"]'),
('yuanqu-9171','吕洞宾三度城南柳・天下乐','谷子敬','元','元曲','yuanqu','','[]','拚着个醉倒黄公旧酒垆，笑三也波闾，楚大夫，如今这汨罗江有谁曾吊古？怕不待骑鲸的飞上天，荷锸的埋入土，则问你独醒的今在无！(酒保云)这先生买了一百钱酒，则管要添。',185,'元曲/yuanqu.json','["拚着个醉倒黄公旧酒垆，笑三也波闾，楚大夫，如今这汨罗江有谁曾吊古？怕不待骑鲸的飞上天，荷锸的埋入土，则问你独醒的今在无！(酒保云)这先生买了一百钱酒，则管要添。", "料这穷道人，那里讨钱还我！没了酒也。", "(正末云)他怕我无钱，就说无了酒。", "我饮兴方浓，怎生是好？(酒保云)你要酒先数钱来。", "(正末云)我委实无钱了也。", "(酒保云)便无钱有甚么随身物件来当？(正末云)道人有何物？(唱)。"]'),
('yuanqu-9172','吕洞宾三度城南柳・幺篇','谷子敬','元','元曲','yuanqu','','[]','这剑六合砌为垆，二气铸成模。',188,'元曲/yuanqu.json','["这剑六合砌为垆，二气铸成模。", "呼的风，唤的雨，驱的云雾，屠的龙，诛的虎，灭的鬼生鬼吾。", "霜锋如巨阙，冰刃胜昆吾；光摇牛斗暗，气压鬼神伏。", "(云)你当今这剑有用他处。", "(酒保接剑，挂背上科，云)这剑是有用处，也好切菜。", "先生，酒不打紧。", "如今天色晚了，这楼上有两个精怪，到晚便出来迷人，酒客晚间不敢在这楼上吃酒。", "(正末云)有甚么精怪？我不怕他。", "(酒保云)你有甚么术法，却不怕他？(正末唱)。"]'),
('yuanqu-9173','吕洞宾三度城南柳・醉中天','谷子敬','元','元曲','yuanqu','','[]','我比你无些惧，你问我有何术？(指剑科)则是这袖里青蛇胆气粗，怕甚么妖精物。',157,'元曲/yuanqu.json','["我比你无些惧，你问我有何术？(指剑科)则是这袖里青蛇胆气粗，怕甚么妖精物。", "我若是拔向尊前起舞，手到处百灵咸助，怎容他山鬼揶揄？(酒保云)既然先生不怕，我与你酒自斟自饮，我下楼去也。", "(下)(桃、柳精上，云)俺二人恰从山中出来，如今天色晚也，咱去楼上宿歇去来。", "(做上楼，惊拜科，云)不知上仙在此，合当万死。", "(正末唱)。"]'),
('yuanqu-9174','吕洞宾三度城南柳・后庭花','谷子敬','元','元曲','yuanqu','','[]','原来是逞妖娆娇艳姝，弄精神老匹夫。',90,'元曲/yuanqu.json','["原来是逞妖娆娇艳姝，弄精神老匹夫。", "玄都观为头树，彭泽庄第一株。", "(云)我问你咱。", "(唱)你待何如，敢又去迷人害物！(柳云)弟子不敢。", "(正末唱)索问甚荣与枯，无知的衰朽木，反不如花解语。"]'),
('yuanqu-9175','吕洞宾三度城南柳・醉扶归','谷子敬','元','元曲','yuanqu','','[]','你自一点芳心苦，(柳云)弟子几时得度脱？(正末云)柳呵，(唱)几时得万结翠眉舒。',238,'元曲/yuanqu.json','["你自一点芳心苦，(柳云)弟子几时得度脱？(正末云)柳呵，(唱)几时得万结翠眉舒。", "(桃、柳各长吁科)(正末唱)您两个对月临风自叹吁，正是你绿惨红愁处。", "(桃云)我这等仙种，师父如何配与我柳树！(正末唱)只合与妖桃共居，天生下连枝树。", "(柳云)师父，弟子端的几时得托生？(正末云)你要托生，你只在老杨家成人。", "(桃云)弟子却是如何？(正末云)你也索跟他将去。", "(柳云)师父别有甚遗下言语？(正末云)你听我说。", "(诗云)独自行来独自坐，无限世人不识我。", "惟有城南柳树精，分明知道神仙过。", "(唱)。"]'),
('yuanqu-9176','吕洞宾三度城南柳・赚煞','谷子敬','元','元曲','yuanqu','','[]','为甚么桃脸破红颜，柳眼垂青顾，认得俺东君是主。',89,'元曲/yuanqu.json','["为甚么桃脸破红颜，柳眼垂青顾，认得俺东君是主。", "堪笑时人空有目，如肓般岂辨贤愚。", "这火凡夫都是些懵懂之徒，不识回仙元姓吕。", "则不如把红尘跳出，袖白云归去，我则待朗吟飞过洞庭湖。", "(下)。"]'),
('yuanqu-9177','吕洞宾三度城南柳・正宫/端正好','谷子敬','元','元曲','yuanqu','','[]','不争我三入岳阳城，又则索再出蓬莱洞，跨黄鹤拂两袖天风。',47,'元曲/yuanqu.json','["不争我三入岳阳城，又则索再出蓬莱洞，跨黄鹤拂两袖天风。", "到世间不是我尘缘冗，则被这花共柳相搬弄。"]'),
('yuanqu-9178','吕洞宾三度城南柳・滚绣球','谷子敬','元','元曲','yuanqu','','[]','怕不你柳色浓，花影重，色深沉暮烟偏重，影扶疏晓日方融。',95,'元曲/yuanqu.json','["怕不你柳色浓，花影重，色深沉暮烟偏重，影扶疏晓日方融。", "柳呵，少不的子树枯，半树荣。", "桃呵，少不的一片西，一片东。", "燕剪就乱丝也无则，莺掷下碎锦也成空。", "几曾见柳有千年绿，都说花无百日红，枉费春工。"]'),
('yuanqu-9179','吕洞宾三度城南柳・倘秀才','谷子敬','元','元曲','yuanqu','','[]','那些也清荫中空，何处也红芳万种，原来昨日今朝事不同。',370,'元曲/yuanqu.json','["那些也清荫中空，何处也红芳万种，原来昨日今朝事不同。", "寻旧迹觅遗踪，空留下故冢。", "(云)我上楼试着咱。", "(做坐还科，云)怎生不见人来(桃、柳精改扮同上)(净云)自家是岳阳楼下卖酒老杨的儿子。", "生下来头发便白，因此人皆叫我老柳。", "我今年二十岁了，娶得个浑家，是东邻李家女儿，名唤做小桃，和我同年同月同日生。", "我父亲亡故多年，我独自管着这酒楼。", "不知怎生，俺这妇人常不言语，可似哑的。", "我十分爱他，他却不爱我，这家缘全然不管。", "恰才有个酒客上楼去了，我去问他，娘子，你好生看着门。", "(做上楼见正末科)(正末云)老柳，你在这里，你认的我么？(净云)我不认的你。", "(正末云)二十年前我和你厮见来。", "(净云)这先生你敢错认了，我恰才二十岁，这二十年前那里得我来？你认的是俺父亲老杨，如今死过多年了。", "(正末背云)他是不认的。", "我去他身上，带意儿说上几句，看他省的省不的。", "(唱)。"]'),
('yuanqu-9180','吕洞宾三度城南柳・滚绣球','谷子敬','元','元曲','yuanqu','','[]','当日死了你那老太公，怎么生下你这个小业种。',120,'元曲/yuanqu.json','["当日死了你那老太公，怎么生下你这个小业种。", "樗散材怎能勾做梁作栋？你这片岁寒心不到的似柏如松。", "留下一枝儿继你祖宗，那取五株儿做你弟兄。", "槁木般病形骸更没些沉重，干柴般瘦身躯有恁么龙钟？枉将你翠眉颦损闲愁甚？空自把青眼睁开不认依，我须是昔日仙翁。"]'),
('yuanqu-9181','吕洞宾三度城南柳・脱布衫','谷子敬','元','元曲','yuanqu','','[]','则见他乌云坠蝉鬓筋松，秋波困醉眼朦胧。',35,'元曲/yuanqu.json','["则见他乌云坠蝉鬓筋松，秋波困醉眼朦胧。", "酒力透冰肌色浓，枕痕印粉腮香重。"]'),
('yuanqu-9182','吕洞宾三度城南柳・小梁州','谷子敬','元','元曲','yuanqu','','[]','为甚么这两朵桃花上脸红，须是你本面真容。',45,'元曲/yuanqu.json','["为甚么这两朵桃花上脸红，须是你本面真容。", "想着那去年今日此门中，你将我曾迎送，这搭里再相逢。"]'),
('yuanqu-9183','吕洞宾三度城南柳・幺篇','谷子敬','元','元曲','yuanqu','','[]','恰便似汉刘郎误访桃源洞，奈惜花人有信难通。',169,'元曲/yuanqu.json','["恰便似汉刘郎误访桃源洞，奈惜花人有信难通。", "(净看旦笑科)(正末唱)他频将柳眼窥，你把花心动。", "怕不年高德重，人则道临老入花丛。", "(净云)好是跷怪，俺这浑家见了这先生，就会说话了，又似认的他一般。", "(正末云)老柳，再打酒来，不少你钱。", "(净取酒上，云)今日见了师父，俺浑家又会说话，我喜之不胜。", "俺夫妻二人伏侍师父，只管吃醉，不要还酒钱。", "(正末唱)。"]'),
('yuanqu-9184','吕洞宾三度城南柳・滚绣球','谷子敬','元','元曲','yuanqu','','[]','我待从容饮巨觥，他可殷勤捧玉钟，出红妆主人情重，强如列珍馐炮凤烹龙。',167,'元曲/yuanqu.json','["我待从容饮巨觥，他可殷勤捧玉钟，出红妆主人情重，强如列珍馐炮凤烹龙。", "(净云)师父，我会舞，等浑家也唱一个曲儿，替师父送酒何如？(做舞唱科)(正末唱)你看尊中酒不空，筵前曲未终，怎消得贤夫妇恁般陪奉，(净云)师父，俺两口儿这般歌舞，堪做一对儿。", "(正末唱)你那小蛮腰敢配不上樊素喉咙。", "休看那舞低杨柳楼心月，且听这歌尽桃花扇底风，倚翠偎红。"]'),
('yuanqu-9185','吕洞宾三度城南柳・白鹤子','谷子敬','元','元曲','yuanqu','','[]','年光弹指过，世事转头空。',29,'元曲/yuanqu.json','["年光弹指过，世事转头空。", "则管苦恋两枝春，可怎生不悟三生梦。"]'),
('yuanqu-9186','吕洞宾三度城南柳・幺','谷子敬','元','元曲','yuanqu','','[]','学长生千岁柏，不老万年松。',28,'元曲/yuanqu.json','["学长生千岁柏，不老万年松。", "我将你柳向玉堂栽，花傍瑶池种。"]'),
('yuanqu-9187','吕洞宾三度城南柳・快活三','谷子敬','元','元曲','yuanqu','','[]','少不的叶凋也翠幕倾，花落也锦机空。',35,'元曲/yuanqu.json','["少不的叶凋也翠幕倾，花落也锦机空。", "管取你一般潇洒月明中，栖不得鸾和凤。"]'),
('yuanqu-9188','吕洞宾三度城南柳・鲍老儿','谷子敬','元','元曲','yuanqu','','[]','那其间白雪飘飘灞岸东，飞絮将斜阳弄；红雨霏霏汉苑中，残英把春光送。',63,'元曲/yuanqu.json','["那其间白雪飘飘灞岸东，飞絮将斜阳弄；红雨霏霏汉苑中，残英把春光送。", "老了锦莺，愁翻粉蝶，怨杀游蜂。", "芳菲渺渺，韶光苒苒，岁月匆匆。"]'),
('yuanqu-9189','吕洞宾三度城南柳・啄木儿尾','谷子敬','元','元曲','yuanqu','','[]','怕不你霜凝时刚挨得秋，雪飘怎过冬？觑了这没下稍的枯杨成何用！想你那南柯则是一梦，争如俺桃花依旧笑春凤。',57,'元曲/yuanqu.json','["怕不你霜凝时刚挨得秋，雪飘怎过冬？觑了这没下稍的枯杨成何用！想你那南柯则是一梦，争如俺桃花依旧笑春凤。", "(同旦下)。"]'),
('yuanqu-9190','吕洞宾三度城南柳・南吕/一枝花','谷子敬','元','元曲','yuanqu','','[]','蝇头利不贪，蜗角名难恋。',59,'元曲/yuanqu.json','["蝇头利不贪，蜗角名难恋。", "行藏全在我，得失总由天。", "甘老江边，富贵非吾愿，清闲守自然。", "学子陵遁迹在严滩，似吕望韬光在渭川。"]'),
('yuanqu-9191','吕洞宾三度城南柳・隔尾','谷子敬','元','元曲','yuanqu','','[]','旋沽村酒家家贱，自钓鲈鱼个个鲜。',51,'元曲/yuanqu.json','["旋沽村酒家家贱，自钓鲈鱼个个鲜。", "醉与樵夫讲些经传。", "春秋有几年，汉唐事几篇？端的谁是准非，咱两个细敷演。"]'),
('yuanqu-9192','吕洞宾三度城南柳・隔尾','谷子敬','元','元曲','yuanqu','','[]','见一个庞眉老叟行在前面，见一个绝色佳人次着后肩。',57,'元曲/yuanqu.json','["见一个庞眉老叟行在前面，见一个绝色佳人次着后肩。", "恰渡过芳洲早望不见。", "多管在竹林寺边，桃花坞前，便趁着东风敢去不远。"]'),
('yuanqu-9193','吕洞宾三度城南柳・牧羊关','谷子敬','元','元曲','yuanqu','','[]','他去处管七十二福地，辖三十六洞天，这河与弱水相连。',72,'元曲/yuanqu.json','["他去处管七十二福地，辖三十六洞天，这河与弱水相连。", "山号昆仑，地名阆苑。", "须不是系马邮亭畔，送客渭城边。", "离你那汴河堤早程三百，隔您那灞陵桥有路八千。"]'),
('yuanqu-9194','吕洞宾三度城南柳・骂玉郎','谷子敬','元','元曲','yuanqu','','[]','觑了这琼花顷刻飘扬遍，银海岛玉山川，沧波万顷明如练。',47,'元曲/yuanqu.json','["觑了这琼花顷刻飘扬遍，银海岛玉山川，沧波万顷明如练。", "龙鳞般云外飘，鹅毛般江上剪，蝶翅般风中旋。"]'),
('yuanqu-9195','吕洞宾三度城南柳・感皇恩','谷子敬','元','元曲','yuanqu','','[]','可早漫地漫天，更扑头扑面。',116,'元曲/yuanqu.json','["可早漫地漫天，更扑头扑面。", "雪拥就浪千堆，雪裁成花六出，雪压得柳三眠。", "(净云)这雪看看下得大了。", "好冷也。", "(正末唱)你这般愁风怕雪，甚的是带雨拖烟？你索拳双足，瞑双目，耸双肩。", "(净云)我起去摇橹，借你蓑衣披着。", "(作借蓑衣科)(正末唱)。"]'),
('yuanqu-9196','吕洞宾三度城南柳・采茶歌','谷子敬','元','元曲','yuanqu','','[]','他将我绿蓑穿，他把那橹绳牵，兀的是柳丝摇拽晚风前。',46,'元曲/yuanqu.json','["他将我绿蓑穿，他把那橹绳牵，兀的是柳丝摇拽晚风前。", "那里是雪片纷纷大如手，须是杨花滚滚乱如绵。"]'),
('yuanqu-9197','吕洞宾三度城南柳・哭皇天','谷子敬','元','元曲','yuanqu','','[]','谁着你锁鸳鸯系不紧垂杨线，今可去觅鸾胶续继弦。',132,'元曲/yuanqu.json','["谁着你锁鸳鸯系不紧垂杨线，今可去觅鸾胶续继弦。", "遮莫你上碧霄下黄泉，赤紧的天高地远。", "你若不依着我正道，我若不指与你迷途。", "柳呵，你便柔肠百结，巧计千般，浑身是眼，寻不见花枝儿般美少年。", "枉将你腰肢摆困，怎得你眉头放展！(净云)我不认的去路，渔翁，指引我去咱。", "(正末唱)。"]'),
('yuanqu-9198','吕洞宾三度城南柳・乌夜啼','谷子敬','元','元曲','yuanqu','','[]','见放着一条捷径疾如箭，索甚么指路金鞭！管教得见你那春风面，行处休俄延，坐处莫留连。',95,'元曲/yuanqu.json','["见放着一条捷径疾如箭，索甚么指路金鞭！管教得见你那春风面，行处休俄延，坐处莫留连。", "要问时，则问那昔年刘阮洞中猿；待寻呵，再休寻旧时王谢堂前燕。", "那里也白玉楼，黄金殿，休看做亚夫营里，陶令门前。"]'),
('yuanqu-9199','吕洞宾三度城南柳・贺新郎','谷子敬','元','元曲','yuanqu','','[]','那搭儿别是一重天，尽都是翠柏林峦。',153,'元曲/yuanqu.json','["那搭儿别是一重天，尽都是翠柏林峦。", "那里取绿杨庭院，数声鹤唳呵不比那两个黄鹂啭。", "纵有那惊俗客云间吠犬，须无那聒行人风外鸣蝉。", "你休错认做章台路，管取你误入武陵源，那里有碧桃千树都开遍。", "你去那丛中寻配偶，便是花里遇神仙。", "(净云)多谢渔翁指引。", "若寻得俺浑家回来，还再谢你。", "(正末云)正道不远，只在这里便是。", "(唱)。"]'),
('yuanqu-9200','吕洞宾三度城南柳・煞尾','谷子敬','元','元曲','yuanqu','','[]','天宽呵，无由得遇青鸾；便海阔也，有信难通锦鲤传。',545,'元曲/yuanqu.json','["天宽呵，无由得遇青鸾；便海阔也，有信难通锦鲤传。", "也不索登长空，临巨渊，过重山，涉大川，只隔得一片白云便相见。", "天涯在你目前，海角在你足边。", "不比你那送行处，西出阳关路儿远。", "(下)(净云)幸得这渔翁渡我过来，又指引我正道，则索依着他前面去。", "走了许远，只见四面云山，重重叠叠，知他是那里！兀那松荫下有个洞门，里面必定有人！我索问一声。", "(做敲门，旦上开门科，问云)是谁？(净做见科，云)我那里不寻，那里不觅，元来你却在这里！咱和你回去来。", "(旦云)这便是家，我那里去！师父在里面等我。", "(净云)这歪刺骨无礼。", "我偌远赶来寻你，你不回去，只恋着那先生，是甚么缘故？这等泼贱，不杀了要他何用？(做拔剑，杀旦科，云)我把这死尸丢在洞门前水里流将去。", "我藏了这剑，等那先生出来，也杀了他，方才出的我这一口臭气。", "(外扮公人上，云)杀人贼，那里去！(净慌走，公人赶上拿住科，云)咱拿杀人贼，见官去来。", "(左右报复，云)(外扮孤上，云)今日升衙。", "是谁这等吵闹！(公人云)拿得杀人贼在此。", "犯人当面。", "(孤云)这厮如何白日杀人？(净云)小人不曾杀人。", "我的浑家被一个先生引到这里，小人寻见了，教他跟我回去，被那先生把我浑家杀了。", "不干小人事。", "(孤云)你认的那先生么？(净云)小人认的。", "(孤云)左右，押这厮去寻那先生来对理。", "(押净下)。"]'),
('yuanqu-9201','吕洞宾三度城南柳・双调/新水令','谷子敬','元','元曲','yuanqu','','[]','恰携的半堤烟雨过潇湘，有心待栽培在九重天上。',51,'元曲/yuanqu.json','["恰携的半堤烟雨过潇湘，有心待栽培在九重天上。", "谁想从朝不见影，到晚要阴凉。", "空教我立尽斜阳，临岐处漫凝望。"]'),
('yuanqu-9202','吕洞宾三度城南柳・驻马听','谷子敬','元','元曲','yuanqu','','[]','则为你体性颠狂，柳絮随风空自忙。',233,'元曲/yuanqu.json','["则为你体性颠狂，柳絮随风空自忙。", "可怜芳魂飘荡，撇得桃花逐水为谁香？你是个入天台逞大胆的莽刘郎，扫蛾眉下毒手的乔张敞。", "只待学赚神女楚襄王，送的下巫峡，你却在阳台上。", "(公人云)同见官去，你两个折证咱。", "(行科，孤上做见科)(正末云)贫道稽首。", "(孤云)兀那道人，那厮指你杀了他媳妇。", "端的是谁杀来？(正末云)他浑家跟我修行办道，这厮寻见，将他杀了。", "不干贫道事。", "(净云)是他杀了！(正末云)则看谁有刀仗，便是杀人的。", "(孤云)这个说的是。", "左右搜看。", "(公人搜净，见剑科)(正末唱)。"]'),
('yuanqu-9203','吕洞宾三度城南柳・乔牌儿','谷子敬','元','元曲','yuanqu','','[]','自古道捉贼先见赃，索甚当官与招状！觑了这残红数点在龙泉上，眼见的小桃花剑下亡。',109,'元曲/yuanqu.json','["自古道捉贼先见赃，索甚当官与招状！觑了这残红数点在龙泉上，眼见的小桃花剑下亡。", "(孤云)这厮白昼杀人，合该偿命，又不合妄指平人，就着这先生亲手杀他。", "(正末指剑科，云)你可还我剑也。", "(净哭云)谁想我死在今朝也？(正末唱)。"]'),
('yuanqu-9204','吕洞宾三度城南柳・雁儿落','谷子敬','元','元曲','yuanqu','','[]','杆子你千条翠带长，万缕青丝扬。',27,'元曲/yuanqu.json','["杆子你千条翠带长，万缕青丝扬。", "不将意马拴，却把心猿放。"]'),
('yuanqu-9205','吕洞宾三度城南柳・得胜令','谷子敬','元','元曲','yuanqu','','[]','呀，推倒老孤桩，横在小池塘。',215,'元曲/yuanqu.json','["呀，推倒老孤桩，横在小池塘。", "未做擎天柱，先为架海梁。", "你看一寸春光，能有几日柔条旺？犯着咱三尺秋霜，管教你登时落叶黄。", "(做杀净，闭目科)(正末背剑，打渔鼓、简子，孤、众人各改扮众仙上)(正末云)弟子如今省了也。", "(净开目科，云)恰才杀了我，如何又活了呀？原来我是城南柳树精，可知头上生出柳枝来。", "(做打稽首，云)师父，原来这官府公人都是神仙，可是那几位？(正末云)这七人是汉钟离、铁拐李、张果老、蓝采和、徐神翁、韩湘子、曹国舅。", "(唱)。"]'),
('yuanqu-9206','吕洞宾三度城南柳・水仙子','谷子敬','元','元曲','yuanqu','','[]','这个是携一条铁拐入仙乡，这个是袖三卷金书出建章，这个是敲数声檀板游方丈，这个是倒骑驴登上苍，这个是提笊篱不认椒房，这个足背葫芦的神通大，这个是种牡丹的名姓香。',116,'元曲/yuanqu.json','["这个是携一条铁拐入仙乡，这个是袖三卷金书出建章，这个是敲数声檀板游方丈，这个是倒骑驴登上苍，这个是提笊篱不认椒房，这个足背葫芦的神通大，这个是种牡丹的名姓香。", "(净云)这七位神仙都认的了。", "师父可是谁？(正末唱)贫道因度柳呵，道号纯阳。"]'),
('yuanqu-9207','吕洞宾三度城南柳・落梅风','谷子敬','元','元曲','yuanqu','','[]','则为你临官路，出粉墙，常只是转眼间花残花放。',45,'元曲/yuanqu.json','["则为你临官路，出粉墙，常只是转眼间花残花放。", "引的个呆崔护洞门前来谒浆，且喜你桃源故人无恙。"]'),
('yuanqu-9208','吕洞宾三度城南柳・折桂令','谷子敬','元','元曲','yuanqu','','[]','端的是隔红尘景物非常，上面有彩凤交飞，青鸟翱翔。',90,'元曲/yuanqu.json','["端的是隔红尘景物非常，上面有彩凤交飞，青鸟翱翔。", "和那瑶草为邻，灵椿共茂，丹桂同芳。", "只教你占断风清月明，根盘的地老天荒。", "我为甚折取垂杨，移向扶桑！但能勾五千岁遐龄，索强如九十日韶光。"]'),
('yuanqu-9209','吕洞宾三度城南柳・随尾','谷子敬','元','元曲','yuanqu','','[]','从此后溪花喜有人相傍，岩枝怕甚风摇荡。',36,'元曲/yuanqu.json','["从此后溪花喜有人相傍，岩枝怕甚风摇荡。", "今日个繁华梦恰才醒，翠红乡再休想。"]'),
('yuanqu-9210','秦修然竹坞听琴・仙吕/赏花时','石子章','元','元曲','yuanqu','','[]','亡化过白头老父母，眼底亲人别又无。',47,'元曲/yuanqu.json','["亡化过白头老父母，眼底亲人别又无。", "我亲笔立定纸文书，分付与你这庄田和那地上，我着你为主不为奴。"]'),
('yuanqu-9211','秦修然竹坞听琴・幺篇','石子章','元','元曲','yuanqu','','[]','更问甚一岁孩儿百岁主，枉了身心活受苦。',53,'元曲/yuanqu.json','["更问甚一岁孩儿百岁主，枉了身心活受苦。", "愿富贵待何如？我则待添香可也补烛，常伏侍着你这一个老姑姑。", "(同下)。"]'),
('yuanqu-9212','秦修然竹坞听琴・仙吕/点绛唇','石子章','元','元曲','yuanqu','','[]','弃了个铜斗儿似家缘，撇下个泼天也似火院，到大来无拘倦。',42,'元曲/yuanqu.json','["弃了个铜斗儿似家缘，撇下个泼天也似火院，到大来无拘倦。", "每日间不断香烟，将一片真心炼。"]'),
('yuanqu-9213','秦修然竹坞听琴・混江龙','石子章','元','元曲','yuanqu','','[]','改换了油头粉面，再不将蛾眉淡扫鬓堆蝉。',146,'元曲/yuanqu.json','["改换了油头粉面，再不将蛾眉淡扫鬓堆蝉。", "将阴功暗垒，道教明传。", "座上全无尘半点，壶中别有一重天。", "向是非海内，入我丛中，将那等不晓事的愚迷劝。", "觑了这飘飘浮肚，冉冉流年。", "(小姑云)我觑了小姐你这等模样好，拣个好官员士夫人家嫁一个不好，出他那家做甚么？你不如归去罢，(正旦云)小姑，你说的差矣。", "(唱)。"]'),
('yuanqu-9214','秦修然竹坞听琴・村里迓鼓','石子章','元','元曲','yuanqu','','[]','你道我不如归去，我待要至心修炼。',76,'元曲/yuanqu.json','["你道我不如归去，我待要至心修炼。", "则他这蝇头蜗角，虚名利休贪休恋。", "倒不如躲是非，忘宠辱，无骄怨。", "问甚么谁得官，谁得禄，谁得钱？呀！到后来死生关临头怎免？。"]'),
('yuanqu-9215','秦修然竹坞听琴・元和令','石子章','元','元曲','yuanqu','','[]','咱人这无常管甚少年？我叹世事忽更变。',49,'元曲/yuanqu.json','["咱人这无常管甚少年？我叹世事忽更变。", "恰天桃喷火柳堆烟，早荷花点翠钿。", "东篱黄菊未开全，又纷纷雪满天。"]'),
('yuanqu-9216','秦修然竹坞听琴・上马娇','石子章','元','元曲','yuanqu','','[]','不如我琴一张，诗一联，乐意自悠然。',35,'元曲/yuanqu.json','["不如我琴一张，诗一联，乐意自悠然。", "试看他富贵和贫贱，都一般白骨葬黄泉。"]'),
('yuanqu-9217','秦修然竹坞听琴・胜葫芦','石子章','元','元曲','yuanqu','','[]','低多少兴废荣枯在眼前，人被利名牵，满目红尘关塞远。',43,'元曲/yuanqu.json','["低多少兴废荣枯在眼前，人被利名牵，满目红尘关塞远。", "笑车轮马足，晨钟暮鼓，空劳碌自年年。"]'),
('yuanqu-9218','秦修然竹坞听琴・幺篇','石子章','元','元曲','yuanqu','','[]','争如我睡彻东窗口影偏，高枕只安眠，愚者白愚贤者贤。',48,'元曲/yuanqu.json','["争如我睡彻东窗口影偏，高枕只安眠，愚者白愚贤者贤。", "炼丹砂九转，袖《黄庭》两卷，诵《老子》五千言。"]'),
('yuanqu-9219','秦修然竹坞听琴・后庭花','石子章','元','元曲','yuanqu','','[]','金垆焚宝烟，瑶琴鸣素弦。',570,'元曲/yuanqu.json','["金垆焚宝烟，瑶琴鸣素弦。", "无非母流水高山调，和那堆风积雪篇，端的这五音全。", "我叮便轻弹一遍，对清宵明月前，更行人迹杏然。", "正泠泠指下传，百般的声不圆，怎么百般的声不圆？(云)我这琴弦断，必有人来窃听，我开这门试看咱。", "(见末科，云)一个好秀才也。", "(秦修然云)呀，一个好姑姑也。", "(正旦云)兀那秀才，你是那里人氏？姓甚名谁？因甚来到俺这庵观？说的是万事都休，说的不是，送你到道录司，不道的饶了你哩。", "(秦修然云)小生南阳府人氏，姓秦双名修然，因为进取功名，到于此处。", "今日在城外踏青赏玩，不想天色昏晚，无处寄宿，来到此处，暂借一宵。", "听的这里弹琴声音嘹亮，因而窃听。", "不想姑姑在此，望恕小生之罪。", "(正旦背云)元来他便是秦修然，我且问他。", "兀那秀才，你认的那指腹成亲郑彩鸾么？(秦修然云)当初我父亲在时，多听的说有一个指腹成亲的郑彩鸾。", "自从我父母亡过，那郑彩鸾也不知所向，小生常切切于心，不能见面。", "(正旦云)秀才你休慌，则我便是郑彩鸾。", "(秦修然云)我那里不寻，那里不觅，你可可在这里。", "小姐，你既然遇着我，正是一对夫妻。", "我和你说句话儿。", "(正旦云)秀才休得无礼。", "我与你虽素有盟约，却不可造次苟合。", "万一外人得知，岂无私奔之诮？(秦修然云)我与你怨女旷夫，隔绝十有余年。", "今日偶尔相逢，天与之便，岂可固执？(正旦云)既然如此，这所在不是说话处，咱去那耳房里说话去来。", "(唱)。"]'),
('yuanqu-9220','秦修然竹坞听琴・金盏儿','石子章','元','元曲','yuanqu','','[]','这搭儿里花影更幽然，桧柏琐苍烟。',80,'元曲/yuanqu.json','["这搭儿里花影更幽然，桧柏琐苍烟。", "则这两桩儿好与人方便，果然是色胆大如天。", "今夜又无甚星河相间阻，莫不着人月两团圆？我可是清闲真道本，则被你坏了我也，无事的散神仙。"]'),
('yuanqu-9221','秦修然竹坞听琴・赚煞','石子章','元','元曲','yuanqu','','[]','建起座七真坛，新盖了三清殿。',93,'元曲/yuanqu.json','["建起座七真坛，新盖了三清殿。", "往常我酝酿真心不浅，不想这一曲瑶琴声婉转，包藏着那美满姻缘。", "并香肩月下星前，共指三生说誓言。", "我也到不的蓬阆苑，羞对着药垆经卷，我愁的是小窗孤枕夜如年。", "(下)。"]'),
('yuanqu-9222','秦修然竹坞听琴・中吕/粉蝶儿','石子章','元','元曲','yuanqu','','[]','这些时懒诵南华，将一串数珠来壁间闲挂，念一首断肠词颠倒熟滑。',69,'元曲/yuanqu.json','["这些时懒诵南华，将一串数珠来壁间闲挂，念一首断肠词颠倒熟滑。", "不免的唤道姑，添净水，我刚刚的把圣贤来参罢。", "若不是会首人家，几番将这道袍脱下。"]'),
('yuanqu-9223','秦修然竹坞听琴・醉春风','石子章','元','元曲','yuanqu','','[]','我如今将草索儿系住心猿，又将藕丝儿缚定意马。',65,'元曲/yuanqu.json','["我如今将草索儿系住心猿，又将藕丝儿缚定意马。", "人说道出家的都待要断尘情，我道来都是些假、假。", "几时能勾月枕双欹，玉箫齐品，翠鸾同跨？。"]'),
('yuanqu-9224','秦修然竹坞听琴・红绣鞋','石子章','元','元曲','yuanqu','','[]','我恰才搭伏定芙蓉懒架，恰合眼梦见他家，觉来也依旧隔天涯。',203,'元曲/yuanqu.json','["我恰才搭伏定芙蓉懒架，恰合眼梦见他家，觉来也依旧隔天涯。", "早是我心绪又乱，更那堪客人侵杂，道甚么相公在门首前方下马。", "(小姑云)相公请进。", "(梁尹见旦科，云)这个道姑是生的好也。", "(正旦云)稽首，相公请坐。", "小姑，快烹茶来。", "(梁尹云)道姑，你也请坐。", "(正旦云)贫姑不敢。", "(梁尹云)道姑，兀的恭敬不如从命。", "(正旦云)既如此。", "斗胆了。", "(稽首坐科)(梁尹云)道姑，我此一来你试猜咱。", "(正旦云)相公此来，贫姑是猜波。", "(唱)。"]'),
('yuanqu-9225','秦修然竹坞听琴・石榴花','石子章','元','元曲','yuanqu','','[]','莫不是山城无事早休衙？(梁尹云)今早不下雨来。',215,'元曲/yuanqu.json','["莫不是山城无事早休衙？(梁尹云)今早不下雨来。", "(正旦唱)朝来微雨润轻纱。", "(梁尹云)这时节正是暮春天道。", "(正旦唱)茸茸芳草衬残霞，都乘着这宝马，(梁尹云)老夫待赏玩踏青咱。", "(正旦唱)迅步行踏。", "(带云)贫姑猜着了也。", "(唱)莫不是那官叫，民快央及的怕？(粱尹云)老夫一径的散心来。", "(正旦唱)因此上出郊外贪寻幽雅。", "(梁尹云)道姑，老夫此来不张伞盖，不摆头踏，你知老夫的这意么？(正旦唱)你可也为甚么不张伞盖不摆头踏？多只是恐惊林下野人家。"]'),
('yuanqu-9226','秦修然竹坞听琴・斗鹌鹑','石子章','元','元曲','yuanqu','','[]','休笑俺草户柴门，那里取那银屏的这绣榻。',192,'元曲/yuanqu.json','["休笑俺草户柴门，那里取那银屏的这绣榻。", "(梁尹云)老夫久慕高风，因此相访。", "(正旦唱)多谢也降尊临卑，屈高、屈高就下。", "(梁尹云)道姑，兀的不是琴？请抚一曲，老夫洗耳。", "(正旦云)琴弦断，弹不得了也。", "(梁尹云)道姑，你那弦断几时了？出家人休调发我。", "(正旦唱)俺出家人从来不会调发，相公少罪咱。", "(梁尹云)道姑既断了弦，市面上别寻一个续上不的？(正旦唱)这弦向那市面上难寻，欲要呵则除江心里旋打。"]'),
('yuanqu-9227','秦修然竹坞听琴・上小楼','石子章','元','元曲','yuanqu','','[]','枉将你那机谋用煞，若知俺这棋中奸诈。',122,'元曲/yuanqu.json','["枉将你那机谋用煞，若知俺这棋中奸诈。", "(梁尹云)这棋有甚么奸诈在那里？(正旦唱)都为那蜗角虚名，蝇头微利，蚁阵蜂衙。", "将一片打动的心，则与人，争高论下，直等待那揭局儿死时才罢。", "(梁尹云)道姑，这棋不下也罢，你有甚么名人书画将来老夫一看。", "(正旦唱)。"]'),
('yuanqu-9228','秦修然竹坞听琴・幺篇','石子章','元','元曲','yuanqu','','[]','止不过羲之字，老杜诗，戴松牛，韩干马。',120,'元曲/yuanqu.json','["止不过羲之字，老杜诗，戴松牛，韩干马。", "止不过枯木竹石，山水翎毛，雪月风花。", "若题着，那些人，都皆亡化，到如今是渔樵一场闲话。", "(梁尹云)道姑，兀这书画，则道老夫不识。", "自古以来，思凡的仙女甚多，则说灵照女透丹霞，这一桩事，你可知道么？(正旦唱)。"]'),
('yuanqu-9229','秦修然竹坞听琴・快活三','石子章','元','元曲','yuanqu','','[]','可不说钟子期访伯牙，倒问我灵照女透丹霞。',70,'元曲/yuanqu.json','["可不说钟子期访伯牙，倒问我灵照女透丹霞。", "(梁尹云)难道是古来的思凡仙女，就也没有？(正旦唱)他问我从古的思凡仙女有来么？则教我半晌家难回话。"]'),
('yuanqu-9230','秦修然竹坞听琴・鲍老儿','石子章','元','元曲','yuanqu','','[]','你将那无显验的文书是监察，须不是俺孔宣圣遗留下。',234,'元曲/yuanqu.json','["你将那无显验的文书是监察，须不是俺孔宣圣遗留下。", "将那个包待制看成做水晶塔，全没些半点儿真实的话。", "只待要说古谈今，寻山问水，傍柳穿花。", "那里也修身正已，利民润物，治国齐家。", "(梁尹背云)我观这道姑，生的外有西施之貌，内有道韫之才，可知我那侄儿留恋着他。", "我闻的侄儿原是与他指腹为婚，正好配成夫妇。", "今我赚的侄儿去了，若还留在此处，我也不放心。", "则除是这般。", "(回云)道姑，我那衙门左右，有一所白云观，是敕建祝寿道院。", "我要请你到观里做个观主，你意下如何？(正旦云)贫姑情愿去。", "(唱)。"]'),
('yuanqu-9231','秦修然竹坞听琴・尾声','石子章','元','元曲','yuanqu','','[]','怎如陀敢门锁绿苔，闲事扫落花。',42,'元曲/yuanqu.json','["怎如陀敢门锁绿苔，闲事扫落花。", "抱瑶琴高卧在松阴下，便做不得神仙，我也快活煞。", "(下)。"]'),
('yuanqu-9232','秦修然竹坞听琴・双调/新水令','石子章','元','元曲','yuanqu','','[]','成就了碧桃花下凤鸾交，怕甚么出家儿被教门中耻笑。',94,'元曲/yuanqu.json','["成就了碧桃花下凤鸾交，怕甚么出家儿被教门中耻笑。", "那里也灵丹腹内安，经卷向杖头挑。", "月夕花朝，将一阵黄粱梦忽惊觉。", "(云)呀！元来是我师父。", "(见科，老道姑云)小姐，你当初怎生出家来？(正旦唱)。"]'),
('yuanqu-9233','秦修然竹坞听琴・乔牌儿','石子章','元','元曲','yuanqu','','[]','几曾见出家的有下稍？趁如今我青春尚年少。',75,'元曲/yuanqu.json','["几曾见出家的有下稍？趁如今我青春尚年少。", "(老道姑云)我教你弹琴，正要清心养性，倒教你引老公不成？(正旦唱)倒是我卓文君一曲求凰操，早把那汉相如引动了。"]'),
('yuanqu-9234','秦修然竹坞听琴・雁儿落','石子章','元','元曲','yuanqu','','[]','别不曾将亲眷邀，那里把你个姑姑告？(老道姑云)你为甚么事便还了俗？(正旦唱)我这有宿缘的要还俗，(老道姑云)我到道录司告去，不道的饶了你哩。',113,'元曲/yuanqu.json','["别不曾将亲眷邀，那里把你个姑姑告？(老道姑云)你为甚么事便还了俗？(正旦唱)我这有宿缘的要还俗，(老道姑云)我到道录司告去，不道的饶了你哩。", "(正旦唱)哎！你个有火性的何须闹？(老道姑云)你既是出不的家，谁教你出家？(正旦唱)。"]'),
('yuanqu-9235','秦修然竹坞听琴・得胜令','石子章','元','元曲','yuanqu','','[]','呀！大古来人怨语声高，怎知俺父母有盟约？你待要锯倒连枝树，分开比翼鸟。',63,'元曲/yuanqu.json','["呀！大古来人怨语声高，怎知俺父母有盟约？你待要锯倒连枝树，分开比翼鸟。", "未曾出胎胞，早指腹成亲了。", "直到的今朝，才得这夫妻成对好。"]'),
('yuanqu-9236','秦修然竹坞听琴・折桂令','石子章','元','元曲','yuanqu','','[]','多应是欲火三焦，一时焰起，遍体焚烧。',49,'元曲/yuanqu.json','["多应是欲火三焦，一时焰起，遍体焚烧。", "似这等难控难持，便待要相偎相傍，也顾不得人笑人嘲。", "想着你瘦山。"]'),
('yuanqu-9237','秦修然竹坞听琴・沽美酒','石子章','元','元曲','yuanqu','','[]','这一领新道袍，似千里赠鹅毛。',40,'元曲/yuanqu.json','["这一领新道袍，似千里赠鹅毛。", "路远风尘你动劳，争知我衣冠改了也，不是做夫人便妆幺。"]'),
('yuanqu-9238','秦修然竹坞听琴・太平令','石子章','元','元曲','yuanqu','','[]','想这段前程非小，俺出家的福分难消。',221,'元曲/yuanqu.json','["想这段前程非小，俺出家的福分难消。", "但则要捉对儿云期雨约，便是掩师徒每全真了道。", "我着你记着，想着，不曾忘了，常言道，一还一报。", "(梁尹云)这新状元你认的么？(老道姑改扮科，云)我不认的。", "(梁尹云)他就是我在南阳时同僚秦思道的孩儿，叫做秦修然。", "(夫人云)可知道来，他原与郑彩鸾指腹成亲的。", "孩儿，你早和俺说知，也省得我这般聒絮。", "(梁尹云)如今我夫人认着老夫，姑姑又与新状元成了亲事，天下喜事无过夫妇团圆。", "便当杀羊造酒，做个大大庆喜的筵席。", "(正旦唱)。"]'),
('yuanqu-9239','秦修然竹坞听琴・离亭宴煞','石子章','元','元曲','yuanqu','','[]','咱如今把围棋识破了输赢着，瑶琴弹彻相思调，这婚姻是天缘凑巧。',99,'元曲/yuanqu.json','["咱如今把围棋识破了输赢着，瑶琴弹彻相思调，这婚姻是天缘凑巧。", "稳坐了七香车，高揭了三檐伞，请受了金花诰。", "再不赴偷香窃玉期，再不事炼药烧丹教，从些后无烦少恼。", "便不能随他萧史并登仙，只情愿守定梁鸿只谐老。"]'),
('yuanqu-9240','喜迁莺・想当初狂态，醉乡中放浪形骸。吾侪，尽都是五陵豪迈，都是些','谷子敬','元','元曲','yuanqu','','[]','阔论高谈梁栋材。',32,'元曲/yuanqu.json','["阔论高谈梁栋材。", "一个个安邦定策，一个个剑挥星斗，一个个胸卷江淮。"]'),
('yuanqu-9241','出队子・到春来东城南陌，信青骢踏绿苔。柳阴中打绕逞狂乖，芳径内妆','谷子敬','元','元曲','yuanqu','','[]','幺真意脉，粉墙上题诗思腻色。',14,'元曲/yuanqu.json','["幺真意脉，粉墙上题诗思腻色。"]'),
('yuanqu-9242','刮地风・到夏来绕定雕栏垂杨摆，绿阴庭槐。戗金船倚棹兰舟外，信意忘','谷子敬','元','元曲','yuanqu','','[]','听韵悠悠乐声一派，摇纨扇玉体相捱。',64,'元曲/yuanqu.json','["听韵悠悠乐声一派，摇纨扇玉体相捱。", "有翡翠轩碧纱橱避暑楼台，捧瑶觞莫减侧，摆列着十二金钗。", "直吃的晚凉生日暮遥天外，共采莲人归去来。"]'),
('yuanqu-9243','西门子・到秋来写长空寒雁儿堪人爱，霁一天秋月色。绿叶儿殷，黄菊儿','谷子敬','元','元曲','yuanqu','','[]','效龙山落帽老秀才，直吃的脸晕红身子儿歪，娇滴滴玉人儿扶策。',29,'元曲/yuanqu.json','["效龙山落帽老秀才，直吃的脸晕红身子儿歪，娇滴滴玉人儿扶策。"]'),
('yuanqu-9244','古水仙子・我、我、我自鉴戒，似、似、似锦阵里疏狂李太白。将、将、','谷子敬','元','元曲','yuanqu','','[]','将宝剑共瑶琴，还、还、还花钱共酒债。',86,'元曲/yuanqu.json','["将宝剑共瑶琴，还、还、还花钱共酒债。", "我、我、我嫌天宽恨地窄，呀、呀、呀，却原来是冬景幽哉。", "看、看、看泻长空瑞雪风乱筛，见、见、见傲冰魂玉梅南轩外，馨、馨、馨，时送将暗香来。"]'),
('yuanqu-9246','商调・集贤宾闺情','谷子敬','元','元曲','yuanqu','','[]','猛听的透帘栊卖花声唤起，将好梦却惊回。',84,'元曲/yuanqu.json','["猛听的透帘栊卖花声唤起，将好梦却惊回。", "更和那迁乔木莺声偏碎，上纱窗日影重移。", "暗沉吟失魄消魂，闷恹恹似醉如痴。", "把重门紧紧深闭起，怕莺花笑人憔悴。", "离愁何日满，此恨有谁知？。"]'),
('yuanqu-9247','逍遥乐・则为那无媒匹配，勾引起无倒断相思，染下这不明白的病疾。眼','谷子敬','元','元曲','yuanqu','','[]','睁睁的将我来抛离，泼乔才更狠似王魁。',54,'元曲/yuanqu.json','["睁睁的将我来抛离，泼乔才更狠似王魁。", "我这里骂一声却又悔，空没乱怎地支持。", "则落的长吁短叹，倒枕垂床，废寝废食。"]'),
('yuanqu-9248','醋葫芦・诗吟出锦绣文，字装成古样体。家冠济楚俊容仪，酒席间唱和音','谷子敬','元','元曲','yuanqu','','[]','韵美。',19,'元曲/yuanqu.json','["韵美。", "一团儿和气，论聪明俊俏有谁及？。"]'),
('yuanqu-9249','梧叶儿・刀搅也似柔肠断，爬推也似泪点垂，似醉有如痴。笔砚上疏了工','谷子敬','元','元曲','yuanqu','','[]','课，茶饭上减了饮食，针指上罢了心机，怎对人言说这就里！。',28,'元曲/yuanqu.json','["课，茶饭上减了饮食，针指上罢了心机，怎对人言说这就里！。"]'),
('yuanqu-9250','柳叶儿・我可甚千娇百媚，全不似旧日容仪，阁不住两眼凄惶泪。不能够','谷子敬','元','元曲','yuanqu','','[]','同欢会，则有分各东西，想人生最苦是别离。',20,'元曲/yuanqu.json','["同欢会，则有分各东西，想人生最苦是别离。"]'),
('yuanqu-9251','尾声・常记得枕席间说的言，星月底设来的誓。谁想这辜恩薄幸负心贼，','谷子敬','元','元曲','yuanqu','','[]','自相别数年无信息。',29,'元曲/yuanqu.json','["自相别数年无信息。", "比及你登科及第，我则索上青山化做望夫石。"]'),
('yuanqu-9252','包待制智斩鲁斋郎・仙吕/端正好','关汉卿','元','元曲','yuanqu','','[]','被论人有势权，原告人无门下，你便不良会可跳塔轮铡，那一个官司敢把勾头押？提起他名儿也怕。',44,'元曲/yuanqu.json','["被论人有势权，原告人无门下，你便不良会可跳塔轮铡，那一个官司敢把勾头押？提起他名儿也怕。"]'),
('yuanqu-9253','包待制智斩鲁斋郎・仙吕/点绛唇','关汉卿','元','元曲','yuanqu','','[]','则俺这令史当权；案房里面关文卷，但有半点儿牵连，那刁蹬无良善。',31,'元曲/yuanqu.json','["则俺这令史当权；案房里面关文卷，但有半点儿牵连，那刁蹬无良善。"]'),
('yuanqu-9254','包待制智斩鲁斋郎・油葫芦','关汉卿','元','元曲','yuanqu','','[]','只待置下庄房买些下田，家私积有数千；那里管三亲六眷尽埋冤。',96,'元曲/yuanqu.json','["只待置下庄房买些下田，家私积有数千；那里管三亲六眷尽埋冤。", "逼的人卖了银头面，我戴着金头面；送的人典了旧宅院，我住着新宅院。", "有一日限满时，便想得重迁；怎知他提刑司刷出三宗卷，恁时节带铁锁纳赃钱。"]'),
('yuanqu-9255','包待制智斩鲁斋郎・天下乐','关汉卿','元','元曲','yuanqu','','[]','那其间敢"卖了城南金谷园"！百姓见无权，一味里掀，波家私如败云风乱卷；或是流二千，遮莫徒一年，恁时节则落的几度喘。',71,'元曲/yuanqu.json','["那其间敢\"卖了城南金谷园\"！百姓见无权，一味里掀，波家私如败云风乱卷；或是流二千，遮莫徒一年，恁时节则落的几度喘。", "（云）早来到坟所也。", "（唱）。"]'),
('yuanqu-9256','包待制智斩鲁斋郎・金盏儿','关汉卿','元','元曲','yuanqu','','[]','觑郊原，正晴暄，古坟新土都添遍，家家化钱烈纸痛难言。',216,'元曲/yuanqu.json','["觑郊原，正晴暄，古坟新土都添遍，家家化钱烈纸痛难言。", "一壁厢黄鹂声恰恰，一壁厢血泪滴涟涟，正是\"莺啼新柳畔，人哭古坟前。", "\"（贴旦云）孔目，咱慢慢耍一会家去。", "（鲁斋郎引张龙上，云）你都跟着我闲游去来。", "这一所好坟也！树木上面一个黄莺儿。", "小的，将弹弓来。", "（做打弹科）（徕儿哭云）奶奶，打破头也！（贴旦云）那个弟子孩儿，闲着那驴蹄烂爪，打过这弹子来？（正末云）这个村弟子孩儿无礼，我家坟院里打过弹子来。", "你敢是不知我的名儿！我出去看波。", "（唱）。"]'),
('yuanqu-9257','包待制智斩鲁斋郎・青哥儿','关汉卿','元','元曲','yuanqu','','[]','你教我如何、如何分辨？（贴旦云）是那一个不晓事弟子孩儿，打破我孩儿的头！（正末唱）省可里乱语胡言。',117,'元曲/yuanqu.json','["你教我如何、如何分辨？（贴旦云）是那一个不晓事弟子孩儿，打破我孩儿的头！（正末唱）省可里乱语胡言。", "（徕儿云）打破我头也！（正末唱）哎，你个不识忧愁小业冤！唬的我魂魄萧然，言语狂颠。", "谁敢迟延？我只得破步撩衣走到跟前，少不的把屎做糕糜咽。"]'),
('yuanqu-9258','包待制智斩鲁斋郎・赚煞','关汉卿','元','元曲','yuanqu','','[]','哎，只被你巧笑倩祸机藏，美目盼灾星现；也是俺连年里时乖运蹇，可可的与那个恶那吒打个撞见，唬的我似没头鹅、热地上的蚰蜒。',124,'元曲/yuanqu.json','["哎，只被你巧笑倩祸机藏，美目盼灾星现；也是俺连年里时乖运蹇，可可的与那个恶那吒打个撞见，唬的我似没头鹅、热地上的蚰蜒。", "恰才个马头边附耳低言，一句话似亲蒙帝王宣。", "（做拿弹子拜科）（唱）这弹子举贤荐贤，他来的扑头扑面，明日个你团圆却教我不团圆！（下）。"]'),
('yuanqu-9259','包待制智斩鲁斋郎・南吕/一枝花','关汉卿','元','元曲','yuanqu','','[]','全失了人伦天地心，倚仗着恶党凶徒势，活支剌娘儿双拆散，生各札夫妇两分离。',89,'元曲/yuanqu.json','["全失了人伦天地心，倚仗着恶党凶徒势，活支剌娘儿双拆散，生各札夫妇两分离。", "从来有日月交蚀，几曾见夫主婚、妻招婿？今日个妻嫁人、夫做媒，自取些奁房断送陪随，那里也羊酒、花红、缎匹？。"]'),
('yuanqu-9260','包待制智斩鲁斋郎・梁州第七','关汉卿','元','元曲','yuanqu','','[]','他凭着恶哏哏威风纠纠，全不怕碧澄澄天网恢恢。',166,'元曲/yuanqu.json','["他凭着恶哏哏威风纠纠，全不怕碧澄澄天网恢恢。", "一夜间摸不着陈抟睡，不分喜怒，不辨高低。", "弄的我身亡家破，财散人离，对浑家又不敢说是谈非，行行里只泪眼愁眉。", "你、你、你，做了个别霸王自刎虞姬，我、我、我，做了个进西施归湖范蠡，来、来、来，浑一似嫁单于出塞明妃。", "正青春似水，娇儿幼女成家计，无忧虑，少萦系；平地起风波二千尺，一家儿瓦解星飞！。"]'),
('yuanqu-9261','包待制智斩鲁斋郎・牧羊关','关汉卿','元','元曲','yuanqu','','[]','怕不"晓日楼台静，春风帘幕低"。',68,'元曲/yuanqu.json','["怕不\"晓日楼台静，春风帘幕低\"。", "没福的怎生消得！这厮强赖人钱财，莽夺人妻室，高筑座营和寨，斜搠面杏黄旗，梁山泊贼相似，与蓼儿洼争甚的！。"]'),
('yuanqu-9262','包待制智斩鲁斋郎・四块玉','关汉卿','元','元曲','yuanqu','','[]','将一杯醇糯酒十分的吃。',114,'元曲/yuanqu.json','["将一杯醇糯酒十分的吃。", "（贴旦云）张孔目少吃，则怕你醉了。", "（正末唱）更怕我酒后疏狂失了便宜。", "扭回身刚咽的口长吁气，我乞求得醉似泥，唤不归；（贴旦云）孔目，你怎么要吃的这等醉？（正末云）大嫂，你那里知道？（唱）我则图别离时，不记得。"]'),
('yuanqu-9263','包待制智斩鲁斋郎・骂玉郎','关汉卿','元','元曲','yuanqu','','[]','也不知你甚些儿看的能当意？要你做夫人，不许我过今日，因此上急忙忙送你到他家内。',78,'元曲/yuanqu.json','["也不知你甚些儿看的能当意？要你做夫人，不许我过今日，因此上急忙忙送你到他家内。", "（贴旦云）孔目，你这般下的也！（正末唱）这都是我缘分薄，恩爱尽，受这等死临逼。"]'),
('yuanqu-9264','包待制智斩鲁斋郎・黄钟尾','关汉卿','元','元曲','yuanqu','','[]','夺了我旧妻儿，却与个新佳配，我正是"弃了甜桃绕山寻醋梨。',113,'元曲/yuanqu.json','["夺了我旧妻儿，却与个新佳配，我正是\"弃了甜桃绕山寻醋梨。", "\"知他是甚亲戚？教喝下庭阶，转过照壁；出的宅门，扭回身体，遥望着后堂内养家的人，贤惠的妻。", "非今生是宿世，我则索寡宿孤眠过年岁，几时能勾再得相逢，则除是南柯梦儿里！（下）。"]'),
('yuanqu-9265','包待制智斩鲁斋郎・中吕/粉蝶儿','关汉卿','元','元曲','yuanqu','','[]','倚仗着恶党凶徒，害良民肆生淫欲，谁敢向他行挟细拿粗？逞刁顽全不想他妻我妇，这的是败坏风俗，那一个敢为敢做！。',54,'元曲/yuanqu.json','["倚仗着恶党凶徒，害良民肆生淫欲，谁敢向他行挟细拿粗？逞刁顽全不想他妻我妇，这的是败坏风俗，那一个敢为敢做！。"]'),
('yuanqu-9266','包待制智斩鲁斋郎・醉春风','关汉卿','元','元曲','yuanqu','','[]','空立着判黎庶受官厅，理军情元帅府，父南子北各分离，端的是苦、苦！俺夫妻千死千生，百伶百俐，怎能勾一完一聚？。',54,'元曲/yuanqu.json','["空立着判黎庶受官厅，理军情元帅府，父南子北各分离，端的是苦、苦！俺夫妻千死千生，百伶百俐，怎能勾一完一聚？。"]'),
('yuanqu-9267','包待制智斩鲁斋郎・红绣鞋','关汉卿','元','元曲','yuanqu','','[]','怕不待打叠起千忧百虑，怎支吾这短叹长吁？（徕儿云）俺母亲怎生不见来了？（正末唱）他可便一上青山化血躯。',77,'元曲/yuanqu.json','["怕不待打叠起千忧百虑，怎支吾这短叹长吁？（徕儿云）俺母亲怎生不见来了？（正末唱）他可便一上青山化血躯。", "将金郎眉甲按，把玉姐手梢扶，兀的不痛杀人也儿共女！。"]'),
('yuanqu-9268','包待制智斩鲁斋郎・迎仙客','关汉卿','元','元曲','yuanqu','','[]','你把孩儿亲觑付、厮抬举。',416,'元曲/yuanqu.json','["你把孩儿亲觑付、厮抬举。", "这两个不肖孩儿也有甚么福？便做道忒贤达，不狠毒。", "（里云）孔目，你放心，就是我的孩儿一般看成。", "（正末唱）看成的似玉颗神珠，终不似他娘肠肚。", "（李四上，云）我来到郑州。", "这是姐姐、姐夫家。", "我叫门咱（做叫门科）（正末云）谁叫门哩？我看去。", "（见科）（正末云）原来是舅子。", "你的症候，我如今也害了也！（李四云）姐姐有好药！（正末云）不是那个急心疼症候，用药医得；是你那整理银壶瓶的症候。", "你姐姐也被鲁斋郎夺将去了也！（李四云）鲁斋郎，你早则要了俺家两个人儿也！（正末云）舅子，我可也强似你。", "他与了我一个小姐，叫做娇娥。", "（李四云）鲁斋郎，你夺了我的浑家，草鸡也不曾与我一个。", "姐夫，既没了姐姐，我回许州去罢。", "（正末云）舅子，这个便是你姐姐一般，厮见一面，怕做甚么？（李四云）既如此，待我也见一面，我就回去。", "姐夫，你可休留我。", "（做相见各留意科）（正末云）舅子，你敢要回去么？（李四云）姐夫，则这里住倒好。", "（正末云）好奇怪也！（唱）。"]'),
('yuanqu-9269','包待制智斩鲁斋郎・红绣鞋','关汉卿','元','元曲','yuanqu','','[]','他两个眉来眼去，不由我不暗暗踌躇。',56,'元曲/yuanqu.json','["他两个眉来眼去，不由我不暗暗踌躇。", "似这般哑谜儿教咱怎猜做？那一个心犹豫，那一个口支吾，莫不你两个有些儿曾面熟？。"]'),
('yuanqu-9270','包待制智斩鲁斋郎・石榴花','关汉卿','元','元曲','yuanqu','','[]','早难道"君子断其初"，今日个亲者便为疏。',92,'元曲/yuanqu.json','["早难道\"君子断其初\"，今日个亲者便为疏。", "人还害你待何如？我是你姐夫，倒做了姨夫。", "当初我医可了你病症还乡去，把你似太行山倚仗做亲属；我一脚的出宅门，你待展污俺婚姻簿，我可便负你有何辜！。"]'),
('yuanqu-9271','包待制智斩鲁斋郎・上小楼','关汉卿','元','元曲','yuanqu','','[]','谁听你花言巧语，我这里寻根拔树。',120,'元曲/yuanqu.json','["谁听你花言巧语，我这里寻根拔树。", "谁似你不分强弱，不识亲疏，不辨贤愚。", "纵是你旧媳妇、旧丈夫，依旧欢聚，可送的俺一家儿灭门绝户！（云）我一双孩儿在那里？（旦云）你去趱文书，他两个寻你去了。", "（正末云）眼见的所算了我那孩儿，兀的不气杀我也！（唱）。"]'),
('yuanqu-9272','包待制智斩鲁斋郎・幺篇','关汉卿','元','元曲','yuanqu','','[]','我一时间不认的人，你两个忒做的出！空教我乞留乞良、迷留没乱、放声啼哭。',203,'元曲/yuanqu.json','["我一时间不认的人，你两个忒做的出！空教我乞留乞良、迷留没乱、放声啼哭。", "这郑孔目拿定了萧娥胡做，知他那里去了赛娘、僧住？（云）罢、罢、罢！浑家被鲁斋郎夺将去了，一双儿女又不知所向。", "甫能得了个女人，又是银匠李四的浑家，我在这里怎生存坐？舅子，我将家缘家计，都分付与你两口儿；每月斋粮道服，休少了我的。", "我往华山出家去也！（李四云）姐夫，你怎生弃舍了铜斗儿家缘、桑麻地土？我扯住你的衣服，至死不放你去。", "（正末唱）。"]'),
('yuanqu-9273','包待制智斩鲁斋郎・十二月','关汉卿','元','元曲','yuanqu','','[]','休把我衣服扯住，情知咱冰炭不同炉。',103,'元曲/yuanqu.json','["休把我衣服扯住，情知咱冰炭不同炉。", "（李四云）姐夫，这桑麻地土、宝贝珍珠，怎生割舍的？（正末唱）管甚么桑麻地土，更问甚宝贝珍珠！（李四云）姐夫，把我浑家与你罢。", "（正末唱）呸，不识羞闲言长语，他须是你儿女妻夫。"]'),
('yuanqu-9274','包待制智斩鲁斋郎・尧民歌','关汉卿','元','元曲','yuanqu','','[]','索甚么恩绝义断写休书？（李四云）鲁斋郎知道，他不怪我？（正末唱）鲁斋郎也不是我护身符。',102,'元曲/yuanqu.json','["索甚么恩绝义断写休书？（李四云）鲁斋郎知道，他不怪我？（正末唱）鲁斋郎也不是我护身符。", "（李四云）俺姐姐不知在那里？（正末唱）他两行红袖醉相扶，\"美女终须累其夫\"！嗟吁，嗟吁！教咱何处居？则不如趁早归山去。"]'),
('yuanqu-9275','包待制智斩鲁斋郎・耍孩儿','关汉卿','元','元曲','yuanqu','','[]','休道是"东君去了花无主"，你自有莺俦燕侣。',109,'元曲/yuanqu.json','["休道是\"东君去了花无主\"，你自有莺俦燕侣。", "我从今万事不关心，还恋甚衾枕欢娱？不见浮云世态纷纷变，秋草人情日日疏，空教我泪洒遍湘江竹！这其间心灰卓氏，干老了相如。", "（李四云）俺姐姐不知在那里？（正末云）你那姐姐呵，（唱）。"]'),
('yuanqu-9276','包待制智斩鲁斋郎・二煞','关汉卿','元','元曲','yuanqu','','[]','这其间听一声"金缕"歌，看两行红袖舞，常则是笙箫缭绕丫鬟簇；三杯酒满金鹦鹉，六扇屏开锦鹧鸪，反倒做他心腹。',72,'元曲/yuanqu.json','["这其间听一声\"金缕\"歌，看两行红袖舞，常则是笙箫缭绕丫鬟簇；三杯酒满金鹦鹉，六扇屏开锦鹧鸪，反倒做他心腹。", "那厮有拐人妻妾的器具，引人妇女的方术。"]'),
('yuanqu-9277','包待制智斩鲁斋郎・尾煞','关汉卿','元','元曲','yuanqu','','[]','再休提掌刑名都孔目，做英雄大丈夫，也只是"野人自爱山中宿"。',50,'元曲/yuanqu.json','["再休提掌刑名都孔目，做英雄大丈夫，也只是\"野人自爱山中宿\"。", "眼看那幼子娇妻，我可也做不的主！（下）。"]'),
('yuanqu-9278','包待制智斩鲁斋郎・双调/新水令','关汉卿','元','元曲','yuanqu','','[]','想人生平地起风波，争似我乐清闲支着个枕头儿高卧！只问你炼丹砂唐吕翁，何如那制律令汉萧何？我这里醉舞狂歌，繁花梦已参破。',59,'元曲/yuanqu.json','["想人生平地起风波，争似我乐清闲支着个枕头儿高卧！只问你炼丹砂唐吕翁，何如那制律令汉萧何？我这里醉舞狂歌，繁花梦已参破。"]'),
('yuanqu-9279','包待制智斩鲁斋郎・风人松','关汉卿','元','元曲','yuanqu','','[]','利名场上苦奔波，因甚强夺？蜗牛角上争人我，梦魂中一枕南柯。',45,'元曲/yuanqu.json','["利名场上苦奔波，因甚强夺？蜗牛角上争人我，梦魂中一枕南柯。", "不恋那三公华屋，且图个五柳婆婆。"]'),
('yuanqu-9280','包待制智斩鲁斋郎・甜水令','关汉卿','元','元曲','yuanqu','','[]','俺这里春夏秋冬，林泉兴味，四时皆可。',50,'元曲/yuanqu.json','["俺这里春夏秋冬，林泉兴味，四时皆可。", "常则是日夜宿山阿，有人相问，静里工夫，炼形打坐，笑指那落叶辞柯。"]'),
('yuanqu-9281','包待制智斩鲁斋郎・折桂令','关汉卿','元','元曲','yuanqu','','[]','想当初向清明日共饮金波，张孔目家世坟莹，须不是风月鸣珂。',98,'元曲/yuanqu.json','["想当初向清明日共饮金波，张孔目家世坟莹，须不是风月鸣珂。", "他将俺儿女夫妻，直认做了云雨巫娥。", "俺自撇下家缘过活，再无心缎匹缤罗你只管信口开合，絮絮聒聒；俺张孔目怎还肯缘木求鱼，鲁斋郎他可敢暴虎冯河！。"]'),
('yuanqu-9282','包待制智斩鲁斋郎・得胜令','关汉卿','元','元曲','yuanqu','','[]','今日个天理竟如何？黎庶尽讴歌。',254,'元曲/yuanqu.json','["今日个天理竟如何？黎庶尽讴歌。", "再不言宋天子英明甚，只说他包龙图智慧多。", "鲁斋郎哥哥，自惹下亡身祸；我舍了个娇娥，早先寻安乐窝。", "（云）今日我去云台观散心咱。", "（贴旦云）李四，你看那道人，好似你姐夫。", "你试唤他一声咱！（李四叫科，云）张孔目！（正末回头科，云是谁叫张孔目？（做见科，云）兀的不是我浑家李氏！（贴巨云）你怎撇了我出了家？劝你还俗罢！（正末诗云）你待散时我不散，悲悲切切男儿汉。", "从前经过旧恩情，要我还俗呵，有如曹司翻旧案。", "（众云）你还了俗罢！（正未云）我修行到这个地步，如何肯再还俗？（众拜科）（正末唱）。"]'),
('yuanqu-9283','包待制智斩鲁斋郎・川拨棹','关汉卿','元','元曲','yuanqu','','[]','不索你闹镬铎，磕着头礼拜我。',92,'元曲/yuanqu.json','["不索你闹镬铎，磕着头礼拜我。", "（李四云）姐夫，今日咱两家夫妇儿女都完聚了，你可怎生舍的出家去？你依着我，只是还了俗者！（正末唱）谁听你两道三科，嚷似蜂窝，甜似蜜钵！我若是还了俗可未可！。"]'),
('yuanqu-9284','包待制智斩鲁斋郎・七弟兄','关汉卿','元','元曲','yuanqu','','[]','你那里问我为何受寂寞，我得过时且自随缘过，得合时且把眼来合，得卧时侧身和衣卧。',39,'元曲/yuanqu.json','["你那里问我为何受寂寞，我得过时且自随缘过，得合时且把眼来合，得卧时侧身和衣卧。"]'),
('yuanqu-9285','包待制智斩鲁斋郎・梅花酒','关汉卿','元','元曲','yuanqu','','[]','不是我自间阔，趁浪逐波，落落拓拓，大笑呵呵。',62,'元曲/yuanqu.json','["不是我自间阔，趁浪逐波，落落拓拓，大笑呵呵。", "夫共妻、任摘离，儿和女、且随他。", "我这里、自磨陀，饮香醪、醉颜配，拚沉睡、在松萝。"]'),
('yuanqu-9286','包待制智斩鲁斋郎・收江南','关汉卿','元','元曲','yuanqu','','[]','呀！抵多少南华庄子鼓盆歌，乌飞兔走疾如梭，猛回头青鬓早皤皤。',52,'元曲/yuanqu.json','["呀！抵多少南华庄子鼓盆歌，乌飞兔走疾如梭，猛回头青鬓早皤皤。", "任傍人劝我，我是个梦中醒人，怎好又着他魔？。"]'),
('yuanqu-9287','包待制智斩鲁斋郎・收尾','关汉卿','元','元曲','yuanqu','','[]','多谢你大恩人救了咱全家祸，抬举的孩儿每双双长大，莫说他做亲的得成就好姻缘，便是俺还俗的也不误了正结果。',51,'元曲/yuanqu.json','["多谢你大恩人救了咱全家祸，抬举的孩儿每双双长大，莫说他做亲的得成就好姻缘，便是俺还俗的也不误了正结果。"]'),
('yuanqu-9288','亻刍梅香骗翰林风月・仙吕/赏花时','郑光祖','元','元曲','yuanqu','','[]','那生他文质彬彬才有余，和俺这相府潭潭德不孤，更怕甚文不在兹乎？合着俺三移的孟母，应对不尘俗。',46,'元曲/yuanqu.json','["那生他文质彬彬才有余，和俺这相府潭潭德不孤，更怕甚文不在兹乎？合着俺三移的孟母，应对不尘俗。"]'),
('yuanqu-9289','亻刍梅香骗翰林风月・幺篇','郑光祖','元','元曲','yuanqu','','[]','更压着汉宫里尊贤曹大家，帷幔底论文董仲舒。',55,'元曲/yuanqu.json','["更压着汉宫里尊贤曹大家，帷幔底论文董仲舒。", "都则是问安否意何如，往复间交谈了数语，几乎间讲遍九经书。", "(二旦下)。"]'),
('yuanqu-9290','亻刍梅香骗翰林风月・仙吕/点绛唇','郑光祖','元','元曲','yuanqu','','[]','书丧秦赢，道绝孔圣，坑灰冷。',29,'元曲/yuanqu.json','["书丧秦赢，道绝孔圣，坑灰冷。", "汉代儒生，他每都拨煨烬寻迹影。"]'),
('yuanqu-9291','亻刍梅香骗翰林风月・混江龙','郑光祖','元','元曲','yuanqu','','[]','孔安国传《中庸》《语》《孟》，马融集《春秋》祖述著左丘明，演《周易》关西夫子，治《尚书》鲁国伏生，校《礼记》舛讹杨子云，作《毛涛》笺注郑康成。',187,'元曲/yuanqu.json','["孔安国传《中庸》《语》《孟》，马融集《春秋》祖述著左丘明，演《周易》关西夫子，治《尚书》鲁国伏生，校《礼记》舛讹杨子云，作《毛涛》笺注郑康成。", "无过是阐大道发扬中正，纪善言问答详明。", "咱祖父乃文林华胄，况外戚是儒业簪缨。", "哀先相几乎绝嗣，使小姐振厥家声。", "又何须悬头刺股，积雪囊萤。", "那里也齐家治国，显姓扬名。", "但只要动天机，合天理，识天时，顺天道，尽天心，知天命。", "寸阴是竞，万理咸精。"]'),
('yuanqu-9292','亻刍梅香骗翰林风月・油葫芦','郑光祖','元','元曲','yuanqu','','[]','小姐你罢女工留心在九大经，吾日三省。',212,'元曲/yuanqu.json','["小姐你罢女工留心在九大经，吾日三省。", "(旦儿云)日月逝矣，岁不我与。", "你为甚么不讲书？(正旦唱)则他那匆匆节序又清明，这其间风光老尽芳菲景。", "今夜个月明闲杀秋千影。", "(旦儿云)樊素，你到后花园中来么？(正旦云)小姐，且休说那后花园中的景致，你则听者。", "(旦儿云)教我听甚么那？(正旦唱)你听波杜鹃声到耳清，闻波梨花香拂鼻馨。", "小姐你把看书心权作游春兆，暂离了三尺短檠灯。", "(旦儿云)樊素，不争俺和你闲行，老夫人知道，可怎了也？(正旦唱)。"]'),
('yuanqu-9293','亻刍梅香骗翰林风月・天下乐','郑光祖','元','元曲','yuanqu','','[]','这其间燕寝夫人梦未醒。',176,'元曲/yuanqu.json','["这其间燕寝夫人梦未醒。", "(旦儿云)老夫人着你伴我读书，你倒搬逗我废学。", "(正旦云)若老夫人知道呵，我便道不干小姐事，都是樊素来。", "(唱)樊素到天明，亲负荆。", "(带云)樊素搬逗小姐废学。", "(唱)比着那终南山割席学管宁。", "(旦儿云)不知你主何意，这早晚只往后花园中去那。", "(正旦唱)不是我主意儿别，啜赚的你早晚行。", "(云)岂不闻春宵一刻值千金！(唱)你休辜负了莺花三月景。"]'),
('yuanqu-9294','亻刍梅香骗翰林风月・那吒令','郑光祖','元','元曲','yuanqu','','[]','摇玎冬玉声，蹴金莲步轻；蹴金莲步轻，踏苍苔月明；踏苍苔月明，浸凌波袜冷。',100,'元曲/yuanqu.json','["摇玎冬玉声，蹴金莲步轻；蹴金莲步轻，踏苍苔月明；踏苍苔月明，浸凌波袜冷。", "(云)小姐，你看花红似锦，柳绿如烟，端的是好春光也。", "(旦儿云)是好景致也。", "(正旦唱)九十日春意浓，千金价春宵永，端的个乐事难并。"]'),
('yuanqu-9295','亻刍梅香骗翰林风月・鹊踏枝','郑光祖','元','元曲','yuanqu','','[]','花共柳笑相迎，风与月更多情。',46,'元曲/yuanqu.json','["花共柳笑相迎，风与月更多情。", "酝酿出嫩绿娇红，淡白深青。", "对如此良辰美景，可知道动骚人风调才情。"]'),
('yuanqu-9296','亻刍梅香骗翰林风月・寄生草','郑光祖','元','元曲','yuanqu','','[]','此景翰林才吟难尽，丹青笔画不成。',78,'元曲/yuanqu.json','["此景翰林才吟难尽，丹青笔画不成。", "觑海棠风锦机摇动鲛绡冷，芳草烟翠纱笼罩玻璃净，垂杨露绿丝穿透珍珠迸。", "池中星有如那玉盘乱撒水晶丸，松梢月恰便似苍龙捧出轩辕镜。"]'),
('yuanqu-9297','亻刍梅香骗翰林风月・幺篇','郑光祖','元','元曲','yuanqu','','[]','他曲未终肠先断，(带云)连我也伤感起来。',130,'元曲/yuanqu.json','["他曲未终肠先断，(带云)连我也伤感起来。", "(唱)俺耳才闻愁越增。", "一程程捱入相思境，一声声总是相思令，一星星尽诉相思病。", "不争向琴操中单诉着你飘零，可不道窗儿外更有个人孤另。", "(白又弹科)(歌云)孤凤求凰兮空哀鸣，离凰何处兮闻此情。", "(正旦云)你别弹一曲也罢呵！(唱)。"]'),
('yuanqu-9298','亻刍梅香骗翰林风月・赚煞','郑光祖','元','元曲','yuanqu','','[]','你道信步出兰庭，院悄人初静。',325,'元曲/yuanqu.json','["你道信步出兰庭，院悄人初静。", "(旦儿云)这早晚有谁出来？(正旦云)不是别人。", "(唱)静听是弹琴的那生。", "(白咳嗽科)(旦儿云)他便知道呵，怎知俺来这里做甚么？(正旦唱)生猜咱无情似有情。", "(旦儿云)怎知无情似有情？(正旦唱)情知咱甚意来听。", "(云)夜深了，咱回去来。", "(旦儿云)这早晚甚么时候了？(正旦唱)听沉罢过初更，更阑也休得消停。", "(旦儿云)你要来便来，你要去便去，再待些儿怕甚么。", "(正旦唱)停待甚忙将那脚步儿行。", "(旦儿云)行到那里去？(正旦唱)行过那梧桐树儿边金井。", "(旦儿云)因甚么往那里去？(正旦唱)井阑边把身躯儿掩映。", "(旦儿云)你前面行，我后面跟将去呵。", "(正旦唱)映着我这影儿呵，(旦儿云)樊素，你则道我不看见你哩。", "(正旦唱)好着我嫌杀月儿明。", "(下)。"]'),
('yuanqu-9299','亻刍梅香骗翰林风月・大石调/念奴娇','郑光祖','元','元曲','yuanqu','','[]','惊飞宿鸟，荡残红，扑簌簌胭脂零落。',143,'元曲/yuanqu.json','["惊飞宿鸟，荡残红，扑簌簌胭脂零落。", "(云)可早来到书房门首了也。", "(唱)门掩苍苔书院悄。", "(云)我且着这唾津儿，润破纸窗，我试看咱。", "(唱)润破纸窗偷瞧。", "(望白科。", "云)两日不见便病的这般瘦了，好可怜人也！(唱)这生则为那一操瑶琴，一番相见，又不曾言期约。", "似这般多情多绪，等闲间早害得来肌肤如削。"]'),
('yuanqu-9300','亻刍梅香骗翰林风月・六国朝','郑光祖','元','元曲','yuanqu','','[]','这生他不思献赋，不想题桥。',367,'元曲/yuanqu.json','["这生他不思献赋，不想题桥。", "则俺那卓文君，本无心把这个汉相如干病倒。", "(云)我入这书房中去。", "先生万福！(白敏中慌搂旦科，云)小姐，来了也。", "(正旦云)你怎的！(白羞科，云)羞杀我也！小生病在身，害的我是这般，小娘子休怪。", "(正旦云)你认的是着！(白敏中云)卟娘子为何至此？(正旦云)夫人致意先生。", "未知经宿病体康胜否？(唱)教解元善服汤药，把贵体和凋。", "(白敏中云)小姐可有甚传示？(正旦唱)且只占苦志攻经史，休把那文章来堕落。", "(白敏中云)小姐还有甚心腹说话么？(正旦掩白口科，唱)你省可里胡言乱语。", "(白敏中云)害的小生魂梦颠倒也。", "(正旦唱)准教你梦断魂劳。", "(白敏中云)小姐端的曾想念小生来么？(正旦云)俺小姐道来，怕足下病笃时，(唱)着碗来大的艾焙烧。", "(云)怕哥哥死时，削一条柳椽儿。", "(白敏中云)削一条柳椽儿，可是为何？(正旦唱)把你来火葬了。"]'),
('yuanqu-9301','亻刍梅香骗翰林风月・初问口','郑光祖','元','元曲','yuanqu','','[]','不争你先辈颠狂，枉惹的爵侪耻笑。',163,'元曲/yuanqu.json','["不争你先辈颠狂，枉惹的爵侪耻笑。", "你恋着这尾生期改尽颜回乐。", "(白敏中云)小生今生不能成双，死于九泉之下，也要相会呵！(正旦唱)又不曾荐枕席，便指望同棺椁，只想夜偷期不记朝闻道。", "(白敏中云)小娘子可怜见，成就了这门亲事，小生必有犬马之报。", "(正旦云)先生既读孔圣之书，必达周公之礼。", "老夫人使妾身探病，如何只管胡言，是何礼也？(唱)。"]'),
('yuanqu-9302','亻刍梅香骗翰林风月・归塞北','郑光祖','元','元曲','yuanqu','','[]','则你那年纪小，有路到青霄，有一日名挂在白玉楼头龙虎榜，愁甚么碧桃花下凤鸾交，早挣个束带立于朝。',47,'元曲/yuanqu.json','["则你那年纪小，有路到青霄，有一日名挂在白玉楼头龙虎榜，愁甚么碧桃花下凤鸾交，早挣个束带立于朝。"]'),
('yuanqu-9303','亻刍梅香骗翰林风月・雁过南楼','郑光祖','元','元曲','yuanqu','','[]','呀！他将那不犯触的庞儿变了，将我这奈抢白的脸儿难描。',103,'元曲/yuanqu.json','["呀！他将那不犯触的庞儿变了，将我这奈抢白的脸儿难描。", "他扑腾腾怒怎消，我可丕丕心头跳，手脚儿滴羞笃速不知一个颠倒。", "忙哀告膝跪着，强扎挣刚陪笑。", "(带云)小姐，若告老夫人去呵，(唱)则被你送了人也干相思洛阳年少。"]'),
('yuanqu-9304','亻刍梅香骗翰林风月・喜秋风','郑光祖','元','元曲','yuanqu','','[]','亏你也用工描。',108,'元曲/yuanqu.json','["亏你也用工描。", "(带云)这的是一把莲。", "(唱)却不是无心草。", "恁的般好门庭倒大来惹人笑。", "(做走科，唱)我将这紫香囊待走向夫人行告。", "(旦儿扯住科，云)我恰才斗你耍来，你便要将到那里去？(正旦唱)你是个女孩儿家端的可是甚为作。"]'),
('yuanqu-9305','亻刍梅香骗翰林风月・归塞北','郑光祖','元','元曲','yuanqu','','[]','请放了。',145,'元曲/yuanqu.json','["请放了。", "(旦儿，云)樊素，你且耽待着些。", "(正旦云)那壁是小姐。", "(唱)怎生向贱妾行告耽饶。", "(旦儿云)是我的不是了也。", "(正旦云)小姐，你恰才不要打我来？(唱)你却不掴绽我这樱桃樊素口。", "(旦儿云)樊素，你打我两下波。", "(正旦云)谁敢汤着你那杨柳小蛮腰。", "(带云)\"你过来跪者。", "\"(唱)今番轮到我妆么。"]'),
('yuanqu-9306','亻刍梅香骗翰林风月・怨别离','郑光祖','元','元曲','yuanqu','','[]','梅香今日有功劳。',179,'元曲/yuanqu.json','["梅香今日有功劳。", "(白敏中云)那简帖儿，小姐收了也不曾？(正旦弹指科，唱)将一个小小的机关儿把你来完备了。", "(白敏中云)有甚好音信？教我知道咱。", "(正旦唱)有他那亲笔写的情词揣着吟藁。", "(白敏中云)小姐的回音，我看咱。", "(正旦怀里取不见科，唱)呀！那里每不见了。", "(白敏中云)你怎么不小心等他不见了！天那！我可死了也。", "(正旦唱)哎！你个不了事的呆才可元来在这手儿卫搦着。"]'),
('yuanqu-9307','亻刍梅香骗翰林风月・归塞北','郑光祖','元','元曲','yuanqu','','[]','这简帖儿方胜小，见甚景像便待把香烧。',50,'元曲/yuanqu.json','["这简帖儿方胜小，见甚景像便待把香烧。", "不争你这狂客谨心参尺素，可待学文王下马拜荆条，见娘书信倒看的乔。"]'),
('yuanqu-9308','亻刍梅香骗翰林风月・净瓶儿','郑光祖','元','元曲','yuanqu','','[]','他想着书舍里人萧索，恰便似阳台上路迢遥。',253,'元曲/yuanqu.json','["他想着书舍里人萧索，恰便似阳台上路迢遥。", "(白敏中云)今夜小姐怎生摆布？(正旦唱)他则待收拾云雨，怕泄漏春娇。", "待和你今宵……(白敏中云)今宵和小姐生怎的？(正旦忍住不说科，唱)一句话到我这舌尖上却咽了。", "(白敏中云)可怎生却咽了？快说波，教小生喜咱。", "(正旦唱)不说破把先生且闷着。", "(白敏中云)小姐怎生分付你来？(正旦唱)他着我对你便低低道，(白敏中云)道甚么？(正旺唱)他教你夜深时休睡，(白敏中云)今夜我那里得那睡来！(正旦云)着你等。", "(白敏中云)怎么又不说了？着小生等甚么？(正旦唱)着你等、等、等到明朝。"]'),
('yuanqu-9309','亻刍梅香骗翰林风月・好观音','郑光祖','元','元曲','yuanqu','','[]','上复你个气咽声丝张京兆，他待填还你枕剩衾薄，待着你帽儿光光过此宵。',78,'元曲/yuanqu.json','["上复你个气咽声丝张京兆，他待填还你枕剩衾薄，待着你帽儿光光过此宵。", "(白敏中云)天色晚了，日头敢落了也呵。", "(正旦唱)恰正午怎盼的日头落，不曾见这急色的呆才料。"]'),
('yuanqu-9310','亻刍梅香骗翰林风月・越调/斗鹌鹑','郑光祖','元','元曲','yuanqu','','[]','想着那星斗文章，几回家逢咱稽颡。',73,'元曲/yuanqu.json','["想着那星斗文章，几回家逢咱稽颡。", "只为那花月精神，一见了教人断肠。", "用了我说六国喉舌，下三齐智量，不甫能添了晚妆，推烧夜香，如此般月白风清，花浓气爽。"]'),
('yuanqu-9311','亻刍梅香骗翰林风月・紫花儿序','郑光祖','元','元曲','yuanqu','','[]','月溶溶梨花庭院，风淡淡杨柳楼台，雾蒙蒙芳草池塘。',74,'元曲/yuanqu.json','["月溶溶梨花庭院，风淡淡杨柳楼台，雾蒙蒙芳草池塘。", "如此般好天良夜，淑女才郎，相将。", "意厮投门厮对户厮当，成就了只凤孤凰。", "这一个月夜南楼，那一个窥视东墙。"]'),
('yuanqu-9312','亻刍梅香骗翰林风月・小桃红','郑光祖','元','元曲','yuanqu','','[]','那生敢倚书窗想像赴高唐。',213,'元曲/yuanqu.json','["那生敢倚书窗想像赴高唐。", "（白敏中向前楼旦科，云）小姐，你来了也。", "（正旦慌科，云）是谁？（白敏中云）是我。", "（正旦唱）吓得我可扑扑小鹿儿心头撞。", "偌早晚是谁人敢无状？（白敏中云)我则道是小姐来了。", "（正旦唱）可怎生恁风狂。", "(白敏中云）我不想是小娘子，你恕罪咱。", "（正旦云）可早是我哩，是夫人呵，可怎生了也。", "（唱）若是俺夫人撞见如何讲？（白敏中云）是小生病得这般昏了也。", "（正旦唱）便道是害的你神魂荡漾，你也将眼皮开放。", "你常好是热蟒也东阳。"]'),
('yuanqu-9313','亻刍梅香骗翰林风月・鬼三台','郑光祖','元','元曲','yuanqu','','[]','呸！这的是赴约的风流况，须不是乐道的颜回巷。',276,'元曲/yuanqu.json','["呸！这的是赴约的风流况，须不是乐道的颜回巷。", "（白敏中云）\"子钓而不纲，弋不射宿\"。", "（正旦唱）哎！那里也歪谈乱讲。", "（白敏中云）小生敢去么？（正旦云）先生，我问你咱。", "（白敏中云）问小生些甚么？（正旦唱）你因甚么病在膏肓？（白敏中云）小生则为小姐来。", "（正旦云）你既为小姐呵，你过去波。", "（白敏中云）是好月色也。", "（正旦唱）百忙里卖弄甚么风清月朗。", "（白敏中云）我向小姐跟前去，怎么百般的那不动脚步也？（正旦唱）当初那不能彀时害的来狂上狂，不甫能得相见唬的来慌上慌。", "（白敏中云）见了小姐，不由的我心头忒忒的怕将起来。", "（正旦唱）见他时胆战心惊，把似你无人处休眠想梦想。"]'),
('yuanqu-9314','亻刍梅香骗翰林风月・金蕉叶','郑光祖','元','元曲','yuanqu','','[]','这的是桃源洞花开艳阳，须不比袄庙火烟飞浩荡。',75,'元曲/yuanqu.json','["这的是桃源洞花开艳阳，须不比袄庙火烟飞浩荡。", "(正旦推白云)（旦儿叫云）是甚么人？（白慌科，云）是小生。", "（正旦唱）阳台上云雨渺芒，可做了蓝桥水洪波泛涨。"]'),
('yuanqu-9315','亻刍梅香骗翰林风月・调笑令','郑光祖','元','元曲','yuanqu','','[]','劈面的便抢，和俺那病襄王。',104,'元曲/yuanqu.json','["劈面的便抢，和俺那病襄王。", "呀！怎生来翻悔了巫山窈窕娘，满口儿之乎者也无拦当，用不着恭俭温良。", "唬的那有情人恨无个地缝儿藏。", "（带云）毛，毛，羞么？（唱）羞杀我也傅粉何郎。", "（白敏中云）百忙中你也花白我。", "（正旦唱）。"]'),
('yuanqu-9316','亻刍梅香骗翰林风月・秃厮儿','郑光祖','元','元曲','yuanqu','','[]','请学士休心劳意攘，俺小姐则是作耍难当。',114,'元曲/yuanqu.json','["请学士休心劳意攘，俺小姐则是作耍难当。", "（旦儿和打正旦科，云）谁着你这早晚引将他来！（正旦云）小姐休闪了手。", "（笑科，唱）这的是我传书寄简请受的赏。", "谁承望，向咱行，倒有风霜。", "（旦儿怒科，云）这一场都是樊素辱败户的小贱人！（正旦唱）。"]'),
('yuanqu-9317','亻刍梅香骗翰林风月・圣药王','郑光祖','元','元曲','yuanqu','','[]','他道是这一场，这一桩，都是这辱门败户小婆娘。',185,'元曲/yuanqu.json','["他道是这一场，这一桩，都是这辱门败户小婆娘。", "（旦儿云）我告夫人去也。", "（正冷笑科，唱）杀人要见伤，拿贼呵要见赃。", "（白怕跪科，云）望小姐怜小生咱。", "（正旦唱）请起来波多愁多病俏才郎。", "（出香囊科）（劳云）打睃。", "（唱）这是谁与他的紫香囊。", "（旦儿云）好姐姐，我斗你耍哩。", "（正旦云）我却疼哩！（白起身科，云）则被你唬杀我也。", "(旦儿云）有人来也！（夫人撞上，咳咳，众做慌科）（正旦唱）。"]'),
('yuanqu-9318','亻刍梅香骗翰林风月・麻郎儿','郑光祖','元','元曲','yuanqu','','[]','这声音九分儿是你的令堂，（夫人云）这一定是樊素小贱人！（正旦唱）呀！头一句先抓揽着梅香。',119,'元曲/yuanqu.json','["这声音九分儿是你的令堂，（夫人云）这一定是樊素小贱人！（正旦唱）呀！头一句先抓揽着梅香。", "（旦儿慌科，云）是谁？（正旦云）小姐，悄悄的，是老夫人来了。", "（旦儿云）樊素，直被你引的老夫人来，可怎了也？（正旦唱）您吵闹起花烛洞房，自支吾待月西厢。"]'),
('yuanqu-9319','亻刍梅香骗翰林风月・幺篇','郑光祖','元','元曲','yuanqu','','[]','哎！不妨。',672,'元曲/yuanqu.json','["哎！不妨。", "（白敏中云）小娘子可怎了也？（怎旦指白科，唱）莫慌。", "（指自科唱）我当。", "（夫人云）先唤过樊素那小贱人来！(白敏中向旦云)小姐，望你遮着俺咱。", "（正旦云）你受责啊，理之当然。", "我可图些甚么来！（旦儿云）罢么，好姐姐，你先过去，你自回的好着么？（正旦云）由他，你两个只在这里，我过去见夫人，若说得过呵，你休欢喜，说不过呵，你休烦恼。", "（见夫人科）（夫人云）小贱人跪者（正旦跪科）（夫人云）小贱人，你知罪么？（正旦云）我不知罪。", "（夫人打科，云）这小贱人！你还说不知。", "你做的好勾当哩！（正旦唱）亲生女非比他行，家丑事不可外扬。", "（夫人云）谁着你引着小姐，往后花园中，看白敏中去来？你若实说呵，我便饶了你，你若不实说呵，我打死你这小贱人！（正旦云）谁见来？（夫人打科，云）我亲自撞见，你还强嘴！（正旦云）老夫人休打闪了手。", "此非妾之罪，皆夫人之过也。", "（唱）你索取一个治家不严的招状。", "（夫人云）这小贱人，连我也指攀着。", "（正旦云）请夫人息雷霆之怒，容贱妾陈是非之由：当日先相国临终遗言道：\"夫人将小姐纳白敏中为婿，为报参军救死之恩，如违我之遗言，我死不瞑目。", "\"言犹在耳。", "白敏中到来，不审夫人何意，却令小姐以兄妹之礼相见。", "既然如此，只何将敏中送于别馆安下，厚赆他还乡，以绝其望。", "却留在后花园中万卷堂上居住。", "使佳人才子，临风对月，心非木石，岂无所思？妾身之罪，固不可逃，无人之愆，亦不可免也。", "（夫人云）我却有甚罪？（正旦云）夫人有四罪。", "（夫人云）我有那四罟？（正旦云）不从相国遗言，罪之一也。", "不能治家，罪之二也。", "不能报白氏之恩，罪之三也。", "不能蔽骨肉之丑，罪之四也。"]'),
('yuanqu-9320','亻刍梅香骗翰林风月・雪里梅','郑光祖','元','元曲','yuanqu','','[]','你好状脸也画眉郎。',119,'元曲/yuanqu.json','["你好状脸也画眉郎。", "（白敏中云）都着你的道儿。", "（正旦唱）并曾千多口小红娘。", "（白敏中云）我这里不敢再住，须索上朝应举去也，你叫小姐见我一面儿去也好。", "（正旦唱）俺姐姐道足下不须悒怏，好事也从来魔障。", "（带云）俺小姐也道来。", "（唱）只教你把心儿放长。"]'),
('yuanqu-9321','亻刍梅香骗翰林风月・青山口','郑光祖','元','元曲','yuanqu','','[]','哎！不妨不妨，你走将来效鸾凤，女孩儿须是慌。',186,'元曲/yuanqu.json','["哎！不妨不妨，你走将来效鸾凤，女孩儿须是慌。", "（白敏中云）这都是小生命薄，偏生逢着夫人走将来的快也。", "（正旦唱）左想右相全不想，可可的老夫人偏撞上，你便有口呵怎可对当。", "好羞惭做这场，教你收拾书箱，打迭行装，便赴科场，献策君皇，两袖天香，一部笙簧。", "宴罢琼林出建章，车盖轩昂，祗候成行。", "乡也么乡却还乡，堂也么堂拜高堂。", "子母商量，旧难忘，锦屏前花独辉煌，那时节也替我撮合山妆一个谎。"]'),
('yuanqu-9322','亻刍梅香骗翰林风月・收尾','郑光祖','元','元曲','yuanqu','','[]','俺小姐情坚如碧玉簪，心赤如黄金凤，意你不别你个白衣相。',173,'元曲/yuanqu.json','["俺小姐情坚如碧玉簪，心赤如黄金凤，意你不别你个白衣相。", "（白敏中云）小姐还有甚么分付小生来？（正旦云）呀！争些儿反来忘了。", "（唱）两件事教先生行拜上，（白敏中云）那两件事那？（正旦云）小姐道，你若是凤墀得志，雁塔题名，可早来呵！（唱）做俺这有情的相国状元郎。", "（白敏中云）那一件却是甚么？（正旦云）则不要叫人骂你。", "（唱）骂你做薄幸的长安少年党。", "（下）。"]'),
('yuanqu-9323','亻刍梅香骗翰林风月・双调/新水令','郑光祖','元','元曲','yuanqu','','[]','今日个洞房中敕赐与栋梁材。',588,'元曲/yuanqu.json','["今日个洞房中敕赐与栋梁材。", "（云）小姐，我可是敢问你么，（唱）则你那寄香囊故人安在？（旦儿云）说这状元好才学哩。", "（正旦唱）都因他七步才及第了。", "（旦儿云）说那人有些亻刍亻刍。", "（正旦唱）带得那一块刍过门来。", "他承恩在玉殿金阶，更堪那兰省乌台。", "似这般相貌胎孩。", "（带云）他今日到咱门呵。", "（唱）休想肯拜俺先代。", "（山人云）兀那媒婆，你说去，时辰到了，豫备香花果品，纸烛千张，坛斗弓箭，五谷寸草，这早晚亲状元敢待来也。", "（白敏中冠带引祗候上，诗云）宫锦官花跃紫骝，夸官三日凤城游。", "不知结彩楼中女，若个争先掷绣球。", "小官白敏中，谁想有今日也。", "我自到贡院中，撺过卷子，金銮殿上，圣人亲试，日不移影，应对百篇，圣人言曰：\"前朝李翰林，不过如此。", "\"将小生一举状元及第，一日加某十三级，官至翰林大学士。", "今奉圣人的命，教我去裴相国家门下为婿。", "虽然如此，想当日被老夫人那场羞辱，有何面目见之？我待不去来，奈圣人的命，不敢有违。", "我如今在使机关，到他家里，则推素不相识，看他认的我么？（行科，山人唱科，诗云）锦城一步一花开，专请新人下马来。", "今日鸾凰城配偶，美满夫妻百岁谐。", "（白将牙笏遮面，与旦并坐科，山人云）将五谷寸草来。", "（官媒云）你正是精驴，休要胡说！（白敏中云）山人去罢。", "（山人下）（正旦云）我待不言语来，他道俺不理会的，我着这秀才，吃我几句儿咱。", "小姐，梅香寻思来，咱人只要得志，便好了也，若是不得志呵，（唱）。"]'),
('yuanqu-9324','亻刍梅香骗翰林风月・乔牌儿','郑光祖','元','元曲','yuanqu','','[]','哎你可甚么酒量宽似海。',79,'元曲/yuanqu.json','["哎你可甚么酒量宽似海。", "（云）（男子生而愿为这有室，女子生而愿为之有家。", "）他说一生不待见妇人之面。", "（唱）岂不闻无后最为大。", "着何时重解香罗带？\"吾未见好德如好色。"]'),
('yuanqu-9325','亻刍梅香骗翰林风月・豆叶黄','郑光祖','元','元曲','yuanqu','','[]','他看书呵秉烛在寒斋，几曾画眉呵走马到章台。',227,'元曲/yuanqu.json','["他看书呵秉烛在寒斋，几曾画眉呵走马到章台。", "（白敏中云）若不是圣人教我来呵，休道是个妮子，你便是玉天仙谁爱他。", "（正旦云）他道非圣人敕命呵，（唱）便做道玉天仙也不爱。", "（白敏中云）男子大丈夫，以功名为念，要这媳妇做甚么！（正旦云）小姐呵，（唱）今夜比宋弘十分事不谐。", "天地有混沌初开，日月有昏昼推排，男女有妇夫和谐。", "他待将大道沈埋，正义全乖，那些儿配合三才？便做有位列三台，也须要燮理阴阳，调和鼎鼐。", "（云）这状元把牙笏半遮其面，未知他生的如何，我试看咱。", "（唱）。"]'),
('yuanqu-9326','亻刍梅香骗翰林风月・滴滴金','郑光祖','元','元曲','yuanqu','','[]','据他这般轩昂，决然生的清奇。',14,'元曲/yuanqu.json','["据他这般轩昂，决然生的清奇。"]'),
('yuanqu-9327','亻刍梅香骗翰林风月・折桂令','郑光祖','元','元曲','yuanqu','','[]','今夜个"有朋自远方来"。',244,'元曲/yuanqu.json','["今夜个\"有朋自远方来\"。", "(旦儿云)是那个亲眷？（正旦唱）你今日对上菱花，配上金钗。", "（旦儿云）你说波，是谁？（正旦唱）当日个赶的你羞脸儿离门，如今个气昂昂日转千阶。", "从今后秦弄玉休登凤台，早则是汉刘郎误入天台。", "（旦儿云）敢不是么？（正旦唱）不索疑猜，我认的明白，不少欠你无万数相忆相思，他步蟾宫将桂枝折得回来。", "（旦儿云）您且慢些欢喜，休认错了。", "（白敏中云）兀那小妈才，你说谁哩！我待不言语来，忍不的你这般胡说乱道。", "你则道我不认的你，你瓣前来，我试问你咱。", "（正旦云）小姐，我道你休说波。", "（唱）。"]'),
('yuanqu-9328','亻刍梅香骗翰林风月・雁儿落','郑光祖','元','元曲','yuanqu','','[]','呀！恼了这春风门下客。',145,'元曲/yuanqu.json','["呀！恼了这春风门下客。", "（白敏中云）你道我不敢打你么？（正旦云）你便是新状元呵。", "也则是俺家新女婿，怎生要打我那？（唱）则是我少欠你那脓血债。", "（白敏中云）你则管胡言乱道，端的是说谁？（正旦唱）据梅香胡口开。", "（白敏中云）我既是你家女婿，也是你的侍长，我怎生不敢打你？（正旦唱）告学士高抬手权耽待。"]'),
('yuanqu-9329','亻刍梅香骗翰林风月・得胜令','郑光祖','元','元曲','yuanqu','','[]','这壁厢是没上下的小奴胎。',251,'元曲/yuanqu.json','["这壁厢是没上下的小奴胎。", "（白敏中云）那壁厢莫不是小姐么？（正旦唱）那壁厢是抢白你的女裙钗。", "（白敏中云）那一夜小姐则被他抢白杀小生也！（正旦唱）那的是俺小姐契贞烈。", "（白敏中云）都是老夫人阻了佳期也，（正旦唱）是俺那老夫人使的计策，把好事冲开，教你挣坐一个金鱼袋。", "（白敏中云）樊素，今日有圣人的命，可将我赶出么？（正旦唱）虽然是御笔亲差，你可也索安排着玉镜台。", "（白敏中云）请岳母拜见咱。", "（夫人上云）我道是谁来，原来却是白敏中。", "（见科）（白敏中云）请岳母稳坐，将酒来，我与岳母把杯呵。", "（正旦云）住者！（唱）。"]'),
('yuanqu-9330','亻刍梅香骗翰林风月・沽美酒','郑光祖','元','元曲','yuanqu','','[]','汉相如志已谐，卓文君笑盈腮，(旦儿云）今日樊素也欢喜了也。',60,'元曲/yuanqu.json','["汉相如志已谐，卓文君笑盈腮，(旦儿云）今日樊素也欢喜了也。", "（正旦唱）这的是一段姻缘天上来。", "现如今名扬四海，正淑女配多才。"]'),
('yuanqu-9331','亻刍梅香骗翰林风月・太平令','郑光祖','元','元曲','yuanqu','','[]','俺小姐这一个有千般娇态，新状元有万种襟怀。',300,'元曲/yuanqu.json','["俺小姐这一个有千般娇态，新状元有万种襟怀。", "荷皇恩荣升宠赍，成配偶不胜感戴。", "端的个美哉，壮哉，这都是圣裁。", "（院公上云）喏！报的夫人、状元知道，有天朝使命到了。", "（白敏中云）快排香案，接待天使。", "（正旦唱）愿万万载民安国泰。", "（李尚书上，云）小官李绛，奉圣人的命，到晋国公宅上，成合这门亲事。", "加官赐赏，走一遭去。", "可早来到也。", "白敏中，你一家儿望阙跪着，听圣人的命：只为你父参军，曾救裴晋公之难，许小蛮为妻，以报大恩，今日敏中登科及第，成就此亲，官封三代，裴夫人赐金千两。", "你听者：（词云）晋国公开勋臣，遗玉带许结婚姻。", "白敏中果登云路，奉圣命匹配成亲。", "赐小蛮凤冠霞帔，赐夫人万两金银。", "今日个加官赐赏，一家门共戴天恩。"]'),
('yuanqu-9332','谢金吾诈拆清风府・仙吕/赏花时','无名氏','元','元曲','yuanqu','','[]','我可甚的要拆倒清风无佞楼？也只为咱与杨家话不投。',162,'元曲/yuanqu.json','["我可甚的要拆倒清风无佞楼？也只为咱与杨家话不投。", "(云)我料得杨景那厮，闻知拆倒了他家门楼，必然赶回家来，与我诘奏其事。", "那时节我预先差人拿住他，奏过圣人，责他擅离信地，私下三关之罪。", "(唱)但赚的离雄州，便好将他斩首，(云)此事只好我和你知，休要泄漏者。", "(谢金吾云)我好不乖哩，要你分付，(王枢密唱)这的是六耳不通谋。", "(同下)。"]'),
('yuanqu-9333','谢金吾诈拆清风府・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','则俺这百尺楼台，是祖先留在。',39,'元曲/yuanqu.json','["则俺这百尺楼台，是祖先留在。", "功劳大，更打着个郡马的名色。", "那厮也怎敢便来胡拆？。"]'),
('yuanqu-9334','谢金吾诈拆清风府・混江龙','无名氏','元','元曲','yuanqu','','[]','这楼呵起初修盖，也不知费他府藏偌多财。',262,'元曲/yuanqu.json','["这楼呵起初修盖，也不知费他府藏偌多财。", "上面有御书的玉札，钦赐的金牌。", "莫说朝省里官员皆下马，便是春秋天子也要降香来。", "(院公云)这早晚敢动手哩，老夫人行动些儿。", "(正旦唱)只听的闹垓垓，越急的我气口怡口怡，脚忙抬，步难捱，半合儿行不出宅门外。", "我这里挡不住夫役，奔不的尘埃。", "(谢金吾云)老夫人，你来做甚么？(正旦云)我这清风无佞楼，是奉圣旨盖的，你怎敢拆毁俺这楼来？(谢金吾云)老夫人，你差矣。", "当初是圣人命替你家盖，如今我也奉圣旨替你家拆。", "是碍了我走路，我要拆来。", "失役每，先把那门楼上的砖瓦乱摔下来。", "(正旦云)这厮好无礼也。", "(唱)。"]'),
('yuanqu-9335','谢金吾诈拆清风府・油葫芦','无名氏','元','元曲','yuanqu','','[]','我只见他带瓦和砖拥下来，(谢金吾云)夫役每，将这椽木都屈拆了，等我拿家去做柴烧，管他怎的。',298,'元曲/yuanqu.json','["我只见他带瓦和砖拥下来，(谢金吾云)夫役每，将这椽木都屈拆了，等我拿家去做柴烧，管他怎的。", "(正旦唱)他、他、他，将椽木拆做柴！(谢金吾云)上紧的拆。", "(正旦唱)他、他、他，催迸的来不放片时刻，则他这满城人那一个不添惊怪，偏我这一家儿直恁的遭残害。", "(谢金吾云)老夫人，上命差遣，盖不由己。", "我直从朝门外拆起，多少王侯宰相家，连片拆了，单单拆的你这一家儿也？(正旦唱)我这里急问他，他那里硬挣□。", "向前去手扌昝住腰间带，(谢金吾云)老夫人，你好没意思。", "我是奉圣人的命，你揪住我待要怎的？(正旦唱)你敢是没圣旨擅差排！(谢金吾云)老夫人，谁敢说慌，现有圣旨哩。", "(正末云)有圣旨在那里？我与你面圣去来。", "(唱)。"]'),
('yuanqu-9336','谢金吾诈拆清风府・天下乐','无名氏','元','元曲','yuanqu','','[]','咱两个厮扭定向君王前奏去来，(谢金吾云)我和你去不妨事。',129,'元曲/yuanqu.json','["咱两个厮扭定向君王前奏去来，(谢金吾云)我和你去不妨事。", "夫役每，不要管他，则管拆着。", "(正旦唱)则你个乔也波才，自恁歹，俺虽是随朝的武官十数载。", "(谢金吾云)只因你这楼正占着官街，方才拆了你的。", "(正旦唱)这门楼谁不曾过去？这门楼谁不曾到来？偏你这谢金吾嫌道窄！。"]'),
('yuanqu-9337','谢金吾诈拆清风府・那吒令','无名氏','元','元曲','yuanqu','','[]',')这都是王枢密，王枢密的计策；故意教谢金吾，谢金吾来拆坏；强把着宋真宗，宋真宗来顶戴。',67,'元曲/yuanqu.json','[")这都是王枢密，王枢密的计策；故意教谢金吾，谢金吾来拆坏；强把着宋真宗，宋真宗来顶戴。", "上不怕天理该，下不怕人情骇，你也启奏的忒不明白。"]'),
('yuanqu-9338','谢金吾诈拆清风府・鹊踏枝','无名氏','元','元曲','yuanqu','','[]','割舍了我个老裙钗，博着你个泼驽骀。',49,'元曲/yuanqu.json','["割舍了我个老裙钗，博着你个泼驽骀。", "遮莫待挝怨鼓撅皇城，死撞金阶。", "觑了他拆的来分外，不由我感叹伤怀。"]'),
('yuanqu-9339','谢金吾诈拆清风府・寄生草','无名氏','元','元曲','yuanqu','','[]','咱和你又无甚别仇隙，怎这般狠布摆？领着火顽皮贼骨浑无赖，也不问个朱楼画壁谁家界？霎时间早雕栏玉砌都安在。',74,'元曲/yuanqu.json','["咱和你又无甚别仇隙，怎这般狠布摆？领着火顽皮贼骨浑无赖，也不问个朱楼画壁谁家界？霎时间早雕栏玉砌都安在。", "似你这不忠不信害人贼，那里也有仁有义朝中客。"]'),
('yuanqu-9340','谢金吾诈拆清风府・村里迓鼓','无名氏','元','元曲','yuanqu','','[]','那厮道朝中臣宰，则俺杨家也不是民间宗派。',216,'元曲/yuanqu.json','["那厮道朝中臣宰，则俺杨家也不是民间宗派。", "(谢金吾云)你还不认的我哩，我是王枢密的女婿，那里看的你个白头叠雪的在眼儿里。", "(正旦唱)元来你倚着丈人行的气概，就待欺负咱年华高迈。", "(金吾云)你这个老人家，好不知高低，我尽让你说几句便罢，则管里倚老卖老，口里唠唠叨叨的说个不了。", "你便就长出些个胡子来，我也不理你。", "你去！(谢金吾推，正旦倒科)(正旦唱)不堤防被他来这一摔，错闪了腰肢，擦伤了膝盖，争些儿磕破了摘袋，哎，你也可怜俺个白头的这奶奶。"]'),
('yuanqu-9341','谢金吾诈拆清风府・青哥儿','无名氏','元','元曲','yuanqu','','[]','那厮拆坏了咱家、咱家第宅，倒把着大言、大言图赖。',87,'元曲/yuanqu.json','["那厮拆坏了咱家、咱家第宅，倒把着大言、大言图赖。", "教我便有口浑身也怎劈划？哎，谁想我到这年衰，值着凶灾。", "被他推倒当街，跌损形骸。", "直从鬼门关上孩儿每喳喳的叫回来，他也忒欺人煞！。"]'),
('yuanqu-9342','谢金吾诈拆清风府・赚煞','无名氏','元','元曲','yuanqu','','[]','若不除得那昧心贼，依旧把俺那门楼盖，则除非把俺杨家姓改！他则待赚俺孩儿寻罪责，则今朝将你个都管亲差。',104,'元曲/yuanqu.json','["若不除得那昧心贼，依旧把俺那门楼盖，则除非把俺杨家姓改！他则待赚俺孩儿寻罪责，则今朝将你个都管亲差。", "这书上已明开，休的胡猜，就儿里关连着大利害。", "虽则是被那厮抢白，嘱付孩儿宁奈，休得要误军机私下禁关来。", "(下)。"]'),
('yuanqu-9343','谢金吾诈拆清风府・南吕/一枝花','无名氏','元','元曲','yuanqu','','[]','这两日气的我闷闷的眠，害得我恹恹的卧。',73,'元曲/yuanqu.json','["这两日气的我闷闷的眠，害得我恹恹的卧。", "把功臣生割舍，纵贼子放乖泼。", "天理如何！着细作都瞒过，圣人前宠用他。", "现放着中书省鼎鼐调和，枢密院将边关事领掇。"]'),
('yuanqu-9344','谢金吾诈拆清风府・梁州第七','无名氏','元','元曲','yuanqu','','[]','都是这两赖子调度的军马，你可甚么一管笔判断山河！痛煞煞这几日难挨过。',167,'元曲/yuanqu.json','["都是这两赖子调度的军马，你可甚么一管笔判断山河！痛煞煞这几日难挨过。", "不听的做夜市的炒闹，争地铺的搀夺。", "经商客旅，买卖无多。", "往常时这清风楼前后屯合，到今日冷清清只一片空阔。", "不见了祥云罩碧瓦丹甍，不见了晓日映珠帘绣幕，不见了香雾锁画戟雕戈。", "那厮敢胡为，乱做。", "把先皇圣旨不怕些儿个，平白地闯出这场祸。", "送的我倒枕着床没奈何，拆的来做不得存活。"]'),
('yuanqu-9345','谢金吾诈拆清风府・骂玉郎','无名氏','元','元曲','yuanqu','','[]','我则见阶直下气倒忙扶坐，我这里慌搂定紧收撮。',48,'元曲/yuanqu.json','["我则见阶直下气倒忙扶坐，我这里慌搂定紧收撮。", "则听的喝喽喽口内潮涎唾，我与你摇臂膊，揪耳朵高声和。"]'),
('yuanqu-9346','谢金吾诈拆清风府・感皇恩','无名氏','元','元曲','yuanqu','','[]','呀，叫一声杨景哥哥，直恁的叫不回他。',72,'元曲/yuanqu.json','["呀，叫一声杨景哥哥，直恁的叫不回他。", "我这里掐人中，七娘子揪头发，一家儿闹喧聒。", "不争你沉沉不醒，撇下了即世的婆婆。", "却教俺怎支持，怎发付，怎结末！。"]'),
('yuanqu-9347','谢金吾诈拆清风府・采茶歌','无名氏','元','元曲','yuanqu','','[]','怕不的平地起干戈，直赶上马嵬坡，(带云)倘若有些好歹呵，(唱)你可便着谁人搭救宋山河。',195,'元曲/yuanqu.json','["怕不的平地起干戈，直赶上马嵬坡，(带云)倘若有些好歹呵，(唱)你可便着谁人搭救宋山河。", "世不曾来家愁杀我，你也心儿里精细不风魔。", "(六郎醒科，云)这父母之仇，几时得报？活活的气杀孩儿也。", "(正旦云)孩儿，我一家儿只靠的你。", "可便回三关去，不要在这里惹出祸来。", "(六郎云)奉母亲的命，孩儿不敢有违，只今晚便回三关去也。", "若再有甚么紧急事，着八娘子稍书来，报您孩儿知道。", "(正旦云)孩儿，我且问你咱，(唱)。"]'),
('yuanqu-9348','谢金吾诈拆清风府・哭皇天','无名氏','元','元曲','yuanqu','','[]','那军情事非轻可，不知你曾引的人来也独自个？(六郎云)母亲，您孩儿同焦赞兄弟来也。',167,'元曲/yuanqu.json','["那军情事非轻可，不知你曾引的人来也独自个？(六郎云)母亲，您孩儿同焦赞兄弟来也。", "(正旦云)焦赞孩儿在那里？着孩儿家里来波。", "(六郎云)入城来不见了也。", "(正旦唱)你道他入城时不见了，因甚的不寻地？他从来有些儿、有些儿撒泼。", "他若是见说拆毁咱楼阁，他若是见说跌损咱肩窝。", "怕不就掇起他不腾腾那杀人心、杀人心如烈火，怎还顾别人的利害，自己的死活。"]'),
('yuanqu-9349','谢金吾诈拆清风府・乌夜啼','无名氏','元','元曲','yuanqu','','[]','哎，还说甚恶人自有恶人磨，这都是你自惹的风波。',248,'元曲/yuanqu.json','["哎，还说甚恶人自有恶人磨，这都是你自惹的风波。", "那贼也正掌着威权大，但有搀搓，谁与兜罗？(带云)孩儿，你也不要顾他了，你只便回三关上去，免堕贼臣之手。", "(六郎云)母亲，您孩儿便去。", "(做别科)(正旦云)孩儿，你且坐着，听上衙更鼓，这早晚几更了？(六郎云)是二更过了。", "(正旦唱)听漏沉沉才勾二更过，意悬悬盼不到来日个。", "你且暂歇波，权时坐，一来是鞍马上困倦，二来是腹内烦渴。", "(云)早鸡鸣了也。", "孩儿，你不可久停久住，便索赶早出城，回三关去。", "小心在意者。", "(六郎云)母亲好将息，您孩儿辞了母亲便去也。", "(正旦唱)。"]'),
('yuanqu-9350','谢金吾诈拆清风府・尾声','无名氏','元','元曲','yuanqu','','[]','只等的鸡鸣便去休担阁，儿也，你若得飞出城门便是你一命脱，我少不的到圣人前自言破。',81,'元曲/yuanqu.json','["只等的鸡鸣便去休担阁，儿也，你若得飞出城门便是你一命脱，我少不的到圣人前自言破。", "怕只怕王枢密的刻薄，百般的将你个杨六郎摧挫，儿也，你只自奔你的前程顾甚我。", "(下)。"]'),
('yuanqu-9351','谢金吾诈拆清风府・越调/斗鹌鹑','无名氏','元','元曲','yuanqu','','[]','我看那赴法的孩儿，则待搭救俺女婿。',73,'元曲/yuanqu.json','["我看那赴法的孩儿，则待搭救俺女婿。", "今日个郡马当刑，畅好是君皇下的。", "臣宰每不劝谏留人，直等到午时三刻，听的那一声叫下手只。", "可不道一将难求，千军易得。"]'),
('yuanqu-9352','谢金吾诈拆清风府・紫花儿序','无名氏','元','元曲','yuanqu','','[]','唬的我急煎煎心如刀搅，痛杀杀腹若锥剜，扑簌簌泪似扒推。',347,'元曲/yuanqu.json','["唬的我急煎煎心如刀搅，痛杀杀腹若锥剜，扑簌簌泪似扒推。", "(王枢密云)刀斧手且住者，不知是那个皇亲国戚来了也。", "等他过去了，才好杀人那。", "(正旦做见，王枢密云)我道是谁，原来是杨六郎丈母长国姑。", "我若是尊敬他，必然要我留人，再奏天子，可不那杨六郎一定饶了？我则把法度利害与他说，怕做甚么！我是东厅枢密使，他又不敢惹我。", "(做施礼科，云)国姑到此有甚么事？(正旦云)我无事也不来。", "(唱)送长休饭着俺这女婿再休思想，永别酒和俺这女婿从此分离，(王枢密云)这的是圣旨哩。", "(正旦唱)谁敢把皇旨轻违。", "(王枢密云)国姑，良吏不管月局，贵人不踏险地。", "这个所在，便不来也罢。", "(正旦唱)这杀场上不关亲因何来到这里？(王枢密云)是、是、是，是杀场上，国姑且请回咱。", "(正旦唱)他两三番把咱支对，你怎么信口胡喷，抢白的我脸上无皮。"]'),
('yuanqu-9353','谢金吾诈拆清风府・金蕉叶','无名氏','元','元曲','yuanqu','','[]','则这满京城百姓每尽知，你与俺大宋朝出甚么气力？提起他父子每端的痛悲，一辈辈于家为国。',42,'元曲/yuanqu.json','["则这满京城百姓每尽知，你与俺大宋朝出甚么气力？提起他父子每端的痛悲，一辈辈于家为国。"]'),
('yuanqu-9354','谢金吾诈拆清风府・寨儿令','无名氏','元','元曲','yuanqu','','[]','他、他、他，也则为俺赵社稷，甘心儿撞倒在李陵碑，便死也不将他名节毁。',99,'元曲/yuanqu.json','["他、他、他，也则为俺赵社稷，甘心儿撞倒在李陵碑，便死也不将他名节毁。", "他也曾斩将搴旗，耀武扬威，普天下那一个不识的他是杨无敌。", "(王枢密云)想他哥哥杨五郎，削发为僧，这等怕死，也是有功劳的？(正旦唱)。"]'),
('yuanqu-9355','谢金吾诈拆清风府・幺篇','无名氏','元','元曲','yuanqu','','[]','你道是杨和尚破天阵吃了些亏，却不道救铜台是靠着伊谁。',409,'元曲/yuanqu.json','["你道是杨和尚破天阵吃了些亏，却不道救铜台是靠着伊谁。", "他兄弟在沙场上苦战争，刀尖上博功绩。", "怎、怎、怎着他云阳市，赴这个好筵席。", "(王枢密云)事做到这里，怕他怎么？我是东厅枢密使，他也不敢惹我。", "国姑，据杨景犯下的罪名，叫做一人造反，九族遭诛。", "国姑你倒要来救那罪人，敢是你女娘家不曾看王法哩。", "(正旦云)我这两个孩儿，当日有功，今日有罪，也合将功折罪。", "王枢密，你则是看我国姑面上。", "将两个孩儿饶过者。", "(王枢密云)这国姑好会做大也。", "我要杀的人，只说看国姑的面皮，我的面皮可着狗吃了？(正旦云)你骂谁哩，你饶便饶，不饶便罢，你怎生骂我？(王枢密云)我歹杀波是东厅枢密使。", "(正旦云)你便做着东厅枢密使来，想你当初不得志时，提着个灰罐儿，卖诗写状，那早晚也是东厅枢密使来？(王枢密云)这个国姑，越饶着越逞，道我不得志时，提着个灰罐儿，卖诗写状。", "你家父祖，当初不得志时，游关西五路，也曾挺着脖子，拽伞车儿来。", "(正旦云)这厮好无礼也。", "(唱)。"]'),
('yuanqu-9356','谢金吾诈拆清风府・鬼三台','无名氏','元','元曲','yuanqu','','[]','百姓每都听得，王枢密这奸贼，敢和咱斗嘴。',102,'元曲/yuanqu.json','["百姓每都听得，王枢密这奸贼，敢和咱斗嘴。", "直恁般无上下失尊卑，我如今问你，问你个骂皇亲的罪过该甚的？(王枢密云)我骂了一个老婆子，有甚的罪过？(正旦唱)可是你掌朝纲的王法也不识。", "常言道莫说他人，先输了自己。"]'),
('yuanqu-9357','谢金吾诈拆清风府・调笑令','无名氏','元','元曲','yuanqu','','[]','你道是，枢密骂不的，是我骂你这改姓更名漏面贼。',123,'元曲/yuanqu.json','["你道是，枢密骂不的，是我骂你这改姓更名漏面贼。", "萧太后使你为奸细，几年间将帝主明欺，(带云)你道我不知道你哩。", "(唱)则那贺驴儿小名须是你。", "(王枢密云)那里是甚么贺驴儿？我是王钦若。", "(正旦云)噤声，那壁姓贺，这壁姓王。", "(唱)可不的山河易改，本姓难移。"]'),
('yuanqu-9358','谢金吾诈拆清风府・雪里梅','无名氏','元','元曲','yuanqu','','[]','剜眼睛便挑剔，剁手足自收拾。',50,'元曲/yuanqu.json','["剜眼睛便挑剔，剁手足自收拾。", "(云)俺府里的亲随那里？(唱)你与我扭开了长枷，将六郎扶起，唤左右快疾。"]'),
('yuanqu-9359','谢金吾诈拆清风府・秃厮儿','无名氏','元','元曲','yuanqu','','[]','不恁的如何救你，不打死不算忠直，我今番下手也则是迟。',41,'元曲/yuanqu.json','["不恁的如何救你，不打死不算忠直，我今番下手也则是迟。", "我和你厮扯定，入宫闱去见官里。"]'),
('yuanqu-9360','谢金吾诈拆清风府・圣药王','无名氏','元','元曲','yuanqu','','[]','遮莫你有势力，有职位，到底是我天朝部下泼奴婢。',209,'元曲/yuanqu.json','["遮莫你有势力，有职位，到底是我天朝部下泼奴婢。", "我可也不怕你，不惧你，我须是天潢支派没猜疑，来、来、来，我敢和你做头抵。", "(王枢密云)我那里认的你这国姑？你先皇潜龙时，贩油伞游关西五路，都不曾有偌多亲眷，今日这个也亲，那个也亲。", "你家姓柴，官里姓赵，胡姑姑假姨姨，可是甚么亲眷？(正旦云)兀那厮，你听着，我是太祖皇帝的妹妹，太宗皇帝的姐姐，真宗皇帝的姑姑，柴驸马的浑家，杜太后的闺女，柴世宗皇帝的媳妇，你偏不认的我！(唱)。"]'),
('yuanqu-9361','谢金吾诈拆清风府・麻郎儿','无名氏','元','元曲','yuanqu','','[]','俺柴家托孤让位，俺赵家受禅登甚。',32,'元曲/yuanqu.json','["俺柴家托孤让位，俺赵家受禅登甚。", "这都是一门亲戚，须不比重山认义。"]'),
('yuanqu-9362','谢金吾诈拆清风府・幺篇','无名氏','元','元曲','yuanqu','','[]','俺大哥开天立极，俺二哥继体垂衣。',38,'元曲/yuanqu.json','["俺大哥开天立极，俺二哥继体垂衣。", "今皇帝是俺嫡堂叔侄，先皇帝是俺同胞的那姊妹。"]'),
('yuanqu-9363','谢金吾诈拆清风府・庆元贞','无名氏','元','元曲','yuanqu','','[]','俺本是深宫内苑帝王姬，如今在琼楼朱邸做贵臣妻。',198,'元曲/yuanqu.json','["俺本是深宫内苑帝王姬，如今在琼楼朱邸做贵臣妻。", "家藏着丹书铁券有光辉，你这贼不知，那个知？怎将俺做的胡姑姑也假姨姨。", "(王枢密云)你为杨六郎，只管骂我。", "杨景私下三关，焦赞擅杀谢金吾一十七口，合该诛杀。", "你怎敢劫了法场，我结纽了你见圣人去来！(正旦云)兀那两街百姓都听者，他在这法场上，骂了我也罢。", "只到朝中，剥了他朝靴，看他脚底板上刺着两行朱砂字道：贺驴儿宁反南朝，不背北番。", "这难道是我妆诬他的？(唱)。"]'),
('yuanqu-9364','谢金吾诈拆清风府・收尾','无名氏','元','元曲','yuanqu','','[]','则他这贺驴儿小名怎许长瞒昧，现放着脚板上两行儿朱砂字迹。',55,'元曲/yuanqu.json','["则他这贺驴儿小名怎许长瞒昧，现放着脚板上两行儿朱砂字迹。", "到来日我一星星奏与君王，不到得轻轻的索放了你。", "(下)。"]'),
('yuanqu-9365','谢金吾诈拆清风府・双调/新水令','无名氏','元','元曲','yuanqu','','[]','我须是真宗皇帝老姑姑，这贼呵谁根前你来我去。',51,'元曲/yuanqu.json','["我须是真宗皇帝老姑姑，这贼呵谁根前你来我去。", "将皇亲厮毁谤，将大将厮亏图。", "我和你直叩青蒲，拣着那爱处做。"]'),
('yuanqu-9366','谢金吾诈拆清风府・甜水令','无名氏','元','元曲','yuanqu','','[]','只见那孩儿每闹闹嚷嚷，聒聒焦焦，簇捧着法场前去。',118,'元曲/yuanqu.json','["只见那孩儿每闹闹嚷嚷，聒聒焦焦，簇捧着法场前去。", "(殿头官云)这法场上，你也不该去么。", "(正旦云)我是他亲丈母，怎不要去送碗长休饭，递杯儿永别酒那？(唱)我须是割不断的紧亲属，因此上熬一片痛苦心肠，忍一点凄惶眼泪，陪一句哀求言语，做杀卑伏。"]'),
('yuanqu-9367','谢金吾诈拆清风府・乔牌儿','无名氏','元','元曲','yuanqu','','[]','便不合离边关到帝都，便不合将谢家十七口一时屠。',45,'元曲/yuanqu.json','["便不合离边关到帝都，便不合将谢家十七口一时屠。", "则俺个官家怎不看功劳簿，纵有那弥天罪也准赎。"]'),
('yuanqu-9368','谢金吾诈拆清风府・水仙子','无名氏','元','元曲','yuanqu','','[]','哎，他道俺劫法场擅放了御囚徒，又道俺恃皇亲毁诏书，又道俺殴大臣激的天颜怒。',120,'元曲/yuanqu.json','["哎，他道俺劫法场擅放了御囚徒，又道俺恃皇亲毁诏书，又道俺殴大臣激的天颜怒。", "(殿头官云)长国姑，你也枉做一场，那杨景、焦赞，到底饶不得这死罪哩。", "(正旦唱)要鸣冤何处所，可不的屈杀无辜。", "既然是饶不的那孩儿命，我也便何颜号国姑，拚纳下这雪白头颅。"]'),
('yuanqu-9369','谢金吾诈拆清风府・侧砖儿','无名氏','元','元曲','yuanqu','','[]','你道我平白地把得人，把得人来加凌辱，这公事眼看虚实定何如？撇起个瓦儿在半空里怎住？须不是我皇姑的厮赃诬。',52,'元曲/yuanqu.json','["你道我平白地把得人，把得人来加凌辱，这公事眼看虚实定何如？撇起个瓦儿在半空里怎住？须不是我皇姑的厮赃诬。"]'),
('yuanqu-9370','谢金吾诈拆清风府・竹枝歌','无名氏','元','元曲','yuanqu','','[]','你道他久在天朝不负初，你道我妄指他做番臣无证处，可怎生搜出那纸文书？反叛的是王枢密，细作是谢金吾。',283,'元曲/yuanqu.json','["你道他久在天朝不负初，你道我妄指他做番臣无证处，可怎生搜出那纸文书？反叛的是王枢密，细作是谢金吾。", "这两个无徒，今日里合天诛。", "(殿头官云)奉圣人的命，长国姑以下，都向阙跪者，听我下断。", "(词云)此桩事久屈无伸，到今日才得明分。", "谢金吾假传圣语，背地里嫉妒元勋。", "清风楼三朝敕建，拆毁做一片灰尘。", "更无端行凶逞势，跌损了佘太夫人。", "倚恃着东厅枢密，他本是叛国奸臣。", "通反书一时败露，枉十年金紫荣身。", "上木驴凌迟碎剐，显见的王法无亲。", "杨六郎合门忠孝，焦光赞侠气超群。", "皆是我天朝名将，加服色并赐麒麟。", "长国姑除邪去害，保忠良重镇关津。", "也论功增封食邑，共皇家万古长春。", "(众谢恩科)(正旦唱)。"]'),
('yuanqu-9371','谢金吾诈拆清风府・清江引','无名氏','元','元曲','yuanqu','','[]','谢得当今圣明主，不受奸臣误。',46,'元曲/yuanqu.json','["谢得当今圣明主，不受奸臣误。", "把清风楼重建一层来，着杨六郎元镇三关去，直把宋江山扶持到万万古。"]'),
('yuanqu-9372','昊天塔孟良盗骨・仙吕/点绛唇','朱凯','元','元曲','yuanqu','','[]','傀儡棚中，鼓笛声送，相搬弄。',68,'元曲/yuanqu.json','["傀儡棚中，鼓笛声送，相搬弄。", "想着那世事皆空，恰便似一枕南柯梦。", "(七郎云)只恨那潘仁美这个奸贼，逼的俺父子并丧番地，可怜人也。", "(正末唱)。"]'),
('yuanqu-9373','昊天塔孟良盗骨・混江龙','朱凯','元','元曲','yuanqu','','[]','盼不到先茔旧垅，黄泉下埋没杀俺这英雄。',135,'元曲/yuanqu.json','["盼不到先茔旧垅，黄泉下埋没杀俺这英雄。", "(七郎云)父亲，俺不能勾青史标名，留芳万古，空怀着一腔怨气，何时分解也？(正末唱)空锁着一腔怨气做不的万丈霓虹。", "本待要汉主台前把俺形容画，准知道李陵碑底早是命途穷。", "怎将那一座两狼山碜可可生扭做祁连冢，也枉了俺半生无敌，十大的这边功。"]'),
('yuanqu-9374','昊天塔孟良盗骨・油葫芦','朱凯','元','元曲','yuanqu','','[]','可便是困杀南山老大虫，枉自有爪和牙成甚么用？都做了一齐分付与东风！想着俺雕弓能劈千钧重，单枪不怕三军众。',90,'元曲/yuanqu.json','["可便是困杀南山老大虫，枉自有爪和牙成甚么用？都做了一齐分付与东风！想着俺雕弓能劈千钧重，单枪不怕三军众。", "也曾将蕃国攻，也曾将敌阵冲。", "一任他八方四面干戈动，那一个敢和俺出马共争锋？。"]'),
('yuanqu-9375','昊天塔孟良盗骨・天下乐','朱凯','元','元曲','yuanqu','','[]','哎！你说甚么胜败兵家本不穷，则这兵也波书，我可索是通。',115,'元曲/yuanqu.json','["哎！你说甚么胜败兵家本不穷，则这兵也波书，我可索是通。", "(带云)俺家姓杨，被番兵陷在虎口交牙峪里，这个叫做羊落虎口，正犯了兵家所忌，怎还有活的人也？(唱)奈贼臣把俺来着了羊投虎口嘶断送，方信道将在谋，不在勇，兀的不横亡了俺这姜太公。"]'),
('yuanqu-9376','昊天塔孟良盗骨・青哥儿','朱凯','元','元曲','yuanqu','','[]','哎他将我这尸骸恁般摩弄，因此上向儿行一星星悲控。',168,'元曲/yuanqu.json','["哎他将我这尸骸恁般摩弄，因此上向儿行一星星悲控。", "(杨景云)父亲，俺想韩延寿那里兵强马壮，只可智取，难以力夺。", "不知三关上二十四个指挥使，还是着那一个和孩儿同去，才得成功也？(正末唱)你若是有心呵可怜见我遍体金枪不耐风，也不须打凤捞龙，别选元戎。", "只在军中，火德天蓬，自有神通。", "觅迹寻踪，撒泼行凶，将俺那骨匣儿早拔出虎狼丛，这便当的你香花供。"]'),
('yuanqu-9377','昊天塔孟良盗骨・寄生草','朱凯','元','元曲','yuanqu','','[]','俺为甚么泪频挥，也只要您心暗懂。',73,'元曲/yuanqu.json','["俺为甚么泪频挥，也只要您心暗懂。", "早遣那嘉山太仆来争哄，把这宣花巨斧轻输动，免着俺昊天塔上长酸痛。", "您若是和番家忘了戴天仇，可不俺望乡台枉做下还家梦。"]'),
('yuanqu-9378','昊天塔孟良盗骨・赚煞尾','朱凯','元','元曲','yuanqu','','[]','儿也你回到圣明朝，备把我这冤情讼。',100,'元曲/yuanqu.json','["儿也你回到圣明朝，备把我这冤情讼。", "我也不望加官赐宠，只要个一体君臣有始终，早迎还俺那无佞清风。", "恨匆匆，睡眼朦胧，儿也说甚的犹恐相逢是梦中。", "嘱咐您个杨家业种，须念着子父每情重，休使俺幽魂愁杀这座梵王宫。"]'),
('yuanqu-9379','昊天塔孟良盗骨・中吕/粉蝶儿','朱凯','元','元曲','yuanqu','','[]','这些时无处征伐，我去那界河边恰才巡罢，我做的一个个活捉生拿。',60,'元曲/yuanqu.json','["这些时无处征伐，我去那界河边恰才巡罢，我做的一个个活捉生拿。", "涌彪躯，舒猿臂肝横胆乍。", "也不索将武艺盘咱，回头儿只看咱披挂。"]'),
('yuanqu-9380','昊天塔孟良盗骨・醉春风','朱凯','元','元曲','yuanqu','','[]','比及你架上掇雕鞍，槽头牵战马。',49,'元曲/yuanqu.json','["比及你架上掇雕鞍，槽头牵战马。", "宣花斧钺手中担，觑敌军似耍，耍。", "万骑交驰，两军相见，咱手里半筹不纳。"]'),
('yuanqu-9381','昊天塔孟良盗骨・斗鹌鹑','朱凯','元','元曲','yuanqu','','[]','哎，那厮须不是布雾的蚩尤，又不是飞天的夜叉。',792,'元曲/yuanqu.json','["哎，那厮须不是布雾的蚩尤，又不是飞天的夜叉。", "(杨景云)那厮见你手段高强，被他藏了躲了呢？(正末唱)那厮便藏在云中，躲在、躲在地下，我也翻过乾坤若见他。", "说那厮能变化，我呵喝一喝骨碌碌的海沸山崩，瞅一瞅赤力力的天摧地塌。", "(杨景云)孟良，你猜了半日，只是猜不着。", "你回避。", "(正末云)既是猜不着，我且回避。", "(正末出门见小军，云)兀那厮！你来这里做甚么？你快实说。", "你若不说，劈了你这颗狗头来，我则一斧！(小军云)适才元帅赏了我酒十瓶，羊肉二十斤，不争你劈了我这头，教我怎么吃？(正末云)快说！你若不说，我就一斧。", "(小军云)老爷不要燥暴就把斧头劈下来，待我说，我说。", "我是杨家府里小军儿，奉佘太君奶奶的命，着我寄一封书与元帅。", "道是梦中看见老令公，说与番兵交战，不想番兵将老令公困在两狼山虎口交牙峪，困的里无粮草，外无救军。", "有七郎打出阵来求救，不想被潘仁美将七郎绑在花标树上，攒箭射死。", "老令公不能得出，撞李陵碑身死。", "今被韩延寿将老令公尸首烧了，将骨殖挂在幽州昊天寺塔尖上。", "但是过来过往的人，有箭的射三箭，无箭的打三砖，名曰百药箭。", "(正末云)敢是百箭会？(小军云)你说的是。", "(正末云)眼见的哥哥召集众将商量，取那父亲骨殖去，是一件紧要的事，故瞒着我来。", "嗨！哥哥，我们二十四个指挥使，都是一般的兄弟，怎么偏心，只与他们计议，独独着我回避？我再过去，白破了哥哥咱。", "(见杨景科，云)哥哥，我猜着了也。", "(杨景云)你猜着甚的？(正末云)哥哥，你要搭救爹爹，抢回骨殖去，是么？(杨景云)谁道是俺奶奶来兄弟？既然你知道，他如今把我父亲的骨殖，挂在幽州昊天寺塔尖上，我待要替我父亲盗取这骨殖去，展转寻思，并无妙策。", "如之奈何？(正末云)哥哥，别的都去不得，只有您兄弟去得。", "(杨景云)兄弟，你若肯去，就是我的重生父母也！(正末云)您兄弟回避！(杨景云)只这一句儿，你就还将我来。", "兄弟，恁着你是怎么去？你说一遍咱。", "(正末唱)。"]'),
('yuanqu-9382','昊天塔孟良盗骨・耍孩儿','朱凯','元','元曲','yuanqu','','[]','则我这慌忙不用别兵甲，轻轻的将衣服来拽扎。',125,'元曲/yuanqu.json','["则我这慌忙不用别兵甲，轻轻的将衣服来拽扎。", "觑着他千军万马只做癞虾蟆，施逞会莽撞拳法。", "我脊梁边稳把葫芦放，顽石上扌蚩扌蚩的将斧刃擦。", "但撞着无干罢，直杀的他似芟蒲刈苇，截瓠外瓜。", "(云)排军，我分付与你两桩儿勾当。", "(岳胜云)兄弟，可是那两桩儿？(正末唱)。"]'),
('yuanqu-9383','昊天塔孟良盗骨・三煞','朱凯','元','元曲','yuanqu','','[]','准挤着迎魂一首幡，安灵的几朵花，众儿郎都把那麻衣搭，紧拴将亡父驮丧马，哥也你牢背着亲爷的灰骨匣。',68,'元曲/yuanqu.json','["准挤着迎魂一首幡，安灵的几朵花，众儿郎都把那麻衣搭，紧拴将亡父驮丧马，哥也你牢背着亲爷的灰骨匣。", "孝名儿传天下，说甚的孟宗哭笋。", "袁孝拖笆。"]'),
('yuanqu-9384','昊天塔孟良盗骨・煞尾','朱凯','元','元曲','yuanqu','','[]','火轮左手拿，管心右手掐。',50,'元曲/yuanqu.json','["火轮左手拿，管心右手掐。", "我摇一摇撼两撼厮琅琅震动琉璃瓦，兀良我与你直推倒了这一座玲珑舍利塔。", "(下)。"]'),
('yuanqu-9385','昊天塔孟良盗骨・正宫/端正好','朱凯','元','元曲','yuanqu','','[]','只一道火光飞，早四野烟云布，都出在我背上的这葫芦。',44,'元曲/yuanqu.json','["只一道火光飞，早四野烟云布，都出在我背上的这葫芦。", "火龙万队空中舞，明朗朗正照着那幽州路。"]'),
('yuanqu-9386','昊天塔孟良盗骨・滚绣球','朱凯','元','元曲','yuanqu','','[]','烧的来无处居，满城中都痛哭，似伴着老令公灰骨，且休题官法如炉，也不索祭风台，也不索狼烟举，抵多少六丁神发怒，我则见通红了半壁天衢。',93,'元曲/yuanqu.json','["烧的来无处居，满城中都痛哭，似伴着老令公灰骨，且休题官法如炉，也不索祭风台，也不索狼烟举，抵多少六丁神发怒，我则见通红了半壁天衢。", "恰便似汉张良烧断了连云栈，李老君推番炼药炉，这火也从无。"]'),
('yuanqu-9387','昊天塔孟良盗骨・倘秀才','朱凯','元','元曲','yuanqu','','[]','端的是好热闹也禅房寺宇，了得也山僧施主，可不道四大人天火最毒，只我个善知识，没贪图，待布施与你一千枝蜡烛。',53,'元曲/yuanqu.json','["端的是好热闹也禅房寺宇，了得也山僧施主，可不道四大人天火最毒，只我个善知识，没贪图，待布施与你一千枝蜡烛。"]'),
('yuanqu-9388','昊天塔孟良盗骨・倘秀才','朱凯','元','元曲','yuanqu','','[]','不甫能撞开了天关地户，跳出这龙潭虎窟。',81,'元曲/yuanqu.json','["不甫能撞开了天关地户，跳出这龙潭虎窟。", "(云)哥哥小心者。", "(杨景云)兄弟也，走便走，你这般叫怎么。", "(正末唱)我则怕孟火星今番惹下火烛，疾快的，骤龙驹，紧走些儿路途。"]'),
('yuanqu-9389','昊天塔孟良盗骨・滚绣球','朱凯','元','元曲','yuanqu','','[]','人奔似室火猪，马窜如尾火虎，哥也猛回头定睛儿偷觑，咱两个可正是凌烟阁上的人物。',108,'元曲/yuanqu.json','["人奔似室火猪，马窜如尾火虎，哥也猛回头定睛儿偷觑，咱两个可正是凌烟阁上的人物。", "知道是和尚在钵盂在，知道是他受苦也俺受苦？这一场拚着不做，抵多少诸葛也那周瑜。", "畅好是焰腾腾博望烧屯计，不刺刺鏖兵赤壁图，不枉了费尽我工夫。"]'),
('yuanqu-9390','昊天塔孟良盗骨・煞尾','朱凯','元','元曲','yuanqu','','[]','你牢背着一匣儿骨殖疾归去，休绕着这千里关山放声哭。',202,'元曲/yuanqu.json','["你牢背着一匣儿骨殖疾归去，休绕着这千里关山放声哭。", "(杨景云)呀，后面喊声起，敢是追兵来了也！(正末云)哥哥你先走，等我敌住他。", "(唱)猛听的城边喊声举，早卷起足律律一阵黑尘土。", "多敢是韩延寿那厮紧追逐，恼了咱嘉州孟太仆。", "生咬定牙关自当住，那怕有十面军兵暗埋伏。", "且和他战个九千合来决胜负，也不是我杀人心忒狠毒，管教他便人亡马倒都做血糊突。", "若放了他一个儿抹的着回家路，哎，兀的不屈沉杀俺宣花也这柄蘸金斧。", "(下)。"]'),
('yuanqu-9391','昊天塔孟良盗骨・双调/新水令','朱凯','元','元曲','yuanqu','','[]','归来余醉未曾醒，但触着我这秃爷爷没些干净。',77,'元曲/yuanqu.json','["归来余醉未曾醒，但触着我这秃爷爷没些干净。", "(做听科，云)哦，恰像似有人哭哩。", "(唱)那哭的莫不是山中老树怪，潭底毒龙精？敢便待显圣通灵，只俺个道高的鬼神敬。"]'),
('yuanqu-9392','昊天塔孟良盗骨・驻马听','朱凯','元','元曲','yuanqu','','[]','那里每噎噎哽哽，搅乱俺这无是无非窗下僧。',98,'元曲/yuanqu.json','["那里每噎噎哽哽，搅乱俺这无是无非窗下僧。", "(杨景云)父亲也，痛杀我也！(正末唱)越哭的孤孤另另，莫不是着枪着箭的败残兵？我靠三门倚定壁儿听，从双肩手抵着牙儿定。", "似这等沸腾腾，可甚么绿阴满地禅房静？。"]'),
('yuanqu-9393','昊天塔孟良盗骨・步步娇','朱凯','元','元曲','yuanqu','','[]','只你个负屈含冤的也合通名姓，莫不是远探你那爹娘的病？(杨景云)不是。',125,'元曲/yuanqu.json','["只你个负屈含冤的也合通名姓，莫不是远探你那爹娘的病？(杨景云)不是。", "(正末唱)莫不是你犯下些违条罪不轻？(杨景云)我有甚么罪犯？(正末唱)莫不是打担推车撞着贼兵？(杨景云)便有贼兵呵，量他到的那里？(正末唱)我连问道你两三声，怎没半句儿将咱来答应？。"]'),
('yuanqu-9394','昊天塔孟良盗骨・雁儿落','朱凯','元','元曲','yuanqu','','[]','俺这里便骂了人也谁敢应？(杨景云)敢打人么？(正末唱)俺这里便打了人也无争竞。',93,'元曲/yuanqu.json','["俺这里便骂了人也谁敢应？(杨景云)敢打人么？(正末唱)俺这里便打了人也无争竞。", "(杨景云)敢劫人么？(正末唱)俺这里便劫了人也没罪名。", "(杨景云)敢杀了么？(正末唱)俺这里便杀了人也不偿命。"]'),
('yuanqu-9395','昊天塔孟良盗骨・水仙子','朱凯','元','元曲','yuanqu','','[]','现如今火烧人肉喷鼻腥，(杨景云)哎，好和尚，可不道为惜飞蛾纱罩灯哩！(正末唱)俺几曾道为惜飞蛾纱罩灯？(做合手科，云)阿弥陀佛！世间万物，不死不生。',238,'元曲/yuanqu.json','["现如今火烧人肉喷鼻腥，(杨景云)哎，好和尚，可不道为惜飞蛾纱罩灯哩！(正末唱)俺几曾道为惜飞蛾纱罩灯？(做合手科，云)阿弥陀佛！世间万物，不死不生。", "(唱)若不杀生呵，有甚么轮回证？这便是咱念阿弥超度的经。", "(杨景云)想你也不是个从幼儿出家的。", "(正末唱)对客官细说分明，我也曾杀的番军怕，几曾有个信士请，直到中年才落发为僧。", "(杨景云)兀那和尚！我也不瞒你，我是大宋国的人。", "(正末云)客官，你既是大宋国人，曾认的那一家人家么？(杨景云)是谁家？(正末云)他家里有个使金刀的。", "(唱)。"]'),
('yuanqu-9396','昊天塔孟良盗骨・雁儿落','朱凯','元','元曲','yuanqu','','[]','他叫做杨令公手段能，(杨景惊科，云)他怎么知道俺父亲哩？兀那和尚！那杨令公有几个孩儿？(正末唱)他有那七个孩儿都也心肠硬。',95,'元曲/yuanqu.json','["他叫做杨令公手段能，(杨景惊科，云)他怎么知道俺父亲哩？兀那和尚！那杨令公有几个孩儿？(正末唱)他有那七个孩儿都也心肠硬。", "(杨景云)他母亲是谁？(正末唱)他母亲是佘太君，敕赐的清风楼无邪佞。"]'),
('yuanqu-9397','昊天塔孟良盗骨・得胜令','朱凯','元','元曲','yuanqu','','[]','呀！他兄弟每多死少波生。',858,'元曲/yuanqu.json','["呀！他兄弟每多死少波生。", "(杨景云)你敢是他家里人么？(正末唱)只我在这五台呵又为僧(杨景云)哦，你元来是杨五郎！你兄弟还有那个在么？(正末唱)有杨六使在三关上，(杨景云)你可认的他哩？(正末云)他是我的兄弟，怎不认的？(唱)和俺一爷娘亲弟兄。", "(杨景云)哥哥，你今日怎就不认得我杨景也？(正末做认科)(唱)休惊，这会合真侥幸！(云)兄弟，闻的你镇守瓦桥关上，怎到得这里？(杨景云)哥哥，您兄弟到幽州昊天寺，取俺父亲的骨殖来了也。", "(正末做悲科)(唱)伤也么情，枉把这幽魂陷虏城。", "(净扮韩延寿上，诗云)我做将军快敌头，不吃干粮则吃肉。", "你道是敢战官军沙塞子，怎知我是畏刀避箭韩延寿。", "某韩延寿是也。", "叵寸奈杨六儿无礼，将他令公骨殖，偷盗去了。", "我领着番兵，连夜追赶。", "原来杨六儿将着骨殖，前面先去，留下孟良，在后当住。", "我如今别着大兵，与孟良厮杀，自己挑选了这五千精兵，抄上前来，明明望见杨六儿，走到五台山下，怎么就不见了？一定躲在这寺里！大小番兵，围了这寺者。", "兀那寺里和尚，快献出杨六儿来！若不献出来，休想满寺和尚，一个得活！(做呐喊打门科)(杨景云)哥哥，兀的不是番兵来了也？(正末云)兄弟不要慌，我出去与他打话。", "我开了这三门。", "(做见科)(韩延寿云)兀那和尚！您这寺里有杨六儿么？献将出来便罢。", "若不献出来呵，将你满寺和尚的头，都似西瓜切将下来，一个也不留还你。", "(正末云)兀那将军！果然有个杨六儿，被我先拿住了，绑缚在这寺里。", "俺出家的人，是慈悲为本，方便为门，休把这许多枪刀，吓杀了俺老师父。", "您去了兵器，下了马，我拿杨六儿与你去请功受赏，好不自在哩。", "(韩延寿云)我依着你，就去了这刀枪，脱了这铠甲，我下了这马。", "和尚，杨六儿在那里？快献出来。", "(正末云)将军，你忙怎的？且跟将我入这三门来，且关上这门。", "(韩延寿云)你为甚么关上门？(正末云)我是小心的，还怕走了杨六儿？(韩延寿云)杨六儿走不出，我也走不去。", "关的是，关的是！(正末做打净科，云)量你这厮走到那里去？(韩延寿云)呀，这和尚不老实，你只好关门杀屎棋，怎么也要打我？(正末唱)。"]'),
('yuanqu-9398','昊天塔孟良盗骨・喜江南','朱凯','元','元曲','yuanqu','','[]','呀，则我这杀人和尚灭门僧，便铁金刚也劝不的肯容情。',69,'元曲/yuanqu.json','["呀，则我这杀人和尚灭门僧，便铁金刚也劝不的肯容情。", "俺兄弟正六郎杨景镇边庭(带云)韩延寿！(唱)也不则你兵临在颈，再休想五千人放半个得回营。"]'),
('yuanqu-9399','南吕・一枝花悔悟','陆登善','元','元曲','yuanqu','','[]','春风柳吐金，夏日荷铺锦。',55,'元曲/yuanqu.json','["春风柳吐金，夏日荷铺锦。", "秋蟾辉碧汉，冬雪老遥岑。", "四季光阴，终日寻芳饮，奇化选拣簪。", "曾共知音，受用了些云屏月枕。"]'),
('yuanqu-9400','梁州・也曾腿厮压齐声儿和曲，头厮顶难字儿闲吟。番思年少如春梦。传','陆登善','元','元曲','yuanqu','','[]','书寄简，剪发捻沉。',100,'元曲/yuanqu.json','["书寄简，剪发捻沉。", "盟山誓海，解佩移簪。", "也曾待佳期到夜半更深，度良宵翠被鸳衾。", "如今腆着脸百事儿妆憨，低着头凡事儿撒吞，睁着眼所事推病。", "聪明，待怎？蓝桥一任洪波浸，但饱暖且则恁。", "始觉从前枉用心，再不追寻。"]'),
('yuanqu-9401','尾・眠花卧柳性全禁，惜玉怜香心再不侵。假若普救寺丽春园待则甚？自','陆登善','元','元曲','yuanqu','','[]','今，自今，把这俏倬家风脱与您。',15,'元曲/yuanqu.json','["今，自今，把这俏倬家风脱与您。"]'),
('yuanqu-9402','南吕・一枝花春雨','马彦良','元','元曲','yuanqu','','[]','润夭桃灼灼红，洗芳草茸茸翠。',64,'元曲/yuanqu.json','["润夭桃灼灼红，洗芳草茸茸翠。", "蝶愁扌扇香粉翅，莺怕展缕金衣。", "堪恨堪宜，耽阁酿蜂儿蜜，喜调和燕子泥。", "游春客怎把芳寻，斗巧女难将翠拾。"]'),
('yuanqu-9403','尾・叮咛这雨声莫打梨花坠，风力休吹柳絮飞。留待睛明好天气，穿一领','马彦良','元','元曲','yuanqu','','[]','布衣，着一对草履，访柳寻春万事喜。',17,'元曲/yuanqu.json','["布衣，着一对草履，访柳寻春万事喜。"]'),
('yuanqu-9404','正宫・醉太平出浴图','顾鉴中','元','元曲','yuanqu','','[]','荡春心火烧，沐天露油浇。',58,'元曲/yuanqu.json','["荡春心火烧，沐天露油浇。", "侍儿扶起一团娇，掩双酥凤绡。", "杏花浅露胭脂萼，鸡头新剥珍珠宝，海堂微隐祸根苗，则是马嵬尘未澡。"]'),
('yuanqu-9405','中吕・普天乐答沈甥书','顾鉴中','元','元曲','yuanqu','','[]','天阔雁还疏，人远心犹近。',311,'元曲/yuanqu.json','["天阔雁还疏，人远心犹近。", "贤甥有义，我岂无亲。", "泪从眼角流，情向书中尽。", "自愧残年多愚钝，丁宁话不叙闲文。", "勤攻书史，常亲笔砚，承维先人。", "赠朱昭信升千户文武继宗门，忠义全臣节。", "枪摇银蟒，笔走鸟蛇。", "箭瑞燕尾钅比，刀取猩喉血。", "戴月披霜无明夜，记当先功次重叠。", "紫泥封昨宵到也，花银带今朝系也，褐罗伞明日来也。", "寄情奇遇凤鸾交，紧挽鸳鸯结。", "津甜稠攘，味苦离别。", "行去恣往来，流水无明夜。", "料得名花怎肯随风谢，惹香泥燕口重叠。", "叹韶光看看过也，想娇溜痴痴望也，许佳期准准来也。", "修竹仕女图意味有谁知，心事无人问。", "郁孤闷翠烟缥渺，覆清寒苍雪缤纷。", "空闻子凤鸣，难觅青鸾信，目断湘云咫尺天涯近。", "欲思不醉无归，望城头双凫早飞。", "喜琴外孤鹤并美，愿天边五马追随。"]'),
('yuanqu-9406','破苻坚蒋神灵应・仙吕/点绛唇','李文蔚','元','元曲','yuanqu','','[]','想起那汉室兴邦，立基开创。',31,'元曲/yuanqu.json','["想起那汉室兴邦，立基开创。", "萧丞相，韩信张良，他正是杰士从天降。"]'),
('yuanqu-9407','破苻坚蒋神灵应・混江龙','李文蔚','元','元曲','yuanqu','','[]','万民仰望，中兴光武出南阳。',101,'元曲/yuanqu.json','["万民仰望，中兴光武出南阳。", "衣冠济楚，人物轩昂。", "道统相承尊礼义，彝伦正体叙纲常。", "因此上繁华美丽，盛成风光，卿云秀气，瑞霭祯祥。", "他正是乐雍熙宁宇宙大朝臣，端的是贺升平安社稷边庭将，那其间息平戈戟，不动刀枪。"]'),
('yuanqu-9408','破苻坚蒋神灵应・油葫芦','李文蔚','元','元曲','yuanqu','','[]','那其间鼎足三分豪气强，魏吴刘英俊广。',148,'元曲/yuanqu.json','["那其间鼎足三分豪气强，魏吴刘英俊广。", "则不如蜀王三请卧龙冈。", "(苻坚云)三分之中，有甚么英才也？(正末唱)那先生神机妙策能雄壮，端的是忠心报国多兴旺。", "(苻坚云)据诸葛谋欺魏国，智压东吴，剑挥星斗，笔扫群雄。", "论行兵古今绝矣。", "(正末唱)他住田渭水滨，下城都濯锦江，端的是英才四海高名望，不枉了青史写贤良。"]'),
('yuanqu-9409','破苻坚蒋神灵应・天下乐','李文蔚','元','元曲','yuanqu','','[]','后来也司马威权立晋邦，兴也波王，据洛阳，因此上群臣劝移都建康。',75,'元曲/yuanqu.json','["后来也司马威权立晋邦，兴也波王，据洛阳，因此上群臣劝移都建康。", "(苻坚云)晋朝有甚大才之人？(正末唱)有谢安雅量宽，有桓冲志气刚，都是些尽全忠，真栋梁。"]'),
('yuanqu-9410','破苻坚蒋神灵应・金盏儿','李文蔚','元','元曲','yuanqu','','[]','我如今火西凉，定西羌，西蜀远远皆归向，削平陇右立秦邦。',133,'元曲/yuanqu.json','["我如今火西凉，定西羌，西蜀远远皆归向，削平陇右立秦邦。", "见如今民安丰稔岁，王道乐遐昌，则不如宽洪兴率土，存正守封疆。", "(苻坚云)军师，想某收蜀破陇，天下十分得其士也。", "今若雄兵大举，有先锋、中军合后，左右接连，旗鼓相望，前后千里，必有万全之功。", "先生勿阻是举也。", "(正末唱)。"]'),
('yuanqu-9411','破苻坚蒋神灵应・醉中天','李文蔚','元','元曲','yuanqu','','[]','仰望着晋室为尊上，纳进可归降，(苻坚云)率百万雄兵，将他一鼓而下也。',105,'元曲/yuanqu.json','["仰望着晋室为尊上，纳进可归降，(苻坚云)率百万雄兵，将他一鼓而下也。", "(正末唱)便休题领貔貅远播扬，大国有驰名将。", "(苻坚云)某用兵无差，遣将得力也。", "(正末唱)休夸逞百能臼强，莫施逞一冲一撞，我则怕枉徒劳措手难防。"]'),
('yuanqu-9412','破苻坚蒋神灵应・尾声','李文蔚','元','元曲','yuanqu','','[]','尊建业望神京，拱上国瞻天象，休小觑东南一方。',570,'元曲/yuanqu.json','["尊建业望神京，拱上国瞻天象，休小觑东南一方。", "看了二水中分白鹭洲，插青天山势轩昂，映晖光，水国江乡，端的是贵府高名王谢堂。", "(苻坚云)先生，凭着俺本国人马，务要征战一遭也。", "(正末唱)慢矜夸兵多将广，且休题人强马壮，(带云)大人，你休举兵，(唱)则不如存仁布德守秦邦。", "(下)(苻坚云)先生去了也。", "某欲待图晋，军师坚意不肯。", "某手下有中大夫阳耳公苻融，此人知天文，晓地理，观气色，辨风云。", "某唤他来，与他商议，看他意下如何？小校，与我请阳平公苻融来者。", "(卒子云)理会的。", "阳平公安在？(苻融上，云)威镇群雄透胆寒，常怀义胆与忠肝，为臣竭力施公正，赤心辅弼立江山。", "小官乃阳平公苻融是也。", "生于汉末之间，学成文武全才，智勇并行。", "小官正在私宅，令人来报苻公呼唤，须索走一遭去。", "报复去，道有苻融来了也。", "(卒子云)理会的。", "喏，报的大人得知，有阳平公来了也。", "(苻坚云)道有请。", "(卒子云)理会的。", "有请(见科)(苻融云)公子呼唤苻融来，有何事商议？(苻坚云)苻融，唤你来别无甚事，某听知的晋国兵微将寡，缺少用武之将，我今要统兵图晋，未知你意下如何？(苻融云)公子，便好道\"国有事君臣议论，家有事父子商量\"。", "今欲要伐晋，必起干戈。", "孙子曰：\"兵者国之大事，死生之地，存亡之道，不可不察也。", "\"晋室虽然兵微将寡，无有不正之事。", "有桓冲、谢安，乃江表社稷之臣。", "今福德在晋，奈长江险阻。"]'),
('yuanqu-9413','破苻坚蒋神灵应・南吕/一枝花','李文蔚','元','元曲','yuanqu','','[]','参透这九宫八卦文，一变千筹数，万敌百战法，三略六韬书。',68,'元曲/yuanqu.json','["参透这九宫八卦文，一变千筹数，万敌百战法，三略六韬书。", "休道那十面埋伏，怎出这妙策幽微趣。", "神机决胜术。", "排玄武接引青龙。", "我若是按朱雀中白虎。"]'),
('yuanqu-9414','破苻坚蒋神灵应・梁州','李文蔚','元','元曲','yuanqu','','[]','运动时风雷鼓舞，端的也行持时日月盈虚，阴阳造化分寒暑。',127,'元曲/yuanqu.json','["运动时风雷鼓舞，端的也行持时日月盈虚，阴阳造化分寒暑。", "霎时间云遮白昼。", "雾障街衢，雨施晦暗，风起吹嘘。", "拨天关动静全殊，应天心逆顺难谟。", "安营时虑险防患，布阵势扬威耀武，排兵时运智施谋。", "提防着路途，问阻，要知进退行军旅，识天文变躔度，大将同劳与士卒，志在孙吴。"]'),
('yuanqu-9415','破苻坚蒋神灵应・牧羊关','李文蔚','元','元曲','yuanqu','','[]','这棋布关天象，似星分运斗枢，(王坦之云)这方圆动静，可是如何？(正末唱)有方圆动静亲疏。',117,'元曲/yuanqu.json','["这棋布关天象，似星分运斗枢，(王坦之云)这方圆动静，可是如何？(正末唱)有方圆动静亲疏。", "静埋伏暗计包藏，动交战攻城必取，(王坦之云)小将军，你观此棋，如排兵布阵相似也。", "(正末唱)圆用兵如棋子，方下寨似棋局。", "倚亲者添雄壮，接疏情势似孤。"]'),
('yuanqu-9416','破苻坚蒋神灵应・隔尾','李文蔚','元','元曲','yuanqu','','[]','苻喂将广非吾许，秦国兵多有若无。',104,'元曲/yuanqu.json','["苻喂将广非吾许，秦国兵多有若无。", "(王坦之云)他则倚仗着兵雄将勇，岂知俺有才俊英杰也。", "(正末唱)不识江南有人物，出豪杰在帝都，显英才在将府，(王坦之云)荐举将军为帅，必然破了秦寇也。", "(正末唱)敢望高贤将谢玄举。"]'),
('yuanqu-9417','破苻坚蒋神灵应・骂玉郎','李文蔚','元','元曲','yuanqu','','[]','亲门"退"字参详去，待教我自省会莫踌躇，他强我弱休畏惧。',43,'元曲/yuanqu.json','["亲门\"退\"字参详去，待教我自省会莫踌躇，他强我弱休畏惧。", "我如今沦进攻。", "要退兵，知天数。"]'),
('yuanqu-9418','破苻坚蒋神灵应・感皇恩','李文蔚','元','元曲','yuanqu','','[]','呀，谩矜夸志卷江湖，便如您智在棋局。',116,'元曲/yuanqu.json','["呀，谩矜夸志卷江湖，便如您智在棋局。", "能通变识行藏，观势要分胜败，知进退紧追逐。", "(王坦之云)将军，令叔写此一字，全在将军妙算。", "\"夫未战者多算胜，少算不胜，何况于无算？\"(正末唱)这里面防危虑险，更那堪损益盈虚，能挑战，善料敌，有神术。"]'),
('yuanqu-9419','破苻坚蒋神灵应・采茶歌','李文蔚','元','元曲','yuanqu','','[]','我这里用机谋，在须臾，这个字可正是要分胜败定赢输。',41,'元曲/yuanqu.json','["我这里用机谋，在须臾，这个字可正是要分胜败定赢输。", "得意何须多计策，算来不索下功大。"]'),
('yuanqu-9420','破苻坚蒋神灵应・尾声','李文蔚','元','元曲','yuanqu','','[]','仿学那汉云氏斩将三通鼓，蜀诸葛排兵八阵图。',774,'元曲/yuanqu.json','["仿学那汉云氏斩将三通鼓，蜀诸葛排兵八阵图。", "到来日陈旌旗列士卒，统于戈御战车，将江山社稷扶，定番邦尽剿除。", "我务要战退了秦苻坚百万的这征夫，托赖着济世宽仁圣明主。", "(下)(谢安云)谢玄去了也。", "相公，你才见么？这棋中之意，进退之节，老夫虽然不语，谢玄观棋得计，他已是参透了也。", "此一去必然成其大功也。", "(王坦之云)老丞相，小官与相公围此一盘棋，小将军解此棋意，自然有个主意也。", "(谢安云)相公不嫌絮烦，听老夫慢慢的说一遍。", "(王坦之云)老丞相，这棋中幽微之趣，可得闻乎？(谢安云)夫围棋者，乃运天地之机，造化阴阳之像，此棋尧王所制，以为悦豫之戏。", "棋盘有四角，按四时春夏秋冬。", "上有方圆动静，方者为盘，圆者为子，动者为阳，静者为阴。", "棋有一十九路。", "(王坦之云)老相公，是那一十九路？(谢安云)是一天、二地、三才、四时、五行、六律、七星、八方、九州、十干、十一冬、十二支、十三闰、十四相、十五望、十六松、十七生、十八却、十九朔。", "外有五盘小棋势。", "(王坦之云)是那五盘小棋势？(谢安云)是小巧势，小妙势，小角势，小机势，小屯势。", "棋盘有三百六十路，按一年三百六十日。", "又有二十四盘大棋势。", "(王坦之云)老丞相，是那二十四盘大棋势？(谢安云)是独飞天鹅势，大海求鱼势，蛟龙竞宝势，蝴蝶绕园势，锦鲤化龙势，双鹤朝圣势，黄河九曲势，华岳三峰势，寒灰发焰势，枯木重荣势，彩凤翻身势，游鱼脱网势，虎护山峪势，两狼斗虎势，七熊争霸势，六出岐山势。", "七擒七纵势，九败章邯势，对面千里势，兔守三穴势，野马跳涧势，批亢捣虚势，三战吕布势，十面埋伏势。", "若论下棋者，一安详，二布置，三用机，四舍弃，五温习，六究理，七自见，八知彼，九从心，十远意。", "远不可太疏，疏则易断；近不可太促，促则势微。", "欲下一子，先观满盘，从初至末，着着当先。", "追杀兮不可太过，妙算兮恭心却战，认真兮弃少就多。", "初间布置张罗，次后往来规措。"]'),
('yuanqu-9421','破苻坚蒋神灵应・正宫/端正好','李文蔚','元','元曲','yuanqu','','[]','我奉朝内帝王宣，持阃外将军令，统貔貅齐出石城，今日个破西秦要把中原定。',594,'元曲/yuanqu.json','["我奉朝内帝王宣，持阃外将军令，统貔貅齐出石城，今日个破西秦要把中原定。", "我则待兴晋室，拒秦兵，望神圣，显威灵，分胜败，见输赢；则要奏凯歌，齐得胜，敲金镫。", "(下)(谢石云)刘牢之，你为前部先锋，率精兵五千，先生新安县白石山洛涧栅，拒敌秦兵。", "桓伊、谢琰为左右二哨，则要您得胜回辽。", "看计行兵，然后某与元帅、统大势雄兵，便来接应也。", "(桓伊云)得今！奉元帅的将令，到来日两阵交锋用智能，今番大战定输赢。", "挟人捉将千般勇，武艺精熟敢战争。", "忘生舍死行忠孝，赤心报国辅朝廷。", "为将行兵周吕望，扶持社稷永兴隆！(下)(谢琰云)得令！奉元帅将令，与苻坚相持厮杀，走一遭去。", "大小三军，听吾将令！到来日雄兵猛将列西东，杀气腾腾罩碧空。", "枪刀灿烂如银练，征尘缭乱马蹄横。", "挟人捉将垓心内，扬威耀武阵云中。", "英雄慷慨忠良将，夺取今番第一功！(下)(刘牢之云)奉元帅将令，领五千人马，与秦兵交战，走一遭去。", "大小三军，听吾将令！三通鼓罢，拔寨起营。", "凛凛威风七尺躯，胸中韬略用机谋。", "匣藏宝剑龙文敕，帐前军将锦模糊。", "英雄勇将持兵刃，智按当年八阵图。", "忠心辅助安天下，杀的那百万贼兵拱手伏！(下)(谢石云)众将去了也。", "某与元帅统领大军，剿除秦兵，走一遭去。", "忠正常怀报国心，英雄慷慨显威风。", "全凭智勇安天下，杀退秦兵建大功！(下)(庙官云)大人去了也。", "小道无甚事，捣蒜吃羊头去也。", "我做道官爱清幽，一生哈答度春秋。", "捣下青蒜酾下酒，柳蒸狗肉烂羊头。"]'),
('yuanqu-9422','破苻坚蒋神灵应・越调/斗鹌鹑','李文蔚','元','元曲','yuanqu','','[]','今日个将出京师，兵离帝辇，试看那杀气弥漫，威风势远，(刘牢之云)你看那剑戟如银练，旗幡彩带飘，是好气势也！(正末唱)剑帔纵横，施旗晃展。',95,'元曲/yuanqu.json','["今日个将出京师，兵离帝辇，试看那杀气弥漫，威风势远，(刘牢之云)你看那剑戟如银练，旗幡彩带飘，是好气势也！(正末唱)剑帔纵横，施旗晃展。", "我如今统禁军，掌大权，凭着俺武略文韬，播得个名扬贵显。"]'),
('yuanqu-9423','破苻坚蒋神灵应・紫花儿序','李文蔚','元','元曲','yuanqu','','[]','我务要剿除了番虏，杀败了羌戎，扫荡了狼烟。',74,'元曲/yuanqu.json','["我务要剿除了番虏，杀败了羌戎，扫荡了狼烟。", "全凭着刀枪锋利，戈甲齐坚，征马宛，恰便似飞虎飞熊下九天。", "今日待与四秦交战，摆列的兵势威严，我则索将令亲传。"]'),
('yuanqu-9424','破苻坚蒋神灵应・谢笑令','李文蔚','元','元曲','yuanqu','','[]','我正是谢玄，特地来破苻坚，我与你答活相持在两阵前。',91,'元曲/yuanqu.json','["我正是谢玄，特地来破苻坚，我与你答活相持在两阵前。", "(苻坚云)量你止有十万军马，急早投降！(正末唱)你正是番人性野心不善，倚兵多小觑中原。", "你若肯将军兵退过河那边，我情愿便伏低纳进尊贤。"]'),
('yuanqu-9425','破苻坚蒋神灵应・秃厮儿','李文蔚','元','元曲','yuanqu','','[]','他退一步非灾怎免，退-步横祸缠绵，仗着他兵雄将多武艺全。',41,'元曲/yuanqu.json','["他退一步非灾怎免，退-步横祸缠绵，仗着他兵雄将多武艺全。", "则我这，计通玄，也波难传。"]'),
('yuanqu-9426','破苻坚蒋神灵应・圣药王','李文蔚','元','元曲','yuanqu','','[]','趁着他过水渊，临岸边，袭兵逞势要争先。',49,'元曲/yuanqu.json','["趁着他过水渊，临岸边，袭兵逞势要争先。", "我见他阵不圆，旗乱展，方才半渡不能前，暂时间则一阵破了苻坚。"]'),
('yuanqu-9427','破苻坚蒋神灵应・尾声','李文蔚','元','元曲','yuanqu','','[]','循环天理随人愿，西秦国时乖命蹇。',428,'元曲/yuanqu.json','["循环天理随人愿，西秦国时乖命蹇。", "今日个定番虏尽消除，留得芳名播年远。", "(同众下)(苻坚慌上，云)当年不信贤人语，今日孤身一旦空。", "某苻坚是也。", "将兵百万图晋，被谢玄一计，着我将兵过河，他来受降。", "军至半渡，晋兵大举，吾兵号令不齐，将我兵杀其大半，水中淹死大半。", "晋兵追至青冈，满山都是晋兵，天丧苻坚也！未知粱成、慕容垂在于何处也？(净梁成、慕容垂慌上)(慕容垂云)走、走、走！一百万秦兵尽皆折了，俺两个刚刚的逃出命来。", "兀那远远的不是苻坚？因为你与晋兵交战，折了俺许多人马，更待干罢！险些儿送了俺性命，你及早受死！(苻坚跪科，云)将军，可怜孤身无处投奔，望将军饶其性命，愿将西秦与之。", "(慕容垂云)苻坚，你既然赤心受命于我，饶你性命！你则是开的口大了，你岂不羞么？收拾方物，准备进贡，你再休题马鞭填塞过江南！(苻坚云)罢罢罢！当此一日不信苻融之言，果然今日将输兵败！即便回还，收拾方物，便来进贡也。", "阵退纷纷看败兵，朔风凛凛卷残云。", "行程凄残无头奔，孤身羞耻向西秦！(下)。"]'),
('yuanqu-9428','破苻坚蒋神灵应・双调/新水令','李文蔚','元','元曲','yuanqu','','[]','则为我运筹一计建功劳，今日个灭苻坚杏无消耗。',50,'元曲/yuanqu.json','["则为我运筹一计建功劳，今日个灭苻坚杏无消耗。", "征尘威势远，杀气阵云高、将呢乓骁．因此上安宇宙、定廊庙。"]'),
('yuanqu-9429','破苻坚蒋神灵应・雁儿落','李文蔚','元','元曲','yuanqu','','[]','非是俺三军费苦劳，谢叔父一计真奇妙。',74,'元曲/yuanqu.json','["非是俺三军费苦劳，谢叔父一计真奇妙。", "因此上八方定虏番，却原来叫海除凶暴。", "(桓冲云)今日个边庭宁静。", "扫荡西秦，八方无事，万万载太平之世也！(正末唱)。"]'),
('yuanqu-9430','破苻坚蒋神灵应・得胜令','李文蔚','元','元曲','yuanqu','','[]','呀！今日个得胜也赴皇朝，恰便似平步上青霄。',362,'元曲/yuanqu.json','["呀！今日个得胜也赴皇朝，恰便似平步上青霄。", "(谢安云)谢玄，此是你智勇机变，所以得胜而回也。", "(正末唱)非是我阵面上随机变，谢叔父棋局中动着高。", "(谢安云)也是你妙算神机，不差半米也，(正末唱)心不尖分毫，真乃是雅量施三略，保祚雅量施三略，保祚着皇朝，播一个美名儿在青史标。", "(桓冲云)谢安、王坦之、谢玄、谢石，您众将望阙跪者！听圣人的命：为您胸怀韬略，腹隐神机，少少之兵，今退百万雄师，累建大功，今日加官赐赏。", "谢安有雅量之。", "举侄设计，有大功勋，加官太保中书省太宰。", "王坦之机变之才，举人得中，加为尚书兼中书门下之职。", "谢玄有退秦兵之勇，淝水之胜。", "有大功勋，加为定番虏大元帅。", "谢石有关张之雄，共谋破秦，累建奇功，加为征讨副帅之职。", "刘牢之、桓尹、谢琰等众将，都肩加字赐赏。", "您是那赤心报国忠良将，今日个杀退苻坚百万兵。", "谢了恩者！(正末唱)。"]'),
('yuanqu-9431','破苻坚蒋神灵应・折桂令','李文蔚','元','元曲','yuanqu','','[]','今日个拜金銮遥望天朝，我这里舞蹈扬尘，展脚舒腰。',365,'元曲/yuanqu.json','["今日个拜金銮遥望天朝，我这里舞蹈扬尘，展脚舒腰。", "(众做拜科)(桓冲云)方今圣人。", "德过尧舜，今日犒劳众将，赐赏加官也。", "(正末唱)俺如今感谢洪恩，蒙承大德，庆贺功劳。", "(做拜科)(桓冲云)您官高极品，位至三公，禄享千钟，辈辈荣袭也。", "(正末唱)一个个居禄位高官贵爵，一个个享荣华列土分茅。", "(做拜科)(桓冲云)圣上宽仁厚德，文武公卿，内外臣僚，永享快乐也。", "(正末唱)则俺这文武臣僚，气势英豪，愿吾皇圣寿齐天，明圣似虞舜唐尧。", "(做拜科)(桓冲断出，云)您众将望阙跪者！听圣人的命：一百万入寇秦兵，接千里旌旗相映。", "虽然他将广兵多，谢安石宽忠秉政。", "能举荐将军谢玄，写退计棋中得令。", "为帅首挂印兴兵，入庙宇拈香祷圣。", "初一阵寿阳当先，后一阵淝水取胜。", "满川野草木为兵，有鹤唳风声相趁。", "今日个靖边境破虏除番，八公山蒋神灵应。", "尽忠心正直为神，万万载中原平定。"]'),
('yuanqu-9432','双调・枳郎儿','柴野愚','元','元曲','yuanqu','','[]','访仙家，访仙家，远远入烟霞。',36,'元曲/yuanqu.json','["访仙家，访仙家，远远入烟霞。", "汲水新烹阳羡茶。", "瑶琴弹罢，看满园金粉落松花。"]'),
('yuanqu-9433','唐明皇秋夜梧桐雨・仙吕/端正好','白朴','元','元曲','yuanqu','','[]','则为你不曾建甚奇功，便教你做元辅，满朝中都指斥銮舆。',47,'元曲/yuanqu.json','["则为你不曾建甚奇功，便教你做元辅，满朝中都指斥銮舆。", "眼见的平章政事难停住，寡人待定夺些别官禄。"]'),
('yuanqu-9434','唐明皇秋夜梧桐雨・幺篇','白朴','元','元曲','yuanqu','','[]','且着你做节度渔阳去，破强寇永镇幽都。',68,'元曲/yuanqu.json','["且着你做节度渔阳去，破强寇永镇幽都。", "休得待国家危急才防护；常先事设权谋，收猛将保皇图。", "分铁券，赐丹书，怎肯便辜负了你这功劳簿。", "(同下)。"]'),
('yuanqu-9435','唐明皇秋夜梧桐雨・仙吕/八声甘州','白朴','元','元曲','yuanqu','','[]','朝纲倦整，寡人待痛饮昭阳，烂醉华清。',66,'元曲/yuanqu.json','["朝纲倦整，寡人待痛饮昭阳，烂醉华清。", "却是吾当有幸，一个太真妃倾国倾城。", "珊瑚枕上两意足，翡翠帘前百媚生。", "夜同寝，昼同行，恰似鸾凤和鸣。"]'),
('yuanqu-9436','唐明皇秋夜梧桐雨・天下乐','白朴','元','元曲','yuanqu','','[]','则见展翅忙呼万岁声，惊的那娉婷将銮驾迎。',55,'元曲/yuanqu.json','["则见展翅忙呼万岁声，惊的那娉婷将銮驾迎。", "一个晕庞儿画不就，描不成。", "行的一步步娇，生的一件件撑，一声声似柳外莺。"]'),
('yuanqu-9437','唐明皇秋夜梧桐雨・醉中天','白朴','元','元曲','yuanqu','','[]','龙麝焚金鼎，花萼插银瓶。',106,'元曲/yuanqu.json','["龙麝焚金鼎，花萼插银瓶。", "小小金盆种五生，供养着鹊桥会丹青帧，把一个米来大蜘蛛儿抱定。", "搀夺尽六宫庞幸，更待怎生般智巧心灵。", "(正末与旦砌末科，云)这金钗一对，钿盒一枚，赐与卿者。", "(旦接科，云)谢了圣恩也。", "(正末唱)。"]'),
('yuanqu-9438','唐明皇秋夜梧桐雨・金盏儿','白朴','元','元曲','yuanqu','','[]','我着绛纱蒙，翠盘盛。',71,'元曲/yuanqu.json','["我着绛纱蒙，翠盘盛。", "两般礼物堪人敬，趁着这新秋节令赐卿卿。", "七宝金钗盟厚意，百花钿盒表深情。", "这金钗儿教你高耸耸头上顶，这钿盒儿把你另巍巍手中擎。"]'),
('yuanqu-9439','唐明皇秋夜梧桐雨・忆王孙','白朴','元','元曲','yuanqu','','[]','瑶阶月色晃疏棂，银烛秋光冷画屏。',78,'元曲/yuanqu.json','["瑶阶月色晃疏棂，银烛秋光冷画屏。", "消遣此时此夜景，有禾步闲庭，苔浸的凌波罗袜冷。", "(云)这秋景与四时不同。", "(旦云)怎见的与四时不同？(正末云)你听我说。", "(唱)。"]'),
('yuanqu-9440','唐明皇秋夜梧桐雨・胜葫芦','白朴','元','元曲','yuanqu','','[]','露下天高夜气清，风掠得羽衣轻，香惹丁东环佩声。',42,'元曲/yuanqu.json','["露下天高夜气清，风掠得羽衣轻，香惹丁东环佩声。", "碧天澄净，银河光莹，只疑是身在玉蓬瀛。"]'),
('yuanqu-9441','唐明皇秋夜梧桐雨・金盏儿','白朴','元','元曲','yuanqu','','[]','他此夕把云路凤车乘，银汉鹊桥平。',101,'元曲/yuanqu.json','["他此夕把云路凤车乘，银汉鹊桥平。", "不甫能今夜成欢庆，枕边忽听晓鸡鸣。", "却早离愁情脉脉，别泪雨泠泠。", "五更长叹息，则是一夜短恩情。", "(旦云)他是天宫星宿，经年不见，不知也曾相忆否？(正末云)他可怎生不想来(唱)。"]'),
('yuanqu-9442','唐明皇秋夜梧桐雨・醉扶归','白朴','元','元曲','yuanqu','','[]','暗想那织女分，牛郎命，虽不老，是长生。',53,'元曲/yuanqu.json','["暗想那织女分，牛郎命，虽不老，是长生。", "他阻隔银河信杳冥，经年度岁成孤另。", "你试向天宫打听，他决害了些相思病。"]'),
('yuanqu-9443','唐明皇秋夜梧桐雨・后庭花','白朴','元','元曲','yuanqu','','[]','偏不是上列着星宿名，下临着尘世生。',49,'元曲/yuanqu.json','["偏不是上列着星宿名，下临着尘世生。", "把天上姻缘重，将人间恩爱轻。", "各办着真诚，天心必应，量他每何足称。"]'),
('yuanqu-9444','唐明皇秋夜梧桐雨・金盏儿','白朴','元','元曲','yuanqu','','[]','咱日日醉霞觥，夜夜宿银屏；他一年一日，见把佳期等。',69,'元曲/yuanqu.json','["咱日日醉霞觥，夜夜宿银屏；他一年一日，见把佳期等。", "若论着多多为胜，咱也合赢。", "我为君王犹妄想，你做皇后尚嫌轻。", "可知道斗牛星畔客，回首问前程。"]'),
('yuanqu-9445','唐明皇秋夜梧桐雨・赚煞尾','白朴','元','元曲','yuanqu','','[]','长如一双钿盒盛，休似两股金钗另，愿世世姻缘注定。',89,'元曲/yuanqu.json','["长如一双钿盒盛，休似两股金钗另，愿世世姻缘注定。", "在天呵做鸳鸯比并，在地呵做连理枝生。", "月澄澄银汉无声，说尽千秋万古情。", "咱各办着志诚，你道谁为显证，有今夜度天河相见女牛星。", "(同下)。"]'),
('yuanqu-9446','唐明皇秋夜梧桐雨・中吕/粉蝶儿','白朴','元','元曲','yuanqu','','[]','天淡云闲，列长空数行征雁。',47,'元曲/yuanqu.json','["天淡云闲，列长空数行征雁。", "御园中夏景初残：柳添黄，荷减翠，秋莲脱瓣。", "坐近幽兰，喷清香玉簪花绽。"]'),
('yuanqu-9447','唐明皇秋夜梧桐雨・叫声','白朴','元','元曲','yuanqu','','[]','共妃子喜开颜，等闲，等闲，御园中列肴馔。',32,'元曲/yuanqu.json','["共妃子喜开颜，等闲，等闲，御园中列肴馔。", "酒注嫩鹅黄，茶点鹧鸪斑。"]'),
('yuanqu-9448','唐明皇秋夜梧桐雨・醉春风','白朴','元','元曲','yuanqu','','[]','酒光泛紫金钟，茶香浮碧玉盏。',47,'元曲/yuanqu.json','["酒光泛紫金钟，茶香浮碧玉盏。", "沉香亭畔晚凉多，把一搭儿亲自拣、拣。", "粉黛浓妆，管弦齐列，绮罗相间。"]'),
('yuanqu-9449','唐明皇秋夜梧桐雨・迎仙客','白朴','元','元曲','yuanqu','','[]','香喷喷正甘，娇滴滴色初绽，只疑是九重天谪来人世间。',51,'元曲/yuanqu.json','["香喷喷正甘，娇滴滴色初绽，只疑是九重天谪来人世间。", "取时难，得后悭。", "可惜不近长安，因此上教驿使把红尘践。"]'),
('yuanqu-9450','唐明皇秋夜梧桐雨・红绣鞋','白朴','元','元曲','yuanqu','','[]','不则向金盘中好看，便宜将玉手擎餐，端的个绛纱笼罩水晶寒。',50,'元曲/yuanqu.json','["不则向金盘中好看，便宜将玉手擎餐，端的个绛纱笼罩水晶寒。", "为甚教寡人醒醉眼，妃子晕娇颜，物稀也人见罕。"]'),
('yuanqu-9451','唐明皇秋夜梧桐雨・快活三','白朴','元','元曲','yuanqu','','[]','嘱付你仙音院莫怠慢，道与你教坊司要迭办。',39,'元曲/yuanqu.json','["嘱付你仙音院莫怠慢，道与你教坊司要迭办。", "把个太真妃扶在翠盘间，快结束，宜妆扮。"]'),
('yuanqu-9452','唐明皇秋夜梧桐雨・鲍老儿','白朴','元','元曲','yuanqu','','[]','双撮得泥金衫袖挽，把月殿里霓裳按，郑观音琵琶准备弹，早搭上鲛绡襟。',63,'元曲/yuanqu.json','["双撮得泥金衫袖挽，把月殿里霓裳按，郑观音琵琶准备弹，早搭上鲛绡襟。", "贤王玉笛，花奴羯鼓，韵美声繁。", "宁王锦瑟，梅妃玉箫，嘹亭循环。"]'),
('yuanqu-9453','唐明皇秋夜梧桐雨・古鲍老','白朴','元','元曲','yuanqu','','[]','屹剌剌撒开紫檀，黄翻绰向前手拈板。',75,'元曲/yuanqu.json','["屹剌剌撒开紫檀，黄翻绰向前手拈板。", "低低的叫声玉环，太真妃笑时花近眼。", "红牙箸趁五音、击着梧桐案，嫩枝柯犹未干、更带着瑶琴音泛，卿呵，你则索出几点琼珠汗。"]'),
('yuanqu-9454','唐明皇秋夜梧桐雨・剔银灯','白朴','元','元曲','yuanqu','','[]','止不过奏说边庭上造反，也合看空便，觑迟疾紧慢。',65,'元曲/yuanqu.json','["止不过奏说边庭上造反，也合看空便，觑迟疾紧慢。", "等不的俺筵上笙歌散，可不气丕丕冒突天颜！那些个齐管仲郑子产，敢待做假忠孝龙逢比干？。"]'),
('yuanqu-9455','唐明皇秋夜梧桐雨・蔓菁菜','白朴','元','元曲','yuanqu','','[]','险些儿慌杀你个周公旦，(李林甫云)陛下，只因女宠盛，谗夫昌，惹起这刀兵来了。',78,'元曲/yuanqu.json','["险些儿慌杀你个周公旦，(李林甫云)陛下，只因女宠盛，谗夫昌，惹起这刀兵来了。", "(正末唱)你道我因歌舞坏江山？你常好是占奸，早难道羽扇纶巾笑谈间，破强虏三十万。"]'),
('yuanqu-9456','唐明皇秋夜梧桐雨・普天乐','白朴','元','元曲','yuanqu','','[]','恨无穷，愁无限。',64,'元曲/yuanqu.json','["恨无穷，愁无限。", "争奈仓卒之际，避不得蓦岭登山。", "銮驾迁，成都盼。", "更那堪氵产水西飞雁，一声声送上雕鞍。", "伤心故园，西风渭水，落日长安。"]'),
('yuanqu-9457','唐明皇秋夜梧桐雨・啄木儿尾','白朴','元','元曲','yuanqu','','[]','端详了你上马娇，怎支吾蜀道难！替你愁那嵯峨峻岭连云栈，自来驱驰可惯，几程儿挨得过剑门关？(同下)。',49,'元曲/yuanqu.json','["端详了你上马娇，怎支吾蜀道难！替你愁那嵯峨峻岭连云栈，自来驱驰可惯，几程儿挨得过剑门关？(同下)。"]'),
('yuanqu-9458','唐明皇秋夜梧桐雨・驻马听','白朴','元','元曲','yuanqu','','[]','隐隐天涯，剩水残山五六搭；萧萧林下，坏垣破屋两三家。',55,'元曲/yuanqu.json','["隐隐天涯，剩水残山五六搭；萧萧林下，坏垣破屋两三家。", "秦川远树雾昏花，灞桥柳风潇洒。", "煞不如碧窗纱晨光闪烁鸳鸯瓦。"]'),
('yuanqu-9459','唐明皇秋夜梧桐雨・沉醉东风','白朴','元','元曲','yuanqu','','[]','父老每忠言听纳，教小储君专任征伐。',93,'元曲/yuanqu.json','["父老每忠言听纳，教小储君专任征伐。", "你也合分取些社稷忧，怎肯教别人把江山霸？将这颗传国宝你行留下，(太子云)儿子只统兵杀贼，岂敢便登天位？(正末唱)剿除了贼徒，救了国家，更避甚称孤道寡？。"]'),
('yuanqu-9460','唐明皇秋夜梧桐雨・步步娇','白朴','元','元曲','yuanqu','','[]','寡人呵万里烟尘，你也合嗟讶，就势儿把吾当唬，国家又不曾亏你伴掐。',56,'元曲/yuanqu.json','["寡人呵万里烟尘，你也合嗟讶，就势儿把吾当唬，国家又不曾亏你伴掐。", "因甚军心有争差？问卿咱，为甚不说半句儿知心话？。"]'),
('yuanqu-9461','唐明皇秋夜梧桐雨・沉醉东风','白朴','元','元曲','yuanqu','','[]','据着杨国忠合该万剐，斗的个禄山贼乱了中华。',138,'元曲/yuanqu.json','["据着杨国忠合该万剐，斗的个禄山贼乱了中华。", "是非寡人股肱难弃舍，更兼与妃子骨肉相牵挂。", "断遣尽枉展污了五条刑法，把他剥了官职，贬做穷民，也是阵杀，允不允，陈玄礼将军鉴察！(众军怒喊科)(陈玄礼云)陛下，军心已变，臣不能禁止，如之奈何？(正末云)随你罢！(众杀杨国忠科)(正末唱)。"]'),
('yuanqu-9462','唐明皇秋夜梧桐雨・雁儿落','白朴','元','元曲','yuanqu','','[]','数层枪，密匝匝，一声喊，山摧塌。',34,'元曲/yuanqu.json','["数层枪，密匝匝，一声喊，山摧塌。", "原来是陈将军号令明，把杨国忠施行罢。"]'),
('yuanqu-9463','唐明皇秋夜梧桐雨・拨不断','白朴','元','元曲','yuanqu','','[]','语喧哗，闹交杂，六军不进屯戈甲。',135,'元曲/yuanqu.json','["语喧哗，闹交杂，六军不进屯戈甲。", "把个马嵬坡簇合沙，又待做甚么？唬的我战钦钦遍体寒毛乍。", "吃紧的军随印转，将令威严；兵权在手，主弱臣强。", "卿呵，则你道波，寡人是怕也那不怕！(云)杨国忠杀了，您众军不进，却为甚的？(陈玄礼云)国忠谋反，贵妃不宜供奉，愿陛下割恩正法。", "(正末唱)。"]'),
('yuanqu-9464','唐明皇秋夜梧桐雨・搅筝琶','白朴','元','元曲','yuanqu','','[]','高力士，道与陈玄礼休没高下，岂可教妃子受刑罚？他见请受着皇后中宫，兼踏着寡人御榻。',102,'元曲/yuanqu.json','["高力士，道与陈玄礼休没高下，岂可教妃子受刑罚？他见请受着皇后中宫，兼踏着寡人御榻。", "他又无罪过，颇贤达。", "须不似周褒姒举火取笑，纣妲己敲胫觑人。", "早间把他个哥哥坏了，总便有万千不是，看寡人也合饶过他，一地胡拿。"]'),
('yuanqu-9465','唐明皇秋夜梧桐雨・风入松','白朴','元','元曲','yuanqu','','[]','止不过凤箫羯鼓间琵琶，忽剌剌板撒红牙。',121,'元曲/yuanqu.json','["止不过凤箫羯鼓间琵琶，忽剌剌板撒红牙。", "假若更添个六幺花十八，那些儿是败国亡家！可知道陈后主遭着杀伐，皆因唱《后庭花》。", "(旦云)妾死不足惜，但主上之恩，不曾报得，数年恩爱，教妾怎生割舍？(正末云)妃子，不济事了，六军心变，寡人自不能保。", "(唱)。"]'),
('yuanqu-9466','唐明皇秋夜梧桐雨・胡十八','白朴','元','元曲','yuanqu','','[]','似恁地对咱，多应来变了卦。',103,'元曲/yuanqu.json','["似恁地对咱，多应来变了卦。", "见俺留恋着他，龙泉三尺手中拿。", "便不将他刺将，也将他吓杀。", "更问甚陛下，大古是知重俺帝王家？(陈玄礼云)愿陛下早割恩正法。", "(旦云)陛下，怎生救妾身一救？(正末云)寡人怎生是好？(唱)。"]'),
('yuanqu-9467','唐明皇秋夜梧桐雨・落梅风','白朴','元','元曲','yuanqu','','[]','眼儿前不甫能栽起合欢树，恨不得手掌里奇擎着解语花，尽今生翠鸾同跨。',55,'元曲/yuanqu.json','["眼儿前不甫能栽起合欢树，恨不得手掌里奇擎着解语花，尽今生翠鸾同跨。", "怎生般爱他看待他，怎下的教横拖在马嵬坡下！。"]'),
('yuanqu-9468','唐明皇秋夜梧桐雨・殿前欢','白朴','元','元曲','yuanqu','','[]','他是朵娇滴滴海棠花，怎做得闹荒荒亡国祸根芽？再不将曲弯弯远山眉儿画，乱松松白鬓堆鸦。',93,'元曲/yuanqu.json','["他是朵娇滴滴海棠花，怎做得闹荒荒亡国祸根芽？再不将曲弯弯远山眉儿画，乱松松白鬓堆鸦。", "怎下的碜磕马蹄儿脸上踏，则将细袅袅咽喉掐，早把条长挽挽素白练安排下。", "他那里一身受死，我痛煞煞独力难加。"]'),
('yuanqu-9469','唐明皇秋夜梧桐雨・沽美酒','白朴','元','元曲','yuanqu','','[]','没乱杀，怎救拔？没奈何，怎留他？把死限俄延了多半霎，生各支勒杀，陈玄礼闹交加。',53,'元曲/yuanqu.json','["没乱杀，怎救拔？没奈何，怎留他？把死限俄延了多半霎，生各支勒杀，陈玄礼闹交加。", "(高力士引旦下)(正末唱)。"]'),
('yuanqu-9470','唐明皇秋夜梧桐雨・太平令','白朴','元','元曲','yuanqu','','[]','怎的教酩子里题名单骂，脑背后着武士金瓜。',117,'元曲/yuanqu.json','["怎的教酩子里题名单骂，脑背后着武士金瓜。", "教几个鲁莽的宫娥监押，休将那软款的娘娘惊唬。", "你呀，见他，问咱，可怜见唐朝天下。", "(高力士持旦衣上，云)娘娘已赐死了，六军进来看视。", "(陈玄礼率众马践科)(正末做哭科，云)妃子，闪杀寡人也呵！(唱)。"]'),
('yuanqu-9471','唐明皇秋夜梧桐雨・三煞','白朴','元','元曲','yuanqu','','[]','不想你马嵬坡下今朝化，没指望长生殿里当时话。',22,'元曲/yuanqu.json','["不想你马嵬坡下今朝化，没指望长生殿里当时话。"]'),
('yuanqu-9472','唐明皇秋夜梧桐雨・太清歌','白朴','元','元曲','yuanqu','','[]','恨无情卷地狂风刮，可怎生偏吹落我御苑名花！想他魂断天涯，作几缕儿彩霞。',79,'元曲/yuanqu.json','["恨无情卷地狂风刮，可怎生偏吹落我御苑名花！想他魂断天涯，作几缕儿彩霞。", "天那！一个汉明妃远把单于嫁，止不过泣西风泪湿胡笳。", "几曾见六军厮践踏，将一个尸首卧黄沙？。"]'),
('yuanqu-9473','唐明皇秋夜梧桐雨・二煞','白朴','元','元曲','yuanqu','','[]','谁收了锦缠联窄面吴绫袜，空感叹这泪斑斓拥项鲛绡帕。',25,'元曲/yuanqu.json','["谁收了锦缠联窄面吴绫袜，空感叹这泪斑斓拥项鲛绡帕。"]'),
('yuanqu-9474','唐明皇秋夜梧桐雨・川拨棹','白朴','元','元曲','yuanqu','','[]','痛怜他不能够水银灌玉匣，又没甚彩女监宫娃，拽布拖麻，奠洒浇茶。',52,'元曲/yuanqu.json','["痛怜他不能够水银灌玉匣，又没甚彩女监宫娃，拽布拖麻，奠洒浇茶。", "只索浅土儿权时葬下，又不及选山陵，将墓打。"]'),
('yuanqu-9475','唐明皇秋夜梧桐雨・鸳鸯煞','白朴','元','元曲','yuanqu','','[]','黄埃散漫悲风飒，碧云黯淡斜阳下。',80,'元曲/yuanqu.json','["黄埃散漫悲风飒，碧云黯淡斜阳下。", "一程程水绿山青，一步步剑岭巴峡。", "唱道感叹情多，忄西惶泪洒，早得升遐，休休却是今生罢。", "这个不得已的官家，哭上逍遥玉骢马。", "(同下)。"]'),
('yuanqu-9476','唐明皇秋夜梧桐雨・正宫/端正好','白朴','元','元曲','yuanqu','','[]','自从幸西川还京兆，甚的是月夜花朝！这半年来白发添多少，怎打叠愁容貌！。',35,'元曲/yuanqu.json','["自从幸西川还京兆，甚的是月夜花朝！这半年来白发添多少，怎打叠愁容貌！。"]'),
('yuanqu-9477','唐明皇秋夜梧桐雨・幺篇','白朴','元','元曲','yuanqu','','[]','瘦岩岩不避群臣笑，玉仪儿将画轴高挑。',33,'元曲/yuanqu.json','["瘦岩岩不避群臣笑，玉仪儿将画轴高挑。", "荔枝花果香檀卓，目觑了伤怀抱。"]'),
('yuanqu-9478','唐明皇秋夜梧桐雨・倘秀才','白朴','元','元曲','yuanqu','','[]','妃子呵，常记得千秋节华清宫宴乐，七夕会长生殿乞巧。',49,'元曲/yuanqu.json','["妃子呵，常记得千秋节华清宫宴乐，七夕会长生殿乞巧。", "誓愿学连理枝比翼鸟，谁想你乘彩凤返丹霄，命夭！。"]'),
('yuanqu-9479','唐明皇秋夜梧桐雨・呆骨朵','白朴','元','元曲','yuanqu','','[]','寡人有心待盖一座杨妃庙，争奈无权柄谢位辞朝。',79,'元曲/yuanqu.json','["寡人有心待盖一座杨妃庙，争奈无权柄谢位辞朝。", "则俺这孤辰限难熬，更打着离恨天最高。", "在生时同衾枕，不能勾死后也同棺椁。", "谁承望马嵬坡尘土中，可惜把一朵海棠花零落了。"]'),
('yuanqu-9480','唐明皇秋夜梧桐雨・白鹤子','白朴','元','元曲','yuanqu','','[]','那身离殿宇，信步下亭皋。',27,'元曲/yuanqu.json','["那身离殿宇，信步下亭皋。", "见杨柳袅翠蓝丝，芙蓉拆胭脂萼。"]'),
('yuanqu-9481','唐明皇秋夜梧桐雨・幺','白朴','元','元曲','yuanqu','','[]','见芙蓉怀媚脸，遇杨柳忆纤腰。',37,'元曲/yuanqu.json','["见芙蓉怀媚脸，遇杨柳忆纤腰。", "依旧的两般儿点缀上阳宫，他管一灵儿潇洒长安道。"]'),
('yuanqu-9482','唐明皇秋夜梧桐雨・幺','白朴','元','元曲','yuanqu','','[]','常记得碧梧桐阴下立，红牙箸手中敲。',30,'元曲/yuanqu.json','["常记得碧梧桐阴下立，红牙箸手中敲。", "他笑整缕金衣，舞按霓裳乐。"]'),
('yuanqu-9483','唐明皇秋夜梧桐雨・幺','白朴','元','元曲','yuanqu','','[]','到如今翠盘中荒草满，芳树下暗香消。',29,'元曲/yuanqu.json','["到如今翠盘中荒草满，芳树下暗香消。", "空对井梧阴，不见倾城貌。"]'),
('yuanqu-9484','唐明皇秋夜梧桐雨・倘秀才','白朴','元','元曲','yuanqu','','[]','本待闲散心追欢取乐，倒惹的感旧恨天荒地老。',62,'元曲/yuanqu.json','["本待闲散心追欢取乐，倒惹的感旧恨天荒地老。", "怏怏归来凤帏悄，甚法儿挨今宵？懊恼！(带云)回到这寝殿中，一弄儿助人愁也。", "(唱)。"]'),
('yuanqu-9485','唐明皇秋夜梧桐雨・芙蓉花','白朴','元','元曲','yuanqu','','[]','淡氤氲篆烟袅，昏惨剌银灯照。',52,'元曲/yuanqu.json','["淡氤氲篆烟袅，昏惨剌银灯照。", "玉漏迢迢，才是初更报。", "暗觑清霄，盼梦里他来到。", "却不道口是心苗，不住的频频叫。"]'),
('yuanqu-9486','唐明皇秋夜梧桐雨・笑和尚','白朴','元','元曲','yuanqu','','[]','原来是滴溜溜绕闲阶败叶飘，疏剌剌刷落叶被西风扫，忽鲁鲁风闪得银灯爆。',67,'元曲/yuanqu.json','["原来是滴溜溜绕闲阶败叶飘，疏剌剌刷落叶被西风扫，忽鲁鲁风闪得银灯爆。", "厮琅琅鸣殿铎，扑簌簌动朱箔，吉丁当玉马儿向檐间闹。", "(做睡科，唱)。"]'),
('yuanqu-9487','唐明皇秋夜梧桐雨・倘秀才','白朴','元','元曲','yuanqu','','[]','闷打颏和衣卧倒，软兀剌方才睡着。',71,'元曲/yuanqu.json','["闷打颏和衣卧倒，软兀剌方才睡着。", "(旦上，云)妾身贵妃是也。", "今日殿中设宴，宫娥，请主上赴席咱。", "(正末唱)忽见青衣走来报，道太真妃将寡人邀，宴乐。"]'),
('yuanqu-9488','唐明皇秋夜梧桐雨・蛮姑儿','白朴','元','元曲','yuanqu','','[]','懊恼，窨约。',67,'元曲/yuanqu.json','["懊恼，窨约。", "惊我来的又不是楼头过雁，砌下寒蛩，檐前玉马，架上金鸡；是兀那窗儿外梧桐上雨潇潇。", "一声声洒残叶，一点点滴寒梢，会把愁人定虐。"]'),
('yuanqu-9489','唐明皇秋夜梧桐雨・叨叨令','白朴','元','元曲','yuanqu','','[]','一会价紧呵，似玉盘中万颗珍珠落；一会价响呵，似玳筵前几簇笙歌闹；一会价清呵，似翠岩头一派寒泉瀑；一会价猛呵，似绣旗下数面征鼙操。',86,'元曲/yuanqu.json','["一会价紧呵，似玉盘中万颗珍珠落；一会价响呵，似玳筵前几簇笙歌闹；一会价清呵，似翠岩头一派寒泉瀑；一会价猛呵，似绣旗下数面征鼙操。", "兀的不恼杀人也么哥！则被他诸般儿雨声相聒噪。"]'),
('yuanqu-9490','唐明皇秋夜梧桐雨・倘秀才','白朴','元','元曲','yuanqu','','[]','这雨一阵阵打梧桐叶凋，一点点滴人心碎了。',43,'元曲/yuanqu.json','["这雨一阵阵打梧桐叶凋，一点点滴人心碎了。", "枉着金井银床紧围绕，只好把泼枝叶做柴烧，锯倒。"]'),
('yuanqu-9491','唐明皇秋夜梧桐雨・滚绣球','白朴','元','元曲','yuanqu','','[]','长生殿那一宵，转回廊，说誓约，不合对梧桐并肩斜靠，尽言词絮絮叨叨。',88,'元曲/yuanqu.json','["长生殿那一宵，转回廊，说誓约，不合对梧桐并肩斜靠，尽言词絮絮叨叨。", "沉香亭那一朝，按霓裳，舞六幺，红牙箸击成腔调，乱宫商闹闹炒炒。", "是兀那当时欢会栽排下，今日凄凉厮辏着，暗地量度。"]'),
('yuanqu-9492','唐明皇秋夜梧桐雨・三煞','白朴','元','元曲','yuanqu','','[]','润蒙蒙杨柳雨，凄凄院宇侵帘幕。',97,'元曲/yuanqu.json','["润蒙蒙杨柳雨，凄凄院宇侵帘幕。", "细丝丝梅子雨，装点江干满楼阁。", "杏花雨红湿阑干，梨花雨玉容寂寞。", "荷花雨翠盖翩翩，豆花雨绿叶潇条。", "都不似你惊魂破梦，助恨添愁，彻夜连宵。", "莫不是水仙弄娇，蘸杨柳洒风飘？。"]'),
('yuanqu-9493','唐明皇秋夜梧桐雨・二煞','白朴','元','元曲','yuanqu','','[]','口床口床似喷泉瑞兽临双沼，刷刷似食叶春蚕散满箔。',77,'元曲/yuanqu.json','["口床口床似喷泉瑞兽临双沼，刷刷似食叶春蚕散满箔。", "乱洒琼阶，水传宫漏，飞上雕檐，酒滴新槽。", "直下的更残漏断，枕冷衾寒，烛灭香消。", "可知道夏天不觉，把高凤麦来漂。"]'),
('yuanqu-9494','唐明皇秋夜梧桐雨・黄钟煞','白朴','元','元曲','yuanqu','','[]','顺西风低把纱窗哨，送寒气频将绣户敲。',179,'元曲/yuanqu.json','["顺西风低把纱窗哨，送寒气频将绣户敲。", "莫不是天故半人愁闷搅？前度铃声响栈道。", "似花奴羯鼓调，如伯牙《水仙操》。", "洗黄花润篱落，渍苍苔倒墙角。", "渲湖山漱石窍，浸枯荷溢池沼。", "沾残蝶粉渐消。", "，洒流萤焰不着。", "绿窗前促织叫，声相近雁影高。", "催邻砧处处捣，助新凉分外早。", "斟量来这一宵，雨和人紧厮熬。", "伴铜壶点点敲，雨更多泪不少。", "雨湿寒梢，泪染龙袍。", "不肯相饶。", "共隔着一树梧桐直滴到晓。"]'),
('yuanqu-9495','南吕・一枝花','孙叔顺','元','元曲','yuanqu','','[]','不恋蜗角名，岂问蝇头利？世情看冷暖，人面逐高低。',59,'元曲/yuanqu.json','["不恋蜗角名，岂问蝇头利？世情看冷暖，人面逐高低。", "闲是闲非，僻掉的都伶俐，百年身图画里。", "本待要快活逍遥，情愿待休官罢职。"]'),
('yuanqu-9496','梁州・谁待想锦衣玉食？甘心守淡饭黄齑。向林泉选一答儿清幽地，闲时','孙叔顺','元','元曲','yuanqu','','[]','一曲，闷后三杯。',97,'元曲/yuanqu.json','["一曲，闷后三杯。", "柴门草户，茅舍疏篱。", "守着咱稚子山妻，伴着几个故友相识。", "每日价笑吟吟谈古论今，闲遥遥游山玩水，乐陶陶下象围棋。", "早起，晚夕，吃醉了重还醉，叹白发紧相逼。", "百岁光阴能有几？快活了是便宜。"]'),
('yuanqu-9497','煞尾・都则是两轮日月搬兴废，一合乾坤洗是非。直宿到红日三竿偃然睡，','孙叔顺','元','元曲','yuanqu','','[]','那些儿况味谁知？一任莺啼唤不起。',16,'元曲/yuanqu.json','["那些儿况味谁知？一任莺啼唤不起。"]'),
('yuanqu-9498','中吕・粉蝶儿','孙叔顺','元','元曲','yuanqu','','[]','海马闲骑，则为瘦人参请他医治，背药包的刘寄奴跟随。',64,'元曲/yuanqu.json','["海马闲骑，则为瘦人参请他医治，背药包的刘寄奴跟随。", "一脚的陌门东，来到这干阁内，飞帘簌地。", "能医其乡妇沉疾，因此上，共宾郎结成欢会。"]'),
('yuanqu-9499','醉春风・说远志诉莲心，靠肌酥偎玉体，食膏粱五味卧重ブ，阳起是你，','孙叔顺','元','元曲','yuanqu','','[]','受用他笑吐丁音、软柔钟乳，到有些五灵之气。',21,'元曲/yuanqu.json','["受用他笑吐丁音、软柔钟乳，到有些五灵之气。"]'),
('yuanqu-9500','迎仙客・行过芍药圃、菊花篱，沉香亭色情何太急！停立在曲槛边，从容','孙叔顺','元','元曲','yuanqu','','[]','在芳径里。',21,'元曲/yuanqu.json','["在芳径里。", "待黄昏不想当归，尚有百部徘徊意。"]'),
('yuanqu-9501','红绣鞋・半夏遐蛇床上同睡，芫花边似燕子双飞。则道洞房风月少人知，','孙叔顺','元','元曲','yuanqu','','[]','不想被红娘先蹴破。',26,'元曲/yuanqu.json','["不想被红娘先蹴破。", "使君子受凌迟，便有他白头公难救你。"]'),
('yuanqu-9502','耍孩儿・木贼般合解到当官跪，刀笔吏焉能放你！便将白纸取招伏，选剥','孙叔顺','元','元曲','yuanqu','','[]','了衤昆布无衣。',52,'元曲/yuanqu.json','["了衤昆布无衣。", "荜澄茄拷打得青皮肿，玄胡索拴缚得狗脊低，你便穿山甲应何济？议论得罪名管仲，毕拨得文案无疑。"]'),
('yuanqu-9503','三煞・他做官司的剖决明，告私情的能指实，监囚在里人心碎。一个旱莲','孙叔顺','元','元曲','yuanqu','','[]','腮空滴白凡泪，一个漏芦腿难禁苦仗笞。',44,'元曲/yuanqu.json','["腮空滴白凡泪，一个漏芦腿难禁苦仗笞。", "吊疼痛，添憔悴。", "问甚么干连你父子？可惜教带累他乌梅。"]'),
('yuanqu-9504','二煞・意浓甜有苦参，事多凶大戟，今日个身遭缧绁，犹道是心甘遂。清','孙叔顺','元','元曲','yuanqu','','[]','廉家却有这糊突事，时罗姐难为官宜妻。',43,'元曲/yuanqu.json','["廉家却有这糊突事，时罗姐难为官宜妻。", "浪荡子合当废，破故纸揩不了腥臭，寒水石洗不尽身肌。"]'),
('yuanqu-9505','一煞・向雨余凉夜中，对天南星月底，说合成织女牵牛会。指望常山远水','孙叔顺','元','元曲','yuanqu','','[]','恩情久，不想这剪草除根巾帻低，那一个画不成青黛蛾眉。',26,'元曲/yuanqu.json','["恩情久，不想这剪草除根巾帻低，那一个画不成青黛蛾眉。"]'),
('yuanqu-9506','尾・骂你个辱先灵的蒋太医，我看你乍回乡归故里！蔓荆子续断了通奸罪，','孙叔顺','元','元曲','yuanqu','','[]','则被那散杏子的康瘤儿笑杀你！。',15,'元曲/yuanqu.json','["则被那散杏子的康瘤儿笑杀你！。"]'),
('yuanqu-9507','仙吕・点绛唇咏教习鼓诉冤','孙叔顺','元','元曲','yuanqu','','[]','每日学按龙韬，演习虎略。',27,'元曲/yuanqu.json','["每日学按龙韬，演习虎略。", "初开教，若论功劳，则俺先来到。"]'),
('yuanqu-9508','混江龙・助威声号，将我先鸣三擂发根苗。渐渐的排成戈戟，纷纷的收聚','孙叔顺','元','元曲','yuanqu','','[]','枪刀。',82,'元曲/yuanqu.json','["枪刀。", "则这两片皮常与军官为耳目，一生心不离了小校做知交。", "虽是我有声难说，有运维消，又不比鸣廉击柝喝号。", "摇铃向军前，则我为头儿闹。", "面皮上常过了无数，助罗边不住的频敲。"]'),
('yuanqu-9509','油葫芦・怎比恁那悠悠吹画角，也每不汤着不动着，教瞒儿满腹中恶气怎','孙叔顺','元','元曲','yuanqu','','[]','生消。',53,'元曲/yuanqu.json','["生消。", "夜阑时直捶到金鸡儿报，早晨间直熬的金乌落。", "他每都披着纸甲，挂着战袍，番来复去由闹，早难道杀气阵云高。"]'),
('yuanqu-9510','天下乐・却什么三十年学六韬，好教我逐朝心内焦，他每没一个有才能有','孙叔顺','元','元曲','yuanqu','','[]','机谋有智略。',33,'元曲/yuanqu.json','["机谋有智略。", "每日加空虚了五六番，干盘了十数遭，恰便似一场家杂剧了。"]'),
('yuanqu-9511','醉中天・想当日两军闹，起全翼赴宣朝。将我击破花腔，它每都哭破眼胞。','孙叔顺','元','元曲','yuanqu','','[]','可正是发擂催军校，不付能勾引的离城去，又将他黎民掳掠，这的是恁破黄巢头件功劳。',39,'元曲/yuanqu.json','["可正是发擂催军校，不付能勾引的离城去，又将他黎民掳掠，这的是恁破黄巢头件功劳。"]'),
('yuanqu-9512','金盏儿・他每哭声苦，可教我怨声高。被我将他众英雄引上阴陵道，他每','孙叔顺','元','元曲','yuanqu','','[]','教场中胆气更那里有分毫。',45,'元曲/yuanqu.json','["教场中胆气更那里有分毫。", "都不肯一心于国死，则待半路里转身逃。", "早难道养军千日，又得用在今朝。"]'),
('yuanqu-9513','南吕・一枝花','孙叔顺','元','元曲','yuanqu','','[]','绣帏中受坎坷，锦帐内挨囚禁。',66,'元曲/yuanqu.json','["绣帏中受坎坷，锦帐内挨囚禁。", "抛掷在忧虑海，啜赚我在闷愁林，好教人难受难禁。", "非是咱淹润，有生活懒动针。", "一会家暗暗思量，思量罢重还再审。"]'),
('yuanqu-9514','梁州・俺根前无疼无热，在谁行留意留情。这烦恼孝经起序才读朕。空教','孙叔顺','元','元曲','yuanqu','','[]','人逐期盼望，每夜吟沉。',99,'元曲/yuanqu.json','["人逐期盼望，每夜吟沉。", "专闻脚步，频听声音。", "那一夜不等到更深，不来也展转沉吟。", "在谁家里打马投壶？在谁家里低唱浅斟？在谁家里并枕同衾？无般儿不侵，纵然不醉连宵饮。", "一脚的踏出门程，不许寻直恁，莫渝滥荒淫。"]'),
('yuanqu-9515','尾・往常时撒拗何曾恁，自当日着迷直至今。你取欢娱我图甚？怎禁那厮','孙叔顺','元','元曲','yuanqu','','[]','负心。',19,'元曲/yuanqu.json','["负心。", "不来也，又教你倚定鲛绡枕头儿盹。"]'),
('yuanqu-9516','仙吕・赏花时','杨果','元','元曲','yuanqu','','[]','秋水粼粼古岸苍，萧索疏篱偎短冈。',33,'元曲/yuanqu.json','["秋水粼粼古岸苍，萧索疏篱偎短冈。", "山色日微茫，黄花绽也，妆点马蹄香。"]'),
('yuanqu-9517','胜葫芦・见一簇人家入屏帐，竹篱折，补苔墙，破设设柴门上张着破网。','杨果','元','元曲','yuanqu','','[]','几间茅屋，一竿风旆，摇曳挂长江。',16,'元曲/yuanqu.json','["几间茅屋，一竿风旆，摇曳挂长江。"]'),
('yuanqu-9518','幺・客况凄凄又一春，十载区区已四旬。犹自在红尘，愁眉镇锁，白发又','杨果','元','元曲','yuanqu','','[]','添新。',3,'元曲/yuanqu.json','["添新。"]'),
('yuanqu-9519','煞尾・腹中愁，心间闷，九曲柔肠闷损。白日伤神犹自轻，到晚来更关情。','杨果','元','元曲','yuanqu','','[]','唱道则听得玉漏声频，搭伏定鲛绡枕头儿盹。',74,'元曲/yuanqu.json','["唱道则听得玉漏声频，搭伏定鲛绡枕头儿盹。", "客窗夜水，有谁人存问？二三更睡不得被儿温。", "花点苍苔绣不匀，莺唤垂杨语未真。", "帘幕絮纷纷，日长人困，风暖兽烟喷。"]'),
('yuanqu-9520','幺・一自檀郎共锦衾，再不曾暗掷金钱卜远人。香脸笑生春，旧时衣裉，','杨果','元','元曲','yuanqu','','[]','宽放出二三分。',7,'元曲/yuanqu.json','["宽放出二三分。"]'),
('yuanqu-9521','幺・倚定门儿语笑喧，来往星眸厮顾恋。彼各正当年，花阴柳影，月底共','杨果','元','元曲','yuanqu','','[]','星前。',3,'元曲/yuanqu.json','["星前。"]'),
('yuanqu-9522','仙吕・翠裙腰','杨果','元','元曲','yuanqu','','[]','莺穿细柳翻金翅，迁上最高枝。',35,'元曲/yuanqu.json','["莺穿细柳翻金翅，迁上最高枝。", "海棠零乱飘阶址，堕胭脂，共谁同唱送春词？。"]'),
('yuanqu-9523','金盏儿・减容姿，瘦腰肢，绣床尘满慵针指。眉懒画，粉羞施，憔悴死。','杨果','元','元曲','yuanqu','','[]','无尽闲愁将甚比？恰如梅子雨丝丝。',16,'元曲/yuanqu.json','["无尽闲愁将甚比？恰如梅子雨丝丝。"]'),
('yuanqu-9524','绿窗愁・有客持书至，还喜却嗟咨。未委归期约几时，先拆破鸳鸯字。原','杨果','元','元曲','yuanqu','','[]','来则是卖弄他风流浪子，夸翰墨，显文词，枉用了身心空费了纸。',29,'元曲/yuanqu.json','["来则是卖弄他风流浪子，夸翰墨，显文词，枉用了身心空费了纸。"]'),
('yuanqu-9525','赚尾・总虚脾，无实事，乔问候的言辞怎使？复别了花笺重作念，偏自家','杨果','元','元曲','yuanqu','','[]','少负你相思。',51,'元曲/yuanqu.json','["少负你相思。", "唱道再展放重读，读罢也无言暗切齿。", "沉吟了数次，骂你个负心贼堪恨，把一封寄来书都扯做纸条儿。"]'),
('yuanqu-9526','功臣宴敬德不伏老・仙吕/点绛唇','杨梓','元','元曲','yuanqu','','[]','想当日炀帝东亡，那其间主公未定。',32,'元曲/yuanqu.json','["想当日炀帝东亡，那其间主公未定。", "中原困，盗起纷纷。", "帝星照河东郡。"]'),
('yuanqu-9527','功臣宴敬德不伏老・混江龙','杨梓','元','元曲','yuanqu','','[]','想着咱初降唐时分，事君竭力致其身，凭着俺十八般武艺，定下了六十四处征尘。',204,'元曲/yuanqu.json','["想着咱初降唐时分，事君竭力致其身，凭着俺十八般武艺，定下了六十四处征尘。", "都是神乌马踏成了这唐社稷，只这个水磨鞭打就了李乾坤，记当日呵扶持主上，今日呵宴赏公卿。", "虽然是功分大小，也须索位列卑尊。", "有功者上首而坐，功少者下位而存。", "若不将咱为头而赐坐，这下位里难以安身。", "老将军非为夸己，也不是我骄人。", "老将军为头，次之是尉迟。", "除此外谁与咱相争竞。", "(秦)老将军有擎天手段(尉)你道俺有擎天手段，老将军俺道你可有盖世的功勋。"]'),
('yuanqu-9528','功臣宴敬德不伏老・油葫芦','杨梓','元','元曲','yuanqu','','[]','(尉)见军师数次殷勤，量尉迟何足沦？怎消的当今天子重贤臣。',177,'元曲/yuanqu.json','["(尉)见军师数次殷勤，量尉迟何足沦？怎消的当今天子重贤臣。", "(李土)吾乃季道宗是也，赴功臣宴走一遭去来。", "(相见介)(李道宗云)这酒该我饮，该我簪花。", "(尉唱)这厮们走将来上首头坐，全无些谦逊，恼得咱便不登登按不住心头忿。", "(李)一杯酒吃了便罢，甚么上首头下首头！我怕你上首头那势凶，下首头怎坐存？我本待要推更衣，又不敢先逃遁。", "我待不言语呵，著这厮欺负俺老功臣。"]'),
('yuanqu-9529','功臣宴敬德不伏老・天下乐','杨梓','元','元曲','yuanqu','','[]','叔宝老将军，你便是活佛也，教咱怎生忍？老将军你便休也不嗔，非是我情性狠。',123,'元曲/yuanqu.json','["叔宝老将军，你便是活佛也，教咱怎生忍？老将军你便休也不嗔，非是我情性狠。", "量这个泼无徒怎敢来小觑人。", "我割舍得发一会儿村，使一会儿狠。", "道宗。", "你有何功劳，敢坐上首，簪我的花，饮我的酒？(李)尉迟恭，你有甚么来要打我？(尉)我不打你这泼无徒教咱怎的忍？。"]'),
('yuanqu-9530','功臣宴敬德不伏老・那吒令','杨梓','元','元曲','yuanqu','','[]','那厮，你听我说。',72,'元曲/yuanqu.json','["那厮，你听我说。", "知尉迟，辕门外的众军；请尉迟，晋天下的万民；谮尉迟的，是你这样小人。", "我将这鏖战册件件与你观，功劳簿桩桩与你论，那其间便见得元勋。"]'),
('yuanqu-9531','功臣宴敬德不伏老・鹊踏枝','杨梓','元','元曲','yuanqu','','[]','我也曾在沙场上领着敌军，舍着残生。',54,'元曲/yuanqu.json','["我也曾在沙场上领着敌军，舍着残生。", "我也曾揸鼓夺旗，抓将挟人。", "我也曾杀得败残兵骨碌碌人头乱滚，渗渗呵热血相喷。"]'),
('yuanqu-9532','功臣宴敬德不伏老・前腔','杨梓','元','元曲','yuanqu','','[]','想为官的如骑着虎，他用人似积薪，教后来人在上居尊。',103,'元曲/yuanqu.json','["想为官的如骑着虎，他用人似积薪，教后来人在上居尊。", "李道宗这厮呵他非武非文，他曾立甚么功勋？怎敢欺侮俺开国的功臣？他走将来上首头无些谦逊，论功处谁敢欺人？若不是军师救了咱危困，他须是一枝一叶，俺须是四海他人。"]'),
('yuanqu-9533','功臣宴敬德不伏老・前腔','杨梓','元','元曲','yuanqu','','[]','也不索胡云，休论我性不容人，拳打下谗臣，恁般生嗔。',120,'元曲/yuanqu.json','["也不索胡云，休论我性不容人，拳打下谗臣，恁般生嗔。", "若不是军师可便劝准，我没来由献甚么勤。", "知他是君负欺臣负欺君。", "若留得个恶楚秦，若留得西楚霸上在呵，怎生便敢诛了韩信？古人言语不虚云。", "想淮阴与鄂国，咱两个同时运。", "一任那渔樵闲话，少不得青史标名。"]'),
('yuanqu-9534','功臣宴敬德不伏老・中吕/粉蝶儿','杨梓','元','元曲','yuanqu','','[]','(尉)为甚么忙出皇州？我将这脱空禅近来参透。',51,'元曲/yuanqu.json','["(尉)为甚么忙出皇州？我将这脱空禅近来参透。", "而不向杀人场闹里钻头，向职田庄。", "居止处。", "将我□□生涯穷究。"]'),
('yuanqu-9535','功臣宴敬德不伏老・醉春风','杨梓','元','元曲','yuanqu','','[]','牢记住战争心，紧抄定抓将手。',68,'元曲/yuanqu.json','["牢记住战争心，紧抄定抓将手。", "□□□云阳市上血染了衣，出那娘的丑，这一个须索□□□□言。", "将我来罪责，若没有军师呵，可不道有谁人将我来搭救。"]'),
('yuanqu-9536','功臣宴敬德不伏老・迎仙客','杨梓','元','元曲','yuanqu','','[]','(尉)怪的这长亭□驿马多。',134,'元曲/yuanqu.json','["(尉)怪的这长亭□驿马多。", "(众)老将军请住马。", "(尉)家童，与我带住马来。", "(童)理会得。", "(尉)我忙下得紫骅骝，唐十宰众公卿可都这里有。", "我可便向前来，忙问候。", "(尉)众大人为何到此？(众)为老将军远行，俺众公卿等特来与老将军饯行。", "(尉)俺这里听说罢缘由，怎消得偌大远劳台候。"]'),
('yuanqu-9537','功臣宴敬德不伏老・红绣鞋','杨梓','元','元曲','yuanqu','','[]','不索你个军师生受，(众跪介)(尉)请起来唐十宰文武公侯。',134,'元曲/yuanqu.json','["不索你个军师生受，(众跪介)(尉)请起来唐十宰文武公侯。", "恁只待要这搭儿折杀下尉迟休。", "众公卿休将我来耻笑，怎么将恩义变为仇。", "那日若无军师。", "与列位大人呵，可著我险峰儿难措手。", "(徐)将酒来，老将军再饮一杯。", "(尉)军师大人，怎么不见叔宝老将军染病在家。", "(众)叔宝将军染病在家。"]'),
('yuanqu-9538','功臣宴敬德不伏老・满庭芳','杨梓','元','元曲','yuanqu','','[]','(尉)可惜老了一个先锋哀帅首，他曾杀得人有家难奔，有国难逃。',187,'元曲/yuanqu.json','["(尉)可惜老了一个先锋哀帅首，他曾杀得人有家难奔，有国难逃。", "只他那十八般武艺都学就，六韬估看得来哀滑熟。", "只他那嘶杀处全无一个对手，只他那持处谁敢与他做敌头，上阵处搀争斗，不刺刺门旗开处，两阵对员，那壁厢问道：大唐家那员名将出马？俺这里回言道：胡国公秦叔宝出马。", "那壁厢乃便回言说道，不好了也。", "(尉)不喇喇闻风儿便走。", "(众)奸一位老将军。", "(尉)军师，他端的要一心儿分破下帝上忧。"]'),
('yuanqu-9539','功臣宴敬德不伏老・尾声','杨梓','元','元曲','yuanqu','','[]','饯一道咸阳陌上尘，折一枝霸陵桥上柳。',56,'元曲/yuanqu.json','["饯一道咸阳陌上尘，折一枝霸陵桥上柳。", "众公卿相见知仙行？(徐)老将军早饮一杯。", "(尉)饮过这一杯西出刚关这饯行的酒。"]'),
('yuanqu-9540','功臣宴敬德不伏老・紫花儿序','杨梓','元','元曲','yuanqu','','[]','若不是老相公倾心儿闹，恰便似韩元师伏剑而亡，我便是子房公拂袖而归。',137,'元曲/yuanqu.json','["若不是老相公倾心儿闹，恰便似韩元师伏剑而亡，我便是子房公拂袖而归。", "奶奶，我如今与伴哥每肥草鸡儿，冲糯洒儿。", "在这职田庄受用，可不强似为官？每日闲伴渔樵。", "每闲话，到豁达似文武班齐，落魄忘机。", "谁待要为是非，我向这急流中涌退。", "我如今罢职闲居，若是那铁肋金牙索战，我看他怎生和他相持。"]'),
('yuanqu-9541','功臣宴敬德不伏老・小桃红','杨梓','元','元曲','yuanqu','','[]','不知今日甚风吹，(徐)久别尊颜。',290,'元曲/yuanqu.json','["不知今日甚风吹，(徐)久别尊颜。", "我这里有一拜。", "(尉)军师，我老夫回礼不得了，我如今讲讲不得这里可便权体罪。", "(徐)老将军。", "我和你自别之后，不觉又是三年光景了。", "(尉)军师一自离朝到今日。", "(徐)老将军染甚病证？(尉)天有不测风云，人有旦夕祸福。", "谁想我临老也带着残疾。", "军师，唐家十路总管。", "都好么？(徐)也都没了。", "(尉)消磨了往日英雄辈。", "高士廉，，杜如晦如何？(徐)都闲了。", "(尉)他可都闲身就国？殷开山，程咬金他两个如何？(徐)都已亡了。", "(尉)他两个都归泉世。", "刘文静、秦叔宝他两个如何？(徐)都病了。", "(尉)军师，唐家十路总管，闲的闲，病的病，死的死，如今止有军师和老汉。", "俺一班儿白发故人稀。"]'),
('yuanqu-9542','功臣宴敬德不伏老・金蕉叶','杨梓','元','元曲','yuanqu','','[]','我、我、我便有几颗头敢违宣抗敕？一句话恼得从头便至尾。',54,'元曲/yuanqu.json','["我、我、我便有几颗头敢违宣抗敕？一句话恼得从头便至尾。", "怎着我这胡老子安邦定国？你何不去教李道宗相持来对垒？。"]'),
('yuanqu-9543','功臣宴敬德不伏老・调笑令','杨梓','元','元曲','yuanqu','','[]','他觑了俺这般模样，临老也带着残疾。',76,'元曲/yuanqu.json','["他觑了俺这般模样，临老也带着残疾。", "军师你觑甚么阃外将军八面威。", "但开门只说我是唐家苗裔，只好去高衙行倚官挟势。", "若不是军师劝谏赦了罪累，险些个死无葬身之地。"]'),
('yuanqu-9544','功臣宴敬德不伏老・秃厮儿','杨梓','元','元曲','yuanqu','','[]','(尉)我怎扶持江山社稷？难沦着鞭简共楂槌你可待强扶持尉迟在军阵里，高丽家捺相持，可教谁敌？。',46,'元曲/yuanqu.json','["(尉)我怎扶持江山社稷？难沦着鞭简共楂槌你可待强扶持尉迟在军阵里，高丽家捺相持，可教谁敌？。"]'),
('yuanqu-9545','功臣宴敬德不伏老・圣药王','杨梓','元','元曲','yuanqu','','[]','军师你莫疑惑，其实的去不得，到朝叫，说与圣人知。',564,'元曲/yuanqu.json','["军师你莫疑惑，其实的去不得，到朝叫，说与圣人知。", "到朝中说与众□□□，如今年纪近丁七十，染□病疾，提起那排军布□□□痴。", "(徐)常言道，老将会兵机。", "(尉)休休休便提起老将会兵机。", "(旦)老爷，你那拐儿。", "(尉)奶奶，老夫风疾举发，去不得。", "(徐)老将军去不得，□□告回。", "(尉)奶奶，送了军师出去，闭了门。", "(徐)出的这门□，我观此人容貌，不是那有病的。", "方才拜下去，那两条□□尤如铁柱一般，那老夫人又在旁边说道，老爷，你那拐儿。", "眉头一层，计上心来，众军校那里。", "(卒)有分付。", "(徐)□众人到这人家去安下，要他男子汉闸草喂马，女人家补衲袄革翁鞋。", "你说，我是高丽的小军，他家是有钱的，□问他要白米饭，妙嫩鸡儿，冲糯酒儿吃，那一个老子口礼打将去。", "(卒)列位，方才老爷分付，着俺拣这房子打进去，开门，开门。", "(尉)奶奶，又是甚么人在外头叫？不要放他进来。", "(旦)理会得。", "(卒)我每是下高丽的小军，行到这里，天色已晚，借你房子歇息一歇息。", "男子汉闸草喂马，女人家补衲袄革翁鞋。", "又要白米饭，炒嫩鸡儿，冲糯酒儿吃。", "夜晚间又要洗洗澡，槌槌腰，刺刺屁股儿。", "(旦)村弟子孩儿，你是甚么人，这等无礼？待我哄他一哄，你在这里歇息，我闭了门者。", "(卒作叫嚷介)(尉)奶奶，外面又是甚么人喧嚷？(旦云)(尉)这厮好无礼，待我自去回他，众长官。", "我这房屋窄小，养不得马，你到别家去罢。"]'),
('yuanqu-9546','功臣宴敬德不伏老・麻郎儿','杨梓','元','元曲','yuanqu','','[]','这厮他便恶狠狠的叫起。',44,'元曲/yuanqu.json','["这厮他便恶狠狠的叫起。", "雄纠纠的欺谁？你毁伤我唐家宰职，(打介)著这厮吃我一会儿脚踢拳槌。"]'),
('yuanqu-9547','功臣宴敬德不伏老・耍三台','杨梓','元','元曲','yuanqu','','[]','你须知咱名讳，尽忠心天知地知。',99,'元曲/yuanqu.json','["你须知咱名讳，尽忠心天知地知。", "这一场小可如美良川交兵的手段，御科园单鞭夺槊的雄威。", "小可如牛口谷鞭伏了窦建德，小可如下河东与刘黑闼相持。", "你看我再施逞生擒王世充的英雄，你看我重施展活捉□世猛当时的气力。"]'),
('yuanqu-9548','功臣宴敬德不伏老・幺篇','杨梓','元','元曲','yuanqu','','[]','我老只老呵，老了咱些年纪；老只老呵，老不了我脑中武艺。',139,'元曲/yuanqu.json','["我老只老呵，老了咱些年纪；老只老呵，老不了我脑中武艺。", "老只老呵，老不了我龙韬虎略；老只老呵，老不-下我妙策神机。", "老只老呵，老不了我一片忠心贯日；老只老呵，尚几自万夫难敌。", "(徐)老将军，你便索要去，只怕你老了，去不得。", "(尉)俺老只老，止不过添下些雪鬓霜髭；老只老，又不曾驼腰曲背。"]'),
('yuanqu-9549','功臣宴敬德不伏老・尾声','杨梓','元','元曲','yuanqu','','[]','老只老呵，只我这水磨鞭不曾长出些白髭须，量这厮何须咱费力。',99,'元曲/yuanqu.json','["老只老呵，只我这水磨鞭不曾长出些白髭须，量这厮何须咱费力。", "你看这厮，明日在垓心里，绰见我那铁扑头，红抹额，乌油甲，皂罗袍，他便跳下马受绳缚，着这厮卷了旗，卸下甲，收了军，拱手儿降俺这大唐同。", "(下)。"]'),
('yuanqu-9550','功臣宴敬德不伏老・双调/新水令','杨梓','元','元曲','yuanqu','','[]','只俺这水磨鞭准准的闲放了一年，不知足那一个合死的与我交战。',124,'元曲/yuanqu.json','["只俺这水磨鞭准准的闲放了一年，不知足那一个合死的与我交战。", "重磨下新日月，再整顿那旧山川。", "只被我剿除了六十四处狼烟，更有一千阵恶征战。", "大小三军，摆开阵势者。", "(丑)来将何人？(尉)尉迟公是你的爹爹。", "(丑)尉迟，你敢来与俺交战？(尉)大小三军，擂起鼓来。"]'),
('yuanqu-9551','功臣宴敬德不伏老・雁儿落','杨梓','元','元曲','yuanqu','','[]','(尉)骤骅骝走似烟，骤骅骝走似烟，战马儿疾如箭。',47,'元曲/yuanqu.json','["(尉)骤骅骝走似烟，骤骅骝走似烟，战马儿疾如箭。", "莫道是平地上走不出，便走到那鬼窟洞里也直寻见。"]'),
('yuanqu-9552','功臣宴敬德不伏老・得胜令','杨梓','元','元曲','yuanqu','','[]','呀，这的是难比美良川，折么尼走上焰魔火，今日是你合休日，今年是你该死年。',194,'元曲/yuanqu.json','["呀，这的是难比美良川，折么尼走上焰魔火，今日是你合休日，今年是你该死年。", "当先，不喇喇一骑马疾如箭；心坚，□□□□□懒赠鞭。", "(小校)把这厮与我绑了，去见圣上去□。", "(徐)下宫徐茂公是也。", "今闻得尉迟敬德活拿了铁肋金牙，这早晚敢待来也。", "小校，尉迟老将军到来，报复□□知道。", "(尉)老夫尉迟是也。", "擒了铁肋金牙，将军府里报功去也。", "(卒)□□。", "(相见介)(徐)老将军鞍马劳神，怎生擒了这厮？慢慢的说一遍。"]'),
('yuanqu-9553','功臣宴敬德不伏老・甜水令','杨梓','元','元曲','yuanqu','','[]','我闲居时老弱恁赢，厮杀处身轻体健。',111,'元曲/yuanqu.json','["我闲居时老弱恁赢，厮杀处身轻体健。", "相持在绿鸭大江边，扑咚咚战鼓声催，二马相交，在垓心鏖战。", "把铁肋金牙活捉下骏马雕鞍。", "(徐)老将军，想昔日在御科园刻马单鞭，今日里扫荡征尘，永息狼烟，把功劳试说一遍，就请挂了黄金印也。", "(尉)。"]'),
('yuanqu-9554','功臣宴敬德不伏老・沽美酒','杨梓','元','元曲','yuanqu','','[]','感水恩赐我竹。',116,'元曲/yuanqu.json','["感水恩赐我竹。", "感皇恩赐我官，重义得列朝班。", "我只愿罢职归农乐残年，向心这职田庄耕锄为伴。", "我只为铁肋金牙逞战权，因此做风颠。", "准知道军师探病原，施机尘将吾赚，参破下尉迟愚见。", "不伏老向江边恶战，我呵，幸遇得圣王明文修武偃，呀，愿皇图河清宴。"]'),
('yuanqu-9555','功臣宴敬德不伏老・尾声','杨梓','元','元曲','yuanqu','','[]','只因我南征北讨能争战，乞刺德心无怨。',52,'元曲/yuanqu.json','["只因我南征北讨能争战，乞刺德心无怨。", "竹节刚鞭打铁叻金牙，顶门上抓七付眼。", "一人有床安天下，万国来朝贺太平。"]'),
('yuanqu-9556','月明和尚度柳翠・仙吕/赏花时','李寿卿','元','元曲','yuanqu','','[]','这月明曾碾破银河万里空，这和尚僻击响金陵半夜钟，端的个洗碧落露浓。',155,'元曲/yuanqu.json','["这月明曾碾破银河万里空，这和尚僻击响金陵半夜钟，端的个洗碧落露浓。", "(行者云)你这和尚，风张风势，说谎调皮，没些儿至诚的。", "(正末唱)也不是我脱空卖弄，(行者云)正是个风魔和尚，挑着这个，不知是甚么东西，恰似个烧饼的晃子。", "你家又不卖饼，要他怎的？不如打破了罢。", "(做打破科)(正末唱)呀、呀、呀，则一拳打破了广寒宫。"]'),
('yuanqu-9557','月明和尚度柳翠・幺篇','李寿卿','元','元曲','yuanqu','','[]','早不见摊子香飘八月风。',219,'元曲/yuanqu.json','["早不见摊子香飘八月风。", "(行者云)八月风腊月雪，冻的要不的。", "(正末云)你休笑我。", "(唱)这的是蟾影光磨百炼铜，这月曾照兴废古今同，你则看那北邙山的故冢。", "(行者云)你这个和尚，则要吃酒吃肉，真是滥僧。", "(正末云)谁是真僧。", "谁是滥僧？(行者云)我是真僧，你是滥僧。", "(正末云)谁是真僧，谁是滥僧？(行者云)你是真僧，我是滥僧，呸，可颠倒了。", "(正末云)你和我争甚么人我，那楚家的陵丘，汉家的墓冢，都在那里也呵，你试觑波。", "(唱)都一般潇洒月明中。", "(下)。"]'),
('yuanqu-9558','月明和尚度柳翠・仙吕/点绛唇','李寿卿','元','元曲','yuanqu','','[]','自从五派禅分，要知根本，西来信，则为这懵懂禅昏，我也曾扯住俺那达摩问。',35,'元曲/yuanqu.json','["自从五派禅分，要知根本，西来信，则为这懵懂禅昏，我也曾扯住俺那达摩问。"]'),
('yuanqu-9559','月明和尚度柳翠・混江龙','李寿卿','元','元曲','yuanqu','','[]','直待要削开混沌，月为精魄柳为魂。',135,'元曲/yuanqu.json','["直待要削开混沌，月为精魄柳为魂。", "一任着纷纷白眼，管甚么滚滚红尘！恰才个袖拂清风临九陌，又早是杖挑明月可便扣三门。", "则为我这半生花酒为檀信，其实的倦贪名利，因此上不断您这腥荤。", "(云)有人来问贫僧，如何是佛？我说：你说的便是。", "有人来问贫僧：如何是道？我道：你道的便是。", "(唱)。"]'),
('yuanqu-9560','月明和尚度柳翠・鹊踏枝','李寿卿','元','元曲','yuanqu','','[]','你则合映着孤村，你却待罩着荒坟。',123,'元曲/yuanqu.json','["你则合映着孤村，你却待罩着荒坟。", "(旦儿云)我这里住如何？(正末云)不争你在这里住呵。", "(唱)不甫能栽向东家，却又早苫上西邻。", "(旦儿云)我那里听你那风言风语。", "(正末云)你可怕那风雨里那，(唱)你休那般絮纷纷似香绵乱滚，柳也，你又早这般安排下断送行人。"]'),
('yuanqu-9561','月明和尚度柳翠・寄生草','李寿卿','元','元曲','yuanqu','','[]','早是这光阴速，更那堪岁月紧，现如今章台怕到春光尽，则这霸陵又早秋霜近，直教楚腰傲杀东风困，有一朝花褪彩云飞。',117,'元曲/yuanqu.json','["早是这光阴速，更那堪岁月紧，现如今章台怕到春光尽，则这霸陵又早秋霜近，直教楚腰傲杀东风困，有一朝花褪彩云飞。", "(旦儿云)我还不老哩。", "(正末云)噤声！(唱)那里取四时柳色黄金嫩？(旦儿云)师父，你休小觑我，我是那镇陌第一人哩。", "(正末唱)。"]'),
('yuanqu-9562','月明和尚度柳翠・后庭花','李寿卿','元','元曲','yuanqu','','[]','你道你是镇柳陌第-人，(云)你认的我么？(旦儿云)我不认得你，你可是谁？(正末云)我是和尚中为头的一个子弟。',280,'元曲/yuanqu.json','["你道你是镇柳陌第-人，(云)你认的我么？(旦儿云)我不认得你，你可是谁？(正末云)我是和尚中为头的一个子弟。", "(旦儿云)那个和尚做子弟来那？(正末云)我说与你我那做子弟处。", "(唱)怎知我上花台端的是第一尊。", "(旦儿云)俺娘看承我，便是地长出菩提树一般哩。", "(正末唱)你娘看承你似地长出菩提树，(云)你敢不是菩提树，(旦儿云)我是甚么？(正末唱)哎，柳也我道来你则是天生来罗汉身。", "(旦儿云)谜言谜语，知他说甚的！(正末唱)劝你呵我是劝着一个木头人。", "哎，柳也你则恋着那锦营花阵。", "(云)你早些儿跟的我出家去罢。", "(旦儿云)我怎么出的家？(正末唱)久以后你少不得这埚儿种下祸根。"]'),
('yuanqu-9563','月明和尚度柳翠・金盏儿','李寿卿','元','元曲','yuanqu','','[]','你道是花与月添神，我道是月与柳招魂。',103,'元曲/yuanqu.json','["你道是花与月添神，我道是月与柳招魂。", "你恋着那清阴半亩香千阵。", "(旦儿云)你看这世界，全是俺花柳妆点成的。", "(正末唱)你道是世间花柳本伶伦，一任你漫天琶柳絮，尽着你满地落风尘，我则去万花丛里过，常是那一叶不沾身。"]'),
('yuanqu-9564','月明和尚度柳翠・赚煞尾','李寿卿','元','元曲','yuanqu','','[]','我本待要蟾宫内栽培的你活，哎，柳也你却待向那牛员外上凋零尽。',128,'元曲/yuanqu.json','["我本待要蟾宫内栽培的你活，哎，柳也你却待向那牛员外上凋零尽。", "惹一番信手拈来斧痕。", "你则听枝上流莺和泪闻，直等的你那皮故成薪。", "你如今正青春，则伴着那暮雨朝云、倚仗着客舍青青柳色新，我本待从根波至本，却把那下梢来不问，哎，柳也，再休提你那永丰坊里旧腰身。", "(下)。"]'),
('yuanqu-9565','月明和尚度柳翠・南吕/一枝花','李寿卿','元','元曲','yuanqu','','[]','我恰才离了曹溪一指前，又来到佛祖三更后。',88,'元曲/yuanqu.json','["我恰才离了曹溪一指前，又来到佛祖三更后。", "我则索分开临济晓，踏破他这葛藤秋。", "百般的救不出白骨荒丘，每日家则恋着花和酒。", "我今番儿度柳，我是个包含着天地风流，只要你肯信俺这波罗蜜咒。"]'),
('yuanqu-9566','月明和尚度柳翠・梁州第七','李寿卿','元','元曲','yuanqu','','[]','投至我度脱的一株翠柳，柳翠口来，少不的搜寻遍四大神州。',217,'元曲/yuanqu.json','["投至我度脱的一株翠柳，柳翠口来，少不的搜寻遍四大神州。", "你倚仗着枝疏叶嫩当时候，不肯道跨天边彩凤，只待要听枝上鸣鸠。", "你可也锁不住心猿意马，却罩定野鹭沙鸥。", "你则恋着他那一时间翠嫩青柔，怎不想久以后绿惨红愁。", "(带云)柳也，你若肯跟我出家去呵，(唱)我着你再休恋那红尘内赤力力虎斗龙争，碧天边来往往乌飞兔走，柳翠崃，早思着绿阴中闹簇簇燕侣莺俦，酒楼，玉沟，跳出那月明圈，不落樵夫勾。", "比及个成材时架梁后，饶你便坚硬心肠似木头，我只着你磨做骷髅。"]'),
('yuanqu-9567','月明和尚度柳翠・隔尾','李寿卿','元','元曲','yuanqu','','[]','你道是月过十五也索还依旧，哎，柳也，谁似你飞尽香绵未肯休，直等的絮满了官街，那其间有谁救？(旦儿云)师父。',193,'元曲/yuanqu.json','["你道是月过十五也索还依旧，哎，柳也，谁似你飞尽香绵未肯休，直等的絮满了官街，那其间有谁救？(旦儿云)师父。", "长老寻你哩。", "(做走科)(正末云)那里去？你待要躲我那。", "(唱)哎，你个迷人的好是费手。", "(旦儿云)师父，行者寻你哩。", "(做走科)(正末云)那里去？你又躲我那。", "(唱)我这个度人的好是缠头。", "(旦儿云)师父，我两次三番躲不过你。", "(正末云)你怎生躲的过我？(唱)谁着你惹一缕清风则在这背巷里走。"]'),
('yuanqu-9568','月明和尚度柳翠・隔尾','李寿卿','元','元曲','yuanqu','','[]','你本恋着朝云暮雨慵回首，却被这明月清风缠杀你那头，不肯将七碗卢仝耐心候。',72,'元曲/yuanqu.json','["你本恋着朝云暮雨慵回首，却被这明月清风缠杀你那头，不肯将七碗卢仝耐心候。", "你解不过这赵州，省不得这悟头。", "柳翠口来，你不向野塘内三眠，偏来渲房取宿。"]'),
('yuanqu-9569','月明和尚度柳翠・牧羊关','李寿卿','元','元曲','yuanqu','','[]','你觑那牛头鬼亲行刃，他把的龙泉剑扯在手。',292,'元曲/yuanqu.json','["你觑那牛头鬼亲行刃，他把的龙泉剑扯在手。", "(带云)柳翠，你若不是我呵，(唱)恰才这清风过，怎了你那六阳会首。", "你跟我去呵，我着你剩积些阴功；你不跟我去呵，早早定了些阳寿。", "你跟我去呵，我着你上明晃晃一条金桥路；你不跟我去呵，便索向翻滚滚千丈奈河流。", "恰才那脖项上可着那钢刀挫。", "哎，柳翠也，抵多少树叶儿便打破你这头。", "(云)且留人者。", "(阎神云)早知圣僧来到，只合远接，接待不着，勿令见罪。", "(正末云)阎神，柳翠犯着何罪？(阎神云)因柳翠触污着圣僧来。", "(正末云)柳翠的罪过，饶的也饶不的？(阎神云)柳翠的罪过，饶他不的。", "鬼力快下手者。", "疾，休推睡里梦里。", "(旦儿做惊醒科，云)兀的不吓杀我也。", "(正末唱)。"]'),
('yuanqu-9570','月明和尚度柳翠・感皇恩','李寿卿','元','元曲','yuanqu','','[]','呀，则见他刀下难收，早吓的汗雨交流，荡了香魂，消了素魄，瞪了星眸。',105,'元曲/yuanqu.json','["呀，则见他刀下难收，早吓的汗雨交流，荡了香魂，消了素魄，瞪了星眸。", "他用着春纤玉手，忙抹这粉颈油头。", "(旦儿云)这的是那里？(正末唱)这的茶房里，桌儿前。", "(旦儿云)这早晚多早晚也？(正末唱)柳翠也，这早晚是午时候。"]'),
('yuanqu-9571','月明和尚度柳翠・采茶歌','李寿卿','元','元曲','yuanqu','','[]','这的是剑光浮，那里也鬼神愁。',208,'元曲/yuanqu.json','["这的是剑光浮，那里也鬼神愁。", "(带云)柳翠，你觑波。", "(唱)兀的不一轮明月在柳梢头。", "枝叶相连百十口，则你那翠眉终日端的为谁愁？(旦儿云)恰才分明的杀坏了我，却又不曾死。", "我待道死来却又生，待道生来却又死。", "生死原来是幻情，幻情灭尽生死止。", "(正末云)假若生死止在何处？速道，速道。", "(旦儿云)师父，我答不的这一转语。", "(正末云)云来云去，虚空本净。", "花开花谢，田地常存。", "(旦儿做拜科，云)弟子早省悟了。", "这回和月常相守也。", "(正末唱)。"]'),
('yuanqu-9572','月明和尚度柳翠・黄钟尾','李寿卿','元','元曲','yuanqu','','[]','你道是这回和月常相守，(带云)我为你走了两番也。',254,'元曲/yuanqu.json','["你道是这回和月常相守，(带云)我为你走了两番也。", "(唱)才赚的春风可便树点头。", "聚莺朋，会燕友，蜂衙喧，蝶梦幽，啭黄鹂，鸣锦鸠，噪昏鸦，覆野鸥，袅金丝，春水沟，拂红裙，夜月楼，酒旗前，望竿后，风又狂，雨又骤，霜正严，雪正厚，霜来欺，月来救，我救的这月里杪椤永长寿。", "(旦儿云)师父，你如今带我那里去？(正末唱)我着你访灵山会首。", "(旦儿云)待我辞别那一班儿姊妹弟兄就跟的去。", "(正末唱)也不索别章台的这故友。", "(旦儿云)师父，为什么不着我别去？(正末云)你道我为甚么不着你别去？(唱)我则怕你又折入情郎画眉手。", "(同下)。"]'),
('yuanqu-9573','月明和尚度柳翠・中吕/粉蝶儿','李寿卿','元','元曲','yuanqu','','[]','投至我度脱的你心回，我着你做师姑大刚来有一个主意，常言道柳絮不沾泥。',97,'元曲/yuanqu.json','["投至我度脱的你心回，我着你做师姑大刚来有一个主意，常言道柳絮不沾泥。", "(带云)柳翠，你跟将我来呵，(唱)不强如万人攀，千人折，我则怕损动了你这春风和气。", "盖因是暮景相催，催的你这瘦伶仃可便翠腰无力。"]'),
('yuanqu-9574','月明和尚度柳翠・醉春风','李寿卿','元','元曲','yuanqu','','[]','早是这日月似飞梭，光阴如逝水。',50,'元曲/yuanqu.json','["早是这日月似飞梭，光阴如逝水。", "你看那席前花影坐间移，想人生能有有几几？参透禅关，了达身命，出离尘世。"]'),
('yuanqu-9575','月明和尚度柳翠・乾荷叶','李寿卿','元','元曲','yuanqu','','[]','你娘呵是个做活的，恨不的待斜飞，你娘呵则是倚仗着你个弟子猱儿势，粘着处休热相偎，逼绰了便是伶俐。',90,'元曲/yuanqu.json','["你娘呵是个做活的，恨不的待斜飞，你娘呵则是倚仗着你个弟子猱儿势，粘着处休热相偎，逼绰了便是伶俐。", "我双关二意说禅机。", "(卜儿云)这和尚不知他说甚么哩。", "(正末唱)老婆婆不解的我这其中意。"]'),
('yuanqu-9576','月明和尚度柳翠・上小楼','李寿卿','元','元曲','yuanqu','','[]','柳翠也，自从你点污了素体，人将你多曾钻刺。',431,'元曲/yuanqu.json','["柳翠也，自从你点污了素体，人将你多曾钻刺。", "郎君每他今后无钱向你的手内，但没权术，吃会抛掷。", "你若到三四五三六里，那其间早则妆幺不得。", "柳翠也，好色的这把骨头儿，你便休恁般寒碎。", "(云)抬了者，抬了者。", "(旦儿云)母亲，将过气球，来，我和师父踢一抛儿咱。", "(卜儿云)下次小的每，将过气球来者。", "(做取气球科)(正末云)柳翠，这个唤做甚么？(旦儿云)师父，这个唤做难当的。", "(正末云)怎生唤做难当的？(旦儿云)师父，这里面有个表，这个为三添气，郎君子弟要难当作耍呵，吹一口气，添上些水润这表，倾了那水，再吹一口气，拴了这葱管儿，便难当作耍。", "去了抛索儿，褪了那口气，便难当作耍不的了也。", "(正末云)假若有这口气呵，(旦儿云)便难当的。", "(正末云)若无这口气呵。", "(旦儿云)便难当不的。", "(正末云)若是无了这一口气呵，原来便难当不的。", "柳翠也，你便是比并着这气球。", "(旦儿云)师父，这气球怎生比并着柳翠？(正末云)你听，我也有一偈。", "(偈云)地水与火风，包含无为公，一朝公去后，四大各西东。", "(唱)。"]'),
('yuanqu-9577','月明和尚度柳翠・幺篇','李寿卿','元','元曲','yuanqu','','[]','郎君心闲时将你脚上踢，兴阑也络在网里，端的个不见实心。',70,'元曲/yuanqu.json','["郎君心闲时将你脚上踢，兴阑也络在网里，端的个不见实心。", "但听抛声，尽是虚脾。", "有一日，臭皮囊褪了口元阳真气。", "柳翠也，早闪下你这褪胞儿便死心塌地。"]'),
('yuanqu-9578','月明和尚度柳翠・满庭芳','李寿卿','元','元曲','yuanqu','','[]','你早则轮回也那绣衣，你和这衫儿永别，将背子道个安置。',442,'元曲/yuanqu.json','["你早则轮回也那绣衣，你和这衫儿永别，将背子道个安置。", "你且暂间波宫样乌云髻，毛角冠摩顶再休题。", "(云)柳翌，你烧了这冠衫背子，有个比喻，(旦儿云)师父。", "有甚么比喻？(正末唱)也则是土葬了你那送子弟麻花孝衣，火烧了你那战郎君的这铠甲头盔，这一场正合着俺邯参禅意。", "你今日个脱身利己，柳翠也，从今片早则去了你那虫吉螂皮。", "(卜儿云)孩儿也，你在家中住一夜去。", "(旦儿云)师父，柳翠的母亲要留柳翠家中住一夜。", "(正末云)柳翠也．你休凡心动。", "你若凡心动呵，我便知道。", "我去也。", "(旦儿云)师父，柳翠并不敢凡心动。", "(正末虚下)(旦儿云)奶奶，员外在那里？(卜儿云)员外在这里。", "员外，你出来。", "(牛员外上，云)奶奶，大姐在那里？(卜儿云)孩儿，员外来了也。", "(牛员外云)大姐，你为甚么出了家？(旦儿云)奶奶，你看着门。", "我和员外说一句话咱。", "(正末上，云)柳翌也，开门来。", "(旦儿慌科，云)师父来了也，我开开这门。", "师父家里来。", "(做不见科，云)那得那师父，元来是我的这耳热，待我关上我这门，员外，则被你想杀我也。", "(正天唱)。"]'),
('yuanqu-9579','月明和尚度柳翠・鲍老儿','李寿卿','元','元曲','yuanqu','','[]','若不是淡月朦胧使的见识，(云)甚么想杀我也牛员外？(唱)兀的不泄漏了春消息。',77,'元曲/yuanqu.json','["若不是淡月朦胧使的见识，(云)甚么想杀我也牛员外？(唱)兀的不泄漏了春消息。", "月转回廊梦欲迷。", "可着我拔树将根觅。", "柳翠也，只怕你春归人老，花残月缺，树倒根摧。"]'),
('yuanqu-9580','月明和尚度柳翠・十二月','李寿卿','元','元曲','yuanqu','','[]','这柳曾深笼着翡翠，这月曾冷浸着玻璃。',50,'元曲/yuanqu.json','["这柳曾深笼着翡翠，这月曾冷浸着玻璃。", "这月曾清光皎皎，这柳柠翠色依依，则一棹风前浪底，咫尺是蓬岛瑶池。"]'),
('yuanqu-9581','月明和尚度柳翠・尧民歌','李寿卿','元','元曲','yuanqu','','[]','柳也，渡你到微茫烟水画桥西。',89,'元曲/yuanqu.json','["柳也，渡你到微茫烟水画桥西。", "(旦儿云)师父，休撇了柳翠。", "(正末唱)柳翠也，我怎肯满船空载月明归？一波才动万波随，半载河东半载河西，谁也么知？三番家度柳翠，去来波我与你同赴龙华会。"]'),
('yuanqu-9582','月明和尚度柳翠・耍孩儿','李寿卿','元','元曲','yuanqu','','[]','毕罢了斜阳古道愁，如织。',179,'元曲/yuanqu.json','["毕罢了斜阳古道愁，如织。", "饱觑着碧天边蟾光似水，冰轮碾破玉尘飞，早则不倚禅床皱定双眉，柳也，你见了些朱门日日临官道，你见了些流水年年绕钓矶。", "(旦儿云)师父，我跟你去了，俺奶奶不思想杀我也。", "(正末唱)则你那桃花脸休洗扬花泪，断不了你那章台上霜风淅淅，渭城边烟雨霏霏。", "(云)柳翌，你来了呵，有几般儿物类失所也。", "(旦儿云)师父，是那几般物类？你说我听咱。", "(正末唱)。"]'),
('yuanqu-9583','月明和尚度柳翠・三煞','李寿卿','元','元曲','yuanqu','','[]','来了你呵，黄莺也懒更啼，金蝉也无处牺，来了你呵，再不见那绿阴深处把青骢系。',155,'元曲/yuanqu.json','["来了你呵，黄莺也懒更啼，金蝉也无处牺，来了你呵，再不见那绿阴深处把青骢系。", "来了你呵，再不见那舞春风楚宫别院纤腰细；来了你呵，再不见那缀晓露汉殿长门翠黛低；来了你呵，再不见那影蹁跹比张绪多娇媚；来了你呵，再不见那助清凉陶令宅两行斜映，增杀气亚夫营万缕低垂。", "(旦儿云)师父，我柳翠将来的究竟，可是如何？(正末唱)。"]'),
('yuanqu-9584','月明和尚度柳翠・二煞','李寿卿','元','元曲','yuanqu','','[]','再不要长事驿使催，河桥赠别离。',73,'元曲/yuanqu.json','["再不要长事驿使催，河桥赠别离。", "则被这月明照破风扶起，直着你九霄碧汉开青眼，煞强如千里红尘锁翠眉。", "度你的是蟾宫桂，你要大呵重登霸岸，要小呵索向隋堤。"]'),
('yuanqu-9585','月明和尚度柳翠・煞尾','李寿卿','元','元曲','yuanqu','','[]','待荣华则被这风雨把你来摧，强打挣又被这霜雪把你欺。',106,'元曲/yuanqu.json','["待荣华则被这风雨把你来摧，强打挣又被这霜雪把你欺。", "(旦儿云)师父，你将的我那里去那？(正末唱)我引你到西天西我佛莲池内。", "(旦儿云)师父，那我佛莲池内，怎用的我着？(正末唱)依旧的插你在南海南观音净瓶里。", "(同下)。"]'),
('yuanqu-9586','月明和尚度柳翠・双调/新水令','李寿卿','元','元曲','yuanqu','','[]','赵州原不下禅床，空闲了散花方丈，法门老比丘，公案不寻常，撇下皮囊，有相是无相。',39,'元曲/yuanqu.json','["赵州原不下禅床，空闲了散花方丈，法门老比丘，公案不寻常，撇下皮囊，有相是无相。"]'),
('yuanqu-9587','月明和尚度柳翠・驻马听','李寿卿','元','元曲','yuanqu','','[]','一世飘扬，不离红尘大道傍，受了半生魔障。',78,'元曲/yuanqu.json','["一世飘扬，不离红尘大道傍，受了半生魔障。", "则你这杨花端的为谁忙，织成新恨柳丝长，唤回午梦是那禅钟响。", "柳翠也来合掌，(带云)若来迟了呵，(唱)脚跟上好打三千棒。"]'),
('yuanqu-9588','月明和尚度柳翠・挂玉钩','李寿卿','元','元曲','yuanqu','','[]','我则听的檀板轻敲绕画梁，将我这慧眼忙开放，却原来一曲莺声啭绿杨，越引的魂飘荡。',70,'元曲/yuanqu.json','["我则听的檀板轻敲绕画梁，将我这慧眼忙开放，却原来一曲莺声啭绿杨，越引的魂飘荡。", "这的是弟子歌，又不是猱儿唱，饶他便铁石般怪心，也则索寸断柔肠。"]'),
('yuanqu-9589','月明和尚度柳翠・雁儿落','李寿卿','元','元曲','yuanqu','','[]','你可便罢追陪百二行，年纪到三十上。',35,'元曲/yuanqu.json','["你可便罢追陪百二行，年纪到三十上。", "何不去步瑶台十二层，离苦海三千丈？。"]'),
('yuanqu-9590','月明和尚度柳翠・得胜令','李寿卿','元','元曲','yuanqu','','[]','柳也，这不是大树大阴凉，我则怕甘做了老孤桩柳也，早逢着玉殿骖鸾客，再休想那章台走马郎。',73,'元曲/yuanqu.json','["柳也，这不是大树大阴凉，我则怕甘做了老孤桩柳也，早逢着玉殿骖鸾客，再休想那章台走马郎。", "度你到西方，饱看取明月清风况，世脱下皮囊，一任教黄莺紫燕忙。"]'),
('yuanqu-9591','月明和尚度柳翠・鸳鸯煞','李寿卿','元','元曲','yuanqu','','[]','撇下这人相我相众生相，出离了生况死况别离况。',169,'元曲/yuanqu.json','["撇下这人相我相众生相，出离了生况死况别离况。", "驾一片祥云，放五色毫光，唱道是佛在四天，月临上方，才得你一缕阴凉，和桂影长相向，伴着这宝盖香幢，再不许春日游人到来赏。", "(观音云)柳也，你听者。", "(偈云)出人寰脱离灾障，拜辞了风流情况。", "三十年堕落尘缘，忙追遣月明和尚。", "再休题舞依依袅娜轻盈，翠巍巍娇柔模样。", "毕罢了爱欲贪嗔，同共到灵山会上。", "(同下)。"]'),
('yuanqu-9592','十探子大闹延安府・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','见如今四海无虞，八方黎庶，皆丰富。',33,'元曲/yuanqu.json','["见如今四海无虞，八方黎庶，皆丰富。", "乐业安居，普天下都托赖着当今福。"]'),
('yuanqu-9593','十探子大闹延安府・混江龙','无名氏','元','元曲','yuanqu','','[]','为官的食君之禄，则要尽忠守节侍銮舆，投至的封妻荫子，使婢驱奴。',146,'元曲/yuanqu.json','["为官的食君之禄，则要尽忠守节侍銮舆，投至的封妻荫子，使婢驱奴。", "若个是雪案萤窗将黄卷读，怎能勾乌靴象简紫朝服，我则待要守清廉播一个万古留名誉。", "咱人要一生谄佞，枉负了七尺身躯。", "(孛老儿云)冤屈也！可谁人与我作主也？(正末云)有那等为官为吏的，陷害良民。", "小官职居清廉，理当正直除奸革弊也呵。", "(唱)。"]'),
('yuanqu-9594','十探子大闹延安府・油葫芦','无名氏','元','元曲','yuanqu','','[]','则为那吏弊官浊民受苦，差小官亲体伏。',94,'元曲/yuanqu.json','["则为那吏弊官浊民受苦，差小官亲体伏。", "有-等权豪势要狠无徒。", "他则待要倚强凌弱胡为做，全不怕一朝人怨天公怒。", "若有那衔冤的来告诉，小官可也无面目。", "施行那徒流笞杖我可便依著条律，不恁的何以得民服。"]'),
('yuanqu-9595','十探子大闹延安府・天下乐','无名氏','元','元曲','yuanqu','','[]','方信道秉正公直是大丈夫。',63,'元曲/yuanqu.json','["方信道秉正公直是大丈夫。", "我可便犹也波豫，自应付。", "我则待赤心报国将社稷扶，我则待要将良善举，我则待把奸恶除，我一心儿敢与民做主。"]'),
('yuanqu-9596','十探子大闹延安府・寄生草','无名氏','元','元曲','yuanqu','','[]','莫不是打官司人连累？莫不是告田宅争地土？莫不是争差斗殴人欺负？则管里捶胸跌脚狠忧虑，则见他寻死觅活因何故？(孛老儿做抢白正末科，云)不干你事，你休管我。',123,'元曲/yuanqu.json','["莫不是打官司人连累？莫不是告田宅争地土？莫不是争差斗殴人欺负？则管里捶胸跌脚狠忧虑，则见他寻死觅活因何故？(孛老儿做抢白正末科，云)不干你事，你休管我。", "(正未唱)哎，你个无运智的光子忒村沙，打甚么个明白冤枉咱行诉。", "(孛老儿云)冤屈也。", "(正末唱)。"]'),
('yuanqu-9597','十探子大闹延安府・正宫/端正好','无名氏','元','元曲','yuanqu','','[]','我若是顺人心，便是我亏天理，似这等衔冤负屈谁知？有这等凶徒恶党可便凭权势，他可便往往的把良民累。',48,'元曲/yuanqu.json','["我若是顺人心，便是我亏天理，似这等衔冤负屈谁知？有这等凶徒恶党可便凭权势，他可便往往的把良民累。"]'),
('yuanqu-9598','十探子大闹延安府・滚绣球','无名氏','元','元曲','yuanqu','','[]','到官中他共你，别辩个是与非，岂不闻人性命关天关地，堪恨那个公平奸佞的庞绩。',109,'元曲/yuanqu.json','["到官中他共你，别辩个是与非，岂不闻人性命关天关地，堪恨那个公平奸佞的庞绩。", "将他个媳妇儿一命亏，马踏翻他年老的妻，又将他个原告人亲儿枷起，好将那杀人贼六问三推。", "可不道明明的王法可便休轻犯，更和那湛湛青天不可欺，莫得耽迟。"]'),
('yuanqu-9599','十探子大闹延安府・呆骨朵','无名氏','元','元曲','yuanqu','','[]','则为他制造的汤水无滋味，你可甚调羹处燮理盐梅。',111,'元曲/yuanqu.json','["则为他制造的汤水无滋味，你可甚调羹处燮理盐梅。", "怎能够做茶饭五味俱全，则您那和鼎鼐四时皆失。", "您治民无决断，他可也怎见这庖官罪！(回回官人云)俺几曾吃一口加味汤。", "(正末唱)他道是他几曾吃一口加味汤，我道来您，可便都不是宰相职。"]'),
('yuanqu-9600','十探子大闹延安府・倘秀才','无名氏','元','元曲','yuanqu','','[]','你见了这李廉使都眉南面北，多管是那相公每饥嗔的这饱喜，则为我无过犯难投宰相机。',53,'元曲/yuanqu.json','["你见了这李廉使都眉南面北，多管是那相公每饥嗔的这饱喜，则为我无过犯难投宰相机。", "您肺腹，我须知，都则为饮食。"]'),
('yuanqu-9601','十探子大闹延安府・滚绣球','无名氏','元','元曲','yuanqu','','[]','非干咱揽是非，听小官说就里，岂知道你倚权豪杀人的详细，你也索问原告人案验虚实，你不将王法依，平将百姓欺，早难道寸心不昧，(庞衙内云)李廉使，你无个面皮，好歹也看',167,'元曲/yuanqu.json','["非干咱揽是非，听小官说就里，岂知道你倚权豪杀人的详细，你也索问原告人案验虚实，你不将王法依，平将百姓欺，早难道寸心不昧，(庞衙内云)李廉使，你无个面皮，好歹也看俺一殿之臣。", "你也忒多揽事。", "(正末唱)哎，你个庞衙内可是那秉正忠直！(庞衙内云)投到我来，大人每都知道了也。", "(正末唱)则你那衙门关节可便灵如卦，岂不问路上行人口胜碑，天网恢恢。"]'),
('yuanqu-9602','十探子大闹延安府・倘秀才','无名氏','元','元曲','yuanqu','','[]','我虽个是垒卵谏忠臣荀息，你叫怎么问牛喘爱民的丙吉？少罪波刘文静、魏贤臣、徐世绩。',55,'元曲/yuanqu.json','["我虽个是垒卵谏忠臣荀息，你叫怎么问牛喘爱民的丙吉？少罪波刘文静、魏贤臣、徐世绩。", "俺须是我，见官里，我和你奏知。"]'),
('yuanqu-9603','十探子大闹延安府・尾声','无名氏','元','元曲','yuanqu','','[]','我便死呵，做一个坚刚节操忠直鬼，不似那坏法欺公谄佞贼，失了人伦，差了道理。',144,'元曲/yuanqu.json','["我便死呵，做一个坚刚节操忠直鬼，不似那坏法欺公谄佞贼，失了人伦，差了道理。", "倚仗着为官更有权势，常把良民又去欺，马踏死他亲娘强要他妻，倒把平人下在牢内。", "若到朝中说就里，那其间赴法遭刑待怨谁？偿人命的官司，须要你当罪。", "(云)便好道杀人的偿命。", "(唱)你看我纳下头皮去来，我和那厮做到底。", "(下)。"]'),
('yuanqu-9604','十探子大闹延安府・中吕/粉蝶儿','无名氏','元','元曲','yuanqu','','[]','我可便奉敕承宣，理刑名勘理文卷，察清浊黜陟官员。',58,'元曲/yuanqu.json','["我可便奉敕承宣，理刑名勘理文卷，察清浊黜陟官员。", "有那害良民，违公道，我着他身加刑宪。", "但有那负屈伸冤，诉情由我行分辩。"]'),
('yuanqu-9605','十探子大闹延安府・醉春风','无名氏','元','元曲','yuanqu','','[]','阶直下威凛凛列公人，书案边忄刍忄敝忄敝排着吏典。',342,'元曲/yuanqu.json','["阶直下威凛凛列公人，书案边忄刍忄敝忄敝排着吏典。", "我则待去奸邪立一统正直碑，把名姓来显，显！为政于民，为臣报国，岂辞劳倦。", "(云)我差人拿那葛彪去了，这早晚敢待来也。", "(葛彪领张千、李万上)(葛彪云)某乃葛彪是也。", "可早来到这门首也。", "张千。", "你先报复去，说道某来了也。", "(张千报科，云)报的大人得知，拿将葛彪来了也。", "(正末云)拿将过来。", "(张千云)拿过去。", "(葛彪云)他不出来接我，我自过去。", "李廉使，我来了，有甚么书呈，将来我看者。", "(正未云)兀那厮，你怎生打死平人，因何不跪着？(葛彪做不跪科)这个廉使，我做甚么打死人来？我不跪。", "并然不干我事。", "(正末云)你不招，更待干罢。", "张千，拿下去打着者。", "(张千云)理会的。", "(做打科)(葛彪云)哎约，哎约！李廉使，你不要歪缠，我不曾惹下事。", "打山屁来了。", "(正末唱)。"]'),
('yuanqu-9606','十探子大闹延安府・迎仙客','无名氏','元','元曲','yuanqu','','[]','我观了他目下情，审了他口中言，这官司你可也怎的免？使不着你倚豪强，更那堪仗势权。',407,'元曲/yuanqu.json','["我观了他目下情，审了他口中言，这官司你可也怎的免？使不着你倚豪强，更那堪仗势权。", "又不比攀指干连，你与我便从实说把招伏串。", "(葛彪云)我可做甚么打死人来？不干我事。", "(正末云)张千，将那厮且拿在一壁有者。", "(张千云)理会的。", "(净袜子两个上，云)自家是个军，身上穿着青。", "白日里铺里睡，到晚偷人家葱。", "我两个是西延边上能行快走的两个探子，一个是李得中，一个是胡乱歇。", "俺两人奉着元帅的言语，有延安府廉使李圭，着俺两个星夜拿将他来。", "来到这衙门首。", "你这里有李圭么？大人的言语，着俺来拿他。", "张千报复去。", "也不必吃酒饭，不必要盘缠，快跟将我去来。", "(张千云)理会的。", "(报科，云)大人，有两个小军来勾大人来。", "(正末云)着过来。", "(张千云)理会的。", "着你过去。", "(做见私)(正末云)你是甚么人？(探子云)俺两个是西延边上葛元帅差来，你跟着我走，走、走！(正末云)这厮好无理也！你男子打死平人，怎敢到来勾我？拿下这厮去跪者。", "(张千云)理会的。", "(正末唱)。"]'),
('yuanqu-9607','十探子大闹延安府・白鹤子','无名氏','元','元曲','yuanqu','','[]','我亲蒙着圣主差，你为元帅镇延边。',143,'元曲/yuanqu.json','["我亲蒙着圣主差，你为元帅镇延边。", "你孩儿为人命犯了王条。", "我可便依国法非私怨。", "(云)拿下去，打四十，抢出去。", "(张千云)理会的。", "二十、三十、四十。", "出去。", "(探子哭科，云)我则道有吃的有钱钞？倒吃了一顿打，气出我个四句来了：我今做事没来由，因为勾人惹场愁，把我拖翻则管打。", "张千是小狗骨头。", "(下)。"]'),
('yuanqu-9608','十探子大闹延安府・白鹤子','无名氏','元','元曲','yuanqu','','[]','他气呸呸恶势煞，雄赳赳扣厅前。',114,'元曲/yuanqu.json','["他气呸呸恶势煞，雄赳赳扣厅前。", "一个个猛虎也似走将来，我直拷的他羊儿般善。", "(云)拿下去，打四十。", "(张千云)理会的。", "三十、四十、出去。", "(探子云)气出我个四句来了：大人做事忒乔，拿住我则管便敲。", "俺两个自家暖痛，头烧酒呷上几瓢。", "(下)。"]'),
('yuanqu-9609','十探子大闹延安府・白鹤子','无名氏','元','元曲','yuanqu','','[]','你两三番勾唤咱，将言语口中传。',33,'元曲/yuanqu.json','["你两三番勾唤咱，将言语口中传。", "粗棍子拷你皮肤，我便是打你那监军面。"]'),
('yuanqu-9610','十探子大闹延安府・白鹤子','无名氏','元','元曲','yuanqu','','[]','见威风雄赳赳，一个扌果袖并揎拳。',33,'元曲/yuanqu.json','["见威风雄赳赳，一个扌果袖并揎拳。", "俺这里不弱似吓魂台。", "便压着阎王殿。"]'),
('yuanqu-9611','十探子大闹延安府・白鹤子','无名氏','元','元曲','yuanqu','','[]','他父为官如泰山，儿犯法罪弥天。',33,'元曲/yuanqu.json','["他父为官如泰山，儿犯法罪弥天。", "我若是避权豪顺人情，枉耽着个为风宪。"]'),
('yuanqu-9612','十探子大闹延安府・快活三','无名氏','元','元曲','yuanqu','','[]','这偿人命是你的罪愆，倒将咱死熬煎。',74,'元曲/yuanqu.json','["这偿人命是你的罪愆，倒将咱死熬煎。", "不招呵一命丧黄泉，(葛彪云)大人，看俺父亲的面皮，我送对烧鹅儿你吃。", "饶了我罢。", "(正末唱)我可便管县么那监军的面？。"]'),
('yuanqu-9613','十探子大闹延安府・朝天子','无名氏','元','元曲','yuanqu','','[]','也是你那命蹇，你休想我便可怜。',120,'元曲/yuanqu.json','["也是你那命蹇，你休想我便可怜。", "笃速速打考的身躯颤。", "打的他皮开肉绽跪在阶前，将你那造恶的形骸变。", "则你那犯法违条，死而无怨，怎禁你那老无知忒自专。", "勘问的这事完，我可回那帝辇，(云)做儿的打死平人，做爷的擅勾台省官员。", "(唱)俺两个便亲自到金銮殿。"]'),
('yuanqu-9614','十探子大闹延安府・啄木儿尾声','无名氏','元','元曲','yuanqu','','[]','教百姓每晓谕的知，将杀人贼斩布市廛，举宜错诸枉民无怨。',53,'元曲/yuanqu.json','["教百姓每晓谕的知，将杀人贼斩布市廛，举宜错诸枉民无怨。", "虽不是包龙图的机变，将我这秉忠百名姓入凌烟。", "(下)。"]'),
('yuanqu-9615','十探子大闹延安府・双调/新水令','无名氏','元','元曲','yuanqu','','[]','为臣尽节整纲常，报君恩敬于事上。',375,'元曲/yuanqu.json','["为臣尽节整纲常，报君恩敬于事上。", "汉廷汲黯忠，唐室魏徵良。", "见如今千载名扬，万古流芳，史记谈扬，一个个凌烟阁画图像。", "(云)左右衙门首觑者，看有甚么人来。", "(张千云)理会的。", "(葛监军上，云)某乃葛怀愍是也。", "统领三军，到于延安府。", "不放三军，寸箭不许带进城去，三军都在城外扎营，我亲自见李圭去来。", "可早到门首也。", "张千报复去，道有葛监军在于门首。", "(张千云)理会的。", "喏！报的大人得知，有葛监军来了也。", "(正末云)他不自过来，着我接待他去？(张千云)俺大人说来，你不自过去，待教俺大人接待你？(葛监军云)此人这等权重，我试看者。", "原来有势剑金牌在此。", "葛怀愍也，你可不来么！我自过去有说话。", "好难请唤也，李圭！(正末云)好无礼也，葛怀愍！(葛监军云)你怎敢屈勘平人？(正末云)你怎敢擅离汛地？(葛监军跪科)(正末云)我身居台省，执掌提刑；你不遵号令，私离边庭。", "我问你波。", "(唱)。"]'),
('yuanqu-9616','十探子大闹延安府・沉醉东风','无名氏','元','元曲','yuanqu','','[]','则你那七禁令何当是你掌？(云)我问你来了呵。',123,'元曲/yuanqu.json','["则你那七禁令何当是你掌？(云)我问你来了呵。", "(唱)则你那三军印寄付与谁行？少罪波逃军营的姜太公，离寨栅的诸葛亮，辱没杀晋尹铎保障金汤。", "你为儿子行凶做爹的撇了战场，(云)为将者一轻、二慢、三盗、四欺、五背、六乱、七误。", "(唱)请你个行号令的监军自想。"]'),
('yuanqu-9617','十探子大闹延安府・沽美酒','无名氏','元','元曲','yuanqu','','[]','我可也敢和你做一场，休想我便肯轻放。',48,'元曲/yuanqu.json','["我可也敢和你做一场，休想我便肯轻放。", "倚着你父子每权豪势力强，你怎敢擅离了边庭地方，忒欺公忒无状。"]'),
('yuanqu-9618','十探子大闹延安府・太平令','无名氏','元','元曲','yuanqu','','[]','也不索用长问短状，直和你见銮舆打一会官房。',148,'元曲/yuanqu.json','["也不索用长问短状，直和你见銮舆打一会官房。", "(范仲淹冲上，云)老夫范仲淹是也。", "可早来到延安府也。", "(张千云)范学士大人下马也，(范仲淹云)甚么人大惊小怪的？(正末唱)正遇着天臣宰相，使不着你狂言抵当。", "他可便倚仗势强，将人命事不偿，(云)做儿的打死平人，做爷的擅离汛地。", "(唱)大人也，他罪难容徒流笞杖。"]'),
('yuanqu-9619','黄钟・醉花阴','侯正卿','元','元曲','yuanqu','','[]','凉夜厌厌露华冷，天淡淡银河耿耿。',33,'元曲/yuanqu.json','["凉夜厌厌露华冷，天淡淡银河耿耿。", "秋月浸闲亭，雨过新凉，梧叶雕金并。"]'),
('yuanqu-9620','出队子・阑干斜凭，强将玉漏听。十分烦恼恰三停，一夜ゐ惶才二更，暗','侯正卿','元','元曲','yuanqu','','[]','屈春纤紧数定。',7,'元曲/yuanqu.json','["屈春纤紧数定。"]'),
('yuanqu-9621','刮地风・短叹长吁千万声，几时到得天明。被宾鸿唤回离愁兴，雨泪盈盈。','侯正卿','元','元曲','yuanqu','','[]','天如悬罄，月如明镜。',34,'元曲/yuanqu.json','["天如悬罄，月如明镜。", "桂影浮，素魄辉，玉盘光静。", "澄澄万里晴，一缕云生。"]'),
('yuanqu-9622','四门子・恰遮了北斗杓儿柄，这凄凉有四星。望鸳鸯尽老无孤另，乍分飞','侯正卿','元','元曲','yuanqu','','[]','可惯经。',34,'元曲/yuanqu.json','["可惯经。", "日日疏，迤逦生，逐朝盼望逐日候等。", "行里焦，梦里惊，心不暂停。"]'),
('yuanqu-9623','水仙子・甚识曾，半霎儿他行不至诚。气命儿般看成，心肝般钦敬，倒将','侯正卿','元','元曲','yuanqu','','[]','人草芥船轻。',38,'元曲/yuanqu.json','["人草芥船轻。", "瞒不过天地神明，说来的咒誓终朝应。", "亏心神鬼还灵圣，肠欲断泪如倾。"]'),
('yuanqu-9624','塞雁儿・牢成，牢成，一句句骂得心疼，据踪迹疏狂似浮萍。山般誓，海','侯正卿','元','元曲','yuanqu','','[]','样盟，半句儿何曾应？。',11,'元曲/yuanqu.json','["样盟，半句儿何曾应？。"]'),
('yuanqu-9625','神仗儿・他待做临川县令，俺不做卢州小卿。学亚仙、元和，王魁、桂英。','侯正卿','元','元曲','yuanqu','','[]','心肠儿可怜，模样儿堪憎。',28,'元曲/yuanqu.json','["心肠儿可怜，模样儿堪憎。", "往常时所事依凭，虽愚滥，可惯经。"]'),
('yuanqu-9626','节节高犯・近新来特改的心肠硬，全不问人绣帏帐罗衾剩，接双栖鸳枕共','侯正卿','元','元曲','yuanqu','','[]','谁并？你纵宝马，跳金鞍，玩玉京，迷恋着良辰媚景。',24,'元曲/yuanqu.json','["谁并？你纵宝马，跳金鞍，玩玉京，迷恋着良辰媚景。"]'),
('yuanqu-9627','挂金索・懵懂心肠，捱不过风流病，短命冤家，断不了疏狂性。第一才郎。','侯正卿','元','元曲','yuanqu','','[]','俺行失信行，第二佳人，自古多簿幸。',17,'元曲/yuanqu.json','["俺行失信行，第二佳人，自古多簿幸。"]'),
('yuanqu-9628','柳叶儿・冷落了绿苔芳径，寂寞了雾帐云屏，消疏了象板鸾笙，生疏了锦','侯正卿','元','元曲','yuanqu','','[]','瑟银筝。',4,'元曲/yuanqu.json','["瑟银筝。"]'),
('yuanqu-9629','黄钟・锦帏绣幕冷清清，银台画灯碧荧荧。金风乱吹黄叶声，沉烟潜消白','侯正卿','元','元曲','yuanqu','','[]','玉鼎。',39,'元曲/yuanqu.json','["玉鼎。", "槛竹筛酒又醒，塞雁归愁越添，檐马劣梦难成。", "早是可惯孤眠，则这些最难打挣。"]'),
('yuanqu-9631','正宫・菩萨蛮客中寄情','侯正卿','元','元曲','yuanqu','','[]','镜中两鬓皤然矣，心头一点愁而已。',28,'元曲/yuanqu.json','["镜中两鬓皤然矣，心头一点愁而已。", "清瘦仗谁医？羁情只自知。"]'),
('yuanqu-9632','月照庭・半纸功名，断送关山。云渺渺，草凄凄。小楼风，重门月，应盼','侯正卿','元','元曲','yuanqu','','[]','人归。',11,'元曲/yuanqu.json','["人归。", "归心急，去路迷。"]'),
('yuanqu-9633','喜春来・家书端可驱邪祟，乡梦真堪疗客饥。眼前百事与心违，不投机，','侯正卿','元','元曲','yuanqu','','[]','除赖酒支持。',6,'元曲/yuanqu.json','["除赖酒支持。"]'),
('yuanqu-9634','高过金盏儿・举金杯，倒金杯，金杯未倒心先醉，酒醒时候更凄凄。情似','侯正卿','元','元曲','yuanqu','','[]','织，招揽下相思无尽期，告他谁？。',16,'元曲/yuanqu.json','["织，招揽下相思无尽期，告他谁？。"]'),
('yuanqu-9635','牡丹春・忽听楼头更漏催，别凤又孤栖。暂朦胧枕上重欢会，梦惊回，又','侯正卿','元','元曲','yuanqu','','[]','是一别离。',5,'元曲/yuanqu.json','["是一别离。"]'),
('yuanqu-9636','醉高歌・客窗夜永岑寂，有多少孤眠况味。欲修锦字凭谁寄？报与些凄凉','侯正卿','元','元曲','yuanqu','','[]','事实。',3,'元曲/yuanqu.json','["事实。"]');
